  // API endpoint to load more products for widget "Show More" button
  app.post("/api/chat/widget/products/more", async (req, res) => {
    try {
      const { businessAccountId, search, offset = 0, minPrice, maxPrice } = req.body;
      
      console.log('[Products More] Request received:', { businessAccountId, search, offset, minPrice, maxPrice });
      
      if (!businessAccountId) {
        return res.status(400).json({ error: "businessAccountId required" });
      }
      
      // Get all products for this business with categories/tags
      const allProducts = await storage.getAllProducts(businessAccountId);
      const productsWithMeta = await Promise.all(
        allProducts.map(async (p) => {
          const categories = await storage.getProductCategories(p.id);
          const tags = await storage.getProductTags(p.id);
          return { ...p, categories, tags };
        })
      );
      
      // Filter by search query if provided (same logic as toolExecutionService)
      // Uses intelligent word-based matching with category-aware logic
      let filteredProducts = productsWithMeta;
      if (search) {
        const searchWords = search.toLowerCase().split(/\s+/).filter((w: string) => w.length > 0);
        
        // Helper: Normalize singular/plural (ring <-> rings, earring <-> earrings)
        const normalizeWord = (word: string): string[] => {
          const variants = [word];
          if (word.endsWith('s') && word.length > 2) {
            variants.push(word.slice(0, -1)); // rings -> ring
          } else {
            variants.push(word + 's'); // ring -> rings
          }
          return variants;
        };
        
        // Helper: Check if word matches using word boundary (prevents 'ring' matching 'earring')
        const matchesWithBoundary = (text: string, word: string): boolean => {
          const variants = normalizeWord(word);
          return variants.some(variant => {
            const regex = new RegExp(`\\b${variant}\\b`, 'i');
            return regex.test(text);
          });
        };
        
        filteredProducts = productsWithMeta.filter(p => {
          // For each search word, check if it matches using word boundary matching
          // This prevents 'ring' from matching 'earring' in any field
          
          const categoryTagText = [...p.categories.map(c => c.name), ...p.tags.map(t => t.name)].join(' ');
          const nameDescText = [p.name || '', p.description || ''].join(' ');
          
          const allWordsMatch = searchWords.every((word: string) => {
            // Check category/tag names with word boundaries
            const matchesCategory = matchesWithBoundary(categoryTagText, word);
            if (matchesCategory) return true;
            
            // Check name/description with word boundaries as well
            // This ensures "ring" doesn't match "earring" in product names
            const matchesNameDesc = matchesWithBoundary(nameDescText, word);
            
            return matchesNameDesc;
          });
          
          return allWordsMatch;
        });
      }
      
      // Apply price filters if provided
      if (minPrice !== undefined || maxPrice !== undefined) {
        filteredProducts = filteredProducts.filter(p => {
          if (p.price === null || p.price === undefined) {
            return false;
          }
          
          const price = parseFloat(p.price.toString());
          
          if (minPrice !== undefined && price < minPrice) {
            return false;
          }
          
          if (maxPrice !== undefined && price > maxPrice) {
            return false;
          }
          
          return true;
        });
      }
      
      // Apply pagination
      const limit = 5;
      const totalCount = filteredProducts.length;
      const paginatedProducts = filteredProducts.slice(offset, offset + limit);
      const hasMore = (offset + limit) < totalCount;
      const nextOffset = hasMore ? offset + limit : null;
      
      res.json({
        success: true,
        data: paginatedProducts,
        pagination: {
          total: totalCount,
          offset: offset,
          limit: limit,
          hasMore: hasMore,
          nextOffset: nextOffset,
          showing: paginatedProducts.length,
          filters: {
            search: search || null,
            minPrice: minPrice !== undefined ? minPrice : null,
            maxPrice: maxPrice !== undefined ? maxPrice : null,
          }
        }
      });
    } catch (error: any) {
      console.error('[Widget Products More] Error:', error);
      res.status(500).json({ error: error.message || "Failed to load products" });
    }
  });

  app.post("/api/chat/widget/stream", async (req, res) => {
    try {
      const { message, businessAccountId, sessionId, language, visitorSessionId, sessionToken, isGuidanceChat, starterQAContext, pageUrl: clientPageUrl, resumeContextId } = req.body;
      
      // Debug logging for language parameter
      console.log('[Widget Stream] Language debug:', {
        languageParam: language || 'NOT_SET',
        languageType: typeof language,
        isAuto: language === 'auto',
        message: message?.substring(0, 50)
      });
      
      if (!message || !businessAccountId) {
        return res.status(400).json({ error: "Message and businessAccountId required" });
      }

      // Use unique session ID for each widget visit (resets on page refresh)
      const widgetUserId = sessionId ? `widget_session_${sessionId}` : `widget_${businessAccountId}`;
      
      // Fetch widget settings, business account, and API key in parallel
      const [settings, businessAccount, openaiApiKey] = await Promise.all([
        storage.getWidgetSettings(businessAccountId),
        storage.getBusinessAccount(businessAccountId),
        storage.getBusinessAccountOpenAIKey(businessAccountId),
      ]);

      console.log('[Widget Stream] Settings loaded:', { 
        hasSettings: !!settings, 
        customInstructions: settings?.customInstructions?.substring(0, 50) || 'NONE',
        responseLength: settings?.responseLength || 'balanced (default)'
      });

      if (!businessAccount) {
        return res.status(404).json({ error: "Business account not found" });
      }

      if (businessAccount.status === 'suspended') {
        return res.status(403).json({ error: "This chatbot is currently unavailable" });
      }

      if (!openaiApiKey) {
        console.warn('[Widget Stream] No OpenAI API key found for business:', businessAccountId);
        return res.status(400).json({ error: "OpenAI API key not configured for this business account" });
      }

      const personality = settings?.personality || 'friendly';
      const responseLength = settings?.responseLength || 'balanced';
      const currency = settings?.currency || 'USD';
      const currencySymbols: Record<string, string> = {
        USD: "$", EUR: "€", GBP: "£", JPY: "¥", CNY: "¥", INR: "₹", AUD: "A$",
        CAD: "C$", CHF: "CHF", SEK: "kr", NZD: "NZ$", SGD: "S$", HKD: "HK$",
        NOK: "kr", MXN: "$", BRL: "R$", ZAR: "R", KRW: "₩", TRY: "₺",
        RUB: "₽", IDR: "Rp", THB: "฿", MYR: "RM"
      };
      const currencySymbol = currencySymbols[currency] || "$";

      // Set up SSE headers immediately — client sees the connection open right away,
      // spinner appears before geolocation / language detection complete
      res.setHeader('Content-Type', 'text/event-stream');
      res.setHeader('Cache-Control', 'no-cache');
      res.setHeader('Connection', 'keep-alive');
      res.setHeader('Access-Control-Allow-Origin', '*');
      res.flushHeaders(); // flush now so client fetch() resolves and spinner appears
      res.write(`data: ${JSON.stringify({ type: 'heartbeat' })}\n\n`); // push through TCP stack

      // Build starter Q&A context string if provided
      let starterQAContextString: string | undefined;
      if (Array.isArray(starterQAContext) && starterQAContext.length > 0) {
        const qaFormatted = starterQAContext
          .filter((qa: { question: string; answer: string }) => qa.question && qa.answer)
          .map((qa: { question: string; answer: string }) => `Q: ${qa.question}\nA: ${qa.answer}`)
          .join('\n\n');
        if (qaFormatted) {
          starterQAContextString = `
=== CRITICAL: PREDEFINED GUIDANCE ANSWERS ===
You MUST follow this strict answer priority:

PRIORITY 1 - PREDEFINED ANSWERS (USE FIRST):
When the user's question matches or is similar to any of these predefined questions, you MUST use the exact predefined answer. Do NOT paraphrase, add to, or ignore these answers:

${qaFormatted}

PRIORITY 2 - BUSINESS KNOWLEDGE (FALLBACK):
If no predefined answer matches, use FAQs, product information, or training data from this business.

PRIORITY 3 - ADMIT UNCERTAINTY:
If the question cannot be answered from predefined answers OR business knowledge, respond with: "I don't have specific information about that. Is there something else I can help you with?"

NEVER use general world knowledge. You are a guidance assistant for this specific context only.
=== END GUIDANCE INSTRUCTIONS ===
`;
        }
      }

      // Run geolocation and language detection in parallel — they're independent of each other
      const clientIp = (req.headers['x-forwarded-for'] as string)?.split(',')[0].trim() ||
                       req.socket.remoteAddress || 'unknown';

      const [visitorCity, detectedLanguage] = await Promise.all([
        resolveVisitorCity(clientIp).then(city => {
          if (city) console.log(`[Widget Stream] Geo-located visitor: ${city}`);
          return city;
        }),
        (!language || language === 'auto')
          ? llamaService.detectLanguage(message, openaiApiKey).catch(() => undefined)
          : Promise.resolve(undefined),
      ]);

      let effectiveLanguage: string | undefined = language || undefined;
      if (!language || language === 'auto') {
        if (detectedLanguage && detectedLanguage !== 'auto' && detectedLanguage !== 'other') {
          effectiveLanguage = detectedLanguage;
          console.log(`[Widget Stream] Language detected: ${detectedLanguage} for "${message.substring(0, 30)}"`);
        }
      }

      // Stream the response
      let resumeText: string | undefined;
      let resumeUrl: string | undefined;
      if (resumeContextId && typeof resumeContextId === 'string') {
        const cached = resumeTextCache.get(resumeContextId);
        if (cached && cached.businessAccountId === businessAccountId) {
          resumeText = cached.text;
          resumeUrl = cached.resumeUrl;
          resumeTextCache.delete(resumeContextId);
          console.log(`[Widget Stream] Resume context retrieved (${resumeText.length} chars)${resumeUrl ? ' with PDF URL' : ''}`);
        }
      }

      for await (const chunk of chatService.streamMessage(message, {
        userId: widgetUserId,
        businessAccountId,
        personality,
        responseLength,
        companyDescription: businessAccount.description || '',
        openaiApiKey,
        currency,
        currencySymbol,
        customInstructions: settings?.customInstructions || undefined,
        preferredLanguage: effectiveLanguage,
        visitorSessionId: visitorSessionId || undefined,
        visitorCity: visitorCity || undefined,
        visitorToken: sessionToken || undefined,
        skipLeadTraining: isGuidanceChat === true,
        starterQAContext: starterQAContextString,
        supportsCalendarUI: true,
        pageUrl: clientPageUrl || undefined,
        systemMode: businessAccount.systemMode || 'full',
        k12EducationEnabled: businessAccount.k12EducationEnabled === 'true',
        jobPortalEnabled: businessAccount.jobPortalEnabled === 'true',
        resumeText,
        resumeUrl,
      })) {
        res.write(`data: ${JSON.stringify(chunk)}\n\n`);
      }

      res.end();
    } catch (error: any) {
      console.error('[Widget Stream] Error:', error);
      res.write(`data: ${JSON.stringify({ type: 'error', data: error.message })}\n\n`);
      res.end();
    }
  });

  app.get("/api/chat/widget/intro", async (req, res) => {
    try {
      const { businessAccountId, language, welcomeBack } = req.query;
      
      if (!businessAccountId) {
        return res.status(400).json({ error: "businessAccountId required" });
      }

      const settings = await storage.getWidgetSettings(businessAccountId as string);
      const businessAccount = await storage.getBusinessAccount(businessAccountId as string);
      
      if (!businessAccount) {
        return res.status(404).json({ error: "Business account not found" });
      }

      // Check if business account is active
      if (businessAccount.status === 'suspended') {
        return res.status(403).json({ error: "This chatbot is currently unavailable" });
      }

      // Handle Welcome Back greeting for returning visitors (after 30+ minutes)
      if (welcomeBack === 'true' && businessAccount.openaiApiKey) {
        try {
          console.log('[Intro API] Generating welcome back message for returning visitor');
          
          const businessName = businessAccount.businessName || businessAccount.name || 'us';
          const systemContext = businessAccount.description ? 
            `You are representing: ${businessAccount.description}` : 
            '';
          
          const openai = new OpenAI({ apiKey: businessAccount.openaiApiKey });
          const completion = await openai.chat.completions.create({
            model: 'gpt-4o-mini',
            messages: [
              { 
                role: 'system', 
                content: `${systemContext}\n\nYou are a friendly AI assistant. Generate a warm, welcoming message for a returning visitor. Keep it brief (1-2 sentences). Don't use emojis. Make it feel personal and inviting.`
              },
              { 
                role: 'user', 
                content: `Generate a welcome back greeting for a visitor returning to ${businessName}. Ask what they'd like to know or how you can help today.`
              }
            ],
            temperature: 0.7,
            max_tokens: 100
          });
          
          let intro = completion.choices[0]?.message?.content?.trim() || "Welcome back! How can I help you today?";
          
          // Translate if needed
          if (language && language !== 'auto' && language !== 'en') {
            const LANGUAGE_NAMES: Record<string, string> = {
              'en': 'English', 'hi': 'Hindi', 'hinglish': 'Hinglish', 'ta': 'Tamil', 'te': 'Telugu',
              'kn': 'Kannada', 'mr': 'Marathi', 'bn': 'Bengali', 'gu': 'Gujarati', 'ml': 'Malayalam',
              'pa': 'Punjabi', 'or': 'Odia', 'as': 'Assamese', 'ur': 'Urdu', 'ne': 'Nepali',
              'es': 'Spanish', 'fr': 'French', 'de': 'German', 'pt': 'Portuguese', 'it': 'Italian',
              'ja': 'Japanese', 'ko': 'Korean', 'zh': 'Chinese', 'ar': 'Arabic', 'ru': 'Russian',
              'th': 'Thai', 'vi': 'Vietnamese', 'id': 'Indonesian', 'ms': 'Malay', 'tr': 'Turkish'
            };
            const langName = LANGUAGE_NAMES[language as string];
            if (langName) {
              const translateCompletion = await openai.chat.completions.create({
                model: 'gpt-4o-mini',
                messages: [
                  { role: 'system', content: `Translate the following text to ${langName}. Return ONLY the translated text, nothing else. Keep the tone and meaning intact.` },
                  { role: 'user', content: intro }
                ],
                temperature: 0.3,
                max_tokens: 200
              });
              intro = translateCompletion.choices[0]?.message?.content?.trim() || intro;
            }
          }
          
          console.log('[Intro API] Welcome back message:', intro);
          return res.json({ intro, isWelcomeBack: true });
        } catch (error) {
          console.error('[Intro API] Welcome back generation failed:', error);
          // Fall through to normal intro
        }
      }

      // Language name mapping for translation
      const LANGUAGE_NAMES: Record<string, string> = {
        'en': 'English', 'hi': 'Hindi', 'hinglish': 'Hinglish', 'ta': 'Tamil', 'te': 'Telugu',
        'kn': 'Kannada', 'mr': 'Marathi', 'bn': 'Bengali', 'gu': 'Gujarati', 'ml': 'Malayalam',
        'pa': 'Punjabi', 'or': 'Odia', 'as': 'Assamese', 'ur': 'Urdu', 'ne': 'Nepali',
        'es': 'Spanish', 'fr': 'French', 'de': 'German', 'pt': 'Portuguese', 'it': 'Italian',
        'ja': 'Japanese', 'ko': 'Korean', 'zh': 'Chinese', 'ar': 'Arabic', 'ru': 'Russian',
        'th': 'Thai', 'vi': 'Vietnamese', 'id': 'Indonesian', 'ms': 'Malay', 'tr': 'Turkish'
      };

      // Helper function to translate text using OpenAI
      const translateText = async (text: string, targetLang: string): Promise<string> => {
        if (!targetLang || targetLang === 'auto' || targetLang === 'en') return text;
        if (!businessAccount.openaiApiKey) return text;
        
        const langName = LANGUAGE_NAMES[targetLang] || targetLang;
        try {
          const openai = new OpenAI({ apiKey: businessAccount.openaiApiKey });
          const completion = await openai.chat.completions.create({
            model: 'gpt-4o-mini',
            messages: [
              { role: 'system', content: `Translate the following text to ${langName}. Return ONLY the translated text, nothing else. Keep the tone and meaning intact.` },
              { role: 'user', content: text }
            ],
            temperature: 0.3,
            max_tokens: 200
          });
          return completion.choices[0]?.message?.content?.trim() || text;
        } catch (error) {
          console.error('[Translation] Failed:', error);
          return text;
        }
      };

      // Check for startFromScratch journey first - if enabled, use first step as greeting
      const journeys = await storage.getAllJourneys(businessAccountId as string);
      const startFromScratchJourney = journeys.find(j => 
        j.status === 'active' && j.startFromScratch === 'true'
      );
      
      if (startFromScratchJourney) {
        const steps = await storage.getJourneySteps(startFromScratchJourney.id);
        if (steps.length > 0) {
          const sortedSteps = steps.sort((a, b) => Number(a.stepOrder) - Number(b.stepOrder));
          const firstStep = sortedSteps[0];
          console.log(`[Widget Intro] Using journey first step as greeting: ${firstStep.questionText.substring(0, 50)}...`);
          
          // Translate if needed
          let introText = firstStep.questionText;
          if (language && language !== 'auto' && language !== 'en') {
            introText = await translateText(introText, language as string);
          }
          
          const response: any = { 
            intro: introText,
            journeyId: startFromScratchJourney.id,
            startFromScratch: true
          };
          
          // For form journeys, include form step data for visual UI
          if (startFromScratchJourney.journeyType === 'form') {
            let options: string[] | undefined;
            if ((firstStep.questionType === 'radio' || firstStep.questionType === 'dropdown') && firstStep.multipleChoiceOptions) {
              try {
                options = JSON.parse(firstStep.multipleChoiceOptions);
              } catch (e) {
                console.error('[Widget Intro] Failed to parse choice options:', e);
              }
            }
            
            response.formStep = {
              stepId: firstStep.id,
              questionText: introText, // Use translated text for formStep too
              questionType: firstStep.questionType || 'text',
              isRequired: firstStep.isRequired === 'true',
              options,
              placeholder: firstStep.placeholderText || undefined,
              stepType: firstStep.toolTrigger || undefined,
            };
            console.log(`[Widget Intro] Form journey - including form step data for visual UI`);
          }
          
          return res.json(response);
        }
      }
      
      // Check welcome message type
      if (settings?.welcomeMessageType === 'custom' && settings?.welcomeMessage) {
        const intro = language && language !== 'auto' 
          ? await translateText(settings.welcomeMessage, language as string)
          : settings.welcomeMessage;
        return res.json({ intro });
      }

      // Generate AI intro if needed and API key is available
      if (businessAccount.openaiApiKey) {
        try {
          const systemContext = businessAccount.description ? 
            `You are representing: ${businessAccount.description}` : 
            '';

          const introResponse = await llamaService.generateToolAwareResponse(
            "Generate a brief, friendly welcome message (1-2 sentences) for a customer visiting our website.",
            [],
            [],
            systemContext,
            settings?.personality || 'friendly',
            businessAccount.openaiApiKey
          );

          const intro = introResponse.content || "Hi! How can I help you today?";
          
          // Cache the intro in widget settings
          if (settings) {
            await storage.upsertWidgetSettings(businessAccountId as string, { cachedIntro: intro });
          }

          return res.json({ intro });
        } catch (error) {
          console.error('[Widget Intro] AI generation failed:', error);
        }
      }

      // Fallback to default message - translate if needed
      const defaultMsg = "Hi! How can I help you today?";
      const intro = language && language !== 'auto' 
        ? await translateText(defaultMsg, language as string)
        : defaultMsg;
      res.json({ intro });
    } catch (error: any) {
      console.error('[Widget Intro] Error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // Widget appointment slots endpoint - returns available appointment slots
  app.get("/api/chat/widget/appointment-slots", async (req, res) => {
    try {
      const { businessAccountId } = req.query;
      
      if (!businessAccountId) {
        return res.status(400).json({ error: "businessAccountId required" });
      }
      
      // Check if appointment booking is enabled
      const widgetSettings = await storage.getWidgetSettings(businessAccountId as string);
      if (widgetSettings?.appointmentBookingEnabled === 'false') {
        return res.json({ 
          slots: {}, 
          total: 0, 
          message: 'Appointment booking is currently unavailable.' 
        });
      }
      
      // Use toolExecutionService to get slots for next 30 days (for calendar view)
      const { ToolExecutionService } = await import('./services/toolExecutionService');
      const today = new Date();
      const endDate = new Date(today);
      endDate.setDate(endDate.getDate() + 30);
      
      const result = await ToolExecutionService.executeTool(
        'list_available_slots',
        { 
          duration_minutes: 30,
          start_date: today.toISOString().split('T')[0],
          end_date: endDate.toISOString().split('T')[0]
        },
        {
          businessAccountId: businessAccountId as string,
          userId: 'widget-user',
          conversationId: '',
          conversationHistory: []
        }
      );
      
      if (result.success && result.data) {
        return res.json(result.data);
      }
      
      return res.json({ slots: {}, total: 0 });
    } catch (error: any) {
      console.error('[Widget Appointment Slots] Error:', error);
      res.status(500).json({ error: error.message });
    }
  });

