  app.post("/api/chat/widget/book-appointment", async (req, res) => {
    try {
      const { businessAccountId, date, time, conversationId } = req.body;
      
      if (!businessAccountId || !date || !time) {
        return res.status(400).json({ error: "businessAccountId, date, and time required" });
      }
      
      // Check if appointments are enabled on the business account
      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      if (!businessAccount || businessAccount.appointmentsEnabled !== 'true') {
        return res.status(400).json({ 
          success: false, 
          error: 'Appointments are not enabled' 
        });
      }
      
      // Validate the date/time slot is available
      const appointmentDate = new Date(date + 'T00:00:00');
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      
      // Check for past dates
      if (appointmentDate < today) {
        return res.status(400).json({ 
          success: false, 
          error: 'Cannot book appointments in the past' 
        });
      }
      
      // Check for conflicting appointments
      const existingAppointments = await storage.getAppointmentsForRange(
        businessAccountId, 
        appointmentDate, 
        appointmentDate
      );
      const conflictingAppointments = existingAppointments.filter(
        (appt: any) => appt.status !== 'cancelled' && appt.appointmentTime === time
      );
      
      if (conflictingAppointments.length > 0) {
        return res.status(400).json({ 
          success: false, 
          error: 'This time slot is no longer available. Please select another time.' 
        });
      }
      
      // Check schedule availability
      const dayOfWeek = appointmentDate.getDay();
      const [scheduleTemplates, overrides] = await Promise.all([
        storage.getScheduleTemplates(businessAccountId),
        storage.getSlotOverridesForRange(businessAccountId, appointmentDate, appointmentDate)
      ]);
      
      // Check if slot is blocked by override
      const dateKey = date;
      const relevantOverrides = overrides.filter((o: any) => {
        const overrideDateKey = new Date(o.slotDate).toISOString().split('T')[0];
        return overrideDateKey === dateKey && o.slotTime === time;
      });
      
      const isBlockedByOverride = relevantOverrides.some((o: any) => o.isAvailable === 'false');
      if (isBlockedByOverride) {
        return res.status(400).json({ 
          success: false, 
          error: 'This time slot is not available' 
        });
      }
      
      // Check if slot is added by override or is within schedule template
      const isAddedByOverride = relevantOverrides.some((o: any) => o.isAvailable === 'true');
      
      // Get schedule templates for this day
      const dayTemplates = scheduleTemplates.filter(
        (t: any) => parseInt(t.dayOfWeek.toString()) === dayOfWeek && t.isActive === 'true'
      );
      
      if (!isAddedByOverride) {
        // Validate against schedule templates
        if (dayTemplates.length === 0) {
          return res.status(400).json({ 
            success: false, 
            error: 'No appointments available on this day' 
          });
        }
        
        // Check if the time falls within any active schedule template
        const isWithinSchedule = dayTemplates.some((template: any) => {
          const startTime = template.startTime;
          const endTime = template.endTime;
          return time >= startTime && time < endTime;
        });
        
        if (!isWithinSchedule) {
          return res.status(400).json({ 
            success: false, 
            error: 'This time slot is outside business hours' 
          });
        }
      }
      
      // Also check if the specific time slot is in the past (for today's date)
      if (appointmentDate.getTime() === today.getTime()) {
        const now = new Date();
        const [slotHours, slotMinutes] = time.split(':').map(Number);
        const slotDateTime = new Date(appointmentDate);
        slotDateTime.setHours(slotHours, slotMinutes, 0, 0);
        
        if (slotDateTime <= now) {
          return res.status(400).json({ 
            success: false, 
            error: 'This time slot has already passed' 
          });
        }
      }
      
      // Get duration from schedule template for this day
      const activeTemplate = dayTemplates.find((t: any) => t.isActive === 'true');
      const durationMinutes = activeTemplate?.slotDuration ? parseInt(activeTemplate.slotDuration) : 30;
      
      // Create appointment with pending status (name/phone to be collected later)
      const appointment = await storage.createAppointment({
        businessAccountId: businessAccountId as string,
        appointmentDate: appointmentDate,
        appointmentTime: time,
        durationMinutes,
        patientName: 'Pending',
        patientPhone: '',
        patientEmail: null,
        status: 'pending',
        conversationId: conversationId || null,
        notes: 'Booked via widget - awaiting contact details'
      });
      
      // Format the date/time for user display
      const formattedDate = appointmentDate.toLocaleDateString('en-US', { 
        weekday: 'long', 
        month: 'long', 
        day: 'numeric' 
      });
      
      const [hours, minutes] = time.split(':').map(Number);
      const period = hours >= 12 ? 'PM' : 'AM';
      const displayHours = hours % 12 || 12;
      const formattedTime = `${displayHours}:${minutes.toString().padStart(2, '0')} ${period}`;
      
      return res.json({ 
        success: true, 
        appointmentId: appointment.id,
        message: `Appointment reserved for ${formattedDate} at ${formattedTime}` 
      });
    } catch (error: any) {
      console.error('[Widget Book Appointment] Error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // Widget update pending appointment with name/phone
  app.post("/api/chat/widget/update-appointment", async (req, res) => {
    try {
      const { appointmentId, conversationId, businessAccountId, name, phone, email } = req.body;
      
      if (!businessAccountId) {
        return res.status(400).json({ error: "businessAccountId required" });
      }
      
      if (!appointmentId && !conversationId) {
        return res.status(400).json({ error: "appointmentId or conversationId required" });
      }
      
      let appointment;
      
      if (appointmentId) {
        appointment = await storage.getAppointment(appointmentId);
      } else if (conversationId) {
        // Find appointment by conversationId
        const appointments = await storage.getAppointmentsByConversationId(conversationId);
        appointment = appointments.find((a: any) => a.status === 'pending');
      }
      
      if (!appointment) {
        return res.status(404).json({ error: "Appointment not found" });
      }
      
      // Verify appointment belongs to the correct business account
      if (appointment.businessAccountId !== businessAccountId) {
        return res.status(403).json({ error: "Not authorized to update this appointment" });
      }
      
      // Only allow updates on pending appointments
      if (appointment.status !== 'pending') {
        return res.status(400).json({ error: "Can only update pending appointments" });
      }
      
      if (phone) {
        const phoneValidation = validatePhoneNumber(phone, '10');
        if (!phoneValidation.isValid) {
          return res.status(400).json({ error: phoneValidation.reasonMessage });
        }
      }

      // Update the appointment with provided details
      const updates: any = {};
      if (name) updates.patientName = name;
      if (phone) updates.patientPhone = phone;
      if (email) updates.patientEmail = email;
      
      // If we have both name and phone, mark as confirmed
      const finalName = name || appointment.patientName;
      const finalPhone = phone || appointment.patientPhone;
      let wasConfirmed = false;
      if (finalName !== 'Pending' && finalPhone) {
        updates.status = 'confirmed';
        updates.notes = 'Booked via widget';
        wasConfirmed = true;
      }
      
      await storage.updateAppointment(appointment.id, updates);
      
      // Save appointment confirmation as message in conversation
      // Use conversationId from request or fall back to appointment's conversationId
      const msgConversationId = conversationId || appointment.conversationId;
      if (wasConfirmed && msgConversationId) {
        try {
          // Reload appointment to get fresh data after update
          const updatedAppointment = await storage.getAppointment(appointment.id);
          if (updatedAppointment) {
            const aptDate = new Date(updatedAppointment.appointmentDate);
            const formattedDate = aptDate.toLocaleDateString('en-US', { 
              weekday: 'short', 
              month: 'short', 
              day: 'numeric' 
            });
            const [hours, minutes] = (updatedAppointment.appointmentTime || '00:00').split(':').map(Number);
            const period = hours >= 12 ? 'PM' : 'AM';
            const displayHours = hours % 12 || 12;
            const formattedTime = `${displayHours}:${minutes.toString().padStart(2, '0')} ${period}`;
            
            await storage.createMessage({
              conversationId: msgConversationId,
              role: 'assistant',
              content: `Appointment confirmed for ${formattedDate} at ${formattedTime}. Name: ${updatedAppointment.patientName}, Phone: ${updatedAppointment.patientPhone}`
            });
          }
        } catch (msgError) {
          console.error('[Widget Update Appointment] Error saving message:', msgError);
          // Non-blocking - don't fail the appointment update
        }
      }
      
      return res.json({ success: true, message: 'Appointment updated' });
    } catch (error: any) {
      console.error('[Widget Update Appointment] Error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // Widget featured products endpoint - returns products for welcome carousel
