  // Translation endpoint for widget messages (nudges, etc.)
  app.post("/api/chat/widget/translate", async (req, res) => {
    try {
      const { businessAccountId, text, targetLanguage } = req.body;
      
      if (!businessAccountId || !text) {
        return res.status(400).json({ error: "businessAccountId and text required" });
      }

      // If no language or auto/english, return original
      if (!targetLanguage || targetLanguage === 'auto' || targetLanguage === 'en') {
        return res.json({ translatedText: text });
      }

      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      if (!businessAccount || !businessAccount.openaiApiKey) {
        return res.json({ translatedText: text });
      }

      // Language name mapping
      const LANGUAGE_NAMES: Record<string, string> = {
        'en': 'English', 'hi': 'Hindi', 'hinglish': 'Hinglish', 'ta': 'Tamil', 'te': 'Telugu',
        'kn': 'Kannada', 'mr': 'Marathi', 'bn': 'Bengali', 'gu': 'Gujarati', 'ml': 'Malayalam',
        'pa': 'Punjabi', 'or': 'Odia', 'as': 'Assamese', 'ur': 'Urdu', 'ne': 'Nepali',
        'es': 'Spanish', 'fr': 'French', 'de': 'German', 'pt': 'Portuguese', 'it': 'Italian',
        'ja': 'Japanese', 'ko': 'Korean', 'zh': 'Chinese', 'ar': 'Arabic', 'ru': 'Russian',
        'th': 'Thai', 'vi': 'Vietnamese', 'id': 'Indonesian', 'ms': 'Malay', 'tr': 'Turkish'
      };

      const langName = LANGUAGE_NAMES[targetLanguage];
      if (!langName) {
        // Unknown language code, return original text
        return res.json({ translatedText: text });
      }
      
      try {
        const openai = new OpenAI({ apiKey: businessAccount.openaiApiKey });
        const completion = await openai.chat.completions.create({
          model: 'gpt-4o-mini',
          messages: [
            { role: 'system', content: `Translate the following text to ${langName}. Return ONLY the translated text, nothing else. Keep the tone and meaning intact.` },
            { role: 'user', content: text }
          ],
          temperature: 0.3,
          max_tokens: 200
        });
        const translatedText = completion.choices[0]?.message?.content?.trim() || text;
        return res.json({ translatedText });
      } catch (error) {
        console.error('[Translation] Failed:', error);
        return res.json({ translatedText: text });
      }
    } catch (error: any) {
      console.error('[Widget Translate] Error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // Batch translation endpoint for menu content
  app.post("/api/chat/widget/translate-batch", async (req, res) => {
    try {
      const { businessAccountId, texts, targetLanguage } = req.body;
      
      if (!businessAccountId || !texts || !Array.isArray(texts)) {
        return res.status(400).json({ error: "businessAccountId and texts array required" });
      }

      // If no language or auto/english, return original texts
      if (!targetLanguage || targetLanguage === 'auto' || targetLanguage === 'en') {
        return res.json({ translatedTexts: texts });
      }

      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      if (!businessAccount || !businessAccount.openaiApiKey) {
        return res.json({ translatedTexts: texts });
      }

      // Language name mapping
      const LANGUAGE_NAMES: Record<string, string> = {
        'en': 'English', 'hi': 'Hindi', 'hinglish': 'Hinglish', 'ta': 'Tamil', 'te': 'Telugu',
        'kn': 'Kannada', 'mr': 'Marathi', 'bn': 'Bengali', 'gu': 'Gujarati', 'ml': 'Malayalam',
        'pa': 'Punjabi', 'or': 'Odia', 'as': 'Assamese', 'ur': 'Urdu', 'ne': 'Nepali',
        'es': 'Spanish', 'fr': 'French', 'de': 'German', 'pt': 'Portuguese', 'it': 'Italian',
        'ja': 'Japanese', 'ko': 'Korean', 'zh': 'Chinese', 'ar': 'Arabic', 'ru': 'Russian',
        'th': 'Thai', 'vi': 'Vietnamese', 'id': 'Indonesian', 'ms': 'Malay', 'tr': 'Turkish'
      };

      const langName = LANGUAGE_NAMES[targetLanguage];
      if (!langName) {
        return res.json({ translatedTexts: texts });
      }
      
      try {
        const openai = new OpenAI({ apiKey: businessAccount.openaiApiKey });
        
        // Create a numbered list for batch translation
        const numberedTexts = texts.map((t: string, i: number) => `${i + 1}. ${t}`).join('\n');
        
        const completion = await openai.chat.completions.create({
          model: 'gpt-4o-mini',
          messages: [
            { 
              role: 'system', 
              content: `Translate each numbered line to ${langName}. Return ONLY the translated lines in the same numbered format. Keep the tone and meaning intact. Example format:
1. Translated text 1
2. Translated text 2` 
            },
            { role: 'user', content: numberedTexts }
          ],
          temperature: 0.3,
          max_tokens: 1000
        });
        
        const response = completion.choices[0]?.message?.content?.trim() || '';
        
        // Parse the numbered response back into an array
        const translatedTexts = texts.map((original: string, index: number) => {
          const pattern = new RegExp(`^${index + 1}\\.\\s*(.+)$`, 'm');
          const match = response.match(pattern);
          return match ? match[1].trim() : original;
        });
        
        return res.json({ translatedTexts });
      } catch (error) {
        console.error('[Batch Translation] Failed:', error);
        return res.json({ translatedTexts: texts });
      }
    } catch (error: any) {
      console.error('[Widget Translate Batch] Error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // On-demand product description translation (called when user clicks a product card)
  app.post("/api/chat/widget/product/translate-description", async (req, res) => {
    try {
      const { productId, businessAccountId, userMessage, targetLanguage } = req.body;

      if (!productId || !businessAccountId || (!userMessage && !targetLanguage)) {
        return res.status(400).json({ error: "productId, businessAccountId and either userMessage or targetLanguage required" });
      }

      const DESCRIPTION_LANG_NAMES: Record<string, string> = {
        'hi': 'Hindi', 'hinglish': 'Hinglish', 'ta': 'Tamil', 'te': 'Telugu',
        'kn': 'Kannada', 'mr': 'Marathi', 'bn': 'Bengali', 'gu': 'Gujarati',
        'ml': 'Malayalam', 'pa': 'Punjabi', 'or': 'Odia', 'as': 'Assamese',
        'ur': 'Urdu', 'ne': 'Nepali', 'es': 'Spanish', 'fr': 'French',
        'de': 'German', 'pt': 'Portuguese', 'it': 'Italian', 'ja': 'Japanese',
        'ko': 'Korean', 'zh': 'Chinese', 'ar': 'Arabic', 'ru': 'Russian'
      };

      const explicitLang = targetLanguage && targetLanguage !== 'auto' && targetLanguage !== 'en'
        ? DESCRIPTION_LANG_NAMES[targetLanguage] || null
        : null;

      // Skip translation if explicit English or no non-English target
      if (targetLanguage === 'en') {
        return res.json({ success: true, description: null });
      }

      const cacheKey = `${productId}:${explicitLang || (userMessage ? userMessage.substring(0, 60) : 'auto')}`;
      if (productDescriptionTranslationCache.has(cacheKey)) {
        return res.json({ success: true, description: productDescriptionTranslationCache.get(cacheKey) });
      }

      const product = await storage.getProduct(productId, businessAccountId);
      if (!product || !product.description) {
        return res.json({ success: true, description: null });
      }

      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      if (!businessAccount || !businessAccount.openaiApiKey) {
        return res.json({ success: true, description: null });
      }

      try {
        const openai = new OpenAI({ apiKey: businessAccount.openaiApiKey });

        let systemPrompt: string;
        let userContent: string;

        if (explicitLang) {
          // Explicit language — translate directly without detection
          systemPrompt = `Translate the following product description to ${explicitLang}.
Return JSON: {"description": "translated description here"}`;
          userContent = `Product description to translate:\n${product.description}`;
        } else {
          // Auto-detect from user message
          systemPrompt = `You detect the language of the user's message and translate the product description to match.

RULES:
1. If user message is in English → return {"skip": true}
2. If user message is in Hindi/Hinglish (romanized Hindi in Latin script) → translate to Hinglish (Latin script, NOT Devanagari)
3. If user message is in Hindi (Devanagari script) → translate to Hindi (Devanagari)
4. For any other language → translate to that language

Return JSON:
- If English: {"skip": true}
- If translation needed: {"description": "translated description here"}`;
          userContent = `User message: "${userMessage}"\n\nProduct description to translate:\n${product.description}`;
        }

        const completion = await openai.chat.completions.create({
          model: 'gpt-4o-mini',
          messages: [
            { role: 'system', content: systemPrompt },
            { role: 'user', content: userContent }
          ],
          temperature: 0.3,
          max_tokens: 600,
          response_format: { type: 'json_object' }
        });

        const content = completion.choices[0]?.message?.content || '{}';
        const parsed = JSON.parse(content);

        if (parsed.skip === true) {
          return res.json({ success: true, description: null });
        }

        const translatedDescription = parsed.description || null;
        if (translatedDescription) {
          productDescriptionTranslationCache.set(cacheKey, translatedDescription);
        }
        return res.json({ success: true, description: translatedDescription });
      } catch (error) {
        console.error('[Product Description Translation] AI call failed:', error);
        return res.json({ success: true, description: null });
      }
    } catch (error: any) {
      console.error('[Product Description Translation] Error:', error);
      res.json({ success: true, description: null });
    }
  });

  // Public widget lead capture endpoint (no auth required)
  app.post("/api/chat/widget/capture-lead", async (req, res) => {
    try {
      const { businessAccountId, name, phone, email, customFields, source, pageUrl, conversationId, formTitle, visitorToken } = req.body;
      
      if (!businessAccountId) {
        return res.status(400).json({ error: "businessAccountId required" });
      }

      // Verify business account exists
      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      if (!businessAccount) {
        return res.status(400).json({ error: "Invalid business account" });
      }

      // Require at least one contact field
      if (!name && !phone && !email) {
        return res.status(400).json({ error: "At least one contact field is required" });
      }

      if (phone) {
        const phoneValidation = validatePhoneNumber(phone, '10');
        if (!phoneValidation.isValid) {
          return res.status(400).json({ error: phoneValidation.reasonMessage });
        }
      }

      // Normalize phone/email for consistent duplicate detection
      const normalizedPhone = phone ? phone.replace(/\D/g, '').slice(-10) : null;
      const normalizedEmail = email ? email.trim().toLowerCase() : null;

      // Check for duplicate lead within last 24 hours (same phone or email for this business)
      const twentyFourHoursAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
      const conditions = [
        eq(leads.businessAccountId, businessAccountId),
        gte(leads.createdAt, twentyFourHoursAgo)
      ];

      let existingLead = null;
      if (normalizedPhone) {
        const recentLeads = await db
          .select()
          .from(leads)
          .where(and(...conditions, isNotNull(leads.phone)))
          .limit(50);
        existingLead = recentLeads.find(l => l.phone && l.phone.replace(/\D/g, '').slice(-10) === normalizedPhone) || null;
      }
      if (!existingLead && normalizedEmail) {
        const [found] = await db
          .select()
          .from(leads)
          .where(and(...conditions, sql`LOWER(TRIM(${leads.email})) = ${normalizedEmail}`))
          .limit(1);
        existingLead = found || null;
      }

      if (existingLead) {
        console.log('[Widget Lead Capture] Duplicate lead detected within 24h, returning existing:', existingLead.id);
        return res.json({ success: true, leadId: existingLead.id, duplicate: true });
      }

      // Get visitor city from IP geolocation
      let visitorCity: string | undefined;
      try {
        const clientIp = (req.headers['x-forwarded-for'] as string)?.split(',')[0].trim() || 
                        req.socket.remoteAddress || 
                        'unknown';
        
        if (clientIp && clientIp !== 'unknown' && !clientIp.startsWith('127.') && !clientIp.startsWith('192.168.') && !clientIp.startsWith('10.') && !clientIp.startsWith('::1')) {
          const geoResponse = await fetch(`http://ip-api.com/json/${clientIp}?fields=status,city`);
          if (geoResponse.ok) {
            const geoData = await geoResponse.json();
            if (geoData.status === 'success' && geoData.city) {
              visitorCity = geoData.city;
              console.log(`[Widget Lead Capture] Geo-located visitor: ${visitorCity}`);
            }
          }
        }
      } catch (error) {
        console.warn('[Widget Lead Capture] Geolocation failed:', error);
      }

      // Build topics of interest: always "Via Form" + any custom field answers
      const customFieldAnswers = customFields && typeof customFields === 'object'
        ? Object.values(customFields as Record<string, string>).map(v => String(v).trim()).filter(Boolean)
        : [];
      const topicsOfInterest = ['Via Form', ...customFieldAnswers];

      // Ensure there is a conversation to link this lead to
      let resolvedConversationId: string | null = conversationId || null;
      if (!resolvedConversationId && visitorToken) {
        const reusable = await storage.findReusableConversation(businessAccountId, visitorToken);
        if (reusable) {
          resolvedConversationId = reusable.id;
          console.log('[Widget Lead Capture] Reusing existing conversation:', resolvedConversationId);
        }
      }
      if (!resolvedConversationId) {
        const newConversation = await storage.createConversation({
          businessAccountId,
          title: (name || phone || null) ? `${name || phone} — ${formTitle || 'Get in Touch'}` : (formTitle || 'Get in Touch'),
          visitorCity: visitorCity || null,
          visitorToken: visitorToken || null,
        });
        resolvedConversationId = newConversation.id;
        console.log('[Widget Lead Capture] Auto-created conversation:', resolvedConversationId);
      }

      // Create the lead
      const lead = await storage.createLead({
        businessAccountId,
        name: name || null,
        phone: phone || null,
        email: email || null,
        source: source || 'menu_lead_form',
        notes: 'Captured via Menu CTA Lead Form',
        status: 'new',
        topicsOfInterest,
        city: visitorCity || null,
        sourceUrl: pageUrl || null,
        conversationId: resolvedConversationId,
      });

      console.log('[Widget Lead Capture] Lead created:', lead.id);

      // Save form data as flowing Q&A messages in the conversation
      try {
        const fieldPairs: { question: string; answer: string }[] = [];
        if (name) fieldPairs.push({ question: 'Name', answer: name });
        if (phone) fieldPairs.push({ question: 'Mobile Number', answer: phone });
        if (email) fieldPairs.push({ question: 'Email', answer: email });
        if (customFields && typeof customFields === 'object') {
          for (const [label, val] of Object.entries(customFields as Record<string, string>)) {
            if (val) fieldPairs.push({ question: label, answer: String(val) });
          }
        }
        for (const pair of fieldPairs) {
          await storage.createMessage({ conversationId: resolvedConversationId, role: 'assistant', content: pair.question, interactionSource: 'form' });
          await storage.createMessage({ conversationId: resolvedConversationId, role: 'user', content: pair.answer, interactionSource: 'form' });
        }
        await storage.updateConversationTimestamp(resolvedConversationId);
      } catch (msgErr) {
        console.warn('[Widget Lead Capture] Could not save form messages:', msgErr);
      }

      // Auto-sync to LeadSquared if enabled (background task)
      (async () => {
        try {
          const settings = await storage.getWidgetSettings(businessAccountId);
          if (settings?.leadsquaredEnabled === 'true' && 
              settings.leadsquaredAccessKey && 
              settings.leadsquaredSecretKey) {
            
            const { decrypt } = await import('./services/encryptionService');
            const decryptedSecretKey = decrypt(settings.leadsquaredSecretKey);
            
            const { createLeadSquaredService } = await import('./services/leadsquaredService');
            const leadsquaredService = await createLeadSquaredService({
              accessKey: settings.leadsquaredAccessKey,
              secretKey: decryptedSecretKey,
              region: settings.leadsquaredRegion as 'india' | 'us' | 'other',
              customHost: settings.leadsquaredCustomHost || undefined,
            });

            const fieldMappings = await storage.getLeadsquaredFieldMappings(businessAccountId);
            const { extractUtmCampaign, extractUtmSource, extractUtmMedium } = await import('./services/leadsquaredService');
            const effectivePageUrl = pageUrl || null;

            let urlExtraction: { university?: string | null; product?: string | null } | undefined;
            const needsUrlExtraction = fieldMappings.some(m => m.isEnabled === 'true' && m.sourceType === 'dynamic' && m.sourceField?.startsWith('urlLookup.'));
            if (needsUrlExtraction && effectivePageUrl) {
              try {
                const { extractProductFromUrl } = await import('./services/urlExtractionService');
                const extractionConfig = {
                  domain: settings.lsqExtractionDomain || null,
                  universities: settings.lsqExtractionUniversities || null,
                  products: settings.lsqExtractionProducts || null,
                  fallbackUniversity: settings.lsqExtractionFallbackUniversity || null,
                  fallbackProduct: settings.lsqExtractionFallbackProduct || null,
                };
                urlExtraction = await extractProductFromUrl(effectivePageUrl, businessAccountId, extractionConfig);
                console.log('[Widget Lead Capture] URL extraction result:', urlExtraction);
              } catch (extractErr) {
                console.warn('[Widget Lead Capture] URL extraction failed:', extractErr);
              }
            }

            const leadContext = {
              lead: {
                name: lead.name || undefined,
                email: lead.email || undefined,
                phone: lead.phone || undefined,
                createdAt: lead.createdAt || undefined,
                sourceUrl: effectivePageUrl || undefined,
              },
              session: {
                city: visitorCity || null,
                pageUrl: effectivePageUrl || null,
                utmCampaign: extractUtmCampaign(effectivePageUrl) || null,
                utmSource: extractUtmSource(effectivePageUrl) || null,
                utmMedium: extractUtmMedium(effectivePageUrl) || null,
              },
              business: {
                name: businessAccount.name || undefined,
                website: businessAccount.website || undefined,
              },
              ...(urlExtraction ? { urlExtraction } : {}),
            };
            
            const syncResult = await leadsquaredService.createLeadWithMappings(fieldMappings, leadContext);
            if (syncResult.success) {
              await storage.updateLead(lead.id, businessAccountId, {
                leadsquaredSyncStatus: 'synced',
                leadsquaredSyncedAt: new Date(),
                leadsquaredLeadId: syncResult.leadId,
                leadsquaredSyncPayload: syncResult.syncPayload || null,
              });
              console.log('[Widget Lead Capture] Synced to LeadSquared, ID:', syncResult.leadId);
            } else {
              await storage.updateLead(lead.id, businessAccountId, {
                leadsquaredSyncStatus: 'failed',
                leadsquaredSyncError: syncResult.message,
                leadsquaredRetryCount: '0',
                leadsquaredNextRetryAt: new Date(Date.now() + 60_000),
              });
              console.error('[Widget Lead Capture] LeadSquared sync failed, will retry:', syncResult.message);
            }
          }
        } catch (syncError) {
          console.error('[Widget Lead Capture] LeadSquared sync failed:', syncError);
        }

        // Auto-sync to Salesforce if enabled
        try {
          const sfSettings = await storage.getWidgetSettings(businessAccountId);
          if (sfSettings?.salesforceEnabled === 'true' &&
              sfSettings.salesforceClientId &&
              sfSettings.salesforceClientSecret &&
              sfSettings.salesforceUsername &&
              sfSettings.salesforcePassword) {
            const { decrypt } = await import('./services/encryptionService');
            const { createSalesforceService } = await import('./services/salesforceService');
            const { extractUtmCampaign, extractUtmSource, extractUtmMedium } = await import('./services/leadsquaredService');
            const sfService = createSalesforceService({
              clientId: sfSettings.salesforceClientId,
              clientSecret: decrypt(sfSettings.salesforceClientSecret),
              username: sfSettings.salesforceUsername,
              password: decrypt(sfSettings.salesforcePassword),
              environment: (sfSettings.salesforceEnvironment || 'production') as 'production' | 'sandbox',
            });
            const sfMappings = await storage.getSalesforceFieldMappings(businessAccountId);
            const effectivePageUrl = pageUrl || null;
            const sfLeadContext = {
              lead: { name: lead.name || undefined, email: lead.email || undefined, phone: lead.phone || undefined, createdAt: lead.createdAt || undefined, sourceUrl: effectivePageUrl || undefined },
              session: { city: visitorCity || null, pageUrl: effectivePageUrl || null, utmCampaign: extractUtmCampaign(effectivePageUrl) || null, utmSource: extractUtmSource(effectivePageUrl) || null, utmMedium: extractUtmMedium(effectivePageUrl) || null },
              business: { name: businessAccount.name || undefined, website: businessAccount.website || undefined },
            };
            const sfResult = await sfService.createLeadWithMappings(sfMappings, sfLeadContext);
            if (sfResult.success) {
              await storage.updateLead(lead.id, businessAccountId, { salesforceSyncStatus: 'synced', salesforceSyncedAt: new Date(), salesforceLeadId: sfResult.leadId });
              console.log('[Widget Lead Capture] Synced to Salesforce, ID:', sfResult.leadId);
            } else {
              await storage.updateLead(lead.id, businessAccountId, { salesforceSyncStatus: 'failed', salesforceSyncError: sfResult.message });
              console.error('[Widget Lead Capture] Salesforce sync failed:', sfResult.message);
            }
          }
        } catch (sfSyncError) {
          console.error('[Widget Lead Capture] Salesforce sync failed:', sfSyncError);
        }
      })();

      return res.json({ success: true, leadId: lead.id });
    } catch (error: any) {
      console.error('[Widget Lead Capture] Error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // Smart Nudge endpoint - generates contextual follow-up questions using AI
  app.post("/api/chat/widget/smart-nudge", async (req, res) => {
    try {
      const { businessAccountId, conversationHistory, productsViewed, targetLanguage, visitorSessionId } = req.body;
      
      if (!businessAccountId) {
        return res.status(400).json({ error: "businessAccountId required" });
      }

      // Check if smart nudge is enabled for this business
      const settings = await storage.getWidgetSettings(businessAccountId);
      if (!settings?.smartNudgeEnabled || settings.smartNudgeEnabled !== 'true') {
        // Return static fallback message (with translation if needed)
        let fallbackMessage = settings?.inactivityNudgeMessage || "Still there? Let me know if you need any help!";
        
        // Translate fallback message if needed
        if (targetLanguage && targetLanguage !== 'auto' && targetLanguage !== 'en') {
          try {
            const businessAccount = await storage.getBusinessAccount(businessAccountId);
            if (businessAccount?.openaiApiKey) {
              const LANGUAGE_NAMES: Record<string, string> = {
                'hi': 'Hindi', 'hinglish': 'Hinglish', 'ta': 'Tamil', 'te': 'Telugu',
                'kn': 'Kannada', 'mr': 'Marathi', 'bn': 'Bengali', 'gu': 'Gujarati',
                'es': 'Spanish', 'fr': 'French', 'de': 'German', 'pt': 'Portuguese',
                'ja': 'Japanese', 'ko': 'Korean', 'zh': 'Chinese', 'ar': 'Arabic'
              };
              const langName = LANGUAGE_NAMES[targetLanguage];
              if (langName) {
                const openai = new OpenAI({ apiKey: businessAccount.openaiApiKey });
                const translation = await openai.chat.completions.create({
                  model: 'gpt-4o-mini',
                  messages: [
                    { role: 'system', content: `Translate to ${langName}. Return ONLY the translated text.` },
                    { role: 'user', content: fallbackMessage }
                  ],
                  temperature: 0.3,
                  max_tokens: 200
                });
                fallbackMessage = translation.choices[0]?.message?.content?.trim() || fallbackMessage;
              }
            }
          } catch (error) {
            console.error('[SmartNudge] Fallback translation failed:', error);
          }
        }
        
        return res.json({ 
          nudgeMessage: fallbackMessage, 
          isSmartNudge: false,
          context: { lastTopic: "unknown", detectedIntent: "unknown" }
        });
      }

      // Import the smart nudge service
      const { smartNudgeService } = await import('./services/smartNudgeService');
      const { checkDiscountEligibility } = await import('./services/nudgeOrchestrationService');

      // Check for discount eligibility if visitorSessionId is provided
      let discountAvailable = false;
      let discountMessage: string | undefined = undefined;
      
      if (visitorSessionId) {
        try {
          const discountNudge = await checkDiscountEligibility(businessAccountId, visitorSessionId);
          if (discountNudge) {
            discountAvailable = true;
            discountMessage = `Special offer: ${discountNudge.discountPercentage}% off with code ${discountNudge.discountCode}`;
            console.log('[SmartNudge] Discount available:', discountMessage);
          }
        } catch (err) {
          console.error('[SmartNudge] Discount check failed:', err);
        }
      }
      
      // Generate smart nudge
      const result = await smartNudgeService.generateSmartNudge({
        businessAccountId,
        conversationHistory: conversationHistory || [],
        productsViewed,
        discountAvailable,
        discountMessage
      });

      // Translate if needed
      let finalMessage = result.nudgeMessage;
      if (targetLanguage && targetLanguage !== 'auto' && targetLanguage !== 'en') {
        try {
          const businessAccount = await storage.getBusinessAccount(businessAccountId);
          if (businessAccount?.openaiApiKey) {
            const LANGUAGE_NAMES: Record<string, string> = {
              'hi': 'Hindi', 'hinglish': 'Hinglish', 'ta': 'Tamil', 'te': 'Telugu',
              'kn': 'Kannada', 'mr': 'Marathi', 'bn': 'Bengali', 'gu': 'Gujarati',
              'es': 'Spanish', 'fr': 'French', 'de': 'German', 'pt': 'Portuguese',
              'ja': 'Japanese', 'ko': 'Korean', 'zh': 'Chinese', 'ar': 'Arabic'
            };
            const langName = LANGUAGE_NAMES[targetLanguage];
            if (langName) {
              const openai = new OpenAI({ apiKey: businessAccount.openaiApiKey });
              const translation = await openai.chat.completions.create({
                model: 'gpt-4o-mini',
                messages: [
                  { role: 'system', content: `Translate to ${langName}. Return ONLY the translated text.` },
                  { role: 'user', content: result.nudgeMessage }
                ],
                temperature: 0.3,
                max_tokens: 200
              });
              finalMessage = translation.choices[0]?.message?.content?.trim() || result.nudgeMessage;
            }
          }
        } catch (error) {
          console.error('[SmartNudge] Translation failed:', error);
        }
      }

      console.log(`[SmartNudge] Generated for ${businessAccountId}: "${finalMessage.slice(0, 50)}..."`);

      res.json({
        nudgeMessage: finalMessage,
        isSmartNudge: true,
        includesDiscount: result.includesDiscount,
        context: result.context
      });

    } catch (error: any) {
      console.error('[SmartNudge] Error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // Save nudge message to conversation history
  app.post("/api/chat/widget/save-nudge", async (req, res) => {
    try {
      const { conversationId, message } = req.body;
      
      if (!conversationId || !message) {
        return res.status(400).json({ error: "conversationId and message required" });
      }
      
      // Save the nudge as an assistant message
      await storage.createMessage({
        conversationId,
        role: 'assistant',
        content: message
      });
      
      // Update conversation timestamp
      await storage.updateConversationTimestamp(conversationId);
      
      console.log(`[SaveNudge] Saved nudge to conversation ${conversationId}`);
      
      res.json({ success: true });
    } catch (error: any) {
      console.error('[SaveNudge] Error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // Configure multer for chat image uploads (memory storage for R2 support)
  const chatImagesDir = path.join(process.cwd(), "uploads", "business-photos");
  
  // Ensure business-photos directory exists (fallback for local storage)
  if (!fs.existsSync(chatImagesDir)) {
    fs.mkdirSync(chatImagesDir, { recursive: true });
  }

  const chatImageUpload = multer({
    storage: multer.memoryStorage(),
    limits: {
      fileSize: 10 * 1024 * 1024, // 10MB limit
    },
    fileFilter: (req, file, cb) => {
      // Accept only image files
      const allowedMimes = ['image/jpeg', 'image/jpg', 'image/png', 'image/gif', 'image/webp'];
      if (allowedMimes.includes(file.mimetype)) {
        cb(null, true);
      } else {
        cb(new Error('Invalid file type. Only JPEG, PNG, GIF, and WebP images are allowed.'));
      }
    },
  });

  const resumeUploadRateLimiter = new Map<string, { count: number; resetAt: number }>();
  const RESUME_UPLOAD_RATE_LIMIT = 10;
  const RESUME_VISION_RATE_LIMIT = 3;
  const RESUME_RATE_WINDOW_MS = 60 * 1000;

  function checkResumeRateLimit(ip: string, isVision: boolean = false): boolean {
    const key = isVision ? `vision:${ip}` : `upload:${ip}`;
    const limit = isVision ? RESUME_VISION_RATE_LIMIT : RESUME_UPLOAD_RATE_LIMIT;
    const now = Date.now();
    const entry = resumeUploadRateLimiter.get(key);
    if (!entry || now > entry.resetAt) {
      resumeUploadRateLimiter.set(key, { count: 1, resetAt: now + RESUME_RATE_WINDOW_MS });
      return true;
    }
    if (entry.count >= limit) return false;
    entry.count++;
    return true;
  }

  setInterval(() => {
    const now = Date.now();
    for (const [key, entry] of resumeUploadRateLimiter) {
      if (now > entry.resetAt) resumeUploadRateLimiter.delete(key);
    }
  }, 5 * 60 * 1000);

  const resumeTextCache = new Map<string, { text: string; businessAccountId: string; createdAt: number; resumeUrl?: string }>();
  const RESUME_CACHE_TTL_MS = 10 * 60 * 1000;

  setInterval(() => {
    const now = Date.now();
    for (const [key, entry] of resumeTextCache) {
      if (now - entry.createdAt > RESUME_CACHE_TTL_MS) resumeTextCache.delete(key);
    }
  }, 2 * 60 * 1000);

  app.post("/api/chat/widget/resume-upload", multer({
    storage: multer.memoryStorage(),
    limits: { fileSize: 10 * 1024 * 1024 },
    fileFilter: (_req, file, cb) => {
      if (file.mimetype === 'application/pdf') {
        cb(null, true);
      } else {
        cb(new Error('Only PDF files are allowed'));
      }
    }
  }).single('resume'), async (req, res) => {
    try {
      const clientIp = req.ip || req.socket.remoteAddress || 'unknown';
      if (!checkResumeRateLimit(clientIp)) {
        return res.status(429).json({ status: 'failed', error: 'Too many resume uploads. Please try again in a minute.' });
      }

      const { businessAccountId } = req.body;

      if (!businessAccountId) {
        return res.status(400).json({ status: 'failed', error: 'businessAccountId required' });
      }

      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      if (!businessAccount || businessAccount.jobPortalEnabled !== 'true') {
        return res.status(403).json({ status: 'failed', error: 'Resume upload not available' });
      }

      if (!req.file) {
        return res.status(400).json({ status: 'failed', error: 'No file uploaded' });
      }

      const { pdfProcessingService } = await import('./services/pdfProcessingService');
      const result = await pdfProcessingService.extractTextFromBufferMultiTier(
        req.file.buffer,
        businessAccountId,
        () => checkResumeRateLimit(clientIp, true)
      );

      if (result.status !== 'failed' && result.text) {
        const { randomUUID } = await import('crypto');
        const resumeContextId = randomUUID();

        let resumeFileUrl: string | undefined;
        try {
          const { r2Storage } = await import('./services/r2StorageService');
          await r2Storage.ensureInitialized();
          if (r2Storage.isEnabled() && req.file) {
            const uploadResult = await r2Storage.uploadFile(
              req.file.buffer,
              req.file.originalname || `resume-${Date.now()}.pdf`,
              'resumes',
              'application/pdf',
              businessAccountId
            );
            if (uploadResult.success && uploadResult.url) {
              resumeFileUrl = uploadResult.url;
              console.log(`[Widget Resume Upload] PDF saved to R2: ${resumeFileUrl}`);
            }
          }
        } catch (r2Err: any) {
          console.warn('[Widget Resume Upload] R2 upload failed (non-fatal):', r2Err.message);
        }

        resumeTextCache.set(resumeContextId, {
          text: result.text.substring(0, 10000),
          businessAccountId,
          createdAt: Date.now(),
          resumeUrl: resumeFileUrl,
        });

        res.json({
          status: result.status,
          resumeContextId,
          extractionMethod: result.extractionMethod,
          pageCount: result.pageCount,
          warning: result.warning,
        });
      } else {
        res.json({
          status: 'failed',
          extractionMethod: result.extractionMethod,
          pageCount: result.pageCount,
          warning: result.warning,
        });
      }
    } catch (error: any) {
      console.error('[Widget Resume Upload] Error:', error);
      res.status(500).json({ status: 'failed', error: error.message || 'Failed to process resume' });
    }
  });

  app.post("/api/chat/widget/upload-image", chatImageUpload.single('image'), async (req, res) => {
    try {
      const { businessAccountId, conversationId } = req.body;
      
      if (!businessAccountId) {
        return res.status(400).json({ error: "businessAccountId required" });
      }

      if (!req.file) {
        return res.status(400).json({ error: "No image file uploaded" });
      }

      let imageUrl: string;

      // Ensure R2 is initialized (checks database config if not already loaded)
      await r2Storage.ensureInitialized();

      // Try R2 storage first, fall back to local storage
      if (r2Storage.isEnabled()) {
        const result = await r2Storage.uploadFile(
          req.file.buffer,
          req.file.originalname,
          "chat-images",
          req.file.mimetype,
          businessAccountId
        );

        if (result.success && result.url) {
          imageUrl = result.url;
          console.log('[Chat Image Upload] Uploaded to R2:', imageUrl);
        } else {
          console.error('[Chat Image Upload] R2 upload failed:', result.error);
          return res.status(500).json({ error: "Failed to upload image" });
        }
      } else {
        // Fallback to local storage
        const correctDir = path.join(chatImagesDir, businessAccountId);
        
        if (!fs.existsSync(correctDir)) {
          fs.mkdirSync(correctDir, { recursive: true });
        }
        
        const timestamp = Date.now();
        const uniqueName = `${timestamp}-${randomUUID()}${path.extname(req.file.originalname)}`;
        const correctPath = path.join(correctDir, uniqueName);
        
        fs.writeFileSync(correctPath, req.file.buffer);
        
        imageUrl = `/uploads/business-photos/${businessAccountId}/${uniqueName}`;
        console.log('[Chat Image Upload] Saved locally:', imageUrl);
      }

      // Track the uploaded image in database for management
      const r2Key = imageUrl.startsWith('https://') ? r2Storage.extractKeyFromUrl(imageUrl) : null;
      try {
        await storage.createUploadedImage({
          businessAccountId,
          imageUrl,
          r2Key: r2Key || undefined,
          originalFilename: req.file.originalname,
          fileSize: req.file.size,
          source: 'visual_search'
        });
      } catch (trackError) {
        console.error('[Chat Image Upload] Failed to track image in database:', trackError);
      }

      res.json({ 
        success: true, 
        imageUrl,
        filename: path.basename(imageUrl)
      });
    } catch (error: any) {
      console.error('[Chat Image Upload] Error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // Visual product matching endpoint - Two-stage approach for accurate matching
  // Stage 1: Vector similarity pre-filter to find top 6 candidates (optimized for speed)
  // Stage 2: GPT-4o-mini visual comparison with actual product images
  app.post("/api/chat/widget/match-products", async (req, res) => {
    try {
      const { businessAccountId, imageUrl, conversationId } = req.body;
      
      if (!businessAccountId || !imageUrl) {
        return res.status(400).json({ error: "businessAccountId and imageUrl required" });
      }

      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      if (!businessAccount) {
        return res.status(404).json({ error: "Business account not found" });
      }

      if (!businessAccount.openaiApiKey) {
        return res.status(400).json({ error: "OpenAI API key not configured" });
      }

      // Read the uploaded image and convert to base64
      let imageBuffer: Buffer;
      let mimeType: string;

      if (imageUrl.startsWith('https://')) {
        try {
          const response = await fetch(imageUrl);
          if (!response.ok) {
            return res.status(404).json({ error: "Image file not found" });
          }
          const arrayBuffer = await response.arrayBuffer();
          imageBuffer = Buffer.from(arrayBuffer);
          mimeType = response.headers.get('content-type') || 'image/jpeg';
        } catch (error) {
          console.error('[Visual Match] Failed to fetch image:', error);
          return res.status(404).json({ error: "Image file not found" });
        }
      } else {
        const imagePath = path.join(process.cwd(), imageUrl.replace(/^\//, ''));
        if (!fs.existsSync(imagePath)) {
          return res.status(404).json({ error: "Image file not found" });
        }
        imageBuffer = fs.readFileSync(imagePath);
        const ext = path.extname(imagePath).toLowerCase();
        const mimeTypes: Record<string, string> = {
          '.png': 'image/png', '.jpg': 'image/jpeg', '.jpeg': 'image/jpeg',
          '.gif': 'image/gif', '.webp': 'image/webp'
        };
        mimeType = mimeTypes[ext] || 'image/jpeg';
      }

      const base64Image = imageBuffer.toString('base64');
      const dataUrl = `data:${mimeType};base64,${base64Image}`;

      // Category detection: Identify which category the uploaded image belongs to
      let detectedCategory: { id: string; name: string } | null = null;
      let matchingCategoryIds: string[] = [];
      
      // Get all available categories for this business
      const allCategories = await storage.getAllCategories(businessAccountId);
      
      if (businessAccount.openaiApiKey && allCategories.length > 0) {
        console.log('[Visual Match] Detecting category from', allCategories.length, 'available categories');
        
        try {
          const openai = new OpenAI({ apiKey: businessAccount.openaiApiKey });
          
          // Build category list for GPT
          const categoryNames = allCategories.map(c => c.name);
          
          const categoryDetectionResponse = await openai.chat.completions.create({
            model: 'gpt-4o-mini',
            messages: [
              {
                role: 'system',
                content: `You are a jewelry classification expert. Look at the image and identify which category it belongs to.

Available categories:
${categoryNames.map((name, i) => `${i + 1}. ${name}`).join('\n')}

Respond with ONLY the exact category name from the list above. Nothing else.
If you cannot determine the category or the image doesn't match any category, respond with: NONE`
              },
              {
                role: 'user',
                content: [
                  { type: 'image_url', image_url: { url: dataUrl, detail: 'low' } },
                  { type: 'text', text: 'Which category does this jewelry belong to?' }
                ]
              }
            ],
            max_tokens: 50,
            temperature: 0
          });
          
          const rawResponse = categoryDetectionResponse.choices[0]?.message?.content?.trim() || '';
          console.log('[Visual Match] GPT category response:', rawResponse);
          
          // Log AI usage
          aiUsageLogger.logImageSearchUsage(businessAccountId, 'gpt-4o-mini', categoryDetectionResponse).catch(err =>
            console.error('[Usage] Failed to log:', err)
          );
          
          // Validate response - find matching category (case-insensitive)
          if (rawResponse && rawResponse.toUpperCase() !== 'NONE') {
            const matchedCategory = allCategories.find(c => 
              c.name.toLowerCase() === rawResponse.toLowerCase()
            );
            
            if (matchedCategory) {
              detectedCategory = { id: matchedCategory.id, name: matchedCategory.name };
              matchingCategoryIds = [matchedCategory.id];
              console.log('[Visual Match] Detected category:', detectedCategory.name, '(ID:', detectedCategory.id, ')');
            } else {
              console.log('[Visual Match] GPT response did not match any category:', rawResponse);
            }
          } else {
            console.log('[Visual Match] No category detected from image');
          }
        } catch (categoryError) {
          console.error('[Visual Match] Category detection failed:', categoryError);
          // Continue without category filtering if detection fails
        }
      } else if (!businessAccount.openaiApiKey) {
        console.log('[Visual Match] No OpenAI key configured - skipping category detection');
      } else {
        console.log('[Visual Match] No categories available - skipping category detection');
      }

      // Import the product image embedding service and jewelry detection
      const { productImageEmbeddingService } = await import('./services/productImageEmbeddingService');
      const { jewelryDetectionService } = await import('./services/jewelryDetectionService');
      const { imageCroppingService } = await import('./services/imageCroppingService');
      const { imageHashService } = await import('./services/imageHashService');
      
      // Check if we have any products with embeddings
      const stats = await productImageEmbeddingService.getEmbeddingStats(businessAccountId);
      
      let candidateProducts: any[];
      let detectedJewelryItems: any[] = [];
      let exactMatch: any = null; // Declare at outer scope so it's accessible in response
      
      // Structure for grouped results by jewelry type
      let groupedResults: { [key: string]: any[] } = {};
      
      if (stats.withEmbedding > 0) {
        // PARALLEL PROCESSING: Run Stage 0 (pHash) and Stage 1 detection concurrently
        console.log('[Visual Match] Starting parallel processing: pHash and jewelry detection');
        const parallelStartTime = Date.now();
        
        // Launch all independent operations in parallel
        const [pHashResult, clipEmbeddingResult, detectionResult] = await Promise.all([
          // 1. Generate pHash (local, fast)
          (async () => {
            try {
              const hash = await imageHashService.generateHash(dataUrl);
              console.log(`[Visual Match] pHash generated: ${hash.substring(0, 8)}...`);
              return hash;
            } catch (e) {
              console.error('[Visual Match] pHash generation failed:', e);
              return null;
            }
          })(),
          // 2. Generate full image embedding (Vision Warehouse)
          (async () => {
            try {
              const { embedding } = await productImageEmbeddingService.embedUploadedImage(dataUrl, businessAccountId);
              console.log('[Visual Match] Full image embedding generated');
              return embedding;
            } catch (e) {
              console.error('[Visual Match] Embedding failed:', e);
              return null;
            }
          })(),
          // 3. Detect jewelry items (GPT-4o Vision API) - starts concurrently!
          (async () => {
            try {
              const detection = await jewelryDetectionService.detectJewelry(imageUrl, businessAccountId);
              console.log(`[Visual Match] Jewelry detection complete: ${detection.detectedItems?.length || 0} items`);
              return detection;
            } catch (e) {
              console.error('[Visual Match] Jewelry detection failed:', e);
              return { success: false, detectedItems: [] };
            }
          })()
        ]);
        
        console.log(`[Visual Match] Parallel processing completed in ${Date.now() - parallelStartTime}ms`);
        
        const uploadedImageHash = pHashResult;
        const fullUploadEmbedding = clipEmbeddingResult;
        
        // STAGE 0: Process exact match check with results from parallel operations
        console.log('[Visual Match] Stage 0: Checking for exact product match');
        try {
          if (fullUploadEmbedding) {
            // Search for exact matches against fullImageEmbedding column
            const exactMatchResults = await db
              .select({
                id: products.id,
                name: products.name,
                description: products.description,
                price: products.price,
                imageUrl: products.imageUrl,
                imageHash: products.imageHash,
                distance: sql<number>`${products.fullImageEmbedding} <=> ${JSON.stringify(fullUploadEmbedding)}::vector`,
              })
              .from(products)
              .where(
                and(
                  eq(products.businessAccountId, businessAccountId),
                  sql`${products.fullImageEmbedding} IS NOT NULL`
                )
              )
              .orderBy(sql`${products.fullImageEmbedding} <=> ${JSON.stringify(fullUploadEmbedding)}::vector`)
              .limit(1);
            
            if (exactMatchResults.length > 0) {
              const topMatch = exactMatchResults[0];
              const similarity = Math.max(0, 1 - topMatch.distance);
              
              console.log(`[Visual Match] Stage 0 best match: ${topMatch.name} (cosine similarity: ${(similarity * 100).toFixed(2)}%)`);
              
              // Check pHash match for TRUE exact image verification
              let pHashMatches = false;
              let pHashDistance = -1;
              
              if (uploadedImageHash && topMatch.imageHash) {
                pHashDistance = imageHashService.calculateHammingDistance(uploadedImageHash, topMatch.imageHash);
                pHashMatches = pHashDistance <= 10; // 0-10 bits = same image (stricter threshold to reduce false positives)
                console.log(`[Visual Match] pHash comparison: distance=${pHashDistance}, matches=${pHashMatches}`);
              } else {
                console.log(`[Visual Match] pHash not available for comparison (uploaded: ${!!uploadedImageHash}, product: ${!!topMatch.imageHash})`);
              }
              
              // Perfect Match requires BOTH: pHash match AND similarity ≥96%
              // Visual fingerprint match is required for "Perfect Match"
              if (pHashMatches && similarity >= 0.96) {
                console.log(`[Visual Match] EXACT MATCH FOUND! Product: ${topMatch.name} (pHash + similarity: ${(similarity * 100).toFixed(1)}%)`);
                
                // Get full product details
                const fullProduct = await storage.getProduct(topMatch.id, businessAccountId);
                if (fullProduct) {
                  exactMatch = {
                    ...fullProduct,
                    similarity: Math.round(similarity * 100),
                    matchQuality: 'perfect_match',
                    matchQualityLabel: 'Perfect Match',
                    rawVectorSimilarity: similarity,
                    pHashDistance: pHashDistance,
                    isExactMatch: true
                  };
                }
              } else {
                console.log(`[Visual Match] No exact match found (similarity: ${(similarity * 100).toFixed(1)}%, pHash match: ${pHashMatches}, distance: ${pHashDistance})`);
              }
            }
          }
        } catch (exactMatchError) {
          console.error('[Visual Match] Exact match check failed:', exactMatchError);
        }
        
        // STAGE 1: Process jewelry detection results (already completed in parallel)
        console.log('[Visual Match] Stage 1: Processing jewelry detection results');
        
        let imagesToProcess: { type: string; dataUrl: string; confidence: number; description: string; detectionIndex: number; attributes?: any }[] = [];
        let collapsedIndices = new Set<number>(); // Track which detection indices are collapsed (duplicates)
        
        // Use detection result from parallel processing
        const detection = detectionResult;
        try {
          if (detection.success && detection.detectedItems.length > 0) {
            console.log(`[Visual Match] Detected ${detection.detectedItems.length} jewelry item(s)`);
            
            // Crop ALL detected jewelry items
            const croppedImages = await imageCroppingService.cropJewelryFromUrl(imageUrl, detection.detectedItems);
            
            // Build list of images to process WITH detection index for dedup tracking
            detection.detectedItems.forEach((item, idx) => {
              const croppedDataUrl = croppedImages[idx]?.croppedDataUrl;
              if (croppedDataUrl) {
                imagesToProcess.push({
                  type: item.type,
                  dataUrl: croppedDataUrl,
                  confidence: item.confidence,
                  description: item.description,
                  detectionIndex: idx,
                  attributes: item.attributes || null
                });
              }
            });
            
            // Store ALL detected items for UI display initially (includes items with failed crops)
            // Will be filtered later to remove collapsed duplicates
            detectedJewelryItems = detection.detectedItems.map((item, idx) => ({
              type: item.type,
              category: jewelryDetectionService.mapTypeToCategory(item.type),
              confidence: item.confidence,
              description: item.description,
              croppedDataUrl: croppedImages[idx]?.croppedDataUrl || null,
              detectionIndex: idx,
              attributes: item.attributes || null
            }));
            
            console.log(`[Visual Match] Processing ${imagesToProcess.length} cropped jewelry items in parallel`);
          }
        } catch (detectionError) {
          console.log('[Visual Match] Jewelry detection failed, using original image:', detectionError);
        }
        
        // If no items detected, use original image as single item
        if (imagesToProcess.length === 0) {
          imagesToProcess.push({
            type: 'unknown',
            dataUrl: dataUrl,
            confidence: 1.0,
            description: 'Original image',
            detectionIndex: -1 // Special index for fallback image
          });
          console.log('[Visual Match] No jewelry detected, using original image');
        }
        
        // STEP 1: Generate embeddings for all detected items in parallel
        const embeddingPromises = imagesToProcess.map(async (item) => {
          try {
            const { embedding } = await productImageEmbeddingService.embedUploadedImage(item.dataUrl, businessAccountId);
            return { ...item, embedding };
          } catch (error) {
            console.error(`[Visual Match] Error embedding ${item.type}:`, error);
            return null;
          }
        });
        
        const embeddedItems = (await Promise.all(embeddingPromises)).filter((item): item is NonNullable<typeof item> => item !== null);
        console.log(`[Visual Match] Generated embeddings for ${embeddedItems.length} items`);
        
        // STEP 2: De-duplicate same-type items with high similarity (>95%)
        // This prevents duplicate earring-pair embeddings
        const cosineSimilarity = (a: number[], b: number[]): number => {
          if (a.length !== b.length) return 0;
          let dot = 0, normA = 0, normB = 0;
          for (let i = 0; i < a.length; i++) {
            dot += a[i] * b[i];
            normA += a[i] * a[i];
            normB += b[i] * b[i];
          }
          const denom = Math.sqrt(normA) * Math.sqrt(normB);
          return denom === 0 ? 0 : dot / denom;
        };
        
        const deduplicatedItems: typeof embeddedItems = [];
        for (const item of embeddedItems) {
          let isDuplicate = false;
          for (const kept of deduplicatedItems) {
            // Only compare items of same type
            if (kept.type === item.type) {
              const similarity = cosineSimilarity(item.embedding, kept.embedding);
              if (similarity >= 0.95) {
                // Keep the one with higher confidence, mark the other as collapsed
                if (item.confidence > kept.confidence) {
                  // Replace kept with item, mark kept's index as collapsed
                  collapsedIndices.add(kept.detectionIndex);
                  const idx = deduplicatedItems.indexOf(kept);
                  deduplicatedItems[idx] = item;
                } else {
                  // Mark current item's index as collapsed
                  collapsedIndices.add(item.detectionIndex);
                }
                isDuplicate = true;
                break;
              }
            }
          }
          if (!isDuplicate) {
            deduplicatedItems.push(item);
          }
        }
        
        if (collapsedIndices.size > 0) {
          console.log(`[Visual Match] De-duplicated ${collapsedIndices.size} similar items`);
          
          // Filter UI items to remove collapsed duplicates (preserves items with failed crops)
          detectedJewelryItems = detectedJewelryItems.filter(
            (item: any) => !collapsedIndices.has(item.detectionIndex)
          );
        }
        
        // STEP 3: Search for similar products using de-duplicated embeddings
        const searchPromises = deduplicatedItems.map(async (item) => {
          try {
            // Normalize type to match database format (e.g., "necklace" -> "necklaces")
            const normalizedType = jewelryDetectionService.mapTypeToCategory(item.type);
            
            // Only filter by type if it's a known jewelry category (not "others" or "unknown")
            // This prevents hiding legitimate results for unrecognized or legacy types
            const shouldFilterByType = normalizedType !== 'others' && normalizedType !== 'unknown';
            const typeFilter = shouldFilterByType ? normalizedType : undefined;
            
            if (!shouldFilterByType) {
              console.log(`[Visual Match] Skipping type filter for "${item.type}" (normalized: "${normalizedType}")`);
            }
            
            const similarProducts = await productImageEmbeddingService.searchSimilarProducts(
              item.embedding,
              businessAccountId,
              6, // Top 6 per jewelry type
              0.85, // 85% similarity threshold
              typeFilter // Filter by normalized jewelry type to avoid cross-category matches
            );
            
            return {
              type: item.type, // Keep original label for UI tabs (e.g., "Necklace", "Earring-Pair")
              confidence: item.confidence,
              description: item.description,
              croppedDataUrl: item.dataUrl,
              candidates: similarProducts.map(p => ({
                id: p.id,
                name: p.name,
                description: p.description,
                price: p.price,
                imageUrl: p.imageUrl,
                vectorSimilarity: p.similarity
              }))
            };
          } catch (error) {
            console.error(`[Visual Match] Error searching ${item.type}:`, error);
            return { type: item.type, confidence: item.confidence, candidates: [] };
          }
        });
        
        const searchResults = await Promise.all(searchPromises);
        console.log(`[Visual Match] Parallel search completed for ${searchResults.length} unique items`);
        
        // Combine all candidates (will be filtered and grouped later)
        candidateProducts = [];
        searchResults.forEach(result => {
          if (result.candidates.length > 0) {
            // Add jewelry type to each candidate for grouping
            result.candidates.forEach((p: any) => {
              candidateProducts.push({
                ...p,
                jewelryType: result.type
              });
            });
          }
        });
        
        console.log('[Visual Match] Stage 1 found', candidateProducts.length, 'total candidates across all types');
      } else {
        // No embeddings - fall back to all products (limited to 6)
        console.log('[Visual Match] No embeddings found, using all products (limited)');
        const allProducts = await storage.getAllProducts(businessAccountId);
        candidateProducts = allProducts.slice(0, 6).map((p: any) => ({
          id: p.id,
          name: p.name,
          description: p.description,
          price: p.price,
          imageUrl: p.imageUrl,
          vectorSimilarity: null
        }));
      }

      if (candidateProducts.length === 0) {
        return res.json({ 
          matches: [], 
          message: "No products found in catalog" 
        });
      }

      // Vision Warehouse with description re-ranking for improved accuracy
      console.log('[Visual Match] Using Vision Warehouse + description re-ranking');
      
      // Fixed similarity threshold - 80% minimum to show results
      // Match quality labels: Perfect Match (96%+ with pHash, Stage 0 only), Very Similar (90-96%), Somewhat Similar (80-90%)
      const similarityThreshold = 80;
      
      // DESCRIPTION & ATTRIBUTE RE-RANKING: Filter false positives using text + attribute similarity
      // Visual search groups by category (gold necklace), descriptions distinguish designs (jali work Om pendant vs plain chain)
      // Attributes provide structured comparison (complexity, dangles, motifs)
      const { attributeMatchingService } = await import('./services/attributeMatchingService');
      
      let uploadedDescriptions: Map<string, { description: string; embedding: number[] }> = new Map();
      let uploadedAttributes: Map<string, any> = new Map();
      const detectedWithDescriptions = detectedJewelryItems.filter((item: any) => item.description);
      
      // Store uploaded item attributes for matching
      detectedJewelryItems.forEach((item: any) => {
        if (item.attributes) {
          uploadedAttributes.set(item.type, item.attributes);
          console.log(`[Visual Match] Stored attributes for ${item.type}:`, JSON.stringify(item.attributes));
        }
      });
      
      if (detectedWithDescriptions.length > 0) {
        console.log(`[Visual Match] Generating description embeddings for ${detectedWithDescriptions.length} detected items IN PARALLEL`);
        try {
          // Generate text embeddings for uploaded jewelry descriptions IN PARALLEL
          const descEmbeddingPromises = detectedWithDescriptions.map(async (item: any) => {
            try {
              const descEmbedding = await embeddingService.generateEmbedding(item.description, businessAccountId);
              return { type: item.type, description: item.description, embedding: descEmbedding };
            } catch (err) {
              console.error(`[Visual Match] Failed to embed description for ${item.type}:`, err);
              return null;
            }
          });
          const descResults = await Promise.all(descEmbeddingPromises);
          descResults.filter((r): r is NonNullable<typeof r> => r !== null).forEach(r => {
            uploadedDescriptions.set(r.type, { description: r.description, embedding: r.embedding });
          });
          console.log(`[Visual Match] Generated ${uploadedDescriptions.size} description embeddings for re-ranking (parallel)`);
        } catch (descError: any) {
          console.error('[Visual Match] Description embedding failed, continuing with visual search only:', descError.message);
        }
      }
      
      // Fetch product description embeddings AND attributes for candidates
      let productDescriptionEmbeddings: Map<string, { description: string; embedding: number[] }> = new Map();
      let productAttributes: Map<string, any> = new Map();
      if (candidateProducts.length > 0) {
        const productIds = candidateProducts.map((p: any) => p.id);
        try {
          const descEmbeddingRows = await db.select({
            productId: productJewelryEmbeddings.productId,
            description: productJewelryEmbeddings.description,
            descriptionEmbedding: productJewelryEmbeddings.descriptionEmbedding,
            jewelryType: productJewelryEmbeddings.jewelryType,
            attributes: productJewelryEmbeddings.attributes
          })
          .from(productJewelryEmbeddings)
          .where(sql`${productJewelryEmbeddings.productId} = ANY(${productIds})`);
          
          for (const row of descEmbeddingRows) {
            if (row.descriptionEmbedding && row.description) {
              productDescriptionEmbeddings.set(row.productId, { 
                description: row.description, 
                embedding: row.descriptionEmbedding as number[] 
              });
            }
            if (row.attributes) {
              productAttributes.set(row.productId, row.attributes);
            }
          }
          console.log(`[Visual Match] Found ${productDescriptionEmbeddings.size} products with description embeddings, ${productAttributes.size} with attributes`);
        } catch (fetchError: any) {
          console.error('[Visual Match] Failed to fetch product descriptions/attributes:', fetchError.message);
        }
      }
      
      // Helper: Compute cosine similarity between two vectors
      const cosineSimilarity = (a: number[], b: number[]): number => {
        if (a.length !== b.length) return 0;
        let dot = 0, normA = 0, normB = 0;
        for (let i = 0; i < a.length; i++) {
          dot += a[i] * b[i];
          normA += a[i] * a[i];
          normB += b[i] * b[i];
        }
        return dot / (Math.sqrt(normA) * Math.sqrt(normB));
      };
      
      // Score scaling function for jewelry matching:
      // - 0.98+ → 100% (exact match)
      // - 0.96-0.98 → 96-99% (Perfect Match range - only shown if pHash matches in Stage 0)
      // - 0.92-0.96 → 90-96% (Very Similar)
      // - 0.88-0.92 → 80-90% (Somewhat Similar)
      // - Below 0.88 → under 80% (filtered out)
      const scaleSimilarity = (rawSimilarity: number): number => {
        if (rawSimilarity >= 0.98) return 100; // Exact/near-exact match
        if (rawSimilarity >= 0.96) {
          // 0.96-0.98 → 96-99%
          return Math.round(96 + (rawSimilarity - 0.96) * 150);
        }
        if (rawSimilarity >= 0.92) {
          // 0.92-0.96 → 90-96%
          return Math.round(90 + (rawSimilarity - 0.92) * 150);
        }
        if (rawSimilarity >= 0.88) {
          // 0.88-0.92 → 80-90%
          return Math.round(80 + (rawSimilarity - 0.88) * 250);
        }
        // Below 0.88 → capped at 79% to ensure filtering
        return Math.min(79, Math.round(rawSimilarity * 90));
      };
      
      // HARD FILTER: Products must pass similarity threshold AND attribute similarity
      // Step 1: Get similarity scores for all candidates
      // Step 2: Filter by attribute match (description no longer used as filter)
      // Step 3: Apply attribute penalties to adjust final ranking
      const ATTRIBUTE_SCORE_THRESHOLD = 0.50; // 50% minimum attribute match required
      
      const productsWithScores = candidateProducts
        .filter((p: any) => p.vectorSimilarity !== null)
        .map((p: any) => {
          const clipScore = scaleSimilarity(p.vectorSimilarity);
          let descriptionSimilarity = 0;
          let hasDescriptionMatch = false;
          let passesDescriptionFilter = false;
          let attributeScore = 0;
          let hasAttributeMatch = false;
          let attributeMatchResult: any = null;
          
          // Description similarity is kept for display/logging but NOT used as a filter
          const uploadedDesc = uploadedDescriptions.get(p.jewelryType);
          const productDesc = productDescriptionEmbeddings.get(p.id);
          
          if (uploadedDesc && productDesc) {
            descriptionSimilarity = cosineSimilarity(uploadedDesc.embedding, productDesc.embedding);
            hasDescriptionMatch = true;
          }
          
          // Check attribute matching (if both uploaded and product have attributes)
          const uploadedAttr = uploadedAttributes.get(p.jewelryType);
          const productAttr = productAttributes.get(p.id);
          
          if (uploadedAttr && productAttr) {
            // Check for hard disqualification - pass RAW similarity score (not scaled) to prevent inflated scores from bypassing checks
            // p.vectorSimilarity is the raw cosine similarity (0-1 range) before sigmoid scaling
            const rawClipScore = p.vectorSimilarity;
            const disqualifyCheck = attributeMatchingService.shouldDisqualify(uploadedAttr, productAttr, undefined, rawClipScore, p.name);
            if (disqualifyCheck.disqualify) {
              console.log(`[Visual Match] DISQUALIFIED ${p.name}: ${disqualifyCheck.reason}`);
              return {
                ...p,
                scaledSimilarity: clipScore,
                rawSimilarity: p.vectorSimilarity,
                descriptionSimilarity,
                hasDescriptionMatch,
                passesDescriptionFilter: false,
                attributeScore: 0,
                hasAttributeMatch: true,
                disqualified: true,
                disqualifyReason: disqualifyCheck.reason
              };
            }
            
            // Calculate attribute match score
            attributeMatchResult = attributeMatchingService.calculateAttributeScore(uploadedAttr, productAttr);
            attributeScore = attributeMatchResult.score;
            hasAttributeMatch = true;
            
            console.log(`[Visual Match] ${p.name} attribute score: ${(attributeScore * 100).toFixed(1)}%, matched: [${attributeMatchResult.matchedAttributes.join(', ')}], mismatched: [${attributeMatchResult.mismatchedAttributes.join(', ')}]`);
          }
          
          // Pass filter if:
          // 1. Attribute score is acceptable (50%+), OR
          // 2. No attributes available (legacy products - allow through with visual similarity only)
          const noDataAvailable = !hasAttributeMatch;
          const passesFilter = (hasAttributeMatch && attributeScore >= ATTRIBUTE_SCORE_THRESHOLD) ||
                               noDataAvailable; // Allow legacy products through
          
          if (!passesFilter) {
            if (hasAttributeMatch && attributeScore < ATTRIBUTE_SCORE_THRESHOLD) {
              console.log(`[Visual Match] FILTERED OUT ${p.name}: raw ${(p.vectorSimilarity * 100).toFixed(1)}%, scaled ${clipScore.toFixed(1)}%, attr ${(attributeScore * 100).toFixed(1)}% < ${ATTRIBUTE_SCORE_THRESHOLD * 100}%`);
            }
          } else {
            const reason = noDataAvailable ? '(legacy - similarity only)' : '';
            console.log(`[Visual Match] PASSED ${p.name}: raw ${(p.vectorSimilarity * 100).toFixed(1)}%, scaled ${clipScore.toFixed(1)}%, attr ${(attributeScore * 100).toFixed(1)}% ${reason}`);
          }
          
          // Calculate combined score for ranking (visual similarity 70%, Attributes 30%)
          const combinedScore = hasAttributeMatch
            ? (clipScore * 0.70) + (attributeScore * 100 * 0.30)
            : clipScore; // Fallback to pure visual similarity if no attributes
          
          return {
            ...p,
            scaledSimilarity: clipScore,
            rawSimilarity: p.vectorSimilarity,
            descriptionSimilarity,
            hasDescriptionMatch,
            passesDescriptionFilter: passesFilter,
            attributeScore,
            hasAttributeMatch,
            attributeMatchResult,
            combinedScore
          };
        })
        // Apply filters: Use RAW CLIP threshold (not sigmoid-scaled) AND attribute pass
        // Raw similarity is 0-1, threshold is percentage, so divide threshold by 100
        .filter((p: any) => (p.rawSimilarity * 100) >= similarityThreshold && p.passesDescriptionFilter && !p.disqualified)
        .sort((a: any, b: any) => {
          // Sort by combined score (considers CLIP, attributes, and description)
          return b.combinedScore - a.combinedScore;
        });
      
      console.log('[Visual Match] Found', productsWithScores.length, 'products passing all filters');
      
      // Fetch complete product data with categories and tags
      const allMatchedProducts = await Promise.all(
        productsWithScores.map(async (product: any) => {
          const fullProduct = await storage.getProduct(product.id, businessAccountId);
          if (!fullProduct) return null;
          
          const [categories, tags] = await Promise.all([
            storage.getProductCategories(product.id),
            storage.getProductTags(product.id)
          ]);
          
          // Determine match quality label based on scaled similarity percentage
          // Stage 1 (similarity-based) matches should NOT show "Perfect Match"
          // Perfect Match is reserved for Stage 0 exact matches (pHash + CLIP verification)
          // Very Similar: 90-96%, Somewhat Similar: 80-90%
          let matchQuality = 'somewhat_similar';
          let matchQualityLabel = 'Somewhat Similar';
          if (product.scaledSimilarity >= 96) {
            // Stage 1 max is "Very Similar" - Perfect Match requires pHash (Stage 0)
            matchQuality = 'very_similar';
            matchQualityLabel = 'Very Similar';
          } else if (product.scaledSimilarity >= 90) {
            matchQuality = 'very_similar';
            matchQualityLabel = 'Very Similar';
          }
          
          return {
            ...fullProduct,
            categories,
            tags,
            similarity: product.scaledSimilarity,
            matchQuality,
            matchQualityLabel,
            rawVectorSimilarity: product.rawSimilarity,
            descriptionSimilarity: product.descriptionSimilarity || 0,
            hasDescriptionMatch: product.hasDescriptionMatch || false,
            attributeScore: product.attributeScore || 0,
            hasAttributeMatch: product.hasAttributeMatch || false,
            combinedScore: product.combinedScore || product.scaledSimilarity,
            jewelryType: product.jewelryType || 'unknown'
          };
        })
      ).then(results => results.filter((p: any) => p !== null));
      
      // STEP 3: Group results by jewelry type
      const matchesByType: { [key: string]: any[] } = {};
      allMatchedProducts.forEach((product: any) => {
        const type = product.jewelryType || 'unknown';
        if (!matchesByType[type]) {
          matchesByType[type] = [];
        }
        // Avoid duplicates (same product might match multiple searches)
        if (!matchesByType[type].some((p: any) => p.id === product.id)) {
          matchesByType[type].push(product);
        }
      });
      
      // Sort each group by match quality first (Very Similar before Somewhat Similar), then by combined score
      const qualityOrder: Record<string, number> = { 'perfect_match': 0, 'very_similar': 1, 'somewhat_similar': 2, 'related': 3 };
      const sortByQualityThenScore = (a: any, b: any) => {
        const qualityDiff = (qualityOrder[a.matchQuality] || 3) - (qualityOrder[b.matchQuality] || 3);
        if (qualityDiff !== 0) return qualityDiff;
        return b.combinedScore - a.combinedScore;
      };
      
      Object.keys(matchesByType).forEach(type => {
        matchesByType[type] = matchesByType[type]
          .sort(sortByQualityThenScore)
          .slice(0, 6);
      });
      
      console.log('[Visual Match] Grouped results:', Object.keys(matchesByType).map(t => `${t}: ${matchesByType[t].length}`).join(', '));
      
      // Also create flat list for backwards compatibility (limit to top 10 after re-ranking)
      const flatMatches = Object.values(matchesByType).flat().sort(sortByQualityThenScore).slice(0, 10);

      // Save matched products to the uploaded image record for history
      try {
        await storage.updateUploadedImageMatchedProducts(imageUrl, businessAccountId, flatMatches);
        console.log('[Visual Match] Saved matched products to history');
      } catch (saveError) {
        console.error('[Visual Match] Failed to save matched products:', saveError);
      }

      res.json({
        success: true,
        imageDescription: 'No similar products found in your collection. Try uploading a different image.',
        detectedCategory: detectedCategory?.name || null,
        exactMatch: exactMatch || null, // Exact product match (≥95% full image similarity)
        matches: flatMatches,
        matchesByType,
        croppedJewelry: detectedJewelryItems.length > 0 ? {
          detected: true,
          primaryImage: detectedJewelryItems[0]?.croppedDataUrl || null,
          type: detectedJewelryItems[0]?.type || null,
          description: detectedJewelryItems[0]?.description || null,
          confidence: detectedJewelryItems[0]?.confidence || null,
          allItems: detectedJewelryItems
        } : { detected: false },
        stats: { 
          candidatesEvaluated: candidateProducts.length,
          embeddingsAvailable: stats.withEmbedding,
          totalProducts: stats.total,
          matchMethod: 'jina_clip_only',
          jewelryTypesDetected: Object.keys(matchesByType).length,
          hasExactMatch: !!exactMatch
        }
      });
    } catch (error: any) {
      console.error('[Visual Match] Error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // OPTIMIZED: Combined upload + detection SSE endpoint
  // Uploads to R2 in parallel with detection to eliminate wait time
  app.post("/api/chat/widget/detect-stream", chatImageUpload.single('image'), async (req, res) => {
    try {
      const { businessAccountId } = req.body;
      
      if (!businessAccountId) {
        return res.status(400).json({ error: "businessAccountId required" });
      }

      if (!req.file) {
        return res.status(400).json({ error: "No image file uploaded" });
      }

      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      if (!businessAccount || !businessAccount.openaiApiKey) {
        return res.status(400).json({ error: "Business account or OpenAI API key not found" });
      }

      // Set up SSE headers
      res.setHeader('Content-Type', 'text/event-stream');
      res.setHeader('Cache-Control', 'no-cache');
      res.setHeader('Connection', 'keep-alive');
      res.setHeader('Access-Control-Allow-Origin', '*');
      res.flushHeaders();

      const sendEvent = (eventType: string, data: any) => {
        res.write(`event: ${eventType}\n`);
        res.write(`data: ${JSON.stringify(data)}\n\n`);
      };

      // Start R2 upload in background immediately (non-blocking)
      sendEvent('status', { stage: 'starting', message: 'Processing image...' });
      
      let imageUrlPromise: Promise<string>;
      
      // Ensure R2 is initialized and start upload in background
      await r2Storage.ensureInitialized();
      if (r2Storage.isEnabled()) {
        imageUrlPromise = (async () => {
          const result = await r2Storage.uploadFile(
            req.file!.buffer,
            req.file!.originalname,
            "chat-images",
            req.file!.mimetype,
            businessAccountId
          );
          if (result.success && result.url) {
            console.log('[Detect Stream] R2 upload completed:', result.url);
            // Track the uploaded image in database
            const r2Key = r2Storage.extractKeyFromUrl(result.url);
            try {
              await storage.createUploadedImage({
                businessAccountId,
                imageUrl: result.url,
                r2Key: r2Key || undefined,
                originalFilename: req.file!.originalname,
                fileSize: req.file!.size,
                source: 'visual_search'
              });
            } catch (trackError) {
              console.error('[Detect Stream] Failed to track image:', trackError);
            }
            return result.url;
          }
          throw new Error('R2 upload failed');
        })();
      } else {
        // Fallback to local storage (blocking since it's fast)
        const correctDir = path.join(process.cwd(), "uploads", "business-photos", businessAccountId);
        if (!fs.existsSync(correctDir)) {
          fs.mkdirSync(correctDir, { recursive: true });
        }
        const timestamp = Date.now();
        const uniqueName = `${timestamp}-${randomUUID()}${path.extname(req.file.originalname)}`;
        const correctPath = path.join(correctDir, uniqueName);
        fs.writeFileSync(correctPath, req.file.buffer);
        const localUrl = `/uploads/business-photos/${businessAccountId}/${uniqueName}`;
        imageUrlPromise = Promise.resolve(localUrl);
        console.log('[Detect Stream] Saved locally:', localUrl);
      }

      // Convert buffer to base64 for detection (immediate, no network)
      const imageBuffer = req.file.buffer;
      const mimeType = req.file.mimetype;
      const base64Image = imageBuffer.toString('base64');
      const dataUrl = `data:${mimeType};base64,${base64Image}`;

      // Import services
      const { productImageEmbeddingService } = await import('./services/productImageEmbeddingService');
      const { jewelryDetectionService } = await import('./services/jewelryDetectionService');
      const { imageCroppingService } = await import('./services/imageCroppingService');
      const { imageHashService } = await import('./services/imageHashService');
      const { attributeMatchingService } = await import('./services/attributeMatchingService');

      // PARALLEL PROCESSING: Run Stage 0 (pHash + CLIP) AND jewelry detection concurrently
      // This cuts processing time roughly in half by not waiting for one to finish before starting the other
      sendEvent('status', { stage: 'stage0', message: 'Analyzing image...' });
      
      const parallelStartTime = Date.now();
      const [pHashResult, clipEmbeddingResult, detectionResult] = await Promise.all([
        // 1. pHash for exact match (local, fast)
        imageHashService.generateHash(dataUrl).catch(() => null),
        // 2. CLIP embedding for similarity search (Jina API - ~30-40s)
        productImageEmbeddingService.embedUploadedImage(dataUrl, businessAccountId as string).catch(() => ({ embedding: null })),
        // 3. Jewelry detection with attribute extraction (OpenAI Vision - ~30-60s) - runs concurrently!
        // Use dataUrl directly since we have the image in memory
        jewelryDetectionService.detectJewelry(dataUrl, businessAccountId as string).catch((e) => {
          console.error('[Detect Stream] Jewelry detection failed:', e);
          return { success: false, detectedItems: [] };
        })
      ]);
      console.log(`[Detect Stream] Parallel processing completed in ${Date.now() - parallelStartTime}ms`);
      
      // Wait for R2 upload to complete for history tracking (should be done by now since detection takes longer)
      const imgUrl = await imageUrlPromise;

      let exactMatch = null;
      if (clipEmbeddingResult.embedding) {
        const exactMatchResults = await db
          .select({
            id: products.id,
            name: products.name,
            description: products.description,
            price: products.price,
            imageUrl: products.imageUrl,
            imageHash: products.imageHash,
            distance: sql<number>`${products.fullImageEmbedding} <=> ${JSON.stringify(clipEmbeddingResult.embedding)}::vector`,
          })
          .from(products)
          .where(
            and(
              eq(products.businessAccountId, businessAccountId as string),
              sql`${products.fullImageEmbedding} IS NOT NULL`
            )
          )
          .orderBy(sql`${products.fullImageEmbedding} <=> ${JSON.stringify(clipEmbeddingResult.embedding)}::vector`)
          .limit(1);

        if (exactMatchResults.length > 0) {
          const topMatch = exactMatchResults[0];
          const similarity = Math.max(0, 1 - topMatch.distance);
          
          let pHashMatches = false;
          let pHashDistance = -1;
          
          if (pHashResult && topMatch.imageHash) {
            pHashDistance = imageHashService.calculateHammingDistance(pHashResult, topMatch.imageHash);
            pHashMatches = pHashDistance <= 10;
          }

          if (pHashMatches && similarity >= 0.96) {
            const fullProduct = await storage.getProduct(topMatch.id, businessAccountId as string);
            if (fullProduct) {
              exactMatch = {
                ...fullProduct,
                similarity: Math.round(similarity * 100),
                matchQuality: 'perfect_match',
                matchQualityLabel: 'Perfect Match',
                isExactMatch: true
              };
              
              // Send exact match immediately!
              sendEvent('exactMatch', { match: exactMatch });
            }
          }
        }
      }

      // STAGE 1: Process jewelry detection results (already completed in parallel)
      sendEvent('status', { stage: 'stage1', message: 'Processing detected jewelry...' });

      let hasSentResults = false;
      const allMatchedProducts: any[] = []; // Collect all matched products for history
      
      // Add exact match to collection if found
      if (exactMatch) {
        allMatchedProducts.push({
          id: exactMatch.id,
          name: exactMatch.name,
          description: exactMatch.description,
          price: exactMatch.price,
          imageUrl: exactMatch.imageUrl,
          similarity: exactMatch.similarity,
          matchQuality: exactMatch.matchQuality,
          isExactMatch: true
        });
      }
      
      try {
        // Use detection result from parallel processing (no need to call again!)
        const detection = detectionResult;
        
        if (detection.success && detection.detectedItems.length > 0) {
          // Crop and embed in parallel
          const croppedImages = await imageCroppingService.cropJewelryFromUrl(imgUrl, detection.detectedItems);
          
          // Check if background removal is enabled
          const widgetSettings = await storage.getWidgetSettings(businessAccountId as string);
          const BACKGROUND_REMOVAL_ENABLED = true; // Always enabled for best matching accuracy
          
          // OPTIMIZATION: Skip heavy background removal during initial upload (~30 sec saved)
          // If BG removal is enabled, save raw cropped images as placeholders (replaced when user clicks "Find Similar")
          // If BG removal is disabled, save cropped images directly (no replacement needed)
          try {
            await storage.clearProcessedImages(imgUrl, businessAccountId as string);
            
            for (let i = 0; i < croppedImages.length; i++) {
              const crop = croppedImages[i];
              const itemType = detection.detectedItems[i]?.type || `Item ${i + 1}`;
              await storage.addProcessedImageToUpload(imgUrl, businessAccountId as string, itemType, crop.croppedDataUrl);
              console.log(`[Visual Match Stream] Saved cropped image for ${itemType} (BG removal: ${BACKGROUND_REMOVAL_ENABLED ? 'deferred' : 'disabled'})`);
            }
          } catch (saveError: any) {
            console.warn('[Visual Match Stream] Failed to save cropped images:', saveError.message);
          }
          
          // Send detection event WITH cropped images, attributes, and bounding boxes
          sendEvent('detection', { 
            detected: true, 
            itemCount: detection.detectedItems.length,
            imageWidth: detection.imageWidth,
            imageHeight: detection.imageHeight,
            items: croppedImages.map((crop, idx) => ({ 
              type: detection.detectedItems[idx].type, 
              description: detection.detectedItems[idx].description,
              croppedDataUrl: crop.croppedDataUrl,
              confidence: detection.detectedItems[idx].confidence || 1.0,
              attributes: detection.detectedItems[idx].attributes || null,
              boundingBox: detection.detectedItems[idx].boundingBox || null
            }))
          });
          
          const embeddingPromises = croppedImages.map(async (crop, idx) => {
            try {
              const { embedding } = await productImageEmbeddingService.embedUploadedImage(crop.croppedDataUrl, businessAccountId as string);
              return { ...detection.detectedItems[idx], embedding, croppedDataUrl: crop.croppedDataUrl };
            } catch {
              return null;
            }
          });

          const embeddedItems = (await Promise.all(embeddingPromises)).filter(Boolean);

          // Search for each item and stream results
          for (const item of embeddedItems) {
            if (!item || !item.embedding) continue;
            
            const normalizedType = jewelryDetectionService.mapTypeToCategory(item.type);
            const typeFilter = normalizedType !== 'others' && normalizedType !== 'unknown' ? normalizedType : undefined;

            let similarProducts = await productImageEmbeddingService.searchSimilarProducts(
              item.embedding,
              businessAccountId as string,
              12, // Get more initially for description filtering
              0.85, // 85% similarity threshold
              typeFilter
            );

            // FINAL STAGE: Filter by description similarity AND attribute matching
            if (similarProducts.length > 0 && item.description) {
              try {
                // Generate text embedding for the detected item's description
                const queryDescriptionEmbedding = await embeddingService.generateEmbedding(
                  item.description,
                  businessAccountId as string
                );
                
                // Batch-load all description embeddings AND attributes in one query (avoid N+1)
                const productIds = similarProducts.map(p => p.id);
                const productJewelryData = await db
                  .select({ 
                    productId: productJewelryEmbeddings.productId,
                    descriptionEmbedding: productJewelryEmbeddings.descriptionEmbedding,
                    attributes: productJewelryEmbeddings.attributes
                  })
                  .from(productJewelryEmbeddings)
                  .where(inArray(productJewelryEmbeddings.productId, productIds));
                
                // Create maps for quick lookup
                const descEmbeddingMap = new Map<string, number[]>();
                const attributesMap = new Map<string, any>();
                for (const row of productJewelryData) {
                  if (row.descriptionEmbedding) {
                    descEmbeddingMap.set(row.productId, row.descriptionEmbedding as number[]);
                  }
                  if (row.attributes) {
                    attributesMap.set(row.productId, row.attributes);
                  }
                }
                
                // Get uploaded item attributes (if available from detection)
                const uploadedAttributes = (item as any).attributes || null;
                if (uploadedAttributes) {
                  console.log(`[Visual Match] Using uploaded attributes for ${(item as any).type}:`, JSON.stringify(uploadedAttributes));
                } else {
                  console.log(`[Visual Match] No uploaded attributes available for ${(item as any).type}, using description-only filtering`);
                }
                
                // Thresholds for filtering
                const DESCRIPTION_SIMILARITY_THRESHOLD = 0.50; // 50% description match
                const ATTRIBUTE_SCORE_THRESHOLD = 0.70; // 70% attribute match as fallback (lowered to allow similar patterns with different colors)
                
                // Filter products by description similarity OR attribute matching
                const filteredProducts = [];
                for (const product of similarProducts) {
                  const productDescEmb = descEmbeddingMap.get(product.id);
                  const productAttributes = attributesMap.get(product.id);
                  
                  let descSimilarity = 0;
                  let hasDescriptionMatch = false;
                  let passesDescriptionFilter = false;
                  let attributeScore = 0;
                  let hasAttributeMatch = false;
                  let isDisqualified = false;
                  let disqualifyReason = '';
                  
                  // Calculate description similarity
                  if (productDescEmb && productDescEmb.length > 0) {
                    let dotProduct = 0;
                    let normA = 0;
                    let normB = 0;
                    for (let i = 0; i < queryDescriptionEmbedding.length; i++) {
                      dotProduct += queryDescriptionEmbedding[i] * productDescEmb[i];
                      normA += queryDescriptionEmbedding[i] * queryDescriptionEmbedding[i];
                      normB += productDescEmb[i] * productDescEmb[i];
                    }
                    const denominator = Math.sqrt(normA) * Math.sqrt(normB);
                    descSimilarity = denominator > 0 ? dotProduct / denominator : 0;
                    hasDescriptionMatch = true;
                    passesDescriptionFilter = descSimilarity >= DESCRIPTION_SIMILARITY_THRESHOLD;
                  }
                  
                  // Calculate attribute matching (if both uploaded and product have attributes)
                  if (uploadedAttributes && productAttributes) {
                    // Check for hard disqualification (e.g., minimal vs intricate complexity)
                    // Pass RAW CLIP score (product.similarity is 0-1 raw cosine similarity, not scaled)
                    const rawClipScore = product.similarity;
                    const disqualifyCheck = attributeMatchingService.shouldDisqualify(uploadedAttributes, productAttributes, undefined, rawClipScore, product.name);
                    if (disqualifyCheck.disqualify) {
                      isDisqualified = true;
                      disqualifyReason = disqualifyCheck.reason;
                      console.log(`[Visual Match] DISQUALIFIED "${product.name}": ${disqualifyReason}`);
                    } else {
                      // Calculate attribute match score
                      const matchResult = attributeMatchingService.calculateAttributeScore(uploadedAttributes, productAttributes);
                      attributeScore = matchResult.score;
                      hasAttributeMatch = true;
                      console.log(`[Visual Match] ${product.name} attribute score: ${(attributeScore * 100).toFixed(1)}%, matched: [${matchResult.matchedAttributes.join(', ')}], mismatched: [${matchResult.mismatchedAttributes.join(', ')}]`);
                    }
                  }
                  
                  // Pass filter if:
                  // 1. Not disqualified by attributes, AND
                  // 2. Attribute score >= threshold OR no data available (description no longer used as filter)
                  const noDataAvailable = !hasAttributeMatch;
                  const passesFilter = !isDisqualified && (
                    (hasAttributeMatch && attributeScore >= ATTRIBUTE_SCORE_THRESHOLD) ||
                    noDataAvailable
                  );
                  
                  if (passesFilter) {
                    // Calculate combined score for ranking (CLIP 70%, Attributes 30% - description removed)
                    const clipScore = product.similarity * 100;
                    const combinedScore = hasAttributeMatch
                      ? (clipScore * 0.70) + (attributeScore * 100 * 0.30)
                      : clipScore;
                    
                    filteredProducts.push({
                      ...product,
                      descriptionSimilarity: descSimilarity,
                      attributeScore: attributeScore,
                      combinedScore: combinedScore
                    });
                    console.log(`[Visual Match] PASSED "${product.name}": similarity ${clipScore.toFixed(1)}%, attr ${(attributeScore * 100).toFixed(1)}%`);
                  } else if (!isDisqualified) {
                    console.log(`[Visual Match] Filtered out "${product.name}" - attr: ${(attributeScore * 100).toFixed(1)}%`);
                  }
                }
                
                // Sort by combined score
                filteredProducts.sort((a, b) => (b.combinedScore || b.similarity * 100) - (a.combinedScore || a.similarity * 100));
                
                similarProducts = filteredProducts;
                console.log(`[Visual Match] After description+attribute filter: ${similarProducts.length} products remain`);
              } catch (descFilterError) {
                console.error('[Visual Match] Description/attribute filtering failed:', descFilterError);
                // Continue with unfiltered results if filtering fails
              }
            }

            if (similarProducts.length > 0) {
              hasSentResults = true;
              // Stream partial results as they come in
              const productsToSend = similarProducts.slice(0, 6).map(p => ({
                id: p.id,
                name: p.name,
                description: p.description,
                price: p.price,
                imageUrl: p.imageUrl,
                similarity: Math.round(p.similarity * 100)
              }));
              
              sendEvent('similarProducts', {
                jewelryType: item.type,
                products: productsToSend
              });
              
              // Add to collection for history (avoid duplicates)
              for (const prod of productsToSend) {
                if (!allMatchedProducts.some(p => p.id === prod.id)) {
                  allMatchedProducts.push(prod);
                }
              }
            }
          }
        }
      } catch (detectionError) {
        console.error('[Visual Match Stream] Jewelry detection failed:', detectionError);
      }

      // Save matched products to history before completing
      if (allMatchedProducts.length > 0) {
        try {
          await storage.updateUploadedImageMatchedProducts(imgUrl, businessAccountId as string, allMatchedProducts);
          console.log(`[Visual Match Stream] Saved ${allMatchedProducts.length} matched products to history`);
        } catch (saveError) {
          console.error('[Visual Match Stream] Failed to save matched products:', saveError);
        }
      }

      // Complete - include imageUrl so client knows the R2 URL for manual crop functionality
      sendEvent('complete', { 
        success: true, 
        hasExactMatch: !!exactMatch,
        hasResults: hasSentResults || !!exactMatch,
        message: exactMatch ? 'Perfect match found!' : (hasSentResults ? 'Search complete' : 'No matches found'),
        imageUrl: imgUrl
      });
      
      res.end();
    } catch (error: any) {
      console.error('[Detect Stream] Error:', error);
      res.write(`event: error\ndata: ${JSON.stringify({ message: error.message })}\n\n`);
      res.end();
    }
  });

  // Legacy GET-based SSE endpoint for backward compatibility (used by EmbedChat widget and external callers)
  // The new POST /api/chat/widget/detect-stream is preferred for internal use
  app.get("/api/chat/widget/match-products-stream", async (req, res) => {
    try {
      const { businessAccountId, imageUrl } = req.query;
      
      if (!businessAccountId || !imageUrl) {
        return res.status(400).json({ error: "businessAccountId and imageUrl required" });
      }

      const businessAccount = await storage.getBusinessAccount(businessAccountId as string);
      if (!businessAccount || !businessAccount.openaiApiKey) {
        return res.status(400).json({ error: "Business account or OpenAI API key not found" });
      }

      // Set up SSE headers
      res.setHeader('Content-Type', 'text/event-stream');
      res.setHeader('Cache-Control', 'no-cache');
      res.setHeader('Connection', 'keep-alive');
      res.setHeader('Access-Control-Allow-Origin', '*');
      res.flushHeaders();

      const sendEvent = (eventType: string, data: any) => {
        res.write(`event: ${eventType}\n`);
        res.write(`data: ${JSON.stringify(data)}\n\n`);
      };

      sendEvent('status', { stage: 'starting', message: 'Processing image...' });

      // Import services
      const { productImageEmbeddingService } = await import('./services/productImageEmbeddingService');
      const { jewelryDetectionService } = await import('./services/jewelryDetectionService');
      const { imageCroppingService } = await import('./services/imageCroppingService');
      const { imageHashService } = await import('./services/imageHashService');
      const { attributeMatchingService } = await import('./services/attributeMatchingService');

      // Read image from URL
      let imageBuffer: Buffer;
      let mimeType: string;
      const imgUrl = imageUrl as string;

      if (imgUrl.startsWith('https://')) {
        const response = await fetch(imgUrl);
        if (!response.ok) {
          sendEvent('error', { message: 'Image file not found' });
          return res.end();
        }
        imageBuffer = Buffer.from(await response.arrayBuffer());
        mimeType = response.headers.get('content-type') || 'image/jpeg';
      } else {
        const imagePath = path.join(process.cwd(), imgUrl.replace(/^\//, ''));
        if (!fs.existsSync(imagePath)) {
          sendEvent('error', { message: 'Image file not found' });
          return res.end();
        }
        imageBuffer = fs.readFileSync(imagePath);
        mimeType = 'image/jpeg';
      }

      const base64Image = imageBuffer.toString('base64');
      const dataUrl = `data:${mimeType};base64,${base64Image}`;

      // Parallel processing
      sendEvent('status', { stage: 'stage0', message: 'Analyzing image...' });
      
      const [pHashResult, clipEmbeddingResult, detectionResult] = await Promise.all([
        imageHashService.generateHash(dataUrl).catch(() => null),
        productImageEmbeddingService.embedUploadedImage(dataUrl, businessAccountId as string).catch(() => ({ embedding: null })),
        jewelryDetectionService.detectJewelry(imgUrl, businessAccountId as string).catch((e) => {
          console.error('[GET Stream] Jewelry detection failed:', e);
          return { success: false, detectedItems: [] };
        })
      ]);

      // Check for exact match
      let exactMatch = null;
      if (clipEmbeddingResult.embedding) {
        const exactMatchResults = await db
          .select({
            id: products.id,
            name: products.name,
            description: products.description,
            price: products.price,
            imageUrl: products.imageUrl,
            imageHash: products.imageHash,
            distance: sql<number>`${products.fullImageEmbedding} <=> ${JSON.stringify(clipEmbeddingResult.embedding)}::vector`,
          })
          .from(products)
          .where(
            and(
              eq(products.businessAccountId, businessAccountId as string),
              sql`${products.fullImageEmbedding} IS NOT NULL`
            )
          )
          .orderBy(sql`${products.fullImageEmbedding} <=> ${JSON.stringify(clipEmbeddingResult.embedding)}::vector`)
          .limit(1);

        if (exactMatchResults.length > 0) {
          const topMatch = exactMatchResults[0];
          const similarity = Math.max(0, 1 - topMatch.distance);
          
          if (similarity >= 0.96) {
            const fullProduct = await storage.getProduct(topMatch.id, businessAccountId as string);
            if (fullProduct) {
              exactMatch = {
                ...fullProduct,
                similarity: Math.round(similarity * 100),
                matchQuality: 'perfect_match',
              };
              sendEvent('exactMatch', { match: exactMatch });
            }
          }
        }
      }

      // Send detection results
      if (detectionResult.success && 'detectedItems' in detectionResult && detectionResult.detectedItems.length > 0) {
        sendEvent('detection', {
          detected: true,
          itemCount: detectionResult.detectedItems.length,
          items: detectionResult.detectedItems.map(item => ({
            type: item.type,
            confidence: item.confidence,
            description: item.description,
            croppedDataUrl: item.croppedDataUrl,
            boundingBox: item.boundingBox
          })),
          imageWidth: 'imageWidth' in detectionResult ? detectionResult.imageWidth : 100,
          imageHeight: 'imageHeight' in detectionResult ? detectionResult.imageHeight : 100
        });
      }

      // Complete
      sendEvent('complete', { 
        success: true, 
        hasExactMatch: !!exactMatch,
        hasResults: !!exactMatch || (detectionResult.success && 'detectedItems' in detectionResult && detectionResult.detectedItems.length > 0),
        message: exactMatch ? 'Perfect match found!' : 'Search complete',
        imageUrl: imgUrl
      });
      
      res.end();
    } catch (error: any) {
      console.error('[GET Stream] Error:', error);
      res.write(`event: error\ndata: ${JSON.stringify({ message: error.message })}\n\n`);
      res.end();
    }
  });

  // Chat widget visual search using Vision Warehouse (with crop support)
  app.post("/api/chat/widget/visual-search", async (req, res) => {
    try {
      const { businessAccountId, imageUrl, boundingBox } = req.body;
      
      if (!businessAccountId || !imageUrl) {
        return res.status(400).json({ error: "businessAccountId and imageUrl required" });
      }

      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      if (!businessAccount) {
        return res.status(404).json({ error: "Business account not found" });
      }

      // Check if Vision Warehouse is configured
      const visualSearchModel = businessAccount.visualSearchModel || 'google_vision_warehouse';
      const useVisionWarehouse = visualSearchModel === 'google_vision_warehouse' &&
        businessAccount.googleVisionWarehouseEndpointId &&
        businessAccount.googleVisionWarehouseCredentials;

      if (!useVisionWarehouse) {
        return res.status(400).json({ 
          error: "Visual search is not configured. Please configure Google Vision Warehouse in settings." 
        });
      }

      // Get widget settings for thresholds and display mode
      const widgetSettings = await storage.getWidgetSettings(businessAccountId);
      const perfectMatchThreshold = (widgetSettings?.perfectMatchThreshold ? parseFloat(widgetSettings.perfectMatchThreshold) : 96) / 100;
      const verySimilarThreshold = (widgetSettings?.verySimilarThreshold ? parseFloat(widgetSettings.verySimilarThreshold) : 85) / 100;
      const somewhatSimilarThreshold = (widgetSettings?.somewhatSimilarThreshold ? parseFloat(widgetSettings.somewhatSimilarThreshold) : 70) / 100;
      const showMatchPercentage = widgetSettings?.showMatchPercentage === 'true';

      console.log('[Chat Visual Search] Starting Vision Warehouse search');

      // Fetch image with security validation
      const sharp = (await import('sharp')).default;
      let imageBuffer: Buffer;
      
      let fetchUrl = imageUrl as string;
      
      // Security: Reject path traversal attempts
      if (fetchUrl.includes('..') || fetchUrl.includes('%2e%2e') || fetchUrl.includes('%2E%2E')) {
        return res.status(400).json({ error: 'Invalid image URL' });
      }
      
      // For local paths, only allow uploads directory
      if (fetchUrl.startsWith('/')) {
        // Restrict to uploads directory only
        if (!fetchUrl.startsWith('/uploads/')) {
          return res.status(400).json({ error: 'Invalid image path' });
        }
        
        if (process.env.NODE_ENV === 'development') {
          const domain = process.env.APP_DOMAIN || process.env.REPLIT_DEV_DOMAIN || 'localhost:5000';
          const protocol = domain.includes('localhost') ? 'http' : 'https';
          fetchUrl = `${protocol}://${domain}${fetchUrl}`;
          console.log('[Chat Visual Search] Mapped relative URL to absolute:', fetchUrl);
        } else {
          // In production, use local file system (only uploads dir)
          const imagePath = path.join(process.cwd(), 'uploads', fetchUrl.replace(/^\/uploads\//, ''));
          // Verify resolved path is still within uploads
          const uploadsDir = path.join(process.cwd(), 'uploads');
          if (!imagePath.startsWith(uploadsDir)) {
            return res.status(400).json({ error: 'Invalid image path' });
          }
          if (!fs.existsSync(imagePath)) {
            return res.status(404).json({ error: "Image file not found" });
          }
          imageBuffer = fs.readFileSync(imagePath);
        }
      }

      if (!imageBuffer!) {
        // Security: For remote URLs, validate against allowed domains
        try {
          const urlObj = new URL(fetchUrl);
          const allowedDomains = [
            'replit.dev',
            'replit.co',
            'r2.cloudflarestorage.com',
            'r2.dev',
            'cloudflare-ipfs.com',
            'cdn.shopify.com',
            'localhost'
          ];
          const isAllowed = allowedDomains.some(domain => 
            urlObj.hostname === domain || urlObj.hostname.endsWith('.' + domain)
          );
          if (!isAllowed) {
            console.log('[Chat Visual Search] Blocked URL from untrusted domain:', urlObj.hostname);
            return res.status(400).json({ error: 'Image URL not from trusted domain' });
          }
          
          const response = await fetch(fetchUrl);
          if (!response.ok) {
            return res.status(404).json({ error: 'Image file not found' });
          }
          imageBuffer = Buffer.from(await response.arrayBuffer());
        } catch (fetchError: any) {
          console.error('[Chat Visual Search] Failed to fetch image:', fetchError);
          return res.status(400).json({ error: 'Failed to fetch image from URL' });
        }
      }

      // Process image (crop if bounding box provided)
      let processedBuffer: Buffer;
      if (boundingBox && typeof boundingBox.x === 'number') {
        const { x, y, width, height } = boundingBox;
        
        const metadata = await sharp(imageBuffer).metadata();
        const imgWidth = metadata.width || 0;
        const imgHeight = metadata.height || 0;
        
        // Convert percentage to pixel coordinates
        const pixelX = Math.round((x / 100) * imgWidth);
        const pixelY = Math.round((y / 100) * imgHeight);
        const pixelWidth = Math.round((width / 100) * imgWidth);
        const pixelHeight = Math.round((height / 100) * imgHeight);
        
        // Clamp to valid bounds
        const clampedX = Math.max(0, Math.min(pixelX, imgWidth - 1));
        const clampedY = Math.max(0, Math.min(pixelY, imgHeight - 1));
        const clampedWidth = Math.max(1, Math.min(pixelWidth, imgWidth - clampedX));
        const clampedHeight = Math.max(1, Math.min(pixelHeight, imgHeight - clampedY));
        
        console.log(`[Chat Visual Search] Cropping: ${clampedX},${clampedY} -> ${clampedWidth}x${clampedHeight}`);
        
        processedBuffer = await sharp(imageBuffer)
          .extract({ left: clampedX, top: clampedY, width: clampedWidth, height: clampedHeight })
          .resize(512, 512, { fit: 'inside', withoutEnlargement: true })
          .jpeg({ quality: 85 })
          .toBuffer();
      } else {
        // Resize full image for Vision Warehouse
        processedBuffer = await sharp(imageBuffer)
          .resize(512, 512, { fit: 'inside', withoutEnlargement: true })
          .jpeg({ quality: 85 })
          .toBuffer();
      }

      const base64Image = processedBuffer.toString('base64');

      // Search using Vision Warehouse
      const { visionWarehouseService } = await import('./services/visionWarehouseService');
      
      const projectNumber = businessAccount.googleVisionWarehouseProjectNumber;
      if (!projectNumber) {
        return res.status(400).json({ error: 'Google Vision Warehouse project number not configured' });
      }

      console.log('[Chat Visual Search] Calling Vision Warehouse API');
      
      const vwResults = await visionWarehouseService.searchByImage(
        businessAccount.googleVisionWarehouseCredentials!,
        businessAccount.googleVisionWarehouseEndpointId!,
        base64Image,
        10,
        undefined,
        projectNumber
      );

      // Filter by minimum threshold
      const filteredResults = vwResults.filter(r => r.score >= somewhatSimilarThreshold);
      
      console.log(`[Chat Visual Search] Vision Warehouse returned ${vwResults.length} total, ${filteredResults.length} above ${somewhatSimilarThreshold * 100}% threshold`);

      if (filteredResults.length === 0) {
        return res.json({
          products: [],
          matchCount: 0,
          message: "No similar products found",
          showMatchPercentage
        });
      }

      // Create score map and fetch products
      const vwScoreMap = new Map(filteredResults.map(r => [r.assetId.replace('p-', ''), r.score]));
      const productIds = filteredResults.map(r => r.assetId.replace('p-', ''));

      const vwProducts = await db
        .select({
          id: products.id,
          name: products.name,
          description: products.description,
          price: products.price,
          imageUrl: products.imageUrl,
        })
        .from(products)
        .where(inArray(products.id, productIds));

      // Map to result format with match quality
      const results = vwProducts.map(p => {
        const similarity = vwScoreMap.get(p.id) || 0.7;
        
        let matchLabel: string;
        let matchQuality: string;
        if (similarity >= perfectMatchThreshold) {
          matchLabel = 'Perfect Match';
          matchQuality = 'perfect_match';
        } else if (similarity >= verySimilarThreshold) {
          matchLabel = 'Very Similar';
          matchQuality = 'very_similar';
        } else {
          matchLabel = 'Somewhat Similar';
          matchQuality = 'somewhat_similar';
        }
        
        return {
          id: p.id,
          name: p.name,
          description: p.description,
          price: p.price,
          imageUrl: p.imageUrl,
          similarity: Math.round(similarity * 100),
          matchScore: Math.round(similarity * 100),
          matchLabel,
          matchQuality,
          displayLabel: showMatchPercentage ? `${Math.round(similarity * 100)}% match` : matchLabel,
        };
      });

      // Sort by similarity descending
      results.sort((a, b) => b.similarity - a.similarity);

      console.log(`[Chat Visual Search] Returning ${results.length} products`);

      return res.json({
        products: results,
        matchCount: results.length,
        searchType: 'vision_warehouse',
        showMatchPercentage,
        message: `Found ${results.length} similar products`
      });

    } catch (error: any) {
      console.error('[Chat Visual Search] Error:', error);
      return res.status(500).json({ error: error.message || 'Visual search failed' });
    }
  });

  // Adjusted boundary search - user modified the AI-detected bounding box
  app.post("/api/visual-search/adjusted-boundary", async (req, res) => {
    try {
      const { businessAccountId, imageUrl, boundingBox, jewelryType, description, clearFirst, originalAttributes } = req.body;
      
      if (!businessAccountId || !imageUrl || !boundingBox) {
        return res.status(400).json({ error: "businessAccountId, imageUrl, and boundingBox required" });
      }

      const { x, y, width, height } = boundingBox;
      if (typeof x !== 'number' || typeof y !== 'number' || typeof width !== 'number' || typeof height !== 'number') {
        return res.status(400).json({ error: "boundingBox must include x, y, width, and height as percentage numbers" });
      }

      console.log(`[Adjusted Boundary Search] Processing box: x=${x.toFixed(1)}%, y=${y.toFixed(1)}%, w=${width.toFixed(1)}%, h=${height.toFixed(1)}%`);

      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      if (!businessAccount || !businessAccount.openaiApiKey) {
        return res.status(400).json({ error: "Business account or OpenAI API key not found" });
      }

      // Check if Google Vision Warehouse or Product Search is configured and selected
      const visualSearchModel = businessAccount.visualSearchModel || 'google_vision_warehouse';
      const useVisionWarehouse = visualSearchModel === 'google_vision_warehouse' &&
        businessAccount.googleVisionWarehouseEndpointId &&
        businessAccount.googleVisionWarehouseCredentials;
      const useProductSearch = visualSearchModel === 'google_product_search' &&
        businessAccount.googleProductSearchProductSetId &&
        businessAccount.googleProductSearchCredentials;

      if (useProductSearch) {
        console.log('[Adjusted Boundary Search] Using Google Product Search for search');
      } else if (useVisionWarehouse) {
        console.log('[Adjusted Boundary Search] Using Google Vision Warehouse for search');
      } else {
        console.log('[Adjusted Boundary Search] No visual search model configured');
        return res.status(400).json({ 
          error: "Visual search is not configured. Please configure Google Vision Warehouse or Google Product Search in the API Keys settings." 
        });
      }

      // Fetch configurable thresholds from widget settings
      // NOTE: Default set to 80% for quality matches - users can lower if needed
      const widgetSettings = await storage.getWidgetSettings(businessAccountId);
      const SIMILARITY_THRESHOLD = (widgetSettings?.clipSimilarityThreshold ? parseFloat(widgetSettings.clipSimilarityThreshold) : 80) / 100;
      const DESCRIPTION_THRESHOLD = (widgetSettings?.descriptionSimilarityThreshold ? parseFloat(widgetSettings.descriptionSimilarityThreshold) : 60) / 100;
      const ATTRIBUTE_THRESHOLD = (widgetSettings?.attributeSimilarityThreshold ? parseFloat(widgetSettings.attributeSimilarityThreshold) : 60) / 100;
      const PERFECT_MATCH_THRESHOLD = (widgetSettings?.perfectMatchThreshold ? parseFloat(widgetSettings.perfectMatchThreshold) : 96) / 100;
      const VERY_SIMILAR_THRESHOLD = (widgetSettings?.verySimilarThreshold ? parseFloat(widgetSettings.verySimilarThreshold) : 85) / 100;
      const SOMEWHAT_SIMILAR_THRESHOLD = (widgetSettings?.somewhatSimilarThreshold ? parseFloat(widgetSettings.somewhatSimilarThreshold) : 70) / 100;
      // Skip background removal when using Vision Warehouse or Product Search - they have built-in preprocessing
      const BACKGROUND_REMOVAL_ENABLED = !useVisionWarehouse && !useProductSearch;

      // Import services for visual search
      const { productImageEmbeddingService } = await import('./services/productImageEmbeddingService');
      const { attributeMatchingService } = await import('./services/attributeMatchingService');
      const { jewelryDetectionService } = await import('./services/jewelryDetectionService');
      const sharp = (await import('sharp')).default;

      // Fetch image
      let imageBuffer: Buffer;
      const imgUrl = imageUrl as string;

      // In development, convert relative URLs to absolute URLs for fetch
      let fetchUrl = imgUrl;
      if (imgUrl.startsWith('/') && process.env.NODE_ENV === 'development') {
        const domain = process.env.APP_DOMAIN || process.env.REPLIT_DEV_DOMAIN || 'localhost:5000';
        const protocol = domain.includes('localhost') ? 'http' : 'https';
        fetchUrl = `${protocol}://${domain}${imgUrl}`;
        console.log('[Adjusted Boundary Search] Mapped relative URL to absolute:', fetchUrl);
      } else if (!imgUrl.startsWith('https://') && !imgUrl.startsWith('/')) {
        return res.status(400).json({ error: 'Only HTTPS URLs are allowed' });
      }

      try {
        const response = await fetch(fetchUrl);
        if (!response.ok) {
          return res.status(404).json({ error: 'Image file not found' });
        }
        imageBuffer = Buffer.from(await response.arrayBuffer());
      } catch (fetchError: any) {
        console.error('[Adjusted Boundary Search] Failed to fetch image:', fetchError);
        return res.status(400).json({ error: 'Failed to fetch image from URL' });
      }

      // Get image dimensions
      let metadata;
      try {
        metadata = await sharp(imageBuffer).metadata();
      } catch (metadataError: any) {
        console.error('[Adjusted Boundary Search] Failed to read image metadata:', metadataError);
        return res.status(400).json({ error: 'Invalid image format' });
      }
      
      const imgWidth = metadata.width || 0;
      const imgHeight = metadata.height || 0;
      
      if (imgWidth === 0 || imgHeight === 0) {
        return res.status(400).json({ error: 'Invalid image dimensions' });
      }

      // Convert percentage to pixel coordinates
      const pixelX = Math.round((x / 100) * imgWidth);
      const pixelY = Math.round((y / 100) * imgHeight);
      const pixelWidth = Math.round((width / 100) * imgWidth);
      const pixelHeight = Math.round((height / 100) * imgHeight);

      // Clamp to valid bounds
      const clampedX = Math.max(0, Math.min(pixelX, imgWidth - 1));
      const clampedY = Math.max(0, Math.min(pixelY, imgHeight - 1));
      const clampedWidth = Math.max(1, Math.min(pixelWidth, imgWidth - clampedX));
      const clampedHeight = Math.max(1, Math.min(pixelHeight, imgHeight - clampedY));

      console.log(`[Adjusted Boundary Search] Crop pixels: ${clampedX},${clampedY} -> ${clampedWidth}x${clampedHeight}`);

      // Crop the image
      let croppedBuffer: Buffer;
      try {
        croppedBuffer = await sharp(imageBuffer)
          .extract({ left: clampedX, top: clampedY, width: clampedWidth, height: clampedHeight })
          .resize(512, 512, { fit: 'inside', withoutEnlargement: true })
          .jpeg({ quality: 85 })
          .toBuffer();
      } catch (cropError: any) {
        console.error('[Adjusted Boundary Search] Crop failed:', cropError);
        return res.status(400).json({ error: 'Failed to crop image' });
      }

      // Apply background removal if enabled
      let processedBuffer = croppedBuffer;
      if (BACKGROUND_REMOVAL_ENABLED) {
        try {
          const { backgroundRemovalService } = await import('./services/backgroundRemovalService');
          console.log('[Adjusted Boundary Search] Background removal enabled, processing...');
          const bgRemovedBuffer = await backgroundRemovalService.removeBackground(croppedBuffer);
          processedBuffer = bgRemovedBuffer;
          console.log('[Adjusted Boundary Search] Background removal completed');
        } catch (bgError: any) {
          console.warn('[Adjusted Boundary Search] Background removal failed, using original:', bgError.message);
        }
      }

      // Convert to data URL for embedding (use processed buffer which may have bg removed)
      const croppedDataUrl = BACKGROUND_REMOVAL_ENABLED && processedBuffer !== croppedBuffer
        ? `data:image/png;base64,${processedBuffer.toString('base64')}`
        : `data:image/jpeg;base64,${croppedBuffer.toString('base64')}`;
      
      // Save the processed image URL for Match History display (append to array)
      if (BACKGROUND_REMOVAL_ENABLED && processedBuffer !== croppedBuffer) {
        try {
          // Clear previous processed images if this is the first item in a batch
          if (clearFirst) {
            await storage.clearProcessedImages(imgUrl, businessAccountId);
            console.log('[Adjusted Boundary Search] Cleared previous processed images');
          }
          const processedBase64 = processedBuffer.toString('base64');
          const processedDataUrl = `data:image/png;base64,${processedBase64}`;
          const itemLabel = jewelryType || 'Processed';
          await storage.addProcessedImageToUpload(imgUrl, businessAccountId, itemLabel, processedDataUrl);
          console.log(`[Adjusted Boundary Search] Saved processed image (${itemLabel}) to database`);
        } catch (saveError) {
          console.error('[Adjusted Boundary Search] Failed to save processed image URL:', saveError);
        }
      }
      
      // Create full image data URL for pHash comparison (Stage 0 needs full image, not cropped)
      const fullImageDataUrl = `data:image/jpeg;base64,${imageBuffer.toString('base64')}`;

      // Import image hash service for Stage 0 exact match
      const { imageHashService } = await import('./services/imageHashService');

      // When using Vision Warehouse, skip CLIP embeddings (VW handles visual search)
      // Only generate pHash for exact match detection (free, local)
      let croppedEmbeddingResult = { description: '', embedding: null as number[] | null };
      let fullImageEmbeddingResult = { description: '', embedding: null as number[] | null };
      let pHashResult: string | null = null;
      let attributeResult = { success: true, attributes: originalAttributes || null, description: description || '', type: jewelryType || 'unknown' };

      // Generate pHash for exact match detection (always, it's free)
      try {
        pHashResult = await imageHashService.generateHash(fullImageDataUrl);
        console.log(`[Adjusted Boundary Search] pHash generated from FULL image: ${pHashResult.substring(0, 8)}...`);
      } catch (e) {
        console.warn('[Adjusted Boundary Search] pHash generation failed:', e);
      }

      // Skip CLIP embeddings and attribute extraction when using Vision Warehouse or Product Search
      if (!useVisionWarehouse && !useProductSearch) {
        // Legacy CLIP mode - generate embeddings and attributes
        const [croppedEmb, fullEmb, attrRes] = await Promise.all([
          productImageEmbeddingService.embedUploadedImage(croppedDataUrl, businessAccountId),
          productImageEmbeddingService.embedUploadedImage(fullImageDataUrl, businessAccountId),
          originalAttributes 
            ? Promise.resolve({ success: true, attributes: originalAttributes, description: description || '', type: jewelryType || 'unknown' })
            : jewelryDetectionService.extractAttributesFromCroppedImage(croppedDataUrl, businessAccountId)
        ]);
        croppedEmbeddingResult = croppedEmb;
        fullImageEmbeddingResult = fullEmb;
        attributeResult = attrRes;
        
        if (originalAttributes) {
          console.log(`[Adjusted Boundary Search] Using original attributes from detect-stream (type: ${jewelryType}, skipped API call)`);
        }
        console.log(`[Adjusted Boundary Search] Embedding generated, attributes: ${attributeResult.success ? 'success' : 'failed'}`);
      } else {
        console.log('[Adjusted Boundary Search] Google Cloud mode - using Vision Warehouse');
      }
      
      // Use cropped embedding for Stage 1 (if available)
      const embeddingResult = croppedEmbeddingResult;

      // STAGE 0: Check for exact product match using pHash (CLIP removed for VW/Product Search mode)
      let exactMatch: any = null;
      console.log('[Adjusted Boundary Search] Stage 0: Checking for exact product match');
      
      // Skip Stage 0 CLIP matching when using Vision Warehouse/Product Search or if no embedding
      if (useVisionWarehouse || useProductSearch || !fullImageEmbeddingResult.embedding || fullImageEmbeddingResult.embedding.length === 0) {
        console.log('[Adjusted Boundary Search] Stage 0: Using pHash-only matching (Google Cloud mode)');
        
        // For Vision Warehouse mode, use pHash-only exact matching
        if (pHashResult) {
          try {
            // Find products with similar pHash
            const pHashCandidates = await db
              .select({
                id: products.id,
                name: products.name,
                description: products.description,
                price: products.price,
                imageUrl: products.imageUrl,
                imageHash: products.imageHash,
              })
              .from(products)
              .where(
                and(
                  eq(products.businessAccountId, businessAccountId),
                  sql`${products.imageHash} IS NOT NULL`
                )
              )
              .limit(100);
            
            for (const candidate of pHashCandidates) {
              if (!candidate.imageHash) continue;
              const pHashDistance = imageHashService.calculateHammingDistance(pHashResult, candidate.imageHash);
              if (pHashDistance <= 10) { // Exact match threshold
                console.log(`[Adjusted Boundary Search] EXACT MATCH FOUND via pHash! ${candidate.name} (distance: ${pHashDistance})`);
                const fullProduct = await storage.getProduct(candidate.id, businessAccountId);
                if (fullProduct) {
                  exactMatch = {
                    ...fullProduct,
                    similarity: 100, // pHash match = 100%
                    matchQuality: 'perfect_match',
                    matchLabel: 'Perfect Match',
                    isExactMatch: true,
                    pHashDistance,
                    pHashMatch: true,
                  };
                  break;
                }
              }
            }
          } catch (e) {
            console.warn('[Adjusted Boundary Search] pHash exact match search failed:', e);
          }
        }
      } else {
      try {
        // Search against fullImageEmbedding using FULL uploaded image embedding (not cropped)
        const exactMatchResults = await db
          .select({
            id: products.id,
            name: products.name,
            description: products.description,
            price: products.price,
            imageUrl: products.imageUrl,
            imageHash: products.imageHash,
            distance: sql<number>`${products.fullImageEmbedding} <=> ${JSON.stringify(fullImageEmbeddingResult.embedding)}::vector`,
          })
          .from(products)
          .where(
            and(
              eq(products.businessAccountId, businessAccountId),
              sql`${products.fullImageEmbedding} IS NOT NULL`
            )
          )
          .orderBy(sql`${products.fullImageEmbedding} <=> ${JSON.stringify(fullImageEmbeddingResult.embedding)}::vector`)
          .limit(3);

        if (exactMatchResults.length > 0) {
          for (const topMatch of exactMatchResults) {
            const similarity = Math.max(0, 1 - topMatch.distance);
            
            console.log(`[Adjusted Boundary Search] Stage 0 candidate: ${topMatch.name} (similarity: ${(similarity * 100).toFixed(2)}%)`);
            
            // Check pHash match
            let pHashMatches = false;
            let pHashDistance = -1;
            
            if (pHashResult && topMatch.imageHash) {
              pHashDistance = imageHashService.calculateHammingDistance(pHashResult, topMatch.imageHash);
              pHashMatches = pHashDistance <= 10; // 0-10 bits = same image (stricter threshold to reduce false positives)
              console.log(`[Adjusted Boundary Search] pHash comparison: distance=${pHashDistance}, matches=${pHashMatches}`);
            }
            
            // Perfect Match requires BOTH: pHash match AND similarity ≥96%
            // Visual fingerprint match is required for "Perfect Match"
            if (pHashMatches && similarity >= 0.96) {
              console.log(`[Adjusted Boundary Search] EXACT MATCH FOUND! ${topMatch.name} (pHash + similarity: ${(similarity * 100).toFixed(1)}%)`);
              
              const fullProduct = await storage.getProduct(topMatch.id, businessAccountId);
              if (fullProduct) {
                exactMatch = {
                  ...fullProduct,
                  similarity: Math.round(similarity * 100),
                  matchQuality: 'perfect_match',
                  matchQualityLabel: 'Perfect Match',
                  rawVectorSimilarity: similarity,
                  pHashDistance: pHashDistance,
                  isExactMatch: true
                };
                break;
              }
            } else {
              console.log(`[Adjusted Boundary Search] Stage 0 no exact match (similarity: ${(similarity * 100).toFixed(1)}%, pHash match: ${pHashMatches}, distance: ${pHashDistance})`);
            }
          }
        }
      } catch (exactMatchError) {
        console.error('[Adjusted Boundary Search] Stage 0 exact match check failed:', exactMatchError);
      }
      } // End of Stage 0 if block

      console.log('[Adjusted Boundary Search] Stage 1: Searching for similar products');

      // Generate description embedding for the 15% weight contribution
      // Use OpenAI text-embedding-3-small (1536-dim) to match stored description embeddings
      let queryDescriptionEmbedding: number[] | null = null;
      const descText = attributeResult.description || description;
      if (descText) {
        try {
          queryDescriptionEmbedding = await embeddingService.generateEmbedding(descText, businessAccountId);
          console.log(`[Adjusted Boundary Search] Generated description embedding (OpenAI 1536-dim)`);
        } catch (descError) {
          console.warn('[Adjusted Boundary Search] Description embedding failed:', descError);
        }
      }

      // Search for similar products using configurable threshold
      
      // Helper function to normalize jewelry type to canonical singular form
      const normalizeJewelryType = (type: string): string => {
        if (!type) return type;
        let normalized = type.toLowerCase().replace(/\s+/g, '-');
        // Handle special plural cases first
        const pluralMappings: Record<string, string> = {
          'brooches': 'brooch',
          'watches': 'watch',
        };
        if (pluralMappings[normalized]) {
          return pluralMappings[normalized];
        }
        // Remove trailing 's' for simple plurals (earrings -> earring, rings -> ring)
        if (normalized.endsWith('s') && !normalized.endsWith('ss')) {
          normalized = normalized.slice(0, -1);
        }
        return normalized;
      };
      
      // Helper function to extract base category from hyphenated types
      // e.g., "pendant-necklace" -> "necklace", "drop-earring" -> "earring"
      const getBaseCategory = (type: string): string | null => {
        if (!type || !type.includes('-')) return null;
        const parts = type.split('-');
        // Return the last part as the base category (usually the main type)
        const lastPart = parts[parts.length - 1];
        return normalizeJewelryType(lastPart);
      };
      
      // Jewelry type compatibility map - uses SINGULAR forms as canonical
      // Both detected types and catalog types are normalized before lookup
      // Includes hyphenated variants that map to base categories
      const typeCompatibilityMap: Record<string, string[]> = {
        'ring': ['ring', 'rings', 'band', 'bands', 'engagement-ring', 'wedding-ring', 'cocktail-ring', 'statement-ring'],
        'band': ['ring', 'rings', 'band', 'bands'],
        'necklace': ['necklace', 'necklaces', 'choker', 'chokers', 'pendant-necklace', 'pendant-necklaces', 'chain-necklace'],
        'choker': ['necklace', 'necklaces', 'choker', 'chokers'],
        'pendant': ['pendant', 'pendants', 'locket', 'lockets', 'pendant-necklace', 'necklace', 'necklaces'],
        'pendant-necklace': ['pendant', 'pendants', 'necklace', 'necklaces', 'pendant-necklace', 'pendant-necklaces'],
        'earring': ['earring', 'earrings', 'earring-pair', 'earring-pairs', 'stud', 'studs', 'hoop', 'hoops', 'drop-earring', 'drop-earrings', 'jhumka', 'jhumkas', 'chandbali', 'chandbalis'],
        'earring-pair': ['earring', 'earrings', 'earring-pair', 'earring-pairs', 'stud', 'studs', 'hoop', 'hoops', 'drop-earring', 'drop-earrings', 'jhumka', 'jhumkas'],
        'drop-earring': ['earring', 'earrings', 'earring-pair', 'drop-earring', 'drop-earrings', 'jhumka', 'jhumkas'],
        'stud': ['earring', 'earrings', 'earring-pair', 'stud', 'studs'],
        'hoop': ['earring', 'earrings', 'earring-pair', 'hoop', 'hoops'],
        'jhumka': ['earring', 'earrings', 'earring-pair', 'jhumka', 'jhumkas', 'drop-earring'],
        'bracelet': ['bracelet', 'bracelets', 'bangle', 'bangles', 'cuff', 'cuffs', 'kada', 'kadas'],
        'bangle': ['bangle', 'bangles', 'bracelet', 'bracelets', 'kada', 'kadas'],
        'kada': ['bangle', 'bangles', 'kada', 'kadas', 'bracelet', 'bracelets'],
        'anklet': ['anklet', 'anklets', 'payal', 'payals'],
        'payal': ['anklet', 'anklets', 'payal', 'payals'],
        'maang-tikka': ['maang-tikka', 'tikka', 'maangtika', 'maang-tikkas'],
        'tikka': ['maang-tikka', 'tikka', 'maangtika'],
        'nose-ring': ['nose-ring', 'nose-rings', 'nath', 'naths'],
        'nath': ['nose-ring', 'nose-rings', 'nath', 'naths'],
        'chain': ['chain', 'chains'],
        'brooch': ['brooch', 'brooches', 'pin', 'pins'],
        'mangalsutra': ['mangalsutra', 'mangalsutras', 'necklace', 'necklaces'],
        'other': ['other', 'others'],
      };
      
      // Get jewelry type - prioritize the original type from UI (jewelryType) over re-detected type (attributeResult.type)
      // This prevents misdetection when cropping changes the AI's interpretation
      const rawDetectedType = (jewelryType || attributeResult.type || '').toLowerCase().replace(/\s+/g, '-');
      const detectedType = normalizeJewelryType(rawDetectedType);
      console.log(`[Adjusted Boundary Search] Using type: "${detectedType}" (from UI: "${jewelryType}", re-detected: "${attributeResult.type || 'none'}")`);
      
      // Get compatible types - first try exact match, then try base category
      let compatibleTypes = typeCompatibilityMap[detectedType];
      if (!compatibleTypes && detectedType) {
        // Try extracting base category from hyphenated type
        const baseCategory = getBaseCategory(rawDetectedType);
        if (baseCategory && typeCompatibilityMap[baseCategory]) {
          console.log(`[Adjusted Boundary Search] Using base category "${baseCategory}" for "${detectedType}"`);
          compatibleTypes = typeCompatibilityMap[baseCategory];
        } else {
          // Fallback: include both detected type and its plural form
          compatibleTypes = [detectedType, detectedType + 's', rawDetectedType, rawDetectedType + 's'];
        }
      } else if (!compatibleTypes) {
        compatibleTypes = [];
      }
      
      console.log(`[Adjusted Boundary Search] Detected type: "${detectedType}", compatible types: [${compatibleTypes.join(', ')}]`);
      
      // Stage 1: Query from productJewelryEmbeddings table for cropped jewelry comparison
      // This compares the cropped uploaded jewelry against cropped catalog jewelry (jewelry-to-jewelry)
      
      // Get Vision Warehouse candidate IDs if configured (for pre-filtering)
      let visionWarehouseCandidateIds: string[] | null = null;
      if (useVisionWarehouse) {
        // Vision Warehouse is configured - use it exclusively (no Jina CLIP fallback)
        const { visionWarehouseService } = await import('./services/visionWarehouseService');
        
        // Use the cropped image for Vision Warehouse search
        const croppedBase64 = croppedDataUrl.replace(/^data:image\/\w+;base64,/, '');
        
        // Pass the configured project number (required for Vision Warehouse API)
        const projectNumber = businessAccount.googleVisionWarehouseProjectNumber;
        if (!projectNumber) {
          return res.status(400).json({ error: 'Google Vision Warehouse project number not configured' });
        }
        
        // Vision Warehouse returns top 10 results sorted by relevance
        // We filter client-side using configurable threshold from widget settings
        const VISION_WAREHOUSE_RELEVANCE_THRESHOLD = SOMEWHAT_SIMILAR_THRESHOLD;
        
        const vwResults = await visionWarehouseService.searchByImage(
          businessAccount.googleVisionWarehouseCredentials!,
          businessAccount.googleVisionWarehouseEndpointId!,
          croppedBase64,
          10, // Top 10 results (already sorted by relevance by Google)
          undefined, // no filters
          projectNumber // Use configured project number
        );

        // Filter client-side by relevance threshold (≥70%)
        const filteredVwResults = vwResults.filter(r => r.score >= VISION_WAREHOUSE_RELEVANCE_THRESHOLD);
        
        console.log(`[Adjusted Boundary Search] Vision Warehouse returned ${vwResults.length} total, ${filteredVwResults.length} above ${VISION_WAREHOUSE_RELEVANCE_THRESHOLD * 100}% threshold`);
        
        // Log individual scores for debugging
        vwResults.forEach(r => {
          const passed = r.score >= VISION_WAREHOUSE_RELEVANCE_THRESHOLD;
          console.log(`[VisionWarehouse] ${r.assetId}: ${(r.score * 100).toFixed(1)}% relevance ${passed ? '✓' : '✗'}`);
        });
        
        // Extract product IDs from filtered Vision Warehouse results
        visionWarehouseCandidateIds = filteredVwResults.map(r => r.assetId.replace('p-', ''));
        
        // VISION WAREHOUSE DIRECT MODE: Skip local CLIP filtering entirely
        // VW products may not have local embeddings, so fetch directly from products table
        if (visionWarehouseCandidateIds.length > 0) {
          console.log(`[Adjusted Boundary Search] Vision Warehouse direct mode - fetching ${visionWarehouseCandidateIds.length} products directly`);
          
          // Create a map of VW scores by product ID
          const vwScoreMap = new Map(filteredVwResults.map(r => [r.assetId.replace('p-', ''), r.score]));
          
          // Fetch products directly from products table (no CLIP embedding requirement)
          const vwProducts = await db
            .select({
              id: products.id,
              name: products.name,
              description: products.description,
              price: products.price,
              imageUrl: products.imageUrl,
              detectedJewelryType: products.detectedJewelryType,
            })
            .from(products)
            .where(inArray(products.id, visionWarehouseCandidateIds));
          
          // Map to result format with VW scores
          const results = vwProducts.map(p => {
            const vwScore = vwScoreMap.get(p.id) || 0.7;
            const matchLabel = vwScore >= 0.95 ? 'Perfect Match' : vwScore >= 0.85 ? 'Very Similar' : 'Somewhat Similar';
            return {
              id: p.id,
              name: p.name,
              description: p.description,
              price: p.price,
              imageUrl: p.imageUrl,
              similarity: vwScore,
              matchScore: Math.round(vwScore * 100),
              matchLabel,
              detectedJewelryType: p.detectedJewelryType || detectedType || 'jewelry',
            };
          });
          
          // Sort by VW score descending
          results.sort((a, b) => b.similarity - a.similarity);
          
          console.log(`[Adjusted Boundary Search] Vision Warehouse direct mode - returning ${results.length} products`);
          
          return res.json({
            products: results,
            matchCount: results.length,
            searchType: 'vision_warehouse_direct',
            message: `Found ${results.length} similar products via Vision Warehouse`
          });
        }
      }
      
      // Google Product Search integration (pay-per-use alternative to Vision Warehouse)
      if (useProductSearch) {
        console.log('[Adjusted Boundary Search] Using Google Product Search for visual search');
        const { productSearchService } = await import('./services/productSearchService');
        
        // Use the cropped image for Product Search
        const croppedBase64 = croppedDataUrl.replace(/^data:image\/\w+;base64,/, '');
        
        // Validate required configuration
        if (!businessAccount.googleProductSearchProjectId || !businessAccount.googleProductSearchLocation) {
          return res.status(400).json({ error: 'Google Product Search project ID or location not configured' });
        }
        
        // Product Search returns top 10 results sorted by relevance
        // Using configurable threshold from widget settings
        const PRODUCT_SEARCH_RELEVANCE_THRESHOLD = SOMEWHAT_SIMILAR_THRESHOLD;
        
        try {
          const psResults = await productSearchService.searchByImage(
            businessAccount.googleProductSearchProjectId,
            businessAccount.googleProductSearchLocation,
            businessAccount.googleProductSearchProductSetId!,
            croppedBase64,
            businessAccount.googleProductSearchCredentials!,
            10 // Top 10 results
          );
          
          // Filter client-side by relevance threshold (≥70%)
          const filteredPsResults = psResults.filter(r => r.score >= PRODUCT_SEARCH_RELEVANCE_THRESHOLD);
          
          console.log(`[Adjusted Boundary Search] Product Search returned ${psResults.length} total, ${filteredPsResults.length} above ${PRODUCT_SEARCH_RELEVANCE_THRESHOLD * 100}% threshold`);
          
          // Log individual scores for debugging
          psResults.forEach(r => {
            const passed = r.score >= PRODUCT_SEARCH_RELEVANCE_THRESHOLD;
            console.log(`[ProductSearch] ${r.productId}: ${(r.score * 100).toFixed(1)}% relevance ${passed ? '✓' : '✗'}`);
          });
          
          // Extract product IDs from filtered Product Search results
          const productSearchCandidateIds = filteredPsResults.map(r => r.productId);
          
          // PRODUCT SEARCH DIRECT MODE: Skip local CLIP filtering entirely
          if (productSearchCandidateIds.length > 0) {
            console.log(`[Adjusted Boundary Search] Product Search direct mode - fetching ${productSearchCandidateIds.length} products directly`);
            
            // Create a map of PS scores by product ID
            const psScoreMap = new Map(filteredPsResults.map(r => [r.productId, r.score]));
            
            // Fetch products directly from products table (no CLIP embedding requirement)
            const psProducts = await db
              .select({
                id: products.id,
                name: products.name,
                description: products.description,
                price: products.price,
                imageUrl: products.imageUrl,
                detectedJewelryType: products.detectedJewelryType,
              })
              .from(products)
              .where(inArray(products.id, productSearchCandidateIds));
            
            // Map to result format with PS scores
            const results = psProducts.map(p => {
              const psScore = psScoreMap.get(p.id) || 0.7;
              const matchLabel = psScore >= 0.95 ? 'Perfect Match' : psScore >= 0.85 ? 'Very Similar' : 'Somewhat Similar';
              return {
                id: p.id,
                name: p.name,
                description: p.description,
                price: p.price,
                imageUrl: p.imageUrl,
                similarity: psScore,
                matchScore: Math.round(psScore * 100),
                matchLabel,
                detectedJewelryType: p.detectedJewelryType || detectedType || 'jewelry',
              };
            });
            
            // Sort by PS score descending
            results.sort((a, b) => b.similarity - a.similarity);
            
            console.log(`[Adjusted Boundary Search] Product Search direct mode - returning ${results.length} products`);
            
            return res.json({
              products: results,
              matchCount: results.length,
              searchType: 'product_search_direct',
              message: `Found ${results.length} similar products via Product Search`
            });
          } else {
            // No results from Product Search
            console.log('[Adjusted Boundary Search] Product Search returned 0 results above threshold');
            const results = exactMatch ? [exactMatch] : [];
            return res.json({
              products: results,
              matchCount: results.length,
              searchType: 'product_search_only',
              message: results.length > 0 ? 'Found exact match' : 'No similar products found in Product Search'
            });
          }
        } catch (psError: any) {
          console.error('[Adjusted Boundary Search] Product Search failed:', psError);
          return res.status(500).json({ 
            error: 'Product Search failed', 
            details: psError.message 
          });
        }
      }
      
      // Build type filter condition for productJewelryEmbeddings.jewelryType
      let jewelryTypeFilterConditions;
      if (compatibleTypes.length > 0 && detectedType) {
        // Filter by compatible jewelry types in the embeddings table
        // Also include "others" type products - these may be misclassified but could still match visually
        jewelryTypeFilterConditions = sql`(LOWER(REPLACE(${productJewelryEmbeddings.jewelryType}, ' ', '-')) IN (${sql.join(compatibleTypes.map(t => sql`${t}`), sql`, `)}) OR LOWER(${productJewelryEmbeddings.jewelryType}) = 'others')`;
      } else {
        // No type detected - fall back to broad search
        console.log('[Adjusted Boundary Search] No type detected, using broad search');
        jewelryTypeFilterConditions = sql`1=1`;
      }
      
      // Build the query conditions
      const baseConditions = and(
        eq(productJewelryEmbeddings.businessAccountId, businessAccountId),
        sql`${productJewelryEmbeddings.embedding} IS NOT NULL`,
        jewelryTypeFilterConditions
      );
      
      // If Vision Warehouse is configured, use ONLY Vision Warehouse results (no CLIP fallback)
      // If VW returns 0 candidates, we return empty results instead of falling back to local search
      if (useVisionWarehouse && (!visionWarehouseCandidateIds || visionWarehouseCandidateIds.length === 0)) {
        console.log('[Adjusted Boundary Search] Vision Warehouse returned 0 results');
        
        // Return exact match if found, otherwise empty results
        const results = exactMatch ? [exactMatch] : [];
        return res.json({
          products: results,
          matchCount: results.length,
          searchType: 'vision_warehouse_only',
          message: results.length > 0 ? 'Found exact match' : 'No similar products found in Vision Warehouse'
        });
      }
      
      // If Vision Warehouse provided candidates, filter to those product IDs
      const queryConditions = visionWarehouseCandidateIds && visionWarehouseCandidateIds.length > 0
        ? and(baseConditions, inArray(products.id, visionWarehouseCandidateIds))
        : baseConditions;
      
      // Query productJewelryEmbeddings with JOIN to products (like Visual Match does)
      // This compares cropped jewelry embeddings, not full image embeddings
      // Uses pgvector distances for proper calibrated scoring
      let candidateProducts = await db
        .select({
          id: products.id,
          name: products.name,
          description: products.description,
          price: products.price,
          imageUrl: products.imageUrl,
          detectedJewelryType: productJewelryEmbeddings.jewelryType,
          distance: sql<number>`${productJewelryEmbeddings.embedding} <=> ${JSON.stringify(embeddingResult.embedding)}::vector`,
        })
        .from(productJewelryEmbeddings)
        .innerJoin(products, eq(productJewelryEmbeddings.productId, products.id))
        .where(queryConditions)
        .orderBy(sql`${productJewelryEmbeddings.embedding} <=> ${JSON.stringify(embeddingResult.embedding)}::vector`)
        .limit(30);
      
      if (visionWarehouseCandidateIds) {
        console.log(`[Adjusted Boundary Search] Vision Warehouse pre-filtered to ${visionWarehouseCandidateIds.length} candidates, found ${candidateProducts.length} with embeddings matching type filter`);
      } else {
        console.log(`[Adjusted Boundary Search] Found ${candidateProducts.length} candidates matching type filter (from cropped jewelry embeddings)`);
      }
      
      // NO BROAD FALLBACK: If no type matches found, only return exact match (if any)
      // This prevents showing unrelated jewelry types (e.g., rings when searching for earrings)
      if (candidateProducts.length === 0 && detectedType) {
        console.log(`[Adjusted Boundary Search] No type-filtered matches found for "${detectedType}" - returning exact match only (no broad fallback)`);
      }

      // Sigmoid-based scaling for jewelry matching
      // Better handles orientation/angle variations than linear scaling
      // Raw 66.5% → ~47% instead of 4.7% (linear was too aggressive)
      const scaleSimilarity = (distance: number): number => {
        let rawSimilarity = Math.max(0, 1 - distance);
        
        // Hard safety bounds for jewelry matching
        // Upper bound raised from 0.85 to 0.95 for better differentiation of high-similarity matches
        rawSimilarity = Math.max(0.55, Math.min(rawSimilarity, 0.95));
        
        // Sigmoid calibration (jewelry-tuned)
        const k = 28;      // steepness
        const x0 = 0.67;   // midpoint for "looks similar"
        
        const score = 1 / (1 + Math.exp(-k * (rawSimilarity - x0)));
        return score;
      };

      // Get product jewelry embeddings for hybrid scoring
      const productIds = candidateProducts.map(p => p.id);
      let productJewelryData: { productId: string; jewelryType: string | null; descriptionEmbedding: number[] | null; attributes: any }[] = [];
      
      if (productIds.length > 0) {
        productJewelryData = await db
          .select({ 
            productId: productJewelryEmbeddings.productId,
            jewelryType: productJewelryEmbeddings.jewelryType,
            descriptionEmbedding: productJewelryEmbeddings.descriptionEmbedding,
            attributes: productJewelryEmbeddings.attributes
          })
          .from(productJewelryEmbeddings)
          .where(inArray(productJewelryEmbeddings.productId, productIds));
      }

      const descEmbeddingMap = new Map<string, number[]>();
      const attributesMap = new Map<string, any>();
      const attributeTypeMap = new Map<string, string>(); // Track which type was used for each product
      
      // CRITICAL FIX: Prioritize matching jewelry type when building attributesMap
      // For products with multiple embeddings (e.g., necklace + earrings), we need the correct one
      // Use compatibleTypes which is already computed above for consistent type matching
      
      for (const pje of productJewelryData) {
        if (pje.descriptionEmbedding) descEmbeddingMap.set(pje.productId, pje.descriptionEmbedding);
        
        if (!pje.attributes) continue;
        
        // Check if this row's jewelry type is compatible with the query type
        const rawRowType = (pje.jewelryType || '').toLowerCase().replace(/\s+/g, '-');
        const normalizedRowType = normalizeJewelryType(rawRowType);
        
        // Row matches if its type (raw or normalized) is in the compatible types list
        const typeMatches = detectedType && compatibleTypes && (
          compatibleTypes.includes(rawRowType) || 
          compatibleTypes.includes(normalizedRowType)
        );
        
        const existingAttrs = attributesMap.get(pje.productId);
        const existingType = attributeTypeMap.get(pje.productId);
        const existingNormalized = existingType ? normalizeJewelryType(existingType) : '';
        const existingMatches = existingType && compatibleTypes && (
          compatibleTypes.includes(existingType) ||
          compatibleTypes.includes(existingNormalized)
        );
        
        // Set attributes if:
        // 1. We don't have attributes for this product yet, OR
        // 2. This row matches query type but existing doesn't
        if (!existingAttrs) {
          attributesMap.set(pje.productId, pje.attributes);
          attributeTypeMap.set(pje.productId, rawRowType);
        } else if (typeMatches && !existingMatches) {
          // Upgrade to the matching type
          attributesMap.set(pje.productId, pje.attributes);
          attributeTypeMap.set(pje.productId, rawRowType);
          console.log(`[Adjusted Boundary Search] Upgraded ${pje.productId} attributes from "${existingType}" to "${rawRowType}" (matches query type "${detectedType}")`);
        }
      }
      console.log(`[Adjusted Boundary Search] Stage 1 attribute map built for ${attributesMap.size} products (query type: "${detectedType}", compatible: [${compatibleTypes?.slice(0,3).join(', ')}...])`);



      const cosineSimilarity = (a: number[], b: number[]): number => {
        if (a.length !== b.length) return 0;
        let dotProduct = 0, normA = 0, normB = 0;
        for (let i = 0; i < a.length; i++) {
          dotProduct += a[i] * b[i];
          normA += a[i] * a[i];
          normB += b[i] * b[i];
        }
        return dotProduct / (Math.sqrt(normA) * Math.sqrt(normB));
      };

      // Using configurable thresholds from widget settings

      const productsWithScores = candidateProducts
        .map(p => {
          const scaledSimilarity = scaleSimilarity(p.distance);
          const clipScore = scaledSimilarity * 100;
          
          // IMPORTANT: Calculate raw CLIP similarity (before sigmoid) for disqualification checks
          // The sigmoid scaling inflates scores to 99%+, which would bypass all disqualification checks
          // Use the UNCLAMPED raw value for shouldDisqualify so the 95% bypass threshold is meaningful
          const rawClipSimilarity = Math.max(0, 1 - p.distance);
          
          // Description similarity kept for display only - no longer used as filter
          let descriptionSimilarity = 0;
          if (queryDescriptionEmbedding && descEmbeddingMap.has(p.id)) {
            descriptionSimilarity = cosineSimilarity(queryDescriptionEmbedding, descEmbeddingMap.get(p.id)!);
          }

          let attributeScore = 0;
          let hasAttributeMatch = false;
          let attributeMatchResult = null;
          const catalogAttrs = attributesMap.get(p.id);
          if (attributeResult.attributes && catalogAttrs) {
            attributeMatchResult = attributeMatchingService.calculateAttributeScore(
              attributeResult.attributes,
              catalogAttrs
            );
            attributeScore = attributeMatchResult.score;
            hasAttributeMatch = attributeScore >= ATTRIBUTE_THRESHOLD;
          }

          let disqualified = false;
          let disqualifyReason = '';
          
          // Check for jewelry type mismatch - hard disqualify incompatible types
          // Normalize product type to singular form for comparison
          const rawProductType = (p.detectedJewelryType || '').toLowerCase().replace(/\s+/g, '-');
          const productType = normalizeJewelryType(rawProductType);
          if (productType && detectedType && productType !== detectedType) {
            // Check if product type (or its raw plural form) is in compatible types
            // Also allow "others" type products - these may be misclassified but could still match visually
            const isCompatible = compatibleTypes.includes(productType) || compatibleTypes.includes(rawProductType) || rawProductType === 'others' || productType === 'others';
            if (!isCompatible) {
              disqualifyReason = `type mismatch (${rawProductType} vs ${detectedType})`;
              disqualified = true;
            }
          }
          
          // Use centralized shouldDisqualify for design complexity, dangle, style, motif, centerpiece, and silhouette mismatches
          // Also checks minimum design attribute match requirement when attributeMatchResult is provided
          // Pass RAW CLIP score (before sigmoid) to prevent inflated scores from bypassing disqualification
          if (!disqualified && attributeResult.attributes && catalogAttrs) {
            const disqualifyResult = attributeMatchingService.shouldDisqualify(
              attributeResult.attributes,
              catalogAttrs,
              attributeMatchResult || undefined,
              rawClipSimilarity,
              p.name
            );
            if (disqualifyResult.disqualify) {
              disqualified = true;
              disqualifyReason = disqualifyResult.reason || 'attribute mismatch';
            }
          }
          
          if (disqualified) {
            console.log(`[Adjusted Boundary Search] Disqualifying "${p.name}": ${disqualifyReason}`);
          }

          // Product must pass CLIP threshold AND Attribute threshold (description no longer used as filter)
          // - CLIP threshold is always required
          // - Attribute match is required when attribute data is available
          // Check that attributes actually have meaningful data (not empty objects)
          const queryHasAttributes = attributeResult.attributes && Object.keys(attributeResult.attributes).length > 0;
          const catalogHasAttributes = catalogAttrs && Object.keys(catalogAttrs).length > 0;
          const hasAttributeData = queryHasAttributes && catalogHasAttributes;
          
          // MATCHING: Use RAW similarity threshold (not sigmoid-scaled) AND attribute match required
          // Similarity threshold is strictly enforced as configured by the user
          let passesFilter = !disqualified && rawClipSimilarity >= SIMILARITY_THRESHOLD;
          if (passesFilter && hasAttributeData && !hasAttributeMatch) {
            passesFilter = false;
          }

          // Updated scoring weights - CLIP 70%, Attribute 30% (description removed from scoring)
          let combinedScore = clipScore * 0.70;
          if (attributeResult.attributes && catalogAttrs) {
            combinedScore += attributeScore * 100 * 0.30;
          } else {
            combinedScore += clipScore * 0.30;
          }

          // Log individual candidate scores
          const rawClipPct = (rawClipSimilarity * 100).toFixed(1);
          const clipPct = (clipScore).toFixed(1);
          const attrPct = (attributeScore * 100).toFixed(1);
          const status = passesFilter ? 'PASSED' : 'FILTERED';
          const reason = disqualified ? '(disqualified)' : 
                        (!passesFilter && rawClipSimilarity < SIMILARITY_THRESHOLD) ? `(similarity < ${(SIMILARITY_THRESHOLD * 100).toFixed(0)}%)` :
                        (!passesFilter && hasAttributeData && !hasAttributeMatch) ? `(attr < ${ATTRIBUTE_THRESHOLD * 100}%)` : '';
          console.log(`[Adjusted Boundary Search] Stage 1 ${status} "${p.name}": raw ${rawClipPct}%, scaled ${clipPct}%, attr ${attrPct}% ${reason}`);

          return {
            ...p,
            similarity: scaledSimilarity,
            clipScore,
            descriptionSimilarity,
            attributeScore,
            passesFilter,
            combinedScore
          };
        })
        .filter(p => p.passesFilter)
        .sort((a, b) => b.combinedScore - a.combinedScore);
      
      // CRITICAL: Deduplicate by product ID - same product may have multiple jewelry embeddings
      // Keep only the highest-scoring entry per product
      const seenProductIds = new Set<string>();
      const deduplicatedProducts = productsWithScores.filter(p => {
        if (seenProductIds.has(p.id)) {
          return false; // Skip duplicate
        }
        seenProductIds.add(p.id);
        return true;
      }).slice(0, 12);

      console.log(`[Adjusted Boundary Search] Found ${deduplicatedProducts.length} Stage 1 products (deduplicated from ${productsWithScores.length})`);

      // Use configurable thresholds for match quality labels
      const getMatchQuality = (similarity: number): string => {
        if (similarity >= VERY_SIMILAR_THRESHOLD) return 'very_similar';
        if (similarity >= SOMEWHAT_SIMILAR_THRESHOLD) return 'somewhat_similar';
        return 'related';
      };

      const getMatchQualityLabel = (quality: string): string => {
        switch (quality) {
          case 'perfect_match': return 'Perfect Match';
          case 'very_similar': return 'Very Similar';
          case 'somewhat_similar': return 'Somewhat Similar';
          default: return 'Related';
        }
      };

      // Remove exact match from Stage 1 results to avoid duplicates
      const exactMatchId = exactMatch?.id;
      const stage1Results = deduplicatedProducts
        .filter(p => p.id !== exactMatchId)
        .map(p => {
          const quality = getMatchQuality(p.similarity);
          return {
            id: p.id,
            name: p.name,
            description: p.description,
            price: p.price,
            imageUrl: p.imageUrl,
            category: p.detectedJewelryType || attributeResult.type || jewelryType,
            similarity: Math.round(p.similarity * 100),
            matchQuality: quality,
            matchQualityLabel: getMatchQualityLabel(quality),
            matchSource: 'stage1_similarity',
            combinedScore: Math.round(p.combinedScore),
            attributeScore: Math.round(p.attributeScore * 100),
            descriptionSimilarity: Math.round(p.descriptionSimilarity * 100)
          };
        })
        // Sort by match quality first (Very Similar before Somewhat Similar), then by combinedScore within each tier
        .sort((a, b) => {
          const qualityOrder: Record<string, number> = { 'very_similar': 0, 'somewhat_similar': 1, 'related': 2 };
          const qualityDiff = (qualityOrder[a.matchQuality] || 2) - (qualityOrder[b.matchQuality] || 2);
          if (qualityDiff !== 0) return qualityDiff;
          return b.combinedScore - a.combinedScore;
        });

      // Combine Stage 0 (exact match) + Stage 1 (similarity) results
      const results: any[] = [];
      
      if (exactMatch) {
        console.log(`[Adjusted Boundary Search] Including Stage 0 exact match: ${exactMatch.name}`);
        results.push({
          id: exactMatch.id,
          name: exactMatch.name,
          description: exactMatch.description,
          price: exactMatch.price,
          imageUrl: exactMatch.imageUrl,
          // Use product's actual stored category, fallback to query type only if not available
          category: exactMatch.detectedJewelryType || attributeResult.type || jewelryType,
          similarity: exactMatch.similarity,
          matchQuality: 'perfect_match',
          matchQualityLabel: 'Perfect Match',
          matchSource: 'stage0_exact',
          isExactMatch: true,
          pHashDistance: exactMatch.pHashDistance
        });
      }
      
      results.push(...stage1Results);
      
      console.log(`[Adjusted Boundary Search] Final results: ${exactMatch ? '1 exact + ' : ''}${stage1Results.length} similar = ${results.length} total`);

      // Save to history
      if (results.length > 0) {
        try {
          await storage.updateUploadedImageMatchedProducts(imgUrl, businessAccountId, results);
        } catch (saveError) {
          console.error('[Adjusted Boundary Search] Failed to save to history:', saveError);
        }
      }

      res.json({
        products: results,
        matchSource: visionWarehouseCandidateIds && visionWarehouseCandidateIds.length > 0 ? 'vision_warehouse' : 'adjusted_boundary',
        hasExactMatch: !!exactMatch,
        stage0Results: exactMatch ? 1 : 0,
        stage1Results: stage1Results.length,
        extractedInfo: {
          type: attributeResult.type || jewelryType,
          description: attributeResult.description || description,
          attributes: attributeResult.attributes
        }
      });

    } catch (error: any) {
      console.error('[Adjusted Boundary Search] Error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // Fast Visual Search - Direct image → Vision Warehouse → results (no GPT Vision, no cropping, no BG removal)
  app.post("/api/visual-search/fast", chatImageUpload.single('image'), async (req, res) => {
    try {
      const startTime = Date.now();
      const businessAccountId = req.body.businessAccountId;
      
      if (!businessAccountId) {
        return res.status(400).json({ error: "businessAccountId required" });
      }

      console.log(`[Fast Visual Search] Starting search for business ${businessAccountId}`);

      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      if (!businessAccount) {
        return res.status(400).json({ error: "Business account not found" });
      }

      // Check if Vision Warehouse is configured
      if (!businessAccount.googleVisionWarehouseEndpointId || 
          !businessAccount.googleVisionWarehouseCredentials ||
          !businessAccount.googleVisionWarehouseProjectNumber) {
        return res.status(400).json({ error: "Google Vision Warehouse not configured for this account" });
      }

      // Get image data - either from file upload or base64 in body
      let imageBase64: string;
      
      if (req.file) {
        imageBase64 = req.file.buffer.toString('base64');
      } else if (req.body.image) {
        // Handle base64 data URL or raw base64
        imageBase64 = req.body.image.replace(/^data:image\/\w+;base64,/, '');
      } else {
        return res.status(400).json({ error: "Image required (file upload or base64)" });
      }

      console.log(`[Fast Visual Search] Image received, sending to Vision Warehouse...`);

      // Fetch configurable threshold from widget settings
      const widgetSettings = await storage.getWidgetSettings(businessAccountId);
      const VISION_WAREHOUSE_RELEVANCE_THRESHOLD = (widgetSettings?.somewhatSimilarThreshold ? parseFloat(widgetSettings.somewhatSimilarThreshold) : 70) / 100;

      // Send directly to Vision Warehouse - it handles preprocessing internally
      const { visionWarehouseService } = await import('./services/visionWarehouseService');
      
      const vwResults = await visionWarehouseService.searchByImage(
        businessAccount.googleVisionWarehouseCredentials,
        businessAccount.googleVisionWarehouseEndpointId,
        imageBase64,
        10, // Top 10 results
        undefined,
        businessAccount.googleVisionWarehouseProjectNumber
      );

      // Filter by relevance threshold
      const filteredResults = vwResults.filter(r => r.score >= VISION_WAREHOUSE_RELEVANCE_THRESHOLD);
      
      console.log(`[Fast Visual Search] Vision Warehouse returned ${vwResults.length} total, ${filteredResults.length} above ${VISION_WAREHOUSE_RELEVANCE_THRESHOLD * 100}% threshold`);
      
      // Log scores
      vwResults.forEach(r => {
        const passed = r.score >= VISION_WAREHOUSE_RELEVANCE_THRESHOLD;
        console.log(`[Fast Visual Search] ${r.assetId}: ${(r.score * 100).toFixed(1)}% ${passed ? '✓' : '✗'}`);
      });

      if (filteredResults.length === 0) {
        const elapsed = Date.now() - startTime;
        console.log(`[Fast Visual Search] No matches above threshold (${elapsed}ms)`);
        return res.json({
          products: [],
          matchCount: 0,
          searchTime: elapsed,
          message: 'No similar products found'
        });
      }

      // Get product IDs from Vision Warehouse results
      const productIds = filteredResults.map(r => r.assetId.replace('p-', '')).filter(Boolean);
      
      if (productIds.length === 0) {
        const elapsed = Date.now() - startTime;
        console.log(`[Fast Visual Search] No valid product IDs found (${elapsed}ms)`);
        return res.json({
          products: [],
          matchCount: 0,
          searchTime: elapsed,
          message: 'No similar products found'
        });
      }
      
      // Fetch product details from database
      const matchedProducts = await db
        .select({
          id: products.id,
          name: products.name,
          description: products.description,
          price: products.price,
          imageUrl: products.imageUrl,
          detectedJewelryType: products.detectedJewelryType
        })
        .from(products)
        .where(and(
          eq(products.businessAccountId, businessAccountId),
          inArray(products.id, productIds)
        ));

      // Create a map for quick lookup and merge with VW scores
      const productMap = new Map(matchedProducts.map(p => [p.id, p]));
      
      // Build results with scores, maintaining VW order (highest relevance first)
      const results = filteredResults
        .map(vwResult => {
          const productId = vwResult.assetId.replace('p-', '');
          const product = productMap.get(productId);
          if (!product) return null;
          
          const similarity = Math.round(vwResult.score * 100);
          const matchQuality = similarity >= 85 ? 'very_similar' : 
                              similarity >= 70 ? 'somewhat_similar' : 'related';
          const matchQualityLabel = matchQuality === 'very_similar' ? 'Very Similar' :
                                   matchQuality === 'somewhat_similar' ? 'Somewhat Similar' : 'Related';
          
          return {
            id: product.id,
            name: product.name,
            description: product.description,
            price: product.price,
            imageUrl: product.imageUrl,
            category: product.detectedJewelryType || 'jewelry',
            similarity,
            matchQuality,
            matchQualityLabel,
            matchSource: 'vision_warehouse_fast'
          };
        })
        .filter(Boolean);

      const elapsed = Date.now() - startTime;
      console.log(`[Fast Visual Search] Returning ${results.length} products (${elapsed}ms)`);

      res.json({
        products: results,
        matchCount: results.length,
        searchTime: elapsed,
        matchSource: 'vision_warehouse_fast'
      });

    } catch (error: any) {
      console.error('[Fast Visual Search] Error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // Jewelry Image Generator (Vista Studio) - Generate product photography from jewelry images using DALL-E
  app.post("/api/jewelry-image-generator/generate", requireAuth, requireBusinessAccount, chatImageUpload.single('image'), async (req, res) => {
    try {
      const businessAccountId = req.user?.activeBusinessAccountId || req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      // Get OpenAI API key for DALL-E image generation
      const openaiApiKey = await storage.getBusinessAccountOpenAIKey(businessAccountId);
      if (!openaiApiKey) {
        return res.status(400).json({ error: "OpenAI API key is required for Vista Studio. Please configure it in your account settings." });
      }

      const { template, cropBox, customPrompt } = req.body;
      
      if (!template) {
        return res.status(400).json({ error: "Template is required" });
      }

      const validTemplates = ['matte-black-mannequin', 'ivory-mannequin', 'charcoal-grey', 'model-neck'];
      if (!validTemplates.includes(template)) {
        return res.status(400).json({ error: "Invalid template. Valid options: " + validTemplates.join(', ') });
      }

      let imageBuffer: Buffer;

      // Handle file upload or base64 data URL
      if (req.file) {
        imageBuffer = req.file.buffer;
      } else if (req.body.imageDataUrl) {
        const base64Data = req.body.imageDataUrl.replace(/^data:image\/\w+;base64,/, '');
        imageBuffer = Buffer.from(base64Data, 'base64');
      } else if (req.body.imageUrl) {
        // Fetch from URL
        const imgUrl = req.body.imageUrl;
        let fetchUrl = imgUrl;
        if (imgUrl.startsWith('/') && process.env.NODE_ENV === 'development') {
          const domain = process.env.APP_DOMAIN || process.env.REPLIT_DEV_DOMAIN || 'localhost:5000';
          const protocol = domain.includes('localhost') ? 'http' : 'https';
          fetchUrl = `${protocol}://${domain}${imgUrl}`;
        }
        const response = await fetch(fetchUrl);
        if (!response.ok) {
          return res.status(404).json({ error: 'Image file not found' });
        }
        imageBuffer = Buffer.from(await response.arrayBuffer());
      } else {
        return res.status(400).json({ error: "Image is required (file, imageDataUrl, or imageUrl)" });
      }

      // Parse cropBox if provided as string
      let parsedCropBox = cropBox;
      if (typeof cropBox === 'string') {
        try {
          parsedCropBox = JSON.parse(cropBox);
        } catch (e) {
          parsedCropBox = undefined;
        }
      }

      const { jewelryImageGeneratorService } = await import('./services/jewelryImageGeneratorService');
      
      const result = await jewelryImageGeneratorService.generateProductImage(
        imageBuffer,
        template,
        parsedCropBox,
        openaiApiKey,
        customPrompt
      );

      res.json({
        success: true,
        imageDataUrl: result.dataUrl,
        template
      });

    } catch (error: any) {
      console.error('[Vista Studio] DALL-E generation error:', error);
      res.status(500).json({ error: error.message || 'Failed to generate image' });
    }
  });

