  // Vista Studio - Create background generation job
  app.post("/api/jewelry-image-generator/jobs", requireAuth, requireBusinessAccount, chatImageUpload.single('image'), async (req, res) => {
    try {
      const businessAccountId = req.user?.activeBusinessAccountId || req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      // Get account to check provider configuration
      const account = await storage.getBusinessAccount(businessAccountId);
      if (!account) {
        return res.status(404).json({ error: "Business account not found" });
      }

      const provider = (account.vistaImageProvider as 'openai' | 'google') || 'openai';

      // Validate API key based on provider
      if (provider === 'google') {
        if (!account.googleNanoBananaApiKey) {
          return res.status(400).json({ error: "Google Nano Banana Pro API key is required. Please configure it in Settings → Vista Studio." });
        }
      } else {
        if (!account.openaiApiKey) {
          return res.status(400).json({ error: "OpenAI API key is required for Vista Studio. Please configure it in your account settings." });
        }
      }

      const { template, cropBox, customPrompt } = req.body;
      
      if (!template) {
        return res.status(400).json({ error: "Template is required" });
      }

      // Template format: category-style (e.g., "necklaces-matte-black-mannequin")
      const validCategories = ['necklaces', 'rings', 'bangles', 'bracelets', 'earrings'];
      const validStyles = ['matte-black-mannequin', 'ivory-mannequin', 'charcoal-grey', 'model-neck'];
      const templateParts = template.split('-');
      const category = templateParts[0];
      const style = templateParts.slice(1).join('-');
      
      if (!validCategories.includes(category) || !validStyles.includes(style)) {
        return res.status(400).json({ error: "Invalid template. Format: category-style" });
      }

      let imageBuffer: Buffer;

      if (req.file) {
        imageBuffer = req.file.buffer;
      } else if (req.body.imageDataUrl) {
        const base64Data = req.body.imageDataUrl.replace(/^data:image\/\w+;base64,/, '');
        imageBuffer = Buffer.from(base64Data, 'base64');
      } else if (req.body.imageUrl) {
        const imgUrl = req.body.imageUrl;
        let fetchUrl = imgUrl;
        if (imgUrl.startsWith('/') && process.env.NODE_ENV === 'development') {
          const domain = process.env.APP_DOMAIN || process.env.REPLIT_DEV_DOMAIN || 'localhost:5000';
          const protocol = domain.includes('localhost') ? 'http' : 'https';
          fetchUrl = `${protocol}://${domain}${imgUrl}`;
        }
        const response = await fetch(fetchUrl);
        if (!response.ok) {
          return res.status(404).json({ error: 'Image file not found' });
        }
        imageBuffer = Buffer.from(await response.arrayBuffer());
      } else {
        return res.status(400).json({ error: "Image is required" });
      }

      // Apply crop if provided
      let processedBuffer = imageBuffer;
      let parsedCropBox = cropBox;
      if (typeof cropBox === 'string') {
        try {
          parsedCropBox = JSON.parse(cropBox);
        } catch (e) {
          parsedCropBox = undefined;
        }
      }

      if (parsedCropBox) {
        const sharp = (await import('sharp')).default;
        const metadata = await sharp(imageBuffer).metadata();
        const imgWidth = metadata.width || 0;
        const imgHeight = metadata.height || 0;

        const pixelX = Math.round((parsedCropBox.x / 100) * imgWidth);
        const pixelY = Math.round((parsedCropBox.y / 100) * imgHeight);
        const pixelWidth = Math.round((parsedCropBox.width / 100) * imgWidth);
        const pixelHeight = Math.round((parsedCropBox.height / 100) * imgHeight);

        const clampedX = Math.max(0, Math.min(pixelX, imgWidth - 1));
        const clampedY = Math.max(0, Math.min(pixelY, imgHeight - 1));
        const clampedWidth = Math.max(1, Math.min(pixelWidth, imgWidth - clampedX));
        const clampedHeight = Math.max(1, Math.min(pixelHeight, imgHeight - clampedY));

        processedBuffer = await sharp(imageBuffer)
          .extract({ left: clampedX, top: clampedY, width: clampedWidth, height: clampedHeight })
          .png()
          .toBuffer();
      }

      const { jewelryImageGeneratorService } = await import('./services/jewelryImageGeneratorService');
      
      // Get the prompt to use - template format is category-style (e.g., "necklaces-matte-black-mannequin")
      let prompt = '';
      if (customPrompt && customPrompt.trim().length > 0) {
        prompt = customPrompt.slice(0, 1000);
      } else {
        // Generate default prompt from category and style
        const defaultPrompt = jewelryImageGeneratorService.getTemplatePrompt(
          category as 'necklaces' | 'rings' | 'bangles' | 'earrings',
          style as 'matte-black-mannequin' | 'ivory-mannequin' | 'charcoal-grey' | 'model-neck'
        );
        prompt = defaultPrompt;
      }

      // Create job and start background processing
      const jobId = await jewelryImageGeneratorService.createJob(
        businessAccountId,
        template,
        prompt,
        processedBuffer,
        provider
      );

      // Start processing in background (don't await)
      jewelryImageGeneratorService.processJob(jobId).catch(err => {
        console.error('[Vista Studio] Background job error:', err);
      });

      res.json({
        success: true,
        jobId,
        status: 'pending'
      });

    } catch (error: any) {
      console.error('[Vista Studio] Job creation error:', error);
      res.status(500).json({ error: error.message || 'Failed to create job' });
    }
  });

