  // Vista Studio - Retry failed job
  app.post("/api/jewelry-image-generator/jobs/:jobId/retry", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.activeBusinessAccountId || req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      const { jobId } = req.params;
      const { jewelryImageGeneratorService } = await import('./services/jewelryImageGeneratorService');
      
      // Get the original job
      const originalJob = await jewelryImageGeneratorService.getJob(jobId, businessAccountId);
      if (!originalJob) {
        return res.status(404).json({ error: "Job not found" });
      }

      if (originalJob.status !== 'failed') {
        return res.status(400).json({ error: "Only failed jobs can be retried" });
      }

      // Use the original job's provider for consistency
      const provider = (originalJob.provider as 'openai' | 'google') || 'openai';

      // Get account to validate API key
      const account = await storage.getBusinessAccount(businessAccountId);
      if (!account) {
        return res.status(404).json({ error: "Business account not found" });
      }

      // Validate API key based on the original job's provider
      if (provider === 'google') {
        if (!account.googleNanoBananaApiKey) {
          return res.status(400).json({ error: "Google Nano Banana Pro API key is required. Please configure it in Settings → Vista Studio." });
        }
      } else {
        if (!account.openaiApiKey) {
          return res.status(400).json({ error: "OpenAI API key is required for Vista Studio. Please configure it in your account settings." });
        }
      }

      // Create a new job with the same settings and provider
      const newJob = await jewelryImageGeneratorService.createJobFromUrl(
        businessAccountId,
        originalJob.templateId,
        originalJob.prompt,
        originalJob.originalImageUrl,
        provider
      );

      // Process the job in the background
      jewelryImageGeneratorService.processJob(newJob.id).catch(err => {
        console.error('[Vista Studio] Background job processing failed:', err);
      });

      res.json({ success: true, jobId: newJob.id });
    } catch (error: any) {
      console.error('[Vista Studio] Error retrying job:', error);
      res.status(500).json({ error: error.message });
    }
  });

