  // Get discount analytics
  app.get("/api/discount-analytics", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user!.businessAccountId!;
      const { startDate, endDate } = req.query;
      
      // Parse date range (default to last 30 days)
      const end = endDate ? new Date(endDate as string) : new Date();
      const start = startDate ? new Date(startDate as string) : new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
      
      // Get all discount offers in date range
      const offers = await storage.getDiscountOffersByDateRange(businessAccountId, start, end);
      
      // Calculate aggregate metrics
      const totalOffers = offers.length;
      const redeemedOffers = offers.filter(o => o.redeemed).length;
      const redemptionRate = totalOffers > 0 ? (redeemedOffers / totalOffers) * 100 : 0;
      const totalRevenue = offers.reduce((sum, o) => sum + parseFloat(o.revenueImpact || '0'), 0);
      
      // Group by product
      const byProduct = offers.reduce((acc, offer) => {
        const productId = offer.productId || 'site-wide';
        if (!acc[productId]) {
          acc[productId] = {
            productId,
            productName: offer.productName || 'Site-Wide',
            totalOffers: 0,
            redeemed: 0,
            revenue: 0,
          };
        }
        acc[productId].totalOffers++;
        if (offer.redeemed) acc[productId].redeemed++;
        acc[productId].revenue += parseFloat(offer.revenueImpact || '0');
        return acc;
      }, {} as Record<string, any>);
      
      // Group by date for time series
      const byDate = offers.reduce((acc, offer) => {
        const date = new Date(offer.offeredAt).toISOString().split('T')[0];
        if (!acc[date]) {
          acc[date] = { date, offers: 0, redeemed: 0, revenue: 0 };
        }
        acc[date].offers++;
        if (offer.redeemed) acc[date].redeemed++;
        acc[date].revenue += parseFloat(offer.revenueImpact || '0');
        return acc;
      }, {} as Record<string, any>);
      
      res.json({
        summary: {
          totalOffers,
          redeemedOffers,
          redemptionRate: Math.round(redemptionRate * 10) / 10,
          totalRevenue: Math.round(totalRevenue * 100) / 100,
          avgOrderValue: redeemedOffers > 0 ? Math.round((totalRevenue / redeemedOffers) * 100) / 100 : 0,
        },
        byProduct: Object.values(byProduct),
        timeSeries: Object.values(byDate).sort((a: any, b: any) => a.date.localeCompare(b.date)),
      });
    } catch (error: any) {
      console.error('[Discount Analytics] Error fetching analytics:', error);
      res.status(500).json({ error: "Failed to fetch discount analytics" });
    }
  });

