  app.get("/api/urgency-offer/active", async (req, res) => {
    try {
      const businessAccountId = req.query.businessAccountId as string;
      const visitorToken = req.query.visitorToken as string || req.query.sessionId as string;
      
      if (!businessAccountId || !visitorToken) {
        return res.status(400).json({ error: "businessAccountId and visitorToken/sessionId are required" });
      }
      
      const { getOfferByVisitorToken, getCampaignById } = await import("./services/urgencyOfferService");
      
      const offer = await getOfferByVisitorToken(businessAccountId, visitorToken);
      
      if (!offer || offer.status === 'redeemed' || offer.status === 'dismissed' || offer.status === 'expired') {
        return res.json({ hasActiveOffer: false });
      }
      
      if (!offer.countdownExpiresAt || offer.countdownExpiresAt.getTime() < Date.now() || offer.status !== 'active') {
        return res.json({ hasActiveOffer: false });
      }
      
      const campaign = offer.campaignId ? await getCampaignById(offer.campaignId) : null;
      
      res.json({
        hasActiveOffer: true,
        offerId: offer.id,
        campaignId: offer.campaignId,
        startedAt: offer.countdownStartedAt?.toISOString(),
        expiresAt: offer.countdownExpiresAt?.toISOString(),
        status: offer.status,
        settings: campaign ? {
          countdownDurationMinutes: campaign.countdownDurationMinutes,
          discountType: campaign.discountType,
          discountValue: campaign.discountValue,
          headline: campaign.headline,
          description: campaign.description,
          ctaButtonText: campaign.ctaButtonText,
          dismissButtonText: campaign.dismissButtonText,
          successMessage: campaign.successMessage,
          phoneInputLabel: campaign.phoneInputLabel,
          phoneInputPlaceholder: campaign.phoneInputPlaceholder,
          requirePhone: campaign.requirePhone
        } : null
      });
    } catch (error: any) {
      console.error('[Urgency Offer] Error fetching active offer:', error);
      res.status(500).json({ error: "Failed to fetch active offer" });
    }
  });

