  app.post("/api/urgency-offer/redeem", async (req, res) => {
    try {
      const { offerId, phoneNumber, phoneCountryCode, pageUrl: offerPageUrl, conversationId } = req.body;
      
      if (!offerId || !phoneNumber) {
        return res.status(400).json({ error: "offerId and phoneNumber are required" });
      }

      const phoneValidation = validatePhoneNumber(phoneNumber, '10');
      if (!phoneValidation.isValid) {
        return res.status(400).json({ error: phoneValidation.reasonMessage });
      }

      let visitorCity: string | null = null;
      try {
        const clientIp = (req.headers['x-forwarded-for'] as string)?.split(',')[0].trim() || 
                        req.socket.remoteAddress || 
                        'unknown';
        if (clientIp && clientIp !== 'unknown' && !clientIp.startsWith('127.') && !clientIp.startsWith('192.168.') && !clientIp.startsWith('10.') && !clientIp.startsWith('::1')) {
          const geoResponse = await fetch(`http://ip-api.com/json/${clientIp}?fields=status,city`);
          if (geoResponse.ok) {
            const geoData = await geoResponse.json();
            if (geoData.status === 'success' && geoData.city) {
              visitorCity = geoData.city;
              console.log(`[Urgency Offer Redeem] Geo-located visitor: ${visitorCity}`);
            }
          }
        }
      } catch (error) {
        console.warn('[Urgency Offer Redeem] Geolocation failed:', error);
      }
      
      const { redeemUrgencyOffer } = await import("./services/urgencyOfferService");
      
      const offer = await redeemUrgencyOffer(offerId, phoneNumber, phoneCountryCode, visitorCity, offerPageUrl || null, conversationId || null);
      
      res.json({
        success: true,
        discountCode: offer.discountCode,
        discountType: offer.discountType,
        discountValue: offer.discountValue
      });
    } catch (error: any) {
      console.error('[Urgency Offer] Error redeeming offer:', error);
      res.status(400).json({ error: error.message || "Failed to redeem offer" });
    }
  });

