  // Cache prewarm endpoint (public, for widget)
  // Simple in-memory throttling to prevent abuse
  const prewarmThrottle = new Map<string, number>();
  const PREWARM_THROTTLE_MS = 30000; // Only allow prewarm once per 30 seconds per IP+businessAccountId

  app.post("/api/chat/prewarm", async (req, res) => {
    try {
      const { businessAccountId } = req.body;
      
      if (!businessAccountId || typeof businessAccountId !== 'string') {
        return res.status(400).json({ error: "businessAccountId is required" });
      }
      
      // Check throttle
      const clientIp = req.ip || req.socket.remoteAddress || 'unknown';
      const throttleKey = `${clientIp}_${businessAccountId}`;
      const lastPrewarm = prewarmThrottle.get(throttleKey);
      const now = Date.now();
      
      if (lastPrewarm && (now - lastPrewarm) < PREWARM_THROTTLE_MS) {
        // Silently succeed - don't expose throttling to client
        return res.json({ success: true, cached: true });
      }
      
      // Validate business account exists and is not suspended
      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      if (!businessAccount) {
        return res.status(404).json({ error: "Business account not found" });
      }
      
      if (businessAccount.accountStatus === 'suspended') {
        return res.status(403).json({ error: "Business account is suspended" });
      }
      
      // Update throttle
      prewarmThrottle.set(throttleKey, now);
      
      // Return immediately - spawn background task asynchronously
      res.json({ success: true });
      
      // Fire-and-forget cache warming in background (after response sent)
      // This runs completely asynchronously without blocking the HTTP response
      (async () => {
        try {
          const widgetSettings = await storage.getWidgetSettings(businessAccountId);
          const personality = widgetSettings?.personality || 'friendly';
          const responseLength = widgetSettings?.responseLength || 'balanced';
          const currency = widgetSettings?.currency || 'INR';
          const customInstructions = widgetSettings?.customInstructions || '';
          
          const currencySymbols: Record<string, string> = {
            'INR': '₹', 'USD': '$', 'AED': 'د.إ', 'EUR': '€', 'GBP': '£',
            'AUD': 'A$', 'CAD': 'C$', 'CHF': 'CHF', 'CNY': '¥', 'JPY': '¥',
            'KRW': '₩', 'SGD': 'S$', 'HKD': 'HK$', 'NZD': 'NZ$', 'SEK': 'kr',
            'NOK': 'kr', 'DKK': 'kr', 'PLN': 'zł', 'BRL': 'R$', 'MXN': '$',
            'ZAR': 'R', 'TRY': '₺', 'RUB': '₽'
          };
          const currencySymbol = currencySymbols[currency] || '$';
          
          const companyDescription = businessAccount.description || '';
          const openaiApiKey = await storage.getBusinessAccountOpenAIKey(businessAccountId);
          
          await chatService.prewarmCache({
            userId: 'prewarm', // Placeholder user ID for prewarm
            businessAccountId,
            personality,
            responseLength,
            companyDescription,
            openaiApiKey,
            currency,
            currencySymbol,
            customInstructions
          });
        } catch (bgError) {
          console.error('[Prewarm] Background cache warming error:', bgError);
        }
      })();
    } catch (error: any) {
      console.error('[Prewarm] Error:', error);
      // Don't expose errors - silently succeed
      res.json({ success: true });
    }
  });

