  // Refine instruction with AI
  app.post("/api/ai/refine-instruction", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const { instruction } = req.body;
      const businessAccountId = req.user?.businessAccountId;

      if (!instruction || typeof instruction !== 'string') {
        return res.status(400).json({ error: "Instruction text is required" });
      }

      if (!businessAccountId) {
        return res.status(403).json({ error: "Business account required" });
      }

      // Get OpenAI API key for this business
      const openaiApiKey = await storage.getBusinessAccountOpenAIKey(businessAccountId);
      if (!openaiApiKey) {
        return res.status(400).json({ error: "OpenAI API key not configured" });
      }

      // Use OpenAI to refine the instruction
      const openai = new OpenAI({ apiKey: openaiApiKey });
      const response = await openai.chat.completions.create({
        model: 'gpt-4o-mini',
        messages: [
          {
            role: 'system',
            content: `You are an AI instruction optimizer for a customer-facing chatbot. Your job is to transform user-written instructions into structured, AI-readable rules that the chatbot can easily understand and apply during conversations.

Your refined instructions should:

1. **TRIGGER CLARITY**: Clearly define when this instruction applies
   - Use explicit trigger phrases: "When the user asks about...", "If the user mentions...", "When someone inquires about..."
   - Include common variations of how users might phrase the query

2. **INTENT MAPPING**: Make the user's intent unmistakable
   - Explicitly state what user intent this instruction handles
   - Include keyword variations (e.g., "EMI payment", "pay EMI", "EMI dues", "monthly installment")

3. **ACTION SPECIFICITY**: Define exactly what the chatbot should do
   - Use clear action verbs: "Respond with...", "Guide them to...", "Provide the following steps..."
   - Include specific URLs, names, or values if mentioned in the original

4. **CONTEXT PRESERVATION**: Keep all business-specific details
   - Preserve exact URLs, contact info, product names, procedures
   - Maintain the same language register (formal/informal) as the original

5. **STRUCTURE FOR AI**: Format for easy AI parsing
   - Start with the trigger condition
   - Follow with the action/response
   - End with any constraints or exceptions

Example transformation:
Original: "if someone wants to pay emi tell them to go to website"
Refined: "When a user asks about paying EMI, making EMI payments, or settling monthly installments, direct them to visit the website at [URL]. Provide step-by-step guidance: 1) Visit the website, 2) Click 'Sign In', 3) Enter registered email, 4) Navigate to payment section."

RULES:
- Keep the output in English
- Don't add information not in the original
- Preserve all URLs, names, and specific details exactly
- Keep it concise but comprehensive (2-4 sentences)
- Use imperative voice for actions

Return ONLY the refined instruction, nothing else.`
          },
          {
            role: 'user',
            content: `Transform this chatbot instruction into an AI-optimized format:\n\n${instruction}`
          }
        ],
        temperature: 0.3,
        max_tokens: 400
      });

      const refinedInstruction = response.choices[0].message.content?.trim() || instruction;

      res.json({
        success: true,
        original: instruction,
        refined: refinedInstruction
      });
    } catch (error: any) {
      console.error('[AI Refine] Error:', error);
      res.status(500).json({
        success: false,
        error: error.message || "Failed to refine instruction"
      });
    }
  });

