  // Chat intro message endpoint
  app.get("/api/chat/intro", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      // Check for startFromScratch journey first - if enabled, use first step as greeting
      const journeys = await storage.getAllJourneys(businessAccountId);
      const startFromScratchJourney = journeys.find(j => 
        j.status === 'active' && j.startFromScratch === 'true'
      );
      
      if (startFromScratchJourney) {
        const steps = await storage.getJourneySteps(startFromScratchJourney.id);
        if (steps.length > 0) {
          // Sort by stepOrder and get first step
          const sortedSteps = steps.sort((a, b) => Number(a.stepOrder) - Number(b.stepOrder));
          const firstStep = sortedSteps[0];
          console.log(`[Intro API] Using journey first step as greeting: ${firstStep.questionText.substring(0, 50)}...`);
          
          const response: any = { 
            intro: firstStep.questionText,
            journeyId: startFromScratchJourney.id,
            startFromScratch: true
          };
          
          // For form journeys, include form step data for visual UI
          if (startFromScratchJourney.journeyType === 'form') {
            let options: string[] | undefined;
            if ((firstStep.questionType === 'radio' || firstStep.questionType === 'dropdown') && firstStep.multipleChoiceOptions) {
              try {
                options = JSON.parse(firstStep.multipleChoiceOptions);
              } catch (e) {
                console.error('[Intro API] Failed to parse choice options:', e);
              }
            }
            
            response.formStep = {
              stepId: firstStep.id,
              questionText: firstStep.questionText,
              questionType: firstStep.questionType || 'text',
              isRequired: firstStep.isRequired === 'true',
              options,
              placeholder: firstStep.placeholderText || undefined,
              stepType: firstStep.toolTrigger || undefined,
            };
            console.log(`[Intro API] Form journey - including form step data for visual UI`);
          }
          
          return res.json(response);
        }
      }

      // Get widget settings from cache to check welcome message type
      const cacheKey = BusinessContextCache.KEYS.WIDGET_SETTINGS(businessAccountId);
      let settings = await businessContextCache.getOrFetch(cacheKey, async () => {
        let s = await storage.getWidgetSettings(businessAccountId);
        if (!s) {
          s = await storage.upsertWidgetSettings(businessAccountId, {});
        }
        return s;
      });

      // If custom message type, return the custom welcome message
      if (settings.welcomeMessageType === "custom") {
        console.log(`[Intro API] Using custom welcome message`);
        return res.json({ intro: settings.welcomeMessage });
      }

      // Use rotating intro messages for better performance (Phase 1 optimization)
      const intro = getRandomIntroMessage();
      console.log(`[Intro API] Using rotating intro message: ${intro.substring(0, 50)}...`);
      res.json({ intro });
    } catch (error: any) {
      res.status(500).json({ error: error.message });
    }
  });

