  // SuperAdmin: Create business account (with user)
  app.post("/api/business-accounts", requireAuth, requireRole("super_admin"), async (req, res) => {
    try {
      const { name, website, username, productTier, chroneyEnabled, whatsappEnabled, instagramEnabled, facebookEnabled } = req.body;
      if (!name) {
        return res.status(400).json({ error: "Business name required" });
      }
      if (!website) {
        return res.status(400).json({ error: "Website URL required" });
      }
      if (!username) {
        return res.status(400).json({ error: "Username required" });
      }
      
      // Basic URL validation
      try {
        new URL(website);
      } catch {
        return res.status(400).json({ error: "Invalid website URL format" });
      }
      
      // Validate email format for username
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!emailRegex.test(username)) {
        return res.status(400).json({ error: "Username must be a valid email address" });
      }
      
      // Validate product tier
      const validTiers = ['chroney', 'jewelry_showcase', 'jewelry_showcase_chroney'];
      const tier = productTier && validTiers.includes(productTier) ? productTier : 'chroney';
      
      // Create business account with feature flags
      const businessAccount = await storage.createBusinessAccount({ 
        name, 
        website, 
        status: "active", 
        productTier: tier,
        chroneyEnabled: chroneyEnabled === true ? "true" : chroneyEnabled === false ? "false" : "true",
        whatsappEnabled: whatsappEnabled === true ? "true" : "false",
        instagramEnabled: instagramEnabled === true ? "true" : "false",
        facebookEnabled: facebookEnabled === true ? "true" : "false",
      });
      
      // Generate secure random password (12 characters: uppercase, lowercase, numbers, symbols)
      const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz23456789!@#$%^&*';
      const password = Array.from({ length: 12 }, () => chars[Math.floor(Math.random() * chars.length)]).join('');
      
      // Create associated user
      const passwordHash = await hashPassword(password);
      const tempPasswordExpiry = new Date();
      tempPasswordExpiry.setDate(tempPasswordExpiry.getDate() + 30);
      
      const user = await storage.createUserWithTempPassword({
        username,
        passwordHash,
        tempPassword: password,
        tempPasswordExpiry,
        mustChangePassword: "true",
        role: "business_user",
        businessAccountId: businessAccount.id,
      });
      
      res.json({
        businessAccount,
        user,
        credentials: {
          username: user.username,
          tempPassword: password,
        }
      });
    } catch (error: any) {
      res.status(500).json({ error: error.message });
    }
  });

  // SuperAdmin: Get all business accounts (with optional pagination)
  app.get("/api/business-accounts", requireAuth, requireRole("super_admin"), async (req, res) => {
    try {
      const limit = req.query.limit ? parseInt(req.query.limit as string, 10) : undefined;
      const offset = req.query.offset ? parseInt(req.query.offset as string, 10) : undefined;
      
      const [accounts, total] = await Promise.all([
        storage.getAllBusinessAccounts(limit, offset),
        storage.getBusinessAccountsCount()
      ]);
      
      // Get live status for all accounts in this batch
      const accountIds = accounts.map(a => a.id);
      const liveStatusMap = await storage.getBusinessAccountsWithPageviewStatus(accountIds);
      
      const { toBusinessAccountDto } = await import("@shared/dto/businessAccount");
      const dtos = accounts.map(account => ({
        ...toBusinessAccountDto(account),
        isLive: liveStatusMap.get(account.id) ?? false
      }));
      
      // Return paginated response with total count
      // hasMore is true if there are more items after this batch
      const currentOffset = offset ?? 0;
      const hasMore = (currentOffset + accounts.length) < total;
      
      res.json({
        accounts: dtos,
        total,
        hasMore
      });
    } catch (error: any) {
      res.status(500).json({ error: error.message });
    }
  });

