  // SuperAdmin: Duplicate business account with data
  app.post("/api/business-accounts/:id/duplicate", requireAuth, requireRole("super_admin"), async (req, res) => {
    try {
      const sourceBusinessId = req.params.id;
      const { name, website, adminName, adminEmail, adminPassword, options } = req.body;

      if (!name || !adminEmail || !adminPassword) {
        return res.status(400).json({ error: "Name, admin email, and password are required" });
      }

      // Check if email already exists
      const existingUser = await db.select().from(users).where(eq(users.username, adminEmail.toLowerCase())).limit(1);
      if (existingUser.length > 0) {
        return res.status(400).json({ error: "An account with this email already exists" });
      }

      // Get source business account
      const sourceAccount = await storage.getBusinessAccount(sourceBusinessId);
      if (!sourceAccount) {
        return res.status(404).json({ error: "Source business account not found" });
      }

      // Create new business account with source settings
      const newBusinessId = randomUUID();
      const [newBusiness] = await db.insert(businessAccounts).values({
        id: newBusinessId,
        name: name.trim(),
        website: website?.trim() || '',
        status: 'active',
        productTier: sourceAccount.productTier,
        shopifyEnabled: sourceAccount.shopifyEnabled === 'true' ? 'true' : 'false',
        appointmentsEnabled: sourceAccount.appointmentsEnabled === 'true' ? 'true' : 'false',
        voiceModeEnabled: sourceAccount.voiceModeEnabled === 'true' ? 'true' : 'false',
        visualSearchEnabled: sourceAccount.visualSearchEnabled === 'true' ? 'true' : 'false',
        jewelryShowcaseEnabled: sourceAccount.jewelryShowcaseEnabled === 'true' ? 'true' : 'false',
        supportTicketsEnabled: sourceAccount.supportTicketsEnabled === 'true' ? 'true' : 'false',
        k12EducationEnabled: sourceAccount.k12EducationEnabled === 'true' ? 'true' : 'false',
        jobPortalEnabled: sourceAccount.jobPortalEnabled === 'true' ? 'true' : 'false',
        systemMode: sourceAccount.systemMode || 'full',
        vistaImageProvider: sourceAccount.vistaImageProvider || 'openai',
      }).returning();

      // Create admin user
      const hashedPwd = await bcrypt.hash(adminPassword, 10);
      const newUserId = randomUUID();
      const tempPasswordExpiry = new Date();
      tempPasswordExpiry.setDate(tempPasswordExpiry.getDate() + 30);
      await db.insert(users).values({
        id: newUserId,
        username: adminEmail.toLowerCase().trim(),
        passwordHash: hashedPwd,
        role: 'business_user',
        businessAccountId: newBusinessId,
        tempPassword: adminPassword,
        tempPasswordExpiry: tempPasswordExpiry,
      });

      // Copy widget settings if requested
      if (options?.copyWidgetSettings) {
        const sourceWidgetSettings = await db.select().from(widgetSettings).where(eq(widgetSettings.businessAccountId, sourceBusinessId)).limit(1);
        if (sourceWidgetSettings.length > 0) {
          const { id, businessAccountId, ...settingsData } = sourceWidgetSettings[0];
          await db.insert(widgetSettings).values({
            ...settingsData,
            id: randomUUID(),
            businessAccountId: newBusinessId,
          });
        }
      }

      // Copy categories first (needed for product references)
      let categoryIdMap: Record<string, string> = {};
      let productIdMap: Record<string, string> = {};
      if (options?.copyProducts) {
        const sourceCategories = await db.select().from(categories).where(eq(categories.businessAccountId, sourceBusinessId));
        for (const cat of sourceCategories) {
          const newCategoryId = randomUUID();
          categoryIdMap[cat.id] = newCategoryId;
          await db.insert(categories).values({
            ...cat,
            id: newCategoryId,
            businessAccountId: newBusinessId,
          });
        }

        // Copy products (including embeddings for visual search)
        const sourceProducts = await db.select().from(products).where(eq(products.businessAccountId, sourceBusinessId));
        for (const product of sourceProducts) {
          const newProductId = randomUUID();
          productIdMap[product.id] = newProductId;
          const { id, businessAccountId, ...productData } = product;
          await db.insert(products).values({
            ...productData,
            id: newProductId,
            businessAccountId: newBusinessId,
          });

          // Copy product-category relationships
          const sourceProductCategories = await db.select().from(productCategoriesTable).where(eq(productCategoriesTable.productId, id));
          for (const pc of sourceProductCategories) {
            const newCategoryId = categoryIdMap[pc.categoryId];
            if (newCategoryId) {
              await db.insert(productCategoriesTable).values({
                productId: newProductId,
                categoryId: newCategoryId,
              });
            }
          }
        }

        // Copy product jewelry embeddings (cropped images, CLIP embeddings, attributes for visual search)
        const sourceEmbeddings = await db.select().from(productJewelryEmbeddings).where(eq(productJewelryEmbeddings.businessAccountId, sourceBusinessId));
        let embeddingsCopied = 0;
        for (const embedding of sourceEmbeddings) {
          const newProductId = productIdMap[embedding.productId];
          if (newProductId) {
            const { id, productId, businessAccountId, ...embeddingData } = embedding;
            await db.insert(productJewelryEmbeddings).values({
              ...embeddingData,
              id: randomUUID(),
              productId: newProductId,
              businessAccountId: newBusinessId,
            });
            embeddingsCopied++;
          }
        }
        if (embeddingsCopied > 0) {
          console.log(`[Duplicate Account] Copied ${embeddingsCopied} jewelry embeddings for visual search`);
        }
      }

      // Copy FAQs if requested
      if (options?.copyFaqs) {
        const sourceFaqs = await db.select().from(faqs).where(eq(faqs.businessAccountId, sourceBusinessId));
        for (const faq of sourceFaqs) {
          const { id, businessAccountId, ...faqData } = faq;
          await db.insert(faqs).values({
            ...faqData,
            id: randomUUID(),
            businessAccountId: newBusinessId,
          });
        }
      }

      // Copy training documents if requested
      if (options?.copyTrainingDocuments) {
        const sourceDocuments = await db.select().from(trainingDocuments).where(eq(trainingDocuments.businessAccountId, sourceBusinessId));
        for (const doc of sourceDocuments) {
          const { id, businessAccountId, ...docData } = doc;
          await db.insert(trainingDocuments).values({
            ...docData,
            id: randomUUID(),
            businessAccountId: newBusinessId,
          });
        }
      }

      // Copy conversation journeys if requested
      if (options?.copyConversationJourneys) {
        const sourceJourneys = await db.select().from(conversationJourneys).where(eq(conversationJourneys.businessAccountId, sourceBusinessId));
        for (const journey of sourceJourneys) {
          const oldJourneyId = journey.id;
          const newJourneyId = randomUUID();
          const { id, businessAccountId, ...journeyData } = journey;
          await db.insert(conversationJourneys).values({
            ...journeyData,
            id: newJourneyId,
            businessAccountId: newBusinessId,
          });

          // Also copy journey steps for this journey
          const sourceSteps = await db.select().from(journeySteps).where(eq(journeySteps.journeyId, oldJourneyId));
          for (const step of sourceSteps) {
            const { id: stepId, journeyId, ...stepData } = step;
            await db.insert(journeySteps).values({
              ...stepData,
              id: randomUUID(),
              journeyId: newJourneyId,
            });
          }
        }
      }

      // Copy schedule templates if requested
      if (options?.copyScheduleTemplates) {
        const sourceTemplates = await db.select().from(scheduleTemplates).where(eq(scheduleTemplates.businessAccountId, sourceBusinessId));
        for (const template of sourceTemplates) {
          const { id, businessAccountId, ...templateData } = template;
          await db.insert(scheduleTemplates).values({
            ...templateData,
            id: randomUUID(),
            businessAccountId: newBusinessId,
          });
        }
      }

      console.log(`[SuperAdmin] Duplicated business account ${sourceBusinessId} -> ${newBusinessId}`);

      const { toBusinessAccountDto } = await import("@shared/dto/businessAccount");
      res.json({
        businessAccount: toBusinessAccountDto(newBusiness),
        credentials: {
          username: adminEmail.toLowerCase().trim(),
          tempPassword: adminPassword,
        },
      });
    } catch (error: any) {
      console.error('[SuperAdmin] Error duplicating business account:', error);
      res.status(500).json({ error: error.message || "Failed to duplicate account" });
    }
  });

  // SuperAdmin: Update API settings (OpenAI API key and currency) for a business account
  app.patch("/api/business-accounts/:id/api-settings", requireAuth, requireRole("super_admin"), async (req, res) => {
    try {
      const { id } = req.params;
      const { openaiApiKey, elevenlabsApiKey, currency } = req.body;
      
      // Verify business account exists
      const businessAccount = await storage.getBusinessAccount(id);
      if (!businessAccount) {
        return res.status(404).json({ error: "Business account not found" });
      }
      
      // Update OpenAI API key if provided
      if (openaiApiKey !== undefined) {
        if (openaiApiKey && typeof openaiApiKey !== 'string') {
          return res.status(400).json({ error: "OpenAI API key must be a string" });
        }
        await storage.updateBusinessAccountOpenAIKey(id, openaiApiKey || null);
      }
      
      // Update ElevenLabs API key if provided
      if (elevenlabsApiKey !== undefined) {
        if (elevenlabsApiKey && typeof elevenlabsApiKey !== 'string') {
          return res.status(400).json({ error: "ElevenLabs API key must be a string" });
        }
        await storage.updateBusinessAccountElevenLabsKey(id, elevenlabsApiKey || null);
      }
      
      // Update currency in widget settings if provided
      if (currency !== undefined) {
        if (typeof currency !== 'string') {
          return res.status(400).json({ error: "Currency must be a string" });
        }
        // Validate currency format (3-letter ISO code)
        if (currency && !/^[A-Z]{3}$/.test(currency)) {
          return res.status(400).json({ error: "Currency must be a valid 3-letter ISO code (e.g., USD, EUR)" });
        }
        await storage.upsertWidgetSettings(id, { currency });
      }
      
      // Fetch updated data
      const updated = await storage.getBusinessAccount(id);
      const widgetSettings = await storage.getWidgetSettings(id);
      
      // Return masked API keys for security
      res.json({
        businessAccountId: updated!.id,
        businessName: updated!.name,
        openaiApiKey: updated!.openaiApiKey ? `sk-...${updated!.openaiApiKey.slice(-4)}` : null,
        hasOpenAIKey: !!updated!.openaiApiKey,
        elevenlabsApiKey: updated!.elevenlabsApiKey ? `sk-...${updated!.elevenlabsApiKey.slice(-4)}` : null,
        hasElevenLabsKey: !!updated!.elevenlabsApiKey,
        currency: widgetSettings?.currency || "USD",
      });
    } catch (error: any) {
      console.error('[SuperAdmin API Settings] Error:', error);
      res.status(500).json({ error: error.message });
    }
  });

