        primaryProvider: current.fallbackProvider,
        primaryApiKey: current.fallbackApiKey,
        primaryModel: current.fallbackModel,
        fallbackProvider: current.primaryProvider,
        fallbackApiKey: current.primaryApiKey,
        fallbackModel: current.primaryModel,
