  app.post("/api/super-admin/master-ai-settings/test", requireAuth, requireRole("super_admin"), async (req, res) => {
    const start = Date.now();
    try {
      const { provider, side, apiKey: bodyApiKey, model } = req.body as {
        provider: "openai" | "gemini";
        side: "primary" | "fallback";
        apiKey?: string;
        model: string;
      };

      let apiKey = bodyApiKey?.trim() || null;

      if (!apiKey) {
        const stored = await storage.getMasterAiSettings();
        apiKey = (side === "primary" ? stored?.primaryApiKey : stored?.fallbackApiKey) ?? null;
      }

      if (!apiKey) {
        return res.status(400).json({ success: false, message: "No API key available to test — save a key first or enter one above." });
      }

      const friendlyError = (err: any): string => {
        const msg: string = (err?.message || err?.toString() || "Unknown error");
        if (err?.status === 401 || /incorrect api key|invalid.*key|authentication/i.test(msg)) {
          return "Invalid API key — check the key and try again";
        }
        if (err?.status === 404 || /model.*not.*found|no such model/i.test(msg)) {
          return `Model not found (${model}) — try a different model`;
        }
        if (err?.status === 429 || /quota|rate.?limit|insufficient_quota/i.test(msg)) {
          return "Quota exceeded or rate limited — check your billing";
        }
        return msg.slice(0, 120);
      };

      if (provider === "openai") {
        const OpenAI = (await import("openai")).default;
        const client = new OpenAI({ apiKey });
        await client.chat.completions.create({
          model,
          messages: [{ role: "user", content: "Reply with: OK" }],
          max_tokens: 5,
        });
      } else {
        const { GoogleGenAI } = await import("@google/genai");
        const ai = new GoogleGenAI({ apiKey });
        await ai.models.generateContent({
          model,
          contents: [{ parts: [{ text: "Reply with: OK" }] }],
        });
      }

      res.json({ success: true, message: "Connection successful", latencyMs: Date.now() - start });
    } catch (error: any) {
      console.error("[Master AI Settings] Test connection error:", error?.message || error);
      const msg: string = (error?.message || error?.toString() || "Unknown error");
      const friendlyMsg = (() => {
        if (error?.status === 401 || /incorrect api key|invalid.*key|authentication/i.test(msg)) return "Invalid API key — check the key and try again";
        if (error?.status === 404 || /model.*not.*found|no such model/i.test(msg)) return `Model not found — try a different model`;
        if (error?.status === 429 || /quota|rate.?limit|insufficient_quota/i.test(msg)) return "Quota exceeded or rate limited — check your billing";
        return msg.slice(0, 120);
      })();
      res.json({ success: false, message: friendlyMsg, latencyMs: Date.now() - start });
    }
  });

