  // SuperAdmin: Generate structured attributes for products missing them
  app.post("/api/business-accounts/:id/generate-attributes", requireAuth, requireRole("super_admin"), async (req, res) => {
    try {
      const { id } = req.params;
      
      const businessAccount = await storage.getBusinessAccount(id);
      if (!businessAccount) {
        return res.status(404).json({ error: "Business account not found" });
      }
      
      if (!businessAccount.openaiApiKey) {
        return res.status(400).json({ error: "No OpenAI API key configured. Please add an OpenAI API key first." });
      }
      
      console.log(`[SuperAdmin] Starting attribute generation for business: ${businessAccount.name}`);
      
      // Find products with embeddings but without attributes
      const productsNeedingAttributes = await db
        .select({
          id: productJewelryEmbeddings.id,
          productId: productJewelryEmbeddings.productId,
          croppedImageUrl: productJewelryEmbeddings.croppedImageUrl,
          jewelryType: productJewelryEmbeddings.jewelryType,
        })
        .from(productJewelryEmbeddings)
        .where(
          and(
            eq(productJewelryEmbeddings.businessAccountId, id),
            isNotNull(productJewelryEmbeddings.croppedImageUrl),
            sql`${productJewelryEmbeddings.attributes} IS NULL`
          )
        )
        .limit(50); // Process in batches of 50
      
      if (productsNeedingAttributes.length === 0) {
        return res.json({
          success: true,
          message: "All products already have attributes",
          processed: 0,
          failed: 0,
          remaining: 0,
        });
      }
      
      console.log(`[SuperAdmin] Found ${productsNeedingAttributes.length} products needing attributes`);
      
      const { jewelryDetectionService } = await import('./services/jewelryDetectionService');
      
      let processed = 0;
      let failed = 0;
      
      // Process each product
      for (const item of productsNeedingAttributes) {
        try {
          if (!item.croppedImageUrl) {
            failed++;
            continue;
          }
          
          // Use extractAttributesFromCroppedImage - designed for already-cropped jewelry images
          // This is more reliable than detectJewelry() which expects full images with bounding boxes
          const result = await jewelryDetectionService.extractAttributesFromCroppedImage(item.croppedImageUrl, id);
          
          if (result.success && result.attributes) {
            // Update the productJewelryEmbeddings record with attributes
            await db
              .update(productJewelryEmbeddings)
              .set({
                attributes: result.attributes,
                description: result.description || null,
                updatedAt: new Date(),
              })
              .where(eq(productJewelryEmbeddings.id, item.id));
            
            processed++;
            console.log(`[SuperAdmin] Generated attributes for product ${item.productId}: ${result.type || item.jewelryType}`);
          } else {
            failed++;
            console.log(`[SuperAdmin] Failed to extract attributes for product ${item.productId}: ${result.error || 'No attributes returned'}`);
          }
        } catch (itemError: any) {
          failed++;
          console.error(`[SuperAdmin] Error processing ${item.productId}:`, itemError.message);
        }
      }
      
      // Count remaining products that need attributes
      const remainingCount = await db
        .select({ count: sql<number>`count(*)::int` })
        .from(productJewelryEmbeddings)
        .where(
          and(
            eq(productJewelryEmbeddings.businessAccountId, id),
            isNotNull(productJewelryEmbeddings.croppedImageUrl),
            sql`${productJewelryEmbeddings.attributes} IS NULL`
          )
        );
      
      const remaining = remainingCount[0]?.count || 0;
      
      console.log(`[SuperAdmin] Attribute generation complete: ${processed} processed, ${failed} failed, ${remaining} remaining`);
      
      res.json({
        success: true,
        message: `Generated attributes for ${processed} products`,
        processed,
        failed,
        remaining,
      });
    } catch (error: any) {
      console.error('[SuperAdmin] Attribute generation error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // SuperAdmin: Get jewelry detection stats for a business account
  app.get("/api/business-accounts/:id/jewelry-detection-stats", requireAuth, requireRole("super_admin"), async (req, res) => {
    try {
      const { id } = req.params;
      
      const businessAccount = await storage.getBusinessAccount(id);
      if (!businessAccount) {
        return res.status(404).json({ error: "Business account not found" });
      }
      
      const productsWithImages = await db
        .select({ count: sql<number>`count(*)::int` })
        .from(products)
        .where(
          and(
            eq(products.businessAccountId, id),
            isNotNull(products.imageUrl)
          )
        );
      
      const productsWithCroppedImages = await db
        .select({ count: sql<number>`count(*)::int` })
        .from(products)
        .where(
          and(
            eq(products.businessAccountId, id),
            isNotNull(products.imageUrl),
            isNotNull(products.croppedJewelryUrl)
          )
        );
      
      // Count products that have multi-item embeddings (more than 1 embedding per product)
      // First get products with their embedding counts
      const productsWithMultipleEmbeddings = await db
        .select({ 
          productId: productJewelryEmbeddings.productId,
          count: sql<number>`count(*)::int`
        })
        .from(productJewelryEmbeddings)
        .where(eq(productJewelryEmbeddings.businessAccountId, id))
        .groupBy(productJewelryEmbeddings.productId);
      
      // Filter to only products with more than 1 embedding
      const multiItemProducts = productsWithMultipleEmbeddings.filter(p => p.count > 1);
      const productsWithMultiItemEmbeddingsCount = multiItemProducts.length;
      
      // Total extra embeddings beyond the primary (sum of (count - 1) for multi-item products)
      const totalMultiItemEmbeddingsCount = multiItemProducts.reduce((sum, p) => sum + (p.count - 1), 0);
      
      // Count products that have any embeddings at all
      const productsWithAnyEmbeddings = productsWithMultipleEmbeddings.length;
      
      const totalWithImages = productsWithImages[0]?.count || 0;
      const totalWithCroppedImages = productsWithCroppedImages[0]?.count || 0;
      const needsJewelryDetection = totalWithImages - totalWithCroppedImages;
      
      // Products with cropped images but no embeddings at all need reprocessing
      const needsMultiItemReprocess = totalWithCroppedImages - productsWithAnyEmbeddings;
      
      res.json({
        totalWithImages,
        totalWithCroppedImages,
        needsJewelryDetection,
        totalMultiItemEmbeddings: totalMultiItemEmbeddingsCount,
        productsWithMultiItemEmbeddings: productsWithMultiItemEmbeddingsCount,
        needsMultiItemReprocess: needsMultiItemReprocess > 0 ? needsMultiItemReprocess : 0,
      });
    } catch (error: any) {
      console.error('[SuperAdmin] Jewelry detection stats error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // SuperAdmin: Reprocess products with jewelry detection and cropping
  app.post("/api/business-accounts/:id/jewelry-detection-process", requireAuth, requireRole("super_admin"), async (req, res) => {
    try {
      const { id } = req.params;
      const { reprocessAll } = req.body;
      
      const businessAccount = await storage.getBusinessAccount(id);
      if (!businessAccount) {
        return res.status(404).json({ error: "Business account not found" });
      }
      
      if (!businessAccount.jinaApiKey) {
        return res.status(400).json({ error: "No Jina API key configured. Please add a Jina API key first." });
      }
      
      const openaiApiKey = await storage.getBusinessAccountOpenAIKey(id);
      if (!openaiApiKey) {
        return res.status(400).json({ error: "No OpenAI API key configured. Please add an OpenAI API key first for jewelry detection." });
      }
      
      const { productImageEmbeddingService } = await import("./services/productImageEmbeddingService");
      
      // When reprocessAll is true, clear ALL existing embeddings first for a fresh start
      if (reprocessAll) {
        console.log(`[SuperAdmin] Clearing all embeddings for business: ${businessAccount.name}`);
        
        // Clear productJewelryEmbeddings table entries
        await db.delete(productJewelryEmbeddings).where(eq(productJewelryEmbeddings.businessAccountId, id));
        
        // Null out all product embedding columns including imageHash
        await db.update(products)
          .set({ 
            imageEmbedding: null, 
            fullImageEmbedding: null, 
            imageHash: null, // Clear pHash for regeneration
            croppedJewelryUrl: null,
            detectedJewelryType: null,
            visualDescription: null
          })
          .where(eq(products.businessAccountId, id));
        
        console.log(`[SuperAdmin] Cleared all embeddings for business: ${businessAccount.name}`);
      }
      
      // Count total products for tracking
      const totalProducts = await db.select({ count: sql<number>`count(*)` })
        .from(products)
        .where(and(
          eq(products.businessAccountId, id),
          isNotNull(products.imageUrl)
        ));
      
      // Track the active processing job
      activeProcessingJobs.set(id, {
        startedAt: new Date(),
        totalProducts: totalProducts[0]?.count || 0,
        type: 'jewelry-detection'
      });
      
      console.log(`[SuperAdmin] Starting jewelry detection processing for business: ${businessAccount.name}`);
      
      // Use forceReprocess=true when we've cleared embeddings, otherwise use incremental processing
      const result = await productImageEmbeddingService.reprocessWithJewelryDetection(id, reprocessAll || false);
      
      // Clear the tracking when done
      activeProcessingJobs.delete(id);
      
      console.log(`[SuperAdmin] Jewelry detection complete: ${result.processed} processed, ${result.failed} failed`);
      
      if (result.stoppedEarly && result.error) {
        return res.status(400).json({
          success: false,
          error: result.error,
          message: `Processing stopped: ${result.error}`,
          processed: result.processed,
          failed: result.failed,
          skipped: result.skipped,
          stoppedEarly: true,
        });
      }
      
      res.json({
        success: true,
        message: `Processed ${result.processed} products with jewelry detection`,
        processed: result.processed,
        failed: result.failed,
        skipped: result.skipped,
      });
    } catch (error: any) {
      // Clear the tracking on error too
      const { id } = req.params;
      activeProcessingJobs.delete(id);
      console.error('[SuperAdmin] Jewelry detection processing error:', error);
      res.status(500).json({ error: error.message });
    }
  });
  
  // SuperAdmin: Check if processing is currently active
  app.get("/api/business-accounts/:id/processing-status", requireAuth, requireRole("super_admin"), async (req, res) => {
    try {
      const { id } = req.params;
      const job = activeProcessingJobs.get(id);
      
      if (job) {
        const elapsedMs = Date.now() - job.startedAt.getTime();
        res.json({
          isProcessing: true,
          type: job.type,
          startedAt: job.startedAt.toISOString(),
          totalProducts: job.totalProducts,
          elapsedSeconds: Math.floor(elapsedMs / 1000)
        });
      } else {
        res.json({ isProcessing: false });
      }
    } catch (error: any) {
      res.status(500).json({ error: error.message });
    }
  });

