  // SuperAdmin: Save R2 storage configuration
  app.post("/api/system/r2-config", requireAuth, requireRole("super_admin"), async (req, res) => {
    try {
      const { accountId, accessKeyId, secretAccessKey, bucketName, publicUrl } = req.body;
      
      if (!accountId || !accessKeyId || !secretAccessKey || !bucketName) {
        return res.status(400).json({ 
          error: "Missing required fields: accountId, accessKeyId, secretAccessKey, bucketName" 
        });
      }
      
      const { systemSettingsService } = await import("./services/systemSettingsService");
      
      const success = await systemSettingsService.setR2Config({
        accountId,
        accessKeyId,
        secretAccessKey,
        bucketName,
        publicUrl: publicUrl || undefined,
      });
      
      if (!success) {
        return res.status(500).json({ error: "Failed to save R2 configuration" });
      }
      
      // Refresh the R2 storage service to use the new config
      await r2Storage.refreshFromDatabase();
      
      res.json({ 
        success: true, 
        message: "R2 configuration saved successfully",
        isEnabled: r2Storage.isEnabled(),
      });
    } catch (error: any) {
      console.error('[R2 Config] Error saving config:', error);
      res.status(500).json({ error: error.message });
    }
  });

