  // SuperAdmin: Remove account from group
  app.delete("/api/super-admin/account-groups/:groupId/members/:accountId", requireAuth, requireRole("super_admin"), async (req, res) => {
    try {
      const { groupId, accountId } = req.params;
      
      // Verify group exists
      const group = await storage.getAccountGroup(groupId);
      if (!group) {
        return res.status(404).json({ error: "Account group not found" });
      }
      
      // Get current members
      const members = await storage.getGroupMembers(groupId);
      const memberToRemove = members.find(m => m.businessAccountId === accountId);
      
      if (!memberToRemove) {
        return res.status(404).json({ error: "Account is not a member of this group" });
      }
      
      // Don't allow removing the primary account (must delete group instead)
      if (memberToRemove.isPrimary === 'true') {
        return res.status(400).json({ error: "Cannot remove primary account. Delete the group instead." });
      }
      
      // Remove from group
      await storage.removeAccountFromGroup(groupId, accountId);
      
      // Return updated members
      const updatedMembers = await storage.getGroupMembers(groupId);
      
      res.json({
        id: group.id,
        name: group.name,
        members: updatedMembers.map(m => ({
          businessAccountId: m.businessAccountId,
          businessName: m.businessAccount.name,
          isPrimary: m.isPrimary === 'true',
        })),
      });
    } catch (error: any) {
      console.error('[SuperAdmin Account Groups] Error removing member:', error);
      res.status(500).json({ error: error.message });
    }
  });
  
  // SuperAdmin: Set primary account for a group
  app.patch("/api/super-admin/account-groups/:groupId/primary", requireAuth, requireRole("super_admin"), async (req, res) => {
    try {
      const { groupId } = req.params;
      const { businessAccountId } = req.body;
      
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account ID is required" });
      }
      
      // Verify group exists
      const group = await storage.getAccountGroup(groupId);
      if (!group) {
        return res.status(404).json({ error: "Account group not found" });
      }
      
      // Get current members
      const members = await storage.getGroupMembers(groupId);
      const targetMember = members.find(m => m.businessAccountId === businessAccountId);
      
      if (!targetMember) {
        return res.status(404).json({ error: "Account is not a member of this group" });
      }
      
      // Check if already primary
      if (targetMember.isPrimary === 'true') {
        return res.status(400).json({ error: "Account is already the primary account" });
      }
      
      // Update: clear current primary and set new primary
      await db.update(accountGroupMembers)
        .set({ isPrimary: 'false' })
        .where(eq(accountGroupMembers.groupId, groupId));
      
      await db.update(accountGroupMembers)
        .set({ isPrimary: 'true' })
        .where(eq(accountGroupMembers.businessAccountId, businessAccountId));
      
      // Update the group's owner to the new primary account's user
      const newOwnerUser = await storage.getUserByBusinessAccountId(businessAccountId);
      if (newOwnerUser) {
        await db.update(accountGroups)
          .set({ 
            ownerUserId: newOwnerUser.id,
            updatedAt: new Date(),
          })
          .where(eq(accountGroups.id, groupId));
      }
      
      // Return updated group
      const updatedGroup = await storage.getAccountGroup(groupId);
      const updatedMembers = await storage.getGroupMembers(groupId);
      
      res.json({
        id: updatedGroup!.id,
        name: updatedGroup!.name,
        ownerUserId: updatedGroup!.ownerUserId,
        primaryHasFullAccess: updatedGroup!.primaryHasFullAccess === 'true',
        createdAt: updatedGroup!.createdAt,
        members: updatedMembers.map(m => ({
          businessAccountId: m.businessAccountId,
          businessName: m.businessAccount.name,
          isPrimary: m.isPrimary === 'true',
        })),
      });
    } catch (error: any) {
      console.error('[SuperAdmin Account Groups] Error setting primary:', error);
      res.status(500).json({ error: error.message });
    }
  });
  
