  // Group Admin: Get journey responses by conversationId
  app.get("/api/group-admin/groups/:groupId/journey-responses/:conversationId", requireAuth, requireGroupAdmin, async (req, res) => {
    try {
      const { groupId, conversationId } = req.params;

      const permissions = await getGroupAdminPermissions(req.user!.id, groupId);
      if (!permissions) {
        return res.status(403).json({ error: "Access denied to this group" });
      }
      if (!permissions.canViewLeads) {
        return res.status(403).json({ error: "No permission to view leads" });
      }

      const accountIds = await getGroupAdminAccountIdsForGroup(req.user!.id, groupId);
      if (accountIds.length === 0) {
        return res.json({ journeyName: null, completed: false, responses: [] });
      }

      const { eq, and, inArray } = await import('drizzle-orm');
      const { journeySessions, journeyResponses, journeySteps, conversationJourneys } = await import('../shared/schema');

      const sessions = await db
        .select({
          sessionId: journeySessions.id,
          journeyId: journeySessions.journeyId,
          journeyName: conversationJourneys.name,
          completed: journeySessions.completed,
        })
        .from(journeySessions)
        .leftJoin(conversationJourneys, eq(journeySessions.journeyId, conversationJourneys.id))
        .where(and(
          eq(journeySessions.conversationId, conversationId),
          inArray(journeySessions.businessAccountId, accountIds)
        ));

      if (sessions.length === 0) {
        return res.json({ journeyName: null, completed: false, responses: [] });
      }

      const session = sessions[0];
      const responses = await db
        .select({
          response: journeyResponses.response,
          questionText: journeySteps.questionText,
          stepOrder: journeySteps.stepOrder,
        })
        .from(journeyResponses)
        .leftJoin(journeySteps, eq(journeyResponses.stepId, journeySteps.id))
        .where(eq(journeyResponses.sessionId, session.sessionId))
        .orderBy(journeySteps.stepOrder);

      res.json({
        journeyName: session.journeyName || 'Unknown Journey',
        completed: session.completed === 'true',
        responses: responses.map(r => ({
          question: r.questionText || 'Unknown',
          answer: r.response,
          stepOrder: r.stepOrder || 0,
        })),
      });
    } catch (error: any) {
      console.error('[Group Admin] Error fetching journey responses:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // Group Admin: Get journey responses by lead ID (handles leads without conversationId)
  app.get("/api/group-admin/groups/:groupId/journey-responses-by-lead/:leadId", requireAuth, requireGroupAdmin, async (req, res) => {
    try {
      const { groupId, leadId } = req.params;

      const permissions = await getGroupAdminPermissions(req.user!.id, groupId);
      if (!permissions) {
        return res.status(403).json({ error: "Access denied to this group" });
      }
      if (!permissions.canViewLeads) {
        return res.status(403).json({ error: "No permission to view leads" });
      }

      const accountIds = await getGroupAdminAccountIdsForGroup(req.user!.id, groupId);
      if (accountIds.length === 0) {
        return res.json({ journeyName: null, completed: false, responses: [] });
      }

      const { eq, and, inArray, desc: descOrder, like } = await import('drizzle-orm');
      const { leads: leadsTable, journeySessions, journeyResponses, journeySteps, conversationJourneys } = await import('../shared/schema');

      const [lead] = await db.select().from(leadsTable).where(and(
        eq(leadsTable.id, leadId),
        inArray(leadsTable.businessAccountId, accountIds)
      ));

      if (!lead) {
        return res.status(404).json({ error: "Lead not found" });
      }

      let session: { sessionId: string; journeyName: string | null; completed: string } | null = null;

      if (lead.conversationId) {
        const sessions = await db
          .select({
            sessionId: journeySessions.id,
            journeyName: conversationJourneys.name,
            completed: journeySessions.completed,
          })
          .from(journeySessions)
          .leftJoin(conversationJourneys, eq(journeySessions.journeyId, conversationJourneys.id))
          .where(and(
            eq(journeySessions.conversationId, lead.conversationId),
            inArray(journeySessions.businessAccountId, accountIds)
          ))
          .orderBy(descOrder(journeySessions.createdAt))
          .limit(1);

        if (sessions.length > 0) {
          session = sessions[0];
        }
      }

      if (!session && lead.phone) {
        const phoneMatches = await db
          .select({
            sessionId: journeySessions.id,
            journeyName: conversationJourneys.name,
            completed: journeySessions.completed,
          })
          .from(journeyResponses)
          .innerJoin(journeySessions, eq(journeyResponses.sessionId, journeySessions.id))
          .leftJoin(conversationJourneys, eq(journeySessions.journeyId, conversationJourneys.id))
          .where(and(
            eq(journeyResponses.response, lead.phone),
            inArray(journeySessions.businessAccountId, accountIds)
          ))
          .orderBy(descOrder(journeySessions.createdAt))
          .limit(1);

        if (phoneMatches.length > 0) {
          session = phoneMatches[0];
        }
      }

      if (!session) {
        return res.json({ journeyName: null, completed: false, responses: [] });
      }
      const responses = await db
        .select({
          response: journeyResponses.response,
          questionText: journeySteps.questionText,
          stepOrder: journeySteps.stepOrder,
        })
        .from(journeyResponses)
        .leftJoin(journeySteps, eq(journeyResponses.stepId, journeySteps.id))
        .where(eq(journeyResponses.sessionId, session.sessionId))
        .orderBy(journeySteps.stepOrder);

      res.json({
        journeyName: session.journeyName || 'Unknown Journey',
        completed: session.completed === 'true',
        responses: responses.map(r => ({
          question: r.questionText || 'Unknown',
          answer: r.response,
          stepOrder: r.stepOrder || 0,
        })),
      });
    } catch (error: any) {
      console.error('[Group Admin] Error fetching journey responses by lead:', error);
      res.status(500).json({ error: error.message });
    }
  });

