  // Parse conversation script with AI
  app.post("/api/journeys/parse-script", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const user = req.user!;
      const businessAccountId = user.businessAccountId!;
      const { script } = req.body;

      if (!script || typeof script !== 'string' || script.trim().length === 0) {
        return res.status(400).json({ error: "Script is required" });
      }

      // Get OpenAI API key
      const openaiApiKey = await storage.getBusinessAccountOpenAIKey(businessAccountId);
      if (!openaiApiKey) {
        return res.status(400).json({ error: "OpenAI API key not configured" });
      }

      const openai = new OpenAI({ apiKey: openaiApiKey });

      // Use GPT-4o to analyze the script
      const completion = await openai.chat.completions.create({
        model: "gpt-4o",
        messages: [
          {
            role: "system",
            content: `You are an expert at analyzing conversation scripts and extracting structured data for chatbot training.

Analyze the provided conversation script and extract:
1. Journey name - a clear, concise name for this conversation flow
2. Description - what this journey accomplishes
3. Steps - each question in the conversation flow with:
   - questionText: the question to ask
   - isRequired: whether it's required (default true)
   - toolTrigger: if it should trigger a tool like "capture_lead", "book_appointment", "get_products", or null
4. Trigger keywords - words/phrases that should auto-start this journey
5. Conversational guidelines - the tone, acknowledgment patterns, and style guide for the AI to follow during this journey

Return a JSON object with this exact structure:
{
  "journeyName": "string",
  "description": "string", 
  "steps": [
    {
      "questionText": "string",
      "isRequired": true,
      "toolTrigger": "capture_lead" | "book_appointment" | "get_products" | null
    }
  ],
  "triggerKeywords": ["keyword1", "keyword2"],
  "conversationalGuidelines": "string - detailed instructions for AI tone and behavior"
}

Important:
- Extract acknowledgment patterns (like "Okay!", "Alright!", "Got it!") into conversational guidelines
- Identify where lead capture should happen (typically when asking for contact info)
- Keep questions concise and natural
- Preserve the conversational flow and sequence`
          },
          {
            role: "user",
            content: `Analyze this conversation script:\n\n${script}`
          }
        ],
        response_format: { type: "json_object" },
        temperature: 0.3,
      });

      const parsed = JSON.parse(completion.choices[0].message.content || "{}");

      // Validate the parsed response
      if (!parsed.journeyName || typeof parsed.journeyName !== 'string') {
        return res.status(400).json({ 
          error: "Invalid script analysis: Journey name is missing or invalid. Please provide a clearer conversation script." 
        });
      }

      if (!parsed.description || typeof parsed.description !== 'string') {
        return res.status(400).json({ 
          error: "Invalid script analysis: Description is missing or invalid. Please provide more context in your script." 
        });
      }

      if (!Array.isArray(parsed.steps) || parsed.steps.length === 0) {
        return res.status(400).json({ 
          error: "Invalid script analysis: No conversation steps found. Please ensure your script contains clear questions." 
        });
      }

      // Validate each step
      for (let i = 0; i < parsed.steps.length; i++) {
        const step = parsed.steps[i];
        if (!step.questionText || typeof step.questionText !== 'string') {
          return res.status(400).json({ 
            error: `Invalid script analysis: Step ${i + 1} is missing a question. Please review your script.` 
          });
        }
        if (typeof step.isRequired !== 'boolean') {
          step.isRequired = true; // Default to required
        }
        if (step.toolTrigger && !['capture_lead', 'book_appointment', 'get_products'].includes(step.toolTrigger)) {
          step.toolTrigger = null; // Reset invalid tool triggers
        }
      }

      // Ensure trigger keywords is an array
      if (!Array.isArray(parsed.triggerKeywords)) {
        parsed.triggerKeywords = [];
      }

      // Ensure conversational guidelines exists
      if (typeof parsed.conversationalGuidelines !== 'string') {
        parsed.conversationalGuidelines = "";
      }

      res.json(parsed);
    } catch (error: any) {
      console.error('[Script Parser] Error:', error);
      res.status(500).json({ error: error.message });
    }
  });

