  // Duplicate journey
  app.post("/api/journeys/:id/duplicate", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const user = req.user!;
      const businessAccountId = user.businessAccountId!;
      const { id } = req.params;

      const sourceJourney = await storage.getJourney(id, businessAccountId);
      if (!sourceJourney) {
        return res.status(404).json({ error: "Journey not found" });
      }

      const sourceSteps = await storage.getJourneySteps(id);

      const newJourney = await db.transaction(async (tx) => {
        const [created] = await tx.insert(conversationJourneys).values({
          businessAccountId,
          name: `Copy of ${sourceJourney.name}`,
          description: sourceJourney.description,
          templateType: sourceJourney.templateType,
          journeyType: sourceJourney.journeyType,
          status: "inactive",
          isDefault: "false",
          triggerMode: sourceJourney.triggerMode,
          triggerKeywords: sourceJourney.triggerKeywords,
          startFromScratch: sourceJourney.startFromScratch,
          conversationalGuidelines: sourceJourney.conversationalGuidelines,
        }).returning();

        const oldToNewStepId: Record<string, string> = {};

        for (const step of sourceSteps) {
          const [newStep] = await tx.insert(journeySteps).values({
            journeyId: created.id,
            stepOrder: step.stepOrder,
            questionText: step.questionText,
            questionType: step.questionType,
            fieldName: step.fieldName,
            isRequired: step.isRequired,
            multipleChoiceOptions: step.multipleChoiceOptions,
            toolTrigger: step.toolTrigger,
            toolParameters: step.toolParameters,
            branchingCondition: step.branchingCondition,
            exitOnValue: step.exitOnValue,
            exitMessage: step.exitMessage,
            skipOnValue: step.skipOnValue,
            skipToStepIndex: step.skipToStepIndex,
            isConditional: step.isConditional,
            completionButtonText: step.completionButtonText,
            placeholderText: step.placeholderText,
            helpText: step.helpText,
          }).returning();
          oldToNewStepId[step.id] = newStep.id;
        }

        for (const step of sourceSteps) {
          if (step.branchingCondition) {
            const condition = JSON.parse(step.branchingCondition);
            let changed = false;
            if (condition.routes && Array.isArray(condition.routes)) {
              for (const route of condition.routes) {
                if (route.targetStepId && oldToNewStepId[route.targetStepId]) {
                  route.targetStepId = oldToNewStepId[route.targetStepId];
                  changed = true;
                }
              }
            }
            if (condition.defaultNextStepId && oldToNewStepId[condition.defaultNextStepId]) {
              condition.defaultNextStepId = oldToNewStepId[condition.defaultNextStepId];
              changed = true;
            }
            if (changed) {
              const newStepId = oldToNewStepId[step.id];
              await tx.update(journeySteps)
                .set({ branchingCondition: JSON.stringify(condition) })
                .where(eq(journeySteps.id, newStepId));
            }
          }
        }

        return created;
      });

      journeyService.invalidateJourneyCache(businessAccountId);

      res.json(newJourney);
    } catch (error: any) {
      console.error('[Journey Duplicate] Error:', error.message);
      res.status(500).json({ error: error.message });
    }
  });

