  // Save LeadSquared settings
  app.post("/api/leadsquared/settings", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const user = req.user!;
      const businessAccountId = user.businessAccountId!;
      const { accessKey, secretKey, region, customHost, enabled } = req.body;
      
      // Get existing settings
      const existingSettings = await storage.getWidgetSettings(businessAccountId);
      
      // Determine what to save
      // If secretKey is provided and not null, it means user is updating it
      // If secretKey is null, keep the existing encrypted secret
      const settingsUpdate: any = {
        leadsquaredAccessKey: accessKey || null,
        leadsquaredRegion: region || null,
        leadsquaredCustomHost: customHost || null,
        leadsquaredEnabled: enabled ? 'true' : 'false',
      };
      
      // Only update secret key if a new one is provided (not null/empty)
      if (secretKey) {
        const { encrypt } = await import('./services/encryptionService');
        settingsUpdate.leadsquaredSecretKey = encrypt(secretKey);
      } else if (existingSettings?.leadsquaredSecretKey) {
        // Keep existing encrypted secret
        settingsUpdate.leadsquaredSecretKey = existingSettings.leadsquaredSecretKey;
      }
      
      // Validate required fields when enabling
      if (enabled) {
        const hasAccessKey = accessKey || existingSettings?.leadsquaredAccessKey;
        const hasSecretKey = secretKey || existingSettings?.leadsquaredSecretKey;
        const hasRegion = region || existingSettings?.leadsquaredRegion;
        
        if (!hasAccessKey || !hasSecretKey || !hasRegion) {
          return res.status(400).json({ 
            error: "Access key, secret key, and region are required when enabling LeadSquared" 
          });
        }
      }
      
      await storage.upsertWidgetSettings(businessAccountId, settingsUpdate);
      
      console.log('[LeadSquared] Settings updated for business:', businessAccountId);
      
      res.json({ success: true, message: "LeadSquared settings saved successfully" });
    } catch (error: any) {
      console.error('[LeadSquared] Save settings error:', error);
      res.status(500).json({ error: error.message });
    }
  });

