  // Manually sync a lead to LeadSquared
  app.post("/api/leadsquared/sync-lead/:leadId", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const user = req.user!;
      const businessAccountId = user.businessAccountId!;
      const { leadId } = req.params;
      
      // Get LeadSquared settings
      const settings = await storage.getWidgetSettings(businessAccountId);
      
      if (!settings || settings.leadsquaredEnabled !== 'true') {
        return res.status(400).json({ error: "LeadSquared integration is not enabled" });
      }
      
      if (!settings.leadsquaredAccessKey || !settings.leadsquaredSecretKey || !settings.leadsquaredRegion) {
        return res.status(400).json({ error: "LeadSquared credentials not configured" });
      }
      
      // SECURITY: Get the lead scoped to businessAccountId (prevents cross-tenant access)
      const lead = await storage.getLead(leadId, businessAccountId);
      
      if (!lead) {
        return res.status(404).json({ error: "Lead not found" });
      }
      
      // Get business account info
      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      
      // Decrypt the secret key
      const { decrypt } = await import('./services/encryptionService');
      const decryptedSecretKey = decrypt(settings.leadsquaredSecretKey);
      
      // Create LeadSquared service
      const { createLeadSquaredService } = await import('./services/leadsquaredService');
      const leadsquaredService = await createLeadSquaredService({
        accessKey: settings.leadsquaredAccessKey,
        secretKey: decryptedSecretKey,
        region: settings.leadsquaredRegion as 'india' | 'us' | 'other',
        customHost: settings.leadsquaredCustomHost || undefined,
      });
      
      const { extractUtmCampaign, extractUtmSource, extractUtmMedium } = await import('./services/leadsquaredService');
      
      // Get field mappings from database (dynamic, configurable)
      const fieldMappings = await storage.getLeadsquaredFieldMappings(businessAccountId);
      
      // Build context for dynamic field mapping
      const leadContext = {
        lead: {
          name: lead.name || null,
          email: lead.email || null,
          phone: lead.phone || null,
          whatsapp: null,
          createdAt: lead.createdAt || null,
          sourceUrl: lead.sourceUrl || null,
        },
        session: {
          city: lead.city || null,
          utmCampaign: extractUtmCampaign(lead.sourceUrl) || null,
          utmSource: extractUtmSource(lead.sourceUrl) || null,
          utmMedium: extractUtmMedium(lead.sourceUrl) || null,
          pageUrl: lead.sourceUrl || null,
        },
        business: {
          name: businessAccount?.name || null,
          website: businessAccount?.website || null,
        }
      };
      
      console.log('[LeadSquared] Manual sync using dynamic field mappings, count:', fieldMappings.length);
      
      // Sync to LeadSquared with dynamic field mappings
      const result = await leadsquaredService.createLeadWithMappings(fieldMappings, leadContext);
      
      if (result.success) {
        // Update lead with sync status
        await storage.updateLead(leadId, businessAccountId, {
          leadsquaredSyncStatus: 'synced',
          leadsquaredSyncedAt: new Date(),
          leadsquaredLeadId: result.leadId,
          leadsquaredSyncError: null,
          leadsquaredSyncPayload: result.syncPayload || null,
        });
        
        console.log('[LeadSquared] Lead synced successfully:', leadId, '→', result.leadId);
        
        res.json({ success: true, message: result.message, leadsquaredLeadId: result.leadId });
      } else {
        // Update lead with error status
        await storage.updateLead(leadId, businessAccountId, {
          leadsquaredSyncStatus: 'failed',
          leadsquaredSyncError: result.message,
        });
        
        res.status(400).json({ success: false, error: result.message });
      }
    } catch (error: any) {
      console.error('[LeadSquared] Sync lead error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // Bulk sync all leads to LeadSquared
  app.post("/api/leadsquared/sync-all", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const user = req.user!;
      const businessAccountId = user.businessAccountId!;
      
      // Get LeadSquared settings
      const settings = await storage.getWidgetSettings(businessAccountId);
      
      if (!settings || settings.leadsquaredEnabled !== 'true') {
        return res.status(400).json({ error: "LeadSquared integration is not enabled" });
      }
      
      if (!settings.leadsquaredAccessKey || !settings.leadsquaredSecretKey || !settings.leadsquaredRegion) {
        return res.status(400).json({ error: "LeadSquared credentials not configured" });
      }
      
      // Get all leads that haven't been synced yet or failed previously
      const allLeads = await storage.getAllLeads(businessAccountId);
      const leads = allLeads.filter(lead => 
        lead.leadsquaredSyncStatus !== 'synced'
      );
      
      if (leads.length === 0) {
        return res.json({ 
          success: true, 
          message: "All leads are already synced to LeadSquared",
          synced: 0,
          failed: 0,
          total: 0
        });
      }
      
      // Get business account info
      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      
      // Decrypt the secret key
      const { decrypt } = await import('./services/encryptionService');
      const decryptedSecretKey = decrypt(settings.leadsquaredSecretKey);
      
      // Create LeadSquared service
      const { createLeadSquaredService } = await import('./services/leadsquaredService');
      const leadsquaredService = await createLeadSquaredService({
        accessKey: settings.leadsquaredAccessKey,
        secretKey: decryptedSecretKey,
        region: settings.leadsquaredRegion as 'india' | 'us' | 'other',
        customHost: settings.leadsquaredCustomHost || undefined,
      });
      
      const { extractUtmCampaign, extractUtmSource, extractUtmMedium } = await import('./services/leadsquaredService');
      
      // Get field mappings from database (dynamic, configurable)
      const fieldMappings = await storage.getLeadsquaredFieldMappings(businessAccountId);
      
      console.log('[LeadSquared] Bulk sync using dynamic field mappings, count:', fieldMappings.length);
      
      let syncedCount = 0;
      let failedCount = 0;
      const errors: string[] = [];
      
      // Sync each lead
      for (const lead of leads) {
        try {
          // Build context for each lead
          const leadContext = {
            lead: {
              name: lead.name || null,
              email: lead.email || null,
              phone: lead.phone || null,
              whatsapp: null,
              createdAt: lead.createdAt || null,
              sourceUrl: lead.sourceUrl || null,
            },
            session: {
              city: lead.city || null,
              utmCampaign: extractUtmCampaign(lead.sourceUrl) || null,
              utmSource: extractUtmSource(lead.sourceUrl) || null,
              utmMedium: extractUtmMedium(lead.sourceUrl) || null,
              pageUrl: lead.sourceUrl || null,
            },
            business: {
              name: businessAccount?.name || null,
              website: businessAccount?.website || null,
            }
          };
          
          const result = await leadsquaredService.createLeadWithMappings(fieldMappings, leadContext);
          
          if (result.success) {
            await storage.updateLead(lead.id, businessAccountId, {
              leadsquaredSyncStatus: 'synced',
              leadsquaredSyncedAt: new Date(),
              leadsquaredLeadId: result.leadId,
              leadsquaredSyncError: null,
              leadsquaredSyncPayload: result.syncPayload || null,
            });
            syncedCount++;
          } else {
            await storage.updateLead(lead.id, businessAccountId, {
              leadsquaredSyncStatus: 'failed',
              leadsquaredSyncError: result.message,
            });
            failedCount++;
            errors.push(`${lead.name || lead.email || lead.phone}: ${result.message}`);
          }
        } catch (syncError: any) {
          await storage.updateLead(lead.id, businessAccountId, {
            leadsquaredSyncStatus: 'failed',
            leadsquaredSyncError: syncError.message,
          });
          failedCount++;
          errors.push(`${lead.name || lead.email || lead.phone}: ${syncError.message}`);
        }
      }
      
      console.log(`[LeadSquared] Bulk sync completed: ${syncedCount} synced, ${failedCount} failed`);
      
      res.json({
        success: true,
        message: `Synced ${syncedCount} leads to LeadSquared${failedCount > 0 ? `, ${failedCount} failed` : ''}`,
        synced: syncedCount,
        failed: failedCount,
        total: leads.length,
        errors: errors.slice(0, 5), // Return first 5 errors only
      });
    } catch (error: any) {
      console.error('[LeadSquared] Bulk sync error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // LeadSquared Field Mappings CRUD
  app.get("/api/leadsquared/field-mappings", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.activeBusinessAccountId || req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: 'Business account not found' });
      }
      const mappings = await storage.getLeadsquaredFieldMappings(businessAccountId);
      
      // Seed defaults if no mappings exist and LeadSquared is enabled
      if (mappings.length === 0) {
        const widgetSettings = await storage.getWidgetSettings(businessAccountId);
        if (widgetSettings?.leadsquaredEnabled === 'true') {
          await storage.seedDefaultLeadsquaredFieldMappings(businessAccountId);
          const seededMappings = await storage.getLeadsquaredFieldMappings(businessAccountId);
          return res.json(seededMappings);
        }
      }
      
      res.json(mappings);
    } catch (error: any) {
      console.error('[LeadSquared] Get field mappings error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  app.post("/api/leadsquared/field-mappings", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.activeBusinessAccountId || req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: 'Business account not found' });
      }
      const { leadsquaredField, sourceType, sourceField, customValue, fallbackValue, displayName, isEnabled, sortOrder } = req.body;
      
      if (!leadsquaredField || !sourceType || !displayName) {
        return res.status(400).json({ error: 'leadsquaredField, sourceType, and displayName are required' });
      }
      
      if (sourceType === 'dynamic' && !sourceField) {
        return res.status(400).json({ error: 'sourceField is required for dynamic mappings' });
      }
      
      if (sourceType === 'custom' && !customValue) {
        return res.status(400).json({ error: 'customValue is required for custom mappings' });
      }
      
      const mapping = await storage.createLeadsquaredFieldMapping({
        businessAccountId,
        leadsquaredField,
        sourceType,
        sourceField: sourceType === 'dynamic' ? sourceField : null,
        customValue: sourceType === 'custom' ? customValue : null,
        fallbackValue: sourceType === 'dynamic' ? (fallbackValue || null) : null,
        displayName,
        isEnabled: isEnabled ?? 'true',
        sortOrder: sortOrder ?? 0,
      });
      
      res.json(mapping);
    } catch (error: any) {
      console.error('[LeadSquared] Create field mapping error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  app.put("/api/leadsquared/field-mappings/:id", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.activeBusinessAccountId || req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: 'Business account not found' });
      }
      const { id } = req.params;
      const { leadsquaredField, sourceType, sourceField, customValue, fallbackValue, displayName, isEnabled, sortOrder } = req.body;
      
      const existing = await storage.getLeadsquaredFieldMapping(id, businessAccountId);
      if (!existing) {
        return res.status(404).json({ error: 'Field mapping not found' });
      }
      
      const updates: any = {};
      if (leadsquaredField !== undefined) updates.leadsquaredField = leadsquaredField;
      if (displayName !== undefined) updates.displayName = displayName;
      if (isEnabled !== undefined) updates.isEnabled = isEnabled;
      if (sortOrder !== undefined) updates.sortOrder = sortOrder;
      
      if (sourceType !== undefined) {
        updates.sourceType = sourceType;
        if (sourceType === 'dynamic') {
          updates.sourceField = sourceField;
          updates.customValue = null;
          updates.fallbackValue = fallbackValue || null;
        } else {
          updates.sourceField = null;
          updates.customValue = customValue;
          updates.fallbackValue = null;
        }
      } else if (sourceField !== undefined || customValue !== undefined) {
        if (existing.sourceType === 'dynamic') {
          updates.sourceField = sourceField;
          if (fallbackValue !== undefined) updates.fallbackValue = fallbackValue || null;
        } else {
          updates.customValue = customValue;
        }
      } else if (fallbackValue !== undefined && existing.sourceType === 'dynamic') {
        updates.fallbackValue = fallbackValue || null;
      }
      
      const updated = await storage.updateLeadsquaredFieldMapping(id, businessAccountId, updates);
      res.json(updated);
    } catch (error: any) {
      console.error('[LeadSquared] Update field mapping error:', error);
      res.status(500).json({ error: error.message });
    }
  });

