  app.post("/api/salesforce/test-connection", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const user = req.user!;
      const businessAccountId = user.businessAccountId!;
      let { clientId, clientSecret, username, password, environment, useExistingSecret } = req.body;

      if (useExistingSecret) {
        const settings = await storage.getWidgetSettings(businessAccountId);
        if (!settings || !settings.salesforceClientSecret || !settings.salesforcePassword) {
          return res.status(400).json({ error: "No saved credentials found" });
        }
        clientId = settings.salesforceClientId;
        username = settings.salesforceUsername;
        environment = settings.salesforceEnvironment;
        const { decrypt } = await import('./services/encryptionService');
        try {
          clientSecret = decrypt(settings.salesforceClientSecret);
          password = decrypt(settings.salesforcePassword);
        } catch {
          return res.status(400).json({ error: "credentials_corrupted", message: "Saved credentials could not be read — please re-enter them." });
        }
      }

      if (!clientId || !clientSecret || !username || !password) {
        return res.status(400).json({ error: "Client ID, Client Secret, Username, and Password are required" });
      }

      const { createSalesforceService } = await import('./services/salesforceService');
      const service = createSalesforceService({ clientId, clientSecret, username, password, environment: environment || 'production' });
      const result = await service.testConnection();

      if (result.success) {
        res.json({ success: true, message: result.message, instanceUrl: result.instanceUrl });
      } else {
        res.status(400).json({ success: false, error: result.message });
      }
    } catch (error: any) {
      console.error('[Salesforce] Test connection error:', error);
      res.status(500).json({ error: error.message });
    }
  });

