  app.post("/api/salesforce/settings", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const user = req.user!;
      const businessAccountId = user.businessAccountId!;
      const { clientId, clientSecret, username, password, environment, enabled } = req.body;

      const existingSettings = await storage.getWidgetSettings(businessAccountId);
      const { encrypt } = await import('./services/encryptionService');

      const update: any = {
        salesforceClientId: clientId || null,
        salesforceUsername: username || null,
        salesforceEnvironment: environment || 'production',
        salesforceEnabled: enabled ? 'true' : 'false',
      };

      if (clientSecret) {
        update.salesforceClientSecret = encrypt(clientSecret);
      } else if (existingSettings?.salesforceClientSecret) {
        update.salesforceClientSecret = existingSettings.salesforceClientSecret;
      }

      if (password) {
        update.salesforcePassword = encrypt(password);
      } else if (existingSettings?.salesforcePassword) {
        update.salesforcePassword = existingSettings.salesforcePassword;
      }

      if (enabled && clientId && (clientSecret || existingSettings?.salesforceClientSecret) && username && (password || existingSettings?.salesforcePassword)) {
        try {
          const { createSalesforceService } = await import('./services/salesforceService');
          const { decrypt } = await import('./services/encryptionService');
          const service = createSalesforceService({
            clientId: clientId || existingSettings?.salesforceClientId || '',
            clientSecret: clientSecret || (existingSettings?.salesforceClientSecret ? decrypt(existingSettings.salesforceClientSecret) : ''),
            username: username || existingSettings?.salesforceUsername || '',
            password: password || (existingSettings?.salesforcePassword ? decrypt(existingSettings.salesforcePassword) : ''),
            environment: (environment || existingSettings?.salesforceEnvironment || 'production') as 'production' | 'sandbox',
          });
          const testResult = await service.testConnection();
          if (testResult.instanceUrl) update.salesforceInstanceUrl = testResult.instanceUrl;
        } catch {}
      }

      await storage.updateWidgetSettings(businessAccountId, update);
      const updatedSettings = await storage.getWidgetSettings(businessAccountId);

      res.json({
        success: true,
        enabled: updatedSettings?.salesforceEnabled === 'true',
        hasCredentials: !!(updatedSettings?.salesforceClientId && updatedSettings?.salesforceClientSecret),
      });
    } catch (error: any) {
      console.error('[Salesforce] Save settings error:', error);
      res.status(500).json({ error: error.message });
    }
  });

