  app.post("/api/custom-crm/settings", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const user = req.user!;
      const businessAccountId = user.businessAccountId!;
      const { enabled, name, apiBaseUrl, apiEndpoint, httpMethod, contentType, authType, authKey, authHeaderName, autoSyncEnabled, callbackUrl } = req.body;

      const [existing] = await db
        .select()
        .from(customCrmSettings)
        .where(eq(customCrmSettings.businessAccountId, businessAccountId))
        .limit(1);

      const { encrypt } = await import('./services/encryptionService');

      const settingsData: any = {
        enabled: !!enabled,
        name: name || "Custom CRM",
        apiBaseUrl: apiBaseUrl || null,
        apiEndpoint: apiEndpoint || null,
        httpMethod: httpMethod || "POST",
        contentType: contentType || "form-data",
        authType: authType || "none",
        authHeaderName: authHeaderName || null,
        autoSyncEnabled: !!autoSyncEnabled,
        callbackUrl: callbackUrl || null,
        updatedAt: new Date(),
      };

      if (authKey) {
        settingsData.authKey = encrypt(authKey);
      } else if (existing?.authKey) {
        settingsData.authKey = existing.authKey;
      }

      if (existing) {
        await db.update(customCrmSettings)
          .set(settingsData)
          .where(eq(customCrmSettings.id, existing.id));
      } else {
        settingsData.businessAccountId = businessAccountId;
        await db.insert(customCrmSettings).values(settingsData);
      }

      console.log("[Custom CRM] Settings updated for business:", businessAccountId);
      res.json({ success: true, message: "Custom CRM settings saved successfully" });
    } catch (error: any) {
      console.error("[Custom CRM] Save settings error:", error);
      res.status(500).json({ error: error.message });
    }
  });

