      if (sourceField !== undefined) safeUpdate.sourceField = sourceField;
      if (customValue !== undefined) safeUpdate.customValue = customValue;
      if (displayName !== undefined) safeUpdate.displayName = displayName;
      if (isEnabled !== undefined) safeUpdate.isEnabled = isEnabled;
      if (sortOrder !== undefined) safeUpdate.sortOrder = sortOrder;
      if (isAutoManaged !== undefined) safeUpdate.isAutoManaged = isAutoManaged;

      const [updated] = await db.update(customCrmFieldMappings)
