  app.post("/api/custom-crm/sync-lead/:leadId", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const user = req.user!;
      const businessAccountId = user.businessAccountId!;
      const { leadId } = req.params;
      const { leadType } = req.body;

      const [settings] = await db
        .select()
        .from(customCrmSettings)
        .where(eq(customCrmSettings.businessAccountId, businessAccountId))
        .limit(1);

      if (!settings || !settings.enabled) {
        return res.status(400).json({ error: "Custom CRM integration is not enabled" });
      }

      if (!settings.apiBaseUrl || !settings.apiEndpoint) {
        return res.status(400).json({ error: "Custom CRM API URL not configured" });
      }

      const fieldMappings = await db
        .select()
        .from(customCrmFieldMappings)
        .where(eq(customCrmFieldMappings.businessAccountId, businessAccountId))
        .orderBy(customCrmFieldMappings.sortOrder);

      if (leadType === 'whatsapp') {
        const [whatsappLead] = await db
          .select()
          .from(whatsappLeads)
          .where(and(
            eq(whatsappLeads.id, leadId),
            eq(whatsappLeads.businessAccountId, businessAccountId)
          ))
          .limit(1);

        if (!whatsappLead) {
          return res.status(404).json({ error: "WhatsApp lead not found" });
        }

        const extractedData = (whatsappLead.extractedData as Record<string, any>) || {};
        const documents = await buildDocumentContext(leadId);
        const leadContext = {
          lead: {
            customerName: whatsappLead.customerName || null,
            customerEmail: whatsappLead.customerEmail || null,
            customerPhone: whatsappLead.customerPhone || null,
            loanAmount: whatsappLead.loanAmount || null,
            address: whatsappLead.address || null,
            loanType: whatsappLead.loanType || null,
            senderPhone: whatsappLead.senderPhone || null,
          },
          extracted: extractedData,
          documents,
        };

        let storeCredential = undefined;
        const storeName = extractedData.store_name || extractedData.storeName;
        const dealerName = extractedData.dealer_name || extractedData.dealerName || extractedData.dealer;
        const cityName = extractedData.city || extractedData.city_name || extractedData.dealer_city || extractedData.dealerCity;

        if (storeName || dealerName) {
          const storeCreds = await db
            .select()
            .from(crmStoreCredentials)
            .where(and(
              eq(crmStoreCredentials.businessAccountId, businessAccountId),
              eq(crmStoreCredentials.isActive, true)
            ));

          const norm = (s?: string | null) => s ? s.trim().toLowerCase() : '';
          const nStore = norm(storeName);
          const nDealer = norm(dealerName);
          const nCity = norm(cityName);

          if (nStore && nDealer && nCity) {
            storeCredential = storeCreds.find(
              sc => norm(sc.storeName) === nStore && norm(sc.dealerName) === nDealer && norm(sc.city) === nCity
            );
          }
          if (!storeCredential && nStore && nDealer) {
            storeCredential = storeCreds.find(
              sc => norm(sc.storeName) === nStore && norm(sc.dealerName) === nDealer
            );
          }
          if (!storeCredential && nStore) {
            storeCredential = storeCreds.find(
              sc => norm(sc.storeName) === nStore
            );
          }
          if (!storeCredential && storeCreds.length > 0 && (nStore || nDealer)) {
            try {
              const OpenAI = (await import('openai')).default;
              const [bizAcct] = await db.select().from(businessAccounts).where(eq(businessAccounts.id, businessAccountId)).limit(1);
              const openaiApiKey = bizAcct?.openaiApiKey ? (await import('./services/encryptionService')).decrypt(bizAcct.openaiApiKey) : process.env.OPENAI_API_KEY;
              if (openaiApiKey) {
                const openaiClient = new OpenAI({ apiKey: openaiApiKey, timeout: 15000 });
                const storeList = storeCreds.map(sc => ({ id: sc.id, dealerName: sc.dealerName, storeName: sc.storeName, city: sc.city || '', storeId: sc.storeId }));
                const prompt = `Match the lead's store info to the closest store credential.\n\nLead info:\n- Dealer: ${dealerName || 'unknown'}\n- City: ${cityName || 'unknown'}\n- Store: ${storeName || 'unknown'}\n\nAvailable stores (JSON):\n${JSON.stringify(storeList)}\n\nReturn ONLY a JSON object: {"matchedId": "<store id or null>", "confidence": <0.0-1.0>}\nIf no good match exists, return {"matchedId": null, "confidence": 0}`;
                const completion = await openaiClient.chat.completions.create({
                  model: 'gpt-4o-mini',
                  messages: [{ role: 'user', content: prompt }],
                  temperature: 0,
                  max_tokens: 100,
                  response_format: { type: 'json_object' },
                });
                const content = completion.choices[0]?.message?.content;
                if (content) {
                  const aiResult = JSON.parse(content);
                  if (aiResult.matchedId && aiResult.confidence >= 0.75) {
                    storeCredential = storeCreds.find(sc => sc.id === aiResult.matchedId);
                    console.log(`[CRM ManualSync] AI fuzzy match: store=${storeCredential?.storeName}, confidence=${aiResult.confidence}`);
                  }
                }
              }
            } catch (aiErr) {
              console.warn(`[CRM ManualSync] AI fuzzy store matching failed:`, aiErr);
            }
          }

          if (storeCredential) {
            console.log(`[CRM ManualSync] Resolved store: ${storeCredential.storeName} (SID: ${storeCredential.sid}, ID: ${storeCredential.storeId})`);
          }
        }

        const { syncLeadWithDocuments } = await import('./services/customCrmService');
        const result = await syncLeadWithDocuments(settings, fieldMappings, leadContext, storeCredential);

        if (result.success) {
          await db.update(whatsappLeads)
            .set({
              customCrmSyncStatus: 'synced',
              customCrmSyncedAt: new Date(),
              customCrmLeadId: result.leadId || result.applicationId || null,
              customCrmSyncError: null,
              customCrmSyncPayload: result.payload as any,
              updatedAt: new Date(),
            })
            .where(eq(whatsappLeads.id, leadId));

          res.json({ success: true, message: result.message, crmLeadId: result.leadId, applicationId: result.applicationId, documentResults: (result as any).documentResults });
        } else {
          await db.update(whatsappLeads)
            .set({
              customCrmSyncStatus: 'failed',
              customCrmSyncError: result.message,
              customCrmSyncPayload: result.payload as any,
              updatedAt: new Date(),
            })
            .where(eq(whatsappLeads.id, leadId));

          res.status(400).json({ success: false, error: result.message });
        }
      } else {
        const lead = await storage.getLead(leadId, businessAccountId);
        if (!lead) {
          return res.status(404).json({ error: "Lead not found" });
        }

        const leadContext = {
          lead: {
            customerName: lead.name || null,
            customerEmail: lead.email || null,
            customerPhone: lead.phone || null,
            loanAmount: null,
            address: null,
            loanType: null,
            senderPhone: null,
          },
          extracted: {} as Record<string, any>,
        };

        const { syncLead } = await import('./services/customCrmService');
        const result = await syncLead(settings, fieldMappings, leadContext);

        if (result.success) {
          await storage.updateLead(leadId, businessAccountId, {
            customCrmSyncStatus: 'synced',
            customCrmSyncedAt: new Date(),
            customCrmLeadId: result.leadId || null,
            customCrmSyncError: null,
            customCrmSyncPayload: result.payload,
          });
          res.json({ success: true, message: result.message, crmLeadId: result.leadId });
        } else {
          await storage.updateLead(leadId, businessAccountId, {
            customCrmSyncStatus: 'failed',
            customCrmSyncError: result.message,
          });
          res.status(400).json({ success: false, error: result.message });
        }
      }
    } catch (error: any) {
      console.error("[Custom CRM] Sync lead error:", error);
      res.status(500).json({ error: error.message });
    }
  });

  app.post("/api/custom-crm/sync-all-whatsapp-leads", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const user = req.user!;
      const businessAccountId = user.businessAccountId!;

      const [settings] = await db
        .select()
        .from(customCrmSettings)
        .where(eq(customCrmSettings.businessAccountId, businessAccountId))
        .limit(1);

      if (!settings || !settings.enabled) {
        return res.status(400).json({ error: "Custom CRM integration is not enabled" });
      }

      if (!settings.apiBaseUrl || !settings.apiEndpoint) {
        return res.status(400).json({ error: "Custom CRM API URL not configured" });
      }

      const fieldMappings = await db
        .select()
        .from(customCrmFieldMappings)
        .where(eq(customCrmFieldMappings.businessAccountId, businessAccountId))
        .orderBy(customCrmFieldMappings.sortOrder);

      if (fieldMappings.length === 0) {
        return res.status(400).json({ error: "No field mappings configured" });
      }

      const unsyncedLeads = await db
        .select()
        .from(whatsappLeads)
        .where(and(
          eq(whatsappLeads.businessAccountId, businessAccountId),
          sql`(${whatsappLeads.customCrmSyncStatus} IS NULL OR ${whatsappLeads.customCrmSyncStatus} = 'failed')`
        ))
        .orderBy(desc(whatsappLeads.createdAt));

      if (unsyncedLeads.length === 0) {
        return res.json({ success: true, message: "No unsynced leads found", synced: 0, failed: 0, total: 0 });
      }

      const storeCreds = await db
        .select()
        .from(crmStoreCredentials)
        .where(and(
          eq(crmStoreCredentials.businessAccountId, businessAccountId),
          eq(crmStoreCredentials.isActive, true)
        ));

      const { syncLeadWithDocuments } = await import('./services/customCrmService');
      let syncedCount = 0;
      let failedCount = 0;
      const norm = (s?: string | null) => s ? s.trim().toLowerCase() : '';

      for (const lead of unsyncedLeads) {
        try {
          const extractedData = (lead.extractedData as Record<string, any>) || {};
          const documents = await buildDocumentContext(lead.id);
          const leadContext = {
            lead: {
              customerName: lead.customerName || null,
              customerEmail: lead.customerEmail || null,
              customerPhone: lead.customerPhone || null,
              loanAmount: lead.loanAmount || null,
              address: lead.address || null,
              loanType: lead.loanType || null,
              senderPhone: lead.senderPhone || null,
            },
            extracted: extractedData,
            documents,
          };

          let storeCredential = undefined;
          const sName = extractedData.store_name || extractedData.storeName;
          const dName = extractedData.dealer_name || extractedData.dealerName || extractedData.dealer;
          const cName = extractedData.city || extractedData.city_name || extractedData.dealer_city || extractedData.dealerCity;

          if ((sName || dName) && storeCreds.length > 0) {
            const nS = norm(sName);
            const nD = norm(dName);
            const nC = norm(cName);
            if (nS && nD && nC) {
              storeCredential = storeCreds.find(sc => norm(sc.storeName) === nS && norm(sc.dealerName) === nD && norm(sc.city) === nC);
            }
            if (!storeCredential && nS && nD) {
              storeCredential = storeCreds.find(sc => norm(sc.storeName) === nS && norm(sc.dealerName) === nD);
            }
            if (!storeCredential && nS) {
              storeCredential = storeCreds.find(sc => norm(sc.storeName) === nS);
            }
            if (!storeCredential && storeCreds.length > 0 && (nS || nD)) {
              try {
                const OpenAI = (await import('openai')).default;
                const [bizAcct] = await db.select().from(businessAccounts).where(eq(businessAccounts.id, businessAccountId)).limit(1);
                const openaiApiKey = bizAcct?.openaiApiKey ? (await import('./services/encryptionService')).decrypt(bizAcct.openaiApiKey) : process.env.OPENAI_API_KEY;
                if (openaiApiKey) {
                  const openaiClient = new OpenAI({ apiKey: openaiApiKey, timeout: 15000 });
                  const storeList = storeCreds.map(sc => ({ id: sc.id, dealerName: sc.dealerName, storeName: sc.storeName, city: sc.city || '', storeId: sc.storeId }));
                  const prompt = `Match the lead's store info to the closest store credential.\n\nLead info:\n- Dealer: ${dName || 'unknown'}\n- City: ${cName || 'unknown'}\n- Store: ${sName || 'unknown'}\n\nAvailable stores (JSON):\n${JSON.stringify(storeList)}\n\nReturn ONLY a JSON object: {"matchedId": "<store id or null>", "confidence": <0.0-1.0>}\nIf no good match exists, return {"matchedId": null, "confidence": 0}`;
                  const completion = await openaiClient.chat.completions.create({
                    model: 'gpt-4o-mini',
                    messages: [{ role: 'user', content: prompt }],
                    temperature: 0,
                    max_tokens: 100,
                    response_format: { type: 'json_object' },
                  });
                  const content = completion.choices[0]?.message?.content;
                  if (content) {
                    const aiResult = JSON.parse(content);
                    if (aiResult.matchedId && aiResult.confidence >= 0.75) {
                      storeCredential = storeCreds.find(sc => sc.id === aiResult.matchedId);
                      console.log(`[CRM BulkSync] AI fuzzy match for lead ${lead.id}: store=${storeCredential?.storeName}, confidence=${aiResult.confidence}`);
                    }
                  }
                }
              } catch (aiErr) {
                console.warn(`[CRM BulkSync] AI fuzzy store matching failed for lead ${lead.id}:`, aiErr);
              }
            }
          }

          const result = await syncLeadWithDocuments(settings, fieldMappings, leadContext, storeCredential);

          if (result.success) {
            await db.update(whatsappLeads)
              .set({
                customCrmSyncStatus: 'synced',
                customCrmSyncedAt: new Date(),
                customCrmLeadId: result.leadId || result.applicationId || null,
                customCrmSyncError: null,
                customCrmSyncPayload: result.payload as any,
                updatedAt: new Date(),
              })
              .where(eq(whatsappLeads.id, lead.id));
            syncedCount++;
          } else {
            await db.update(whatsappLeads)
              .set({
                customCrmSyncStatus: 'failed',
                customCrmSyncError: result.message,
                customCrmSyncPayload: result.payload as any,
                updatedAt: new Date(),
              })
              .where(eq(whatsappLeads.id, lead.id));
            failedCount++;
          }
        } catch (err: any) {
          console.error(`[CRM BulkSync] Error syncing lead ${lead.id}:`, err);
          await db.update(whatsappLeads)
            .set({
              customCrmSyncStatus: 'failed',
              customCrmSyncError: err.message || 'Unknown error',
              updatedAt: new Date(),
            })
            .where(eq(whatsappLeads.id, lead.id));
          failedCount++;
        }
      }

      res.json({
        success: true,
        message: `Bulk sync complete: ${syncedCount} synced, ${failedCount} failed out of ${unsyncedLeads.length} leads`,
        synced: syncedCount,
        failed: failedCount,
        total: unsyncedLeads.length,
      });
    } catch (error: any) {
      console.error("[Custom CRM] Bulk sync error:", error);
      res.status(500).json({ error: error.message });
    }
  });

  app.get("/api/custom-crm/store-credentials/export-template", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const user = req.user!;
      const businessAccountId = user.businessAccountId!;

      const activeFlow = await db
        .select({ id: whatsappFlows.id, name: whatsappFlows.name })
        .from(whatsappFlows)
        .where(and(
          eq(whatsappFlows.businessAccountId, businessAccountId),
          eq(whatsappFlows.isActive, "true")
        ))
        .limit(1);

      if (activeFlow.length === 0) {
        return res.status(404).json({ error: "No active WhatsApp flow found for this account" });
      }

      const steps = await db
        .select()
        .from(whatsappFlowSteps)
        .where(eq(whatsappFlowSteps.flowId, activeFlow[0].id))
        .orderBy(whatsappFlowSteps.stepOrder);

      const dropdownSteps = steps.filter(s => s.type === 'dropdown' || s.type === 'list');

      const stepByField = new Map<string, typeof dropdownSteps[0]>();
      for (const s of dropdownSteps) {
        if (s.saveToField) stepByField.set(s.saveToField, s);
      }

      const storeStep = dropdownSteps.find(s =>
        s.saveToField && /store/i.test(s.saveToField)
      );

      const opts = (step: any) => step?.options as any;

      const extractItems = (step: any): { id: string; title: string }[] => {
        const o = opts(step);
        if (o?.dropdownItems) return o.dropdownItems;
        if (o?.sections) {
          return (o.sections as any[]).flatMap((s: any) => s.rows || s.items || []);
        }
        return [];
      };

      type Row = { dealerName: string; city: string; storeName: string };
      const rows: Row[] = [];

      if (storeStep) {
        const storeOpts = opts(storeStep);
        const storeDepFields: string[] = storeOpts?.dependsOnFields || (storeOpts?.dependsOnField ? [storeOpts.dependsOnField] : []);

        if (storeOpts?.conditionalOptions && storeDepFields.length > 0) {
          const storeCondOpts = storeOpts.conditionalOptions as Record<string, { id: string; title: string }[]>;
          const parentField = storeDepFields[0];
          const parentStep = stepByField.get(parentField);

          if (parentStep) {
            const parentOpts = opts(parentStep);
            const parentDepFields: string[] = parentOpts?.dependsOnFields || (parentOpts?.dependsOnField ? [parentOpts.dependsOnField] : []);

            if (parentOpts?.conditionalOptions && parentDepFields.length > 0) {
              const parentCondOpts = parentOpts.conditionalOptions as Record<string, { id: string; title: string }[]>;
              const extractCityFromTitle = (title: string): string => {
                const lastDash = title.lastIndexOf('-');
                if (lastDash > 0 && lastDash < title.length - 1) {
                  return title.substring(0, lastDash).trim();
                }
                return title;
              };

              for (const [gpKey, parentItems] of Object.entries(parentCondOpts)) {
                const dealerName = gpKey;

                for (const parentItem of parentItems) {
                  const cityValue = extractCityFromTitle(parentItem.title);
                  const stores = storeCondOpts[parentItem.title] || [];

                  for (const store of stores) {
                    rows.push({ dealerName, city: cityValue, storeName: store.title });
                  }
                }
              }
            } else {
              const isDealerParent = /dealer/i.test(parentField);

              for (const [parentKey, stores] of Object.entries(storeCondOpts)) {
                for (const store of stores) {
                  rows.push({
                    dealerName: isDealerParent ? parentKey : '',
                    city: !isDealerParent ? parentKey : '',
                    storeName: store.title,
                  });
                }
              }
            }
          } else {
            for (const [key, stores] of Object.entries(storeCondOpts)) {
              const parts = key.split('|').map(s => s.trim());
              for (const store of stores) {
                rows.push({ dealerName: parts[0] || '', city: parts[1] || '', storeName: store.title });
              }
            }
          }
        } else {
          const storeItems = extractItems(storeStep);
          const dealerStep = dropdownSteps.find(s => s.saveToField && /dealer/i.test(s.saveToField) && !/city/i.test(s.saveToField));
          const dealerItems = dealerStep ? extractItems(dealerStep) : [];

          for (const s of storeItems) {
            rows.push({ dealerName: dealerItems.length > 0 ? dealerItems[0].title : 'Default', city: '', storeName: s.title });
          }
        }
      }

      rows.sort((a, b) => a.dealerName.localeCompare(b.dealerName) || a.city.localeCompare(b.city) || a.storeName.localeCompare(b.storeName));

      if (rows.length === 0) {
        return res.status(404).json({ error: "No store dropdown options found in the active WhatsApp flow. Ensure the flow has a cascading dropdown step that saves to a 'store' field." });
      }

      const existingCreds = await db
        .select({
          dealerName: crmStoreCredentials.dealerName,
          storeName: crmStoreCredentials.storeName,
          city: crmStoreCredentials.city,
          storeId: crmStoreCredentials.storeId,
          sid: crmStoreCredentials.sid,
        })
        .from(crmStoreCredentials)
        .where(and(
          eq(crmStoreCredentials.businessAccountId, businessAccountId),
          eq(crmStoreCredentials.isActive, true)
        ));

      const credMap = new Map<string, { storeId: number | null; sid: string }>();
      for (const c of existingCreds) {
        const key = `${(c.dealerName || '').trim().toLowerCase()}|${(c.city || '').trim().toLowerCase()}|${(c.storeName || '').trim().toLowerCase()}`;
        credMap.set(key, { storeId: c.storeId, sid: c.sid });
      }

      const excelRows = rows.map(r => {
        const key = `${r.dealerName.trim().toLowerCase()}|${r.city.trim().toLowerCase()}|${r.storeName.trim().toLowerCase()}`;
        const match = credMap.get(key);
        return {
          'Dealer Name': r.dealerName,
          'City': r.city,
          'Store Name': r.storeName,
          'Store ID': match?.storeId ?? '',
          'SID': match?.sid ?? '',
          'Secret': '',
        };
      });

      const XLSX = await import('xlsx');
      const ws = XLSX.utils.json_to_sheet(excelRows);
      const colWidths = [
        { wch: 25 }, { wch: 20 }, { wch: 40 }, { wch: 12 }, { wch: 15 }, { wch: 25 },
      ];
      ws['!cols'] = colWidths;

      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, ws, 'Store Credentials Template');
      const buf = XLSX.write(wb, { type: 'buffer', bookType: 'xlsx' });

      res.setHeader('Content-Type', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
      res.setHeader('Content-Disposition', 'attachment; filename="store_credentials_template.xlsx"');
      res.send(Buffer.from(buf));
    } catch (error: any) {
      console.error("[Store Credentials] Export template error:", error);
      res.status(500).json({ error: error.message });
    }
  });

