  app.post("/api/public-chat/:token/resume-upload", multer({
    storage: multer.memoryStorage(),
    limits: { fileSize: 10 * 1024 * 1024 },
    fileFilter: (_req, file, cb) => {
      if (file.mimetype === 'application/pdf') {
        cb(null, true);
      } else {
        cb(new Error('Only PDF files are allowed'));
      }
    }
  }).single('resume'), async (req, res) => {
    try {
      const clientIp = req.ip || req.socket.remoteAddress || 'unknown';
      if (!checkResumeRateLimit(clientIp)) {
        return res.status(429).json({ status: 'failed', error: 'Too many resume uploads. Please try again in a minute.' });
      }

      const { token } = req.params;
      const link = await storage.getPublicChatLinkByToken(token);
      if (!link || link.isActive !== 'true') {
        return res.status(404).json({ status: 'failed', error: 'Chat link not found' });
      }

      if (link.password) {
        const verificationCookie = req.signedCookies[`public_chat_verified_${token}`];
        if (verificationCookie !== 'true') {
          return res.status(403).json({ status: 'failed', error: 'Password verification required' });
        }
      }

      const businessAccount = await storage.getBusinessAccount(link.businessAccountId);
      if (!businessAccount || businessAccount.jobPortalEnabled !== 'true') {
        return res.status(403).json({ status: 'failed', error: 'Resume upload not available' });
      }

      if (!req.file) {
        return res.status(400).json({ status: 'failed', error: 'No file uploaded' });
      }

      const { pdfProcessingService } = await import('./services/pdfProcessingService');
      const result = await pdfProcessingService.extractTextFromBufferMultiTier(
        req.file.buffer,
        link.businessAccountId,
        () => checkResumeRateLimit(clientIp, true)
      );

      if (result.status !== 'failed' && result.text) {
        const { randomUUID } = await import('crypto');
        const resumeContextId = randomUUID();

        let resumeFileUrl: string | undefined;
        try {
          const { r2Storage } = await import('./services/r2StorageService');
          await r2Storage.ensureInitialized();
          if (r2Storage.isEnabled() && req.file) {
            const uploadResult = await r2Storage.uploadFile(
              req.file.buffer,
              req.file.originalname || `resume-${Date.now()}.pdf`,
              'resumes',
              'application/pdf',
              link.businessAccountId
            );
            if (uploadResult.success && uploadResult.url) {
              resumeFileUrl = uploadResult.url;
              console.log(`[Public Resume Upload] PDF saved to R2: ${resumeFileUrl}`);
            }
          }
        } catch (r2Err: any) {
          console.warn('[Public Resume Upload] R2 upload failed (non-fatal):', r2Err.message);
        }

        resumeTextCache.set(resumeContextId, {
          text: result.text.substring(0, 10000),
          businessAccountId: link.businessAccountId,
          createdAt: Date.now(),
          resumeUrl: resumeFileUrl,
        });

        res.json({
          status: result.status,
          resumeContextId,
          extractionMethod: result.extractionMethod,
          pageCount: result.pageCount,
          warning: result.warning,
        });
      } else {
        res.json({
          status: 'failed',
          extractionMethod: result.extractionMethod,
          pageCount: result.pageCount,
          warning: result.warning,
        });
      }
    } catch (error: any) {
      console.error('[Resume Upload] Error:', error);
      res.status(500).json({ status: 'failed', error: error.message || 'Failed to process resume' });
    }
  });

  // Public: Stream message in public chat (SSE streaming, no auth required)
  app.post("/api/public-chat/:token/stream", async (req, res) => {
    try {
      const { token } = req.params;
      const { message, sessionId, language, visitorSessionId, resumeContextId } = req.body;

      if (!message || typeof message !== 'string') {
        return res.status(400).json({ error: "Message is required" });
      }

      const link = await storage.getPublicChatLinkByToken(token);
      
      if (!link || link.isActive !== "true") {
        return res.status(404).json({ error: "Chat link not found or disabled" });
      }

      // Check password verification if password is set
      if (link.password) {
        const verificationCookie = req.signedCookies[`public_chat_verified_${token}`];
        if (verificationCookie !== 'true') {
          return res.status(403).json({ error: "Password verification required" });
        }
      }

      const businessAccountId = link.businessAccountId;
      const publicUserId = sessionId ? `public_session_${sessionId}` : `public_${token}`;

      // Get widget settings and business account info
      const settings = await storage.getWidgetSettings(businessAccountId);
      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      
      if (!businessAccount) {
        return res.status(404).json({ error: "Business account not found" });
      }

      // Get the API key for this business account
      const openaiApiKey = await storage.getBusinessAccountOpenAIKey(businessAccountId);
      
      if (!openaiApiKey) {
        console.warn('[Public Chat Stream] No OpenAI API key found for business:', businessAccountId);
        return res.status(400).json({ error: "OpenAI API key not configured" });
      }

      const personality = settings?.personality || 'friendly';
      const responseLength = settings?.responseLength || 'balanced';
      const currency = settings?.currency || 'USD';
      const currencySymbols: Record<string, string> = {
        USD: "$", EUR: "€", GBP: "£", JPY: "¥", CNY: "¥", INR: "₹", AUD: "A$",
        CAD: "C$", CHF: "CHF", SEK: "kr", NZD: "NZ$", SGD: "S$", HKD: "HK$",
        NOK: "kr", MXN: "$", BRL: "R$", ZAR: "R", KRW: "₩", TRY: "₺",
        RUB: "₽", IDR: "Rp", THB: "฿", MYR: "RM"
      };
      const currencySymbol = currencySymbols[currency] || "$";

      // Set up SSE headers
      res.setHeader('Content-Type', 'text/event-stream');
      res.setHeader('Cache-Control', 'no-cache');
      res.setHeader('Connection', 'keep-alive');
      res.setHeader('Access-Control-Allow-Origin', '*');

      let resumeText: string | undefined;
      let resumeUrl: string | undefined;
      if (resumeContextId && typeof resumeContextId === 'string') {
        const cached = resumeTextCache.get(resumeContextId);
        if (cached && cached.businessAccountId === businessAccountId) {
          resumeText = cached.text;
          resumeUrl = cached.resumeUrl;
          resumeTextCache.delete(resumeContextId);
          console.log(`[Public Chat Stream] Resume context retrieved (${resumeText.length} chars)${resumeUrl ? ' with PDF URL' : ''}`);
        }
      }

      // Stream the response
      for await (const chunk of chatService.streamMessage(message, {
        userId: publicUserId,
        businessAccountId,
        personality,
        responseLength,
        companyDescription: businessAccount.description || '',
        openaiApiKey,
        currency,
        currencySymbol,
        customInstructions: settings?.customInstructions || undefined,
        preferredLanguage: language || undefined,
        visitorSessionId: visitorSessionId || undefined,
        supportsCalendarUI: true,
        systemMode: businessAccount.systemMode || 'full',
        k12EducationEnabled: businessAccount.k12EducationEnabled === 'true',
        jobPortalEnabled: businessAccount.jobPortalEnabled === 'true',
        resumeText,
        resumeUrl,
      })) {
        res.write(`data: ${JSON.stringify(chunk)}\n\n`);
      }

      res.end();
    } catch (error: any) {
      console.error('[Public Chat Stream] Error:', error);
      res.write(`data: ${JSON.stringify({ type: 'error', data: error.message })}\n\n`);
      res.end();
    }
  });

