  async function performOpenAITryOn(
    openaiKey: string,
    selfieBuffer: Buffer,
    productBuffer: Buffer,
    tryOnPrompt: string
  ): Promise<string> {
    const OpenAI = (await import('openai')).default;
    const { toFile } = await import('openai');
    const sharpModule = (await import('sharp')).default;

    const MAX_DIM = 1024;
    const resizedSelfie = await sharpModule(selfieBuffer)
      .resize({ width: MAX_DIM, height: MAX_DIM, fit: 'inside', withoutEnlargement: true })
      .jpeg({ quality: 85 })
      .toBuffer();
    const resizedProduct = await sharpModule(productBuffer)
      .resize({ width: MAX_DIM, height: MAX_DIM, fit: 'inside', withoutEnlargement: true })
      .jpeg({ quality: 85 })
      .toBuffer();

    console.log(`[Try-On][OpenAI] Selfie: ${(resizedSelfie.length / 1024).toFixed(1)} KB | Product: ${(resizedProduct.length / 1024).toFixed(1)} KB (resized to max ${MAX_DIM}px)`);

    const client = new OpenAI({ apiKey: openaiKey, timeout: 120000 });
    const tryOnStartTime = Date.now();

    try {
      console.log('[Try-On][OpenAI] Trying Responses API with 2 separate images | start time:', new Date().toISOString());

      const selfieB64 = `data:image/jpeg;base64,${resizedSelfie.toString('base64')}`;
      const productB64 = `data:image/jpeg;base64,${resizedProduct.toString('base64')}`;
      const augmentedPrompt = `The first image is a photo of a person. The second image is a product item. ${tryOnPrompt}`;

      const response = await client.responses.create({
        model: 'gpt-image-1',
        input: [
          {
            role: 'user',
            content: [
              { type: 'input_image', image_url: selfieB64, detail: 'high' },
              { type: 'input_image', image_url: productB64, detail: 'high' },
              { type: 'input_text', text: augmentedPrompt },
            ],
          },
        ],
        tools: [{ type: 'image_generation', quality: 'high', size: '1024x1024' }],
      });

      const elapsed = ((Date.now() - tryOnStartTime) / 1000).toFixed(1);
      console.log(`[Try-On][OpenAI] Responses API succeeded in ${elapsed}s`);

      const imageOutput = response.output.find(
        (item: any) => item.type === 'image_generation_call' && item.result
      );

      if (!imageOutput || !(imageOutput as any).result) {
        const outputTypes = response.output.map((item: any) => item.type);
        console.error(`[Try-On][OpenAI] No image in Responses API output. Types: ${JSON.stringify(outputTypes)}`);
        throw new Error('No image returned from Responses API');
      }

      const b64Image = (imageOutput as any).result;
      const resultBuffer = Buffer.from(b64Image, 'base64');
      return `data:image/png;base64,${resultBuffer.toString('base64')}`;

    } catch (responsesErr: any) {
      const errMsg = responsesErr?.message || '';
      const isUnsupported = errMsg.includes('not supported') || responsesErr?.status === 400;

      if (!isUnsupported) {
        throw responsesErr;
      }

      console.log(`[Try-On][OpenAI] Responses API not supported for this key, falling back to images.edit composite approach`);

      const selfiePng = await sharpModule(resizedSelfie).png().toBuffer();
      const productPng = await sharpModule(resizedProduct).png().toBuffer();
      const [selfieMeta, productMeta] = await Promise.all([
        sharpModule(selfiePng).metadata(),
        sharpModule(productPng).metadata(),
      ]);

      const targetH = Math.max(selfieMeta.height || 512, productMeta.height || 512);
      const totalW = (selfieMeta.width || 512) + (productMeta.width || 512);

      const compositeImage = await sharpModule({
        create: { width: totalW, height: targetH, channels: 4 as const, background: { r: 255, g: 255, b: 255, alpha: 1 } },
      })
        .composite([
          { input: selfiePng, left: 0, top: 0 },
          { input: productPng, left: selfieMeta.width || 512, top: 0 },
        ])
        .png()
        .toBuffer();

      console.log(`[Try-On][OpenAI] Composite image: ${totalW}x${targetH} | ${(compositeImage.length / 1024).toFixed(1)} KB`);

      const imageFile = await toFile(compositeImage, 'tryon_input.png', { type: 'image/png' });
      const compositePrompt = `This image contains two photos side by side. The LEFT photo is a person (selfie). The RIGHT photo is a product/jewelry item. ${tryOnPrompt}`;

      console.log('[Try-On][OpenAI] Calling gpt-image-1 via images.edit | start time:', new Date().toISOString());

      const response = await client.images.edit({
        model: 'gpt-image-1',
        image: imageFile,
        prompt: compositePrompt,
        size: '1024x1024',
      });

      const elapsed = ((Date.now() - tryOnStartTime) / 1000).toFixed(1);
      console.log(`[Try-On][OpenAI] images.edit responded in ${elapsed}s`);

      if (!response.data || response.data.length === 0) {
        throw new Error('No image returned from OpenAI gpt-image-1 images.edit');
      }

      const generatedData = response.data[0];
      let resultBuffer: Buffer;

      if (generatedData.b64_json) {
        resultBuffer = Buffer.from(generatedData.b64_json, 'base64');
      } else if (generatedData.url) {
        const imgResp = await fetch(generatedData.url);
        if (!imgResp.ok) {
          throw new Error(`Failed to fetch generated image from URL (status ${imgResp.status})`);
        }
        resultBuffer = Buffer.from(await imgResp.arrayBuffer());
      } else {
        throw new Error('No image data in OpenAI images.edit response');
      }

      return `data:image/png;base64,${resultBuffer.toString('base64')}`;
    }
  }

  // Virtual Try-On endpoint - user uploads selfie + product image, AI generates try-on preview
  app.post("/api/chat/widget/try-on", upload.fields([
    { name: 'selfie', maxCount: 1 },
    { name: 'product', maxCount: 1 }
  ]), async (req, res) => {
    let provider: string = 'google';
    let businessAccount: any = null;
    let selfieBuffer: Buffer = Buffer.alloc(0);
    let productBuffer: Buffer = Buffer.alloc(0);
    let tryOnPrompt: string = '';
    let productName: string = '';

    try {
      const { businessAccountId, productImageUrl, productName: pName, productType } = req.body;
      productName = pName || '';
      
      if (!businessAccountId) {
        return res.status(400).json({ error: "businessAccountId is required" });
      }

      businessAccount = await storage.getBusinessAccount(businessAccountId);
      if (!businessAccount) {
        return res.status(404).json({ error: "Business account not found" });
      }

      const widgetSettings = await storage.getWidgetSettings(businessAccountId);
      if (widgetSettings?.tryOnEnabled !== 'true') {
        return res.status(403).json({ error: "Virtual try-on is not enabled for this business" });
      }

      provider = (businessAccount.vistaImageProvider as 'openai' | 'google') || 'google';
      
      const { decrypt } = await import('./services/encryptionService');
      let apiKey: string | null = null;
      if (provider === 'google') {
        if (businessAccount.googleNanoBananaApiKey) {
          try {
            apiKey = decrypt(businessAccount.googleNanoBananaApiKey);
          } catch (e) {
            const raw = businessAccount.googleNanoBananaApiKey;
            if (!raw.includes(':')) apiKey = raw;
          }
        }
      } else {
        if (businessAccount.openaiApiKey) {
          try {
            apiKey = decrypt(businessAccount.openaiApiKey);
          } catch (e) {
            const raw = businessAccount.openaiApiKey;
            if (raw.startsWith('sk-') || !raw.includes(':')) apiKey = raw;
          }
        }
      }

      let apiKeySource = 'none';
      if (apiKey) {
        apiKeySource = 'business-account';
        console.log(`[Try-On] API key resolved from: ${apiKeySource} | key length: ${apiKey.length}`);
      }

      if (!apiKey) {
        const masterSettings = await storage.getMasterAiSettings();
        if (provider === 'openai' && masterSettings?.primaryApiKey) {
          apiKey = masterSettings.primaryApiKey;
          apiKeySource = 'master-settings';
        } else if (provider === 'openai') {
          apiKey = process.env.OPENAI_API_KEY || process.env.AI_INTEGRATIONS_OPENAI_API_KEY || null;
          if (apiKey) apiKeySource = 'env-var';
        }
      }

      if (!apiKey) {
        console.error(`[Try-On] No API key found for provider: ${provider} — checked business-account, master-settings, env-var`);
        return res.status(400).json({ 
          error: `${provider === 'google' ? 'Google Nano Banana Pro' : 'OpenAI'} API key is required for Try-On feature. Please configure it in settings.` 
        });
      }

      console.log(`[Try-On] API key resolved from: ${apiKeySource} | provider: ${provider} | key length: ${apiKey.length}`);

      let selfieMimeType = 'image/jpeg';
      const files = req.files as { [fieldname: string]: Express.Multer.File[] };
      
      if (files?.selfie?.[0]) {
        selfieBuffer = files.selfie[0].buffer;
        selfieMimeType = files.selfie[0].mimetype || 'image/jpeg';
      } else if (req.body.selfieDataUrl) {
        const selfieDataUrlMatch = req.body.selfieDataUrl.match(/^data:(image\/\w+);base64,/);
        selfieMimeType = selfieDataUrlMatch ? selfieDataUrlMatch[1] : 'image/jpeg';
        const base64Data = req.body.selfieDataUrl.replace(/^data:image\/\w+;base64,/, '');
        selfieBuffer = Buffer.from(base64Data, 'base64');
      } else {
        return res.status(400).json({ error: "Selfie image is required" });
      }

      // Helper: detect MIME type from buffer magic bytes
      const detectMimeType = (buf: Buffer): string => {
        if (buf[0] === 0xFF && buf[1] === 0xD8 && buf[2] === 0xFF) return 'image/jpeg';
        if (buf[0] === 0x89 && buf[1] === 0x50 && buf[2] === 0x4E && buf[3] === 0x47) return 'image/png';
        if (buf[0] === 0x52 && buf[1] === 0x49 && buf[2] === 0x46 && buf[3] === 0x46 &&
            buf[8] === 0x57 && buf[9] === 0x45 && buf[10] === 0x42 && buf[11] === 0x50) return 'image/webp';
        if (buf[0] === 0x47 && buf[1] === 0x49 && buf[2] === 0x46) return 'image/gif';
        return 'image/jpeg'; // safe default
      };

      let productMimeType = 'image/jpeg';
      if (files?.product?.[0]) {
        productBuffer = files.product[0].buffer;
        productMimeType = files.product[0].mimetype || detectMimeType(productBuffer);
      } else if (req.body.productDataUrl) {
        const dataUrlMatch = req.body.productDataUrl.match(/^data:(image\/\w+);base64,/);
        productMimeType = dataUrlMatch ? dataUrlMatch[1] : 'image/jpeg';
        const base64Data = req.body.productDataUrl.replace(/^data:image\/\w+;base64,/, '');
        productBuffer = Buffer.from(base64Data, 'base64');
      } else if (productImageUrl) {
        // Fetch product image from URL
        const productFetchResponse = await fetch(productImageUrl);
        if (!productFetchResponse.ok) {
          return res.status(400).json({ error: "Failed to fetch product image" });
        }
        const contentType = productFetchResponse.headers.get('content-type');
        const arrayBuffer = await productFetchResponse.arrayBuffer();
        productBuffer = Buffer.from(arrayBuffer);
        productMimeType = (contentType && contentType.startsWith('image/'))
          ? contentType.split(';')[0].trim()
          : detectMimeType(productBuffer);
      } else {
        return res.status(400).json({ error: "Product image is required" });
      }

      // Confirm selfie MIME from magic bytes if not already detected
      if (selfieMimeType === 'image/jpeg') {
        selfieMimeType = detectMimeType(selfieBuffer);
      }

      // Gemini only supports: jpeg, png, gif, webp — convert anything else to jpeg
      const GEMINI_SUPPORTED_MIME = ['image/jpeg', 'image/png', 'image/gif', 'image/webp'];

      if (!GEMINI_SUPPORTED_MIME.includes(selfieMimeType)) {
        console.log(`[Try-On] Converting selfie from ${selfieMimeType} → image/jpeg`);
        selfieBuffer = await sharp(selfieBuffer).jpeg({ quality: 90 }).toBuffer();
        selfieMimeType = 'image/jpeg';
      }

      if (!GEMINI_SUPPORTED_MIME.includes(productMimeType)) {
        console.log(`[Try-On] Converting product from ${productMimeType} → image/jpeg`);
        productBuffer = await sharp(productBuffer).jpeg({ quality: 90 }).toBuffer();
        productMimeType = 'image/jpeg';
      }

      console.log('[Try-On] Processing request for product:', productName || 'Unknown');
      console.log(`[Try-On] Selfie buffer size: ${(selfieBuffer.length / 1024).toFixed(1)} KB | MIME: ${selfieMimeType}`);
      console.log(`[Try-On] Product buffer size: ${(productBuffer.length / 1024).toFixed(1)} KB | MIME: ${productMimeType}`);

      let jewelryType = (productType || 'accessory').toLowerCase();

      try {
        const OpenAIDetect = (await import('openai')).default;
        let detectKey: string | null = null;
        if (businessAccount.openaiApiKey) {
          try {
            const { decrypt: dec } = await import('./services/encryptionService');
            detectKey = dec(businessAccount.openaiApiKey);
          } catch {
            const raw = businessAccount.openaiApiKey;
            if (raw.startsWith('sk-') || !raw.includes(':')) detectKey = raw;
          }
        }
        if (!detectKey) {
          const ms = await storage.getMasterAiSettings();
          if (ms?.primaryApiKey) detectKey = ms.primaryApiKey;
        }
        if (!detectKey) {
          detectKey = process.env.OPENAI_API_KEY || process.env.AI_INTEGRATIONS_OPENAI_API_KEY || null;
        }

        if (detectKey) {
          const detectClient = new OpenAIDetect({ apiKey: detectKey, timeout: 10000 });
          const productBase64ForDetect = productBuffer.toString('base64');
          const detectResponse = await detectClient.chat.completions.create({
            model: 'gpt-4o-mini',
            max_tokens: 20,
            messages: [{
              role: 'user',
              content: [
                { type: 'image_url', image_url: { url: `data:${productMimeType};base64,${productBase64ForDetect}`, detail: 'low' } },
                { type: 'text', text: 'What is this product? Reply with ONLY the product type in 1-3 words (e.g., watch, necklace, earring, ring, bracelet, t-shirt, sunglasses, hat, handbag, shoe). Nothing else.' }
              ]
            }]
          });
          const detected = detectResponse.choices?.[0]?.message?.content?.trim().toLowerCase();
          if (detected && detected.length < 30) {
            console.log(`[Try-On] AI detected product type: "${detected}" (was: "${jewelryType}")`);
            jewelryType = detected;
          }
        } else {
          console.log('[Try-On] No OpenAI key for product detection, using fallback:', jewelryType);
        }
      } catch (detectErr: any) {
        console.log(`[Try-On] Product detection failed (${detectErr?.message}), using fallback: ${jewelryType}`);
      }

      console.log(`[Try-On] Final product type for prompt: ${jewelryType}`);
      
      if (jewelryType.includes('necklace') || jewelryType.includes('chain') || jewelryType.includes('pendant')) {
        tryOnPrompt = `Take the person in the first image and show them wearing the jewelry from the second image. 
Place the necklace/pendant naturally around their neck, ensuring:
- The necklace drapes realistically on their chest/neckline
- The size and proportion match their body
- The lighting on the jewelry matches the person's lighting
- The jewelry's reflections and shadows look natural
- Preserve the exact design of the jewelry without modification
- Preserve the person's face, clothing, and background exactly as they appear`;
      } else if (jewelryType.includes('earring')) {
        tryOnPrompt = `Take the person in the first image and show them wearing the earrings from the second image.
Place the earrings naturally on their ears, ensuring:
- The earrings hang or attach to the ears realistically
- The size and proportion match their face
- The lighting on the earrings matches the person's lighting
- Preserve the exact design of the earrings without modification
- Preserve the person's face, hairstyle, and background exactly`;
      } else if (jewelryType.includes('ring')) {
        tryOnPrompt = `Take the person in the first image and show them wearing the ring from the second image.
Place the ring naturally on their finger, ensuring:
- The ring fits realistically on an appropriate finger
- The size looks proportional to their hand
- The lighting and reflections look natural
- Preserve the exact design of the ring without modification
- Preserve the rest of the image exactly`;
      } else if (jewelryType.includes('bangle') || jewelryType.includes('bracelet')) {
        tryOnPrompt = `Take the person in the first image and show them wearing the bangle/bracelet from the second image.
Place the jewelry naturally on their wrist, ensuring:
- The bangle/bracelet fits realistically around their wrist
- The size looks proportional
- The lighting and reflections look natural
- Preserve the exact design of the jewelry without modification
- Preserve the rest of the image exactly`;
      } else {
        // Generic jewelry/clothing try-on
        tryOnPrompt = `Take the person from the first image and realistically apply the ${jewelryType} from the second image onto the correct anatomical position.

Strict Requirements:
- Detect the correct body region for ${jewelryType}.
- Align the item according to body pose and perspective.
- Adjust scale proportionally to the person's body dimensions.
- Match lighting direction, intensity, and shadow softness.
- Blend edges naturally with skin or clothing.
- Apply realistic occlusion (hair, sleeves, folds).
- Preserve the exact product design, texture, logo, and color without modification.
- Do not change the person's face, expression, body shape, or background.
- Ensure photorealistic output with no floating artifacts.`;
      }

      // Import and use the image provider
      const { createImageProvider } = await import('./services/imageGenerationProviders');
      const imageProvider = createImageProvider(provider, apiKey);

      // For multi-image prompts with Google, we need to modify the approach
      if (provider === 'google') {
        const { GoogleGenAI } = await import('@google/genai');
        const client = new GoogleGenAI({ apiKey });

        const selfieBase64 = selfieBuffer.toString('base64');
        const productBase64 = productBuffer.toString('base64');

        const tryOnStartTime = Date.now();
        console.log('[Try-On] Calling gemini-3-pro-image-preview | start time:', new Date().toISOString());

        const generateContentPromise = client.models.generateContent({
          model: 'gemini-3-pro-image-preview',
          contents: [
            {
              role: 'user',
              parts: [
                {
                  inlineData: {
                    mimeType: selfieMimeType,
                    data: selfieBase64,
                  },
                },
                {
                  inlineData: {
                    mimeType: productMimeType,
                    data: productBase64,
                  },
                },
                {
                  text: tryOnPrompt,
                },
              ],
            },
          ],
          config: {
            responseModalities: ['TEXT', 'IMAGE'],
          } as any,
        });

        const timeoutPromise = new Promise<never>((_, reject) =>
          setTimeout(() => reject(new Error('Try-On request timed out after 90 seconds. Please try again.')), 90000)
        );

        const response = await Promise.race([generateContentPromise, timeoutPromise]);

        const tryOnElapsed = ((Date.now() - tryOnStartTime) / 1000).toFixed(1);
        console.log(`[Try-On] Gemini responded in ${tryOnElapsed}s`);
        console.log(`[Try-On] Candidates count: ${response.candidates?.length ?? 0}`);

        if (!response.candidates || response.candidates.length === 0) {
          console.error('[Try-On] No candidates in response. Full response:', JSON.stringify(response, null, 2));
          throw new Error('No response from Google AI');
        }

        const candidate = response.candidates[0];
        console.log(`[Try-On] Candidate finish reason: ${candidate.finishReason ?? 'N/A'}`);
        if (candidate.safetyRatings && candidate.safetyRatings.length > 0) {
          console.log('[Try-On] Safety ratings:', JSON.stringify(candidate.safetyRatings));
        }

        if (!candidate.content || !candidate.content.parts) {
          console.error('[Try-On] No content/parts in candidate:', JSON.stringify(candidate, null, 2));
          throw new Error('No content in response');
        }

        console.log(`[Try-On] Parts count: ${candidate.content.parts.length}`);
        candidate.content.parts.forEach((part: any, i: number) => {
          if (part.inlineData) {
            console.log(`[Try-On] Part[${i}]: inlineData | mimeType: ${part.inlineData.mimeType} | data length: ${part.inlineData.data?.length ?? 0} chars`);
          } else if (part.text !== undefined) {
            console.log(`[Try-On] Part[${i}]: text | content: "${part.text?.substring(0, 200)}"`);
          } else {
            console.log(`[Try-On] Part[${i}]: unknown type | keys: ${Object.keys(part).join(', ')}`);
          }
        });

        let resultImageData: string | undefined;
        for (const part of candidate.content.parts) {
          if (part.inlineData && part.inlineData.data) {
            resultImageData = part.inlineData.data;
            break;
          }
        }

        if (!resultImageData) {
          console.error('[Try-On] No image part found in response. Parts were:', candidate.content.parts.map((p: any) => Object.keys(p).join(',')).join(' | '));
          throw new Error('No image generated. The AI may have declined to process this request.');
        }

        const resultDataUrl = `data:image/png;base64,${resultImageData}`;

        console.log('[Try-On] Successfully generated try-on image');

        return res.json({
          success: true,
          tryOnImageUrl: resultDataUrl,
          productName: productName || 'Product',
          message: 'Try-on image generated successfully'
        });

      } else {
        // OpenAI approach - use image editing with gpt-image-1
        const openaiResult = await performOpenAITryOn(apiKey, selfieBuffer, productBuffer, tryOnPrompt);
        console.log('[Try-On] Successfully generated try-on image via OpenAI');
        return res.json({
          success: true,
          tryOnImageUrl: openaiResult,
          productName: productName || 'Product',
          message: 'Try-on image generated successfully'
        });
      }

    } catch (error: any) {
      console.error('[Try-On] Primary provider failed:', error?.message);

      if (provider === 'google' && businessAccount) {
        try {
          console.log('[Try-On] Google failed, falling back to OpenAI...');
          const { decrypt } = await import('./services/encryptionService');
          let fallbackKey: string | null = null;

          if (businessAccount.openaiApiKey) {
            try {
              fallbackKey = decrypt(businessAccount.openaiApiKey);
            } catch (e) {
              const raw = businessAccount.openaiApiKey;
              if (raw.startsWith('sk-') || !raw.includes(':')) fallbackKey = raw;
            }
          }

          if (!fallbackKey) {
            const masterSettings = await storage.getMasterAiSettings();
            if (masterSettings?.primaryApiKey) fallbackKey = masterSettings.primaryApiKey;
          }
          if (!fallbackKey) {
            fallbackKey = process.env.OPENAI_API_KEY || process.env.AI_INTEGRATIONS_OPENAI_API_KEY || null;
          }

          if (!fallbackKey) {
            console.error('[Try-On] No OpenAI fallback key available, re-throwing original error');
            throw error;
          }

          console.log(`[Try-On] Fallback OpenAI key found (length: ${fallbackKey.length})`);
          const fallbackResult = await performOpenAITryOn(fallbackKey, selfieBuffer, productBuffer, tryOnPrompt);
          console.log('[Try-On] Successfully generated try-on image via OpenAI fallback');
          return res.json({
            success: true,
            tryOnImageUrl: fallbackResult,
            productName: productName || 'Product',
            message: 'Try-on image generated successfully (via fallback)'
          });
        } catch (fallbackError: any) {
          console.error('[Try-On] OpenAI fallback also failed:', fallbackError?.message);
        }
      }

      console.error('[Try-On] Error code:', error?.code);
      console.error('[Try-On] Error status:', error?.status);
      console.error('[Try-On] Error details:', error?.details ? JSON.stringify(error.details) : 'none');
      console.error('[Try-On] Error stack:', error?.stack?.split('\n').slice(0, 5).join(' | '));
      return res.status(500).json({ error: error.message || 'Try-on generation failed' });
    }
  });

  // Configure multer for Excel file uploads (memory storage)
  const excelUpload = multer({
    storage: multer.memoryStorage(),
    limits: {
      fileSize: 10 * 1024 * 1024, // 10MB limit
    },
    fileFilter: (req, file, cb) => {
      // Accept Excel and CSV files
      const allowedMimes = [
        'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet', // .xlsx
        'application/vnd.ms-excel', // .xls
        'text/csv', // .csv
      ];
      const allowedExtensions = ['.xlsx', '.xls', '.csv'];
      const fileExtension = path.extname(file.originalname).toLowerCase();
      
      if (allowedMimes.includes(file.mimetype) || allowedExtensions.includes(fileExtension)) {
        cb(null, true);
      } else {
        cb(new Error('Invalid file type. Only Excel (.xlsx, .xls) and CSV (.csv) files are allowed.'));
      }
    },
  });

  // Configure multer for PDF file uploads (memory storage for R2 support)
  const trainingDocsDir = path.join(process.cwd(), "uploads", "training-docs");
  
  // Ensure training-docs directory exists (fallback for local storage)
  if (!fs.existsSync(trainingDocsDir)) {
    fs.mkdirSync(trainingDocsDir, { recursive: true });
  }

  const pdfUpload = multer({
    storage: multer.memoryStorage(),
    limits: {
      fileSize: 25 * 1024 * 1024, // 25MB limit
    },
    fileFilter: (req, file, cb) => {
      // Accept only PDF files
      const allowedMimes = ['application/pdf'];
      const allowedExtensions = ['.pdf'];
      const fileExtension = path.extname(file.originalname).toLowerCase();
      
      if (allowedMimes.includes(file.mimetype) || allowedExtensions.includes(fileExtension)) {
        cb(null, true);
      } else {
        cb(new Error('Invalid file type. Only PDF files are allowed.'));
      }
    },
  });

  // Configure multer for avatar uploads (memory storage for R2 support)
  const avatarDir = path.join(process.cwd(), "public", "avatars", "custom");
  
  // Ensure avatar directory exists (fallback for local storage)
  if (!fs.existsSync(avatarDir)) {
    fs.mkdirSync(avatarDir, { recursive: true });
  }

  const avatarUpload = multer({
    storage: multer.memoryStorage(),
    limits: {
      fileSize: 5 * 1024 * 1024, // 5MB limit
    },
    fileFilter: (req, file, cb) => {
      // Accept only image files (jpg, jpeg, png, webp)
      const allowedMimes = ['image/jpeg', 'image/jpg', 'image/png', 'image/webp'];
      const allowedExtensions = ['.jpg', '.jpeg', '.png', '.webp'];
      const fileExtension = path.extname(file.originalname).toLowerCase();
      
      if (allowedMimes.includes(file.mimetype) || allowedExtensions.includes(fileExtension)) {
        cb(null, true);
      } else {
        cb(new Error('Invalid file type. Only JPG, JPEG, PNG, and WebP images are allowed.'));
      }
    },
  });

  // Upload product image endpoint
  app.post("/api/upload-image", requireAuth, requireBusinessAccount, upload.single('image'), async (req, res) => {
    try {
      if (!req.file) {
        return res.status(400).json({ error: "No file uploaded" });
      }

      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      let imageUrl: string;

      // Ensure R2 is initialized (checks database config if not already loaded)
      await r2Storage.ensureInitialized();

      // Try R2 storage first, fall back to local storage
      if (r2Storage.isEnabled()) {
        const result = await r2Storage.uploadFile(
          req.file.buffer,
          req.file.originalname,
          "products",
          req.file.mimetype,
          businessAccountId
        );

        if (result.success && result.url) {
          imageUrl = result.url;
          console.log('[Product Image Upload] Uploaded to R2:', imageUrl);
        } else {
          console.error('[Product Image Upload] R2 upload failed:', result.error);
          return res.status(500).json({ error: "Failed to upload image" });
        }
      } else {
        // Fallback to local storage with business ID directory
        const businessDir = path.join(portfolioDir, businessAccountId);
        if (!fs.existsSync(businessDir)) {
          fs.mkdirSync(businessDir, { recursive: true });
        }
        const uniqueName = `${randomUUID()}${path.extname(req.file.originalname)}`;
        const filepath = path.join(businessDir, uniqueName);
        fs.writeFileSync(filepath, req.file.buffer);
        imageUrl = `/portfolio/${businessAccountId}/${uniqueName}`;
        console.log('[Product Image Upload] Saved locally:', imageUrl);
      }

      res.json({ imageUrl });
    } catch (error: any) {
      console.error("Error uploading image:", error);
      res.status(500).json({ error: error.message || "Failed to upload image" });
    }
  });

  // Delete product image endpoint
  app.delete("/api/delete-image", requireAuth, async (req, res) => {
    try {
      const { imageUrl } = req.body;
      
      if (!imageUrl) {
        return res.status(400).json({ error: "Image URL required" });
      }

      // Check if this is an R2 URL
      if (imageUrl.startsWith('https://') && imageUrl.includes('.r2.')) {
        const key = r2Storage.extractKeyFromUrl(imageUrl);
        if (key) {
          const result = await r2Storage.deleteFile(key);
          if (!result.success) {
            console.error('[Product Image Delete] R2 delete failed:', result.error);
          }
        }
        return res.json({ success: true });
      }

      // Handle local file deletion
      const filename = imageUrl.replace('/portfolio/', '');
      
      // Sanitize filename to prevent directory traversal
      const sanitizedFilename = path.basename(filename);
      
      // Ensure filename doesn't start with a dot (hidden files)
      if (sanitizedFilename.startsWith('.')) {
        return res.status(403).json({ error: "Access denied" });
      }
      
      const filepath = path.join(portfolioDir, sanitizedFilename);
      
      // Verify the resolved path is within the Portfolio directory
      const normalizedPath = path.normalize(filepath);
      if (!normalizedPath.startsWith(portfolioDir)) {
        return res.status(403).json({ error: "Access denied" });
      }

      // Delete file if it exists
      if (fs.existsSync(normalizedPath)) {
        fs.unlinkSync(normalizedPath);
      }

      res.json({ success: true });
    } catch (error: any) {
      console.error("Error deleting image:", error);
      res.status(500).json({ error: error.message || "Failed to delete image" });
    }
  });

  // Serve images from Portfolio directory
  app.get("/portfolio/:filename", async (req, res) => {
    try {
      const filename = req.params.filename;
      
      // Sanitize filename to prevent directory traversal
      const sanitizedFilename = path.basename(filename);
      
      // Ensure filename doesn't start with a dot (hidden files)
      if (sanitizedFilename.startsWith('.')) {
        return res.status(403).json({ error: "Access denied" });
      }
      
      const filepath = path.join(portfolioDir, sanitizedFilename);
      
      // Verify the resolved path is within the Portfolio directory
      const normalizedPath = path.normalize(filepath);
      if (!normalizedPath.startsWith(portfolioDir)) {
        return res.status(403).json({ error: "Access denied" });
      }

      // Check if file exists
      if (!fs.existsSync(normalizedPath)) {
        return res.status(404).json({ error: "Image not found" });
      }

      // Send file with appropriate headers
      res.sendFile(normalizedPath, {
        headers: {
          'Cache-Control': 'public, max-age=31536000', // Cache for 1 year
        }
      });
    } catch (error: any) {
      console.error("Error serving image:", error);
      res.status(500).json({ error: "Failed to serve image" });
    }
  });

