  app.get("/api/products", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }
      
      // Support pagination with optional page and limit params
      const page = parseInt(req.query.page as string) || 1;
      const limit = parseInt(req.query.limit as string) || 0; // 0 means no limit (backwards compatible)
      const source = req.query.source as string | undefined; // Optional source filter
      
      let products = await storage.getAllProducts(businessAccountId);
      
      // Filter by source if provided
      if (source) {
        products = products.filter(p => p.source === source);
      }
      
      // If no limit, return all products (backwards compatible)
      if (limit === 0) {
        return res.json(products);
      }
      
      // Apply pagination
      const total = products.length;
      const totalPages = Math.ceil(total / limit);
      const offset = (page - 1) * limit;
      const paginatedProducts = products.slice(offset, offset + limit);
      
      res.json({
        products: paginatedProducts,
        pagination: {
          page,
          limit,
          total,
          totalPages,
          hasMore: page < totalPages
        }
      });
    } catch (error: any) {
      res.status(500).json({ error: error.message });
    }
  });

  // Price distribution endpoint for Jewelry Showcase histogram (must be before :id route)
  app.get("/api/products/price-distribution", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      const allProducts = await storage.getAllProducts(businessAccountId);
      const prices = allProducts
        .filter(p => p.price)
        .map(p => parseFloat(p.price!))
        .sort((a, b) => a - b);

      if (prices.length === 0) {
        return res.json({
          buckets: [],
          average: 0,
          min: 0,
          max: 0,
          totalProducts: 0
        });
      }

      const min = Math.min(...prices);
      const max = Math.max(...prices);
      const average = prices.reduce((sum, p) => sum + p, 0) / prices.length;
      
      const bucketCount = 20;
      const bucketSize = (max - min) / bucketCount || 1;
      const buckets: { start: number; end: number; count: number }[] = [];
      
      for (let i = 0; i < bucketCount; i++) {
        const start = min + i * bucketSize;
        const end = min + (i + 1) * bucketSize;
        const count = prices.filter(p => p >= start && (i === bucketCount - 1 ? p <= end : p < end)).length;
        buckets.push({ start, end, count });
      }

      res.json({
        buckets,
        average: Math.round(average),
        min: Math.round(min),
        max: Math.round(max),
        totalProducts: prices.length
      });
    } catch (error: any) {
      res.status(500).json({ error: error.message });
    }
  });

