  // Product embeddings debug endpoint - shows all products with their cropped images and embeddings
  // MUST be defined BEFORE /api/products/:id to avoid route collision
  // OPTIMIZED: Does NOT fetch full vector embeddings (768+ dimensions) to avoid memory issues in production
  app.get("/api/products/embeddings-debug", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }
      
      // Get products WITHOUT fetching the actual embedding vectors (they're huge!)
      // Use raw SQL to get embedding existence as booleans
      const allProducts = await db
        .select({
          id: products.id,
          name: products.name,
          imageUrl: products.imageUrl,
          detectedJewelryType: products.detectedJewelryType,
          croppedJewelryUrl: products.croppedJewelryUrl,
          // Use SQL expressions to check if embeddings exist without fetching them
          hasImageEmbedding: sql<boolean>`CASE WHEN ${products.imageEmbedding} IS NOT NULL THEN true ELSE false END`,
          hasFullImageEmbedding: sql<boolean>`CASE WHEN ${products.fullImageEmbedding} IS NOT NULL THEN true ELSE false END`,
        })
        .from(products)
        .where(eq(products.businessAccountId, businessAccountId))
        .orderBy(desc(products.updatedAt))
        .limit(100);
      
      // Get jewelry embeddings WITHOUT the large vector columns
      const productIds = allProducts.map(p => p.id);
      const allEmbeddings = productIds.length > 0 
        ? await db
            .select({
              id: productJewelryEmbeddings.id,
              productId: productJewelryEmbeddings.productId,
              jewelryType: productJewelryEmbeddings.jewelryType,
              confidence: productJewelryEmbeddings.confidence,
              croppedImageUrl: productJewelryEmbeddings.croppedImageUrl,
              processedImageUrl: productJewelryEmbeddings.processedImageUrl,
              boundingBox: productJewelryEmbeddings.boundingBox,
              isPrimary: productJewelryEmbeddings.isPrimary,
              description: productJewelryEmbeddings.description,
              attributes: productJewelryEmbeddings.attributes,
              createdAt: productJewelryEmbeddings.createdAt,
              updatedAt: productJewelryEmbeddings.updatedAt,
              // Check embedding existence without fetching the vectors
              hasEmbedding: sql<boolean>`CASE WHEN ${productJewelryEmbeddings.embedding} IS NOT NULL THEN true ELSE false END`,
              hasDescriptionEmbedding: sql<boolean>`CASE WHEN ${productJewelryEmbeddings.descriptionEmbedding} IS NOT NULL THEN true ELSE false END`,
            })
            .from(productJewelryEmbeddings)
            .where(and(
              eq(productJewelryEmbeddings.businessAccountId, businessAccountId),
              inArray(productJewelryEmbeddings.productId, productIds)
            ))
        : [];
      
      // Map embeddings to products
      const embeddingsByProduct = new Map<string, any[]>();
      for (const emb of allEmbeddings) {
        const existing = embeddingsByProduct.get(emb.productId) || [];
        existing.push(emb);
        embeddingsByProduct.set(emb.productId, existing);
      }
      
      const result = allProducts.map(product => ({
        id: product.id,
        name: product.name,
        imageUrl: product.imageUrl,
        detectedJewelryType: product.detectedJewelryType,
        croppedJewelryUrl: product.croppedJewelryUrl,
        hasImageEmbedding: product.hasImageEmbedding,
        hasFullImageEmbedding: product.hasFullImageEmbedding,
        // Since we don't fetch the actual vectors, we can't get exact dimensions
        // Use fixed 768 dimensions for CLIP embeddings if they exist
        imageEmbeddingSummary: product.hasImageEmbedding ? { dimensions: 768 } : null,
        fullImageEmbeddingSummary: product.hasFullImageEmbedding ? { dimensions: 768 } : null,
        jewelryEmbeddings: (embeddingsByProduct.get(product.id) || []).map(emb => {
          let parsedBoundingBox = null;
          if (emb.boundingBox) {
            try {
              parsedBoundingBox = typeof emb.boundingBox === 'string' 
                ? JSON.parse(emb.boundingBox) 
                : emb.boundingBox;
            } catch (e) {
              console.error('[Embeddings Debug] Failed to parse boundingBox:', e);
            }
          }
          return {
            id: emb.id,
            jewelryType: emb.jewelryType,
            confidence: emb.confidence,
            croppedImageUrl: emb.croppedImageUrl,
            processedImageUrl: emb.processedImageUrl,
            boundingBox: parsedBoundingBox,
            isPrimary: emb.isPrimary,
            description: emb.description,
            hasEmbedding: emb.hasEmbedding,
            hasDescriptionEmbedding: emb.hasDescriptionEmbedding,
            // Use fixed dimensions since we don't fetch actual vectors
            embeddingSummary: emb.hasEmbedding ? { dimensions: 768 } : null,
            descriptionEmbeddingSummary: emb.hasDescriptionEmbedding ? { dimensions: 1536 } : null,
            attributes: emb.attributes,
            embeddedAt: emb.updatedAt // Use updatedAt as embeddedAt proxy
          };
        })
      }));
      
      res.json(result);
    } catch (error: any) {
      console.error("[Embeddings Debug] DETAILED ERROR:");
      console.error("[Embeddings Debug] Message:", error.message);
      console.error("[Embeddings Debug] Code:", error.code);
      console.error("[Embeddings Debug] Detail:", error.detail);
      console.error("[Embeddings Debug] Hint:", error.hint);
      console.error("[Embeddings Debug] Stack:", error.stack);
      console.error("[Embeddings Debug] Full error:", JSON.stringify(error, Object.getOwnPropertyNames(error)));
      res.status(500).json({ 
        error: error.message,
        code: error.code,
        detail: error.detail,
        hint: error.hint
      });
    }
  });

