  // Vista Insights - Visual Search Analytics
  app.get("/api/vista/insights", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      // Get all uploaded images with their match data
      const images = await storage.getUploadedImages(businessAccountId);
      
      // Get all products for category analysis
      const allProducts = await storage.getAllProducts(businessAccountId);
      
      // Build product lookup map
      const productMap = new Map<string, any>();
      for (const p of allProducts) {
        productMap.set(p.id, p);
      }
      
      // Analytics aggregation
      const categoryDistribution: Record<string, number> = {};
      const topMatchedProducts: Record<string, { count: number; product: any }> = {};
      const searchesByHour: Record<number, number> = {};
      const searchesByDay: Record<string, number> = {};
      const demandGaps: any[] = []; // Searches with no/few matches
      
      let totalSearches = images.length;
      let searchesWithMatches = 0;
      let searchesWithExactMatch = 0;
      let totalMatchCount = 0;
      
      for (const image of images) {
        // Parse matched products (with error handling for invalid JSON)
        let matches: any[] = [];
        if (image.matchedProducts) {
          try {
            matches = JSON.parse(image.matchedProducts);
          } catch (parseError) {
            console.warn('[Vista Insights] Skipping image with invalid matchedProducts JSON:', image.id);
            matches = [];
          }
        }
        
        if (matches.length > 0) {
          searchesWithMatches++;
          totalMatchCount += matches.length;
          
          // Check for exact matches
          const hasExact = matches.some((m: any) => m.isExactMatch);
          if (hasExact) {
            searchesWithExactMatch++;
          }
          
          // Track unique categories for THIS search event (to count each search once per category)
          const categoriesInThisSearch = new Set<string>();
          
          // Count matched products
          for (const match of matches) {
            if (match.id) {
              if (!topMatchedProducts[match.id]) {
                topMatchedProducts[match.id] = { 
                  count: 0, 
                  product: productMap.get(match.id) || match 
                };
              }
              topMatchedProducts[match.id].count++;
            }
            
            // Extract category from product (track unique per search)
            const product = productMap.get(match.id);
            if (product?.detectedJewelryType) {
              categoriesInThisSearch.add(product.detectedJewelryType);
            }
          }
          
          // Now increment categoryDistribution once per unique category in this search
          for (const category of categoriesInThisSearch) {
            categoryDistribution[category] = (categoryDistribution[category] || 0) + 1;
          }
        } else {
          // This is a demand gap - search with no matches
          demandGaps.push({
            id: image.id,
            imageUrl: image.imageUrl,
            searchedAt: image.createdAt,
            source: image.source
          });
        }
        
        // Time-based analytics
        const searchDate = new Date(image.createdAt);
        const hour = searchDate.getHours();
        const dayKey = searchDate.toISOString().split('T')[0];
        
        searchesByHour[hour] = (searchesByHour[hour] || 0) + 1;
        searchesByDay[dayKey] = (searchesByDay[dayKey] || 0) + 1;
      }
      
      // Format top matched products (sorted by count)
      const topMatched = Object.entries(topMatchedProducts)
        .map(([id, data]) => ({
          id,
          name: data.product?.name || 'Unknown',
          imageUrl: data.product?.imageUrl,
          matchCount: data.count,
          category: data.product?.detectedJewelryType
        }))
        .sort((a, b) => b.matchCount - a.matchCount)
        .slice(0, 10);
      
      // Format category distribution for pie chart
      const categoryData = Object.entries(categoryDistribution)
        .map(([name, value]) => ({ name, value }))
        .sort((a, b) => b.value - a.value);
      
      // Format hourly distribution for bar chart
      const hourlyData = Array.from({ length: 24 }, (_, hour) => ({
        hour: `${hour.toString().padStart(2, '0')}:00`,
        searches: searchesByHour[hour] || 0
      }));
      
      // Format daily trend (last 30 days)
      const today = new Date();
      const dailyData = Array.from({ length: 30 }, (_, i) => {
        const date = new Date(today);
        date.setDate(date.getDate() - (29 - i));
        const dateKey = date.toISOString().split('T')[0];
        return {
          date: dateKey,
          searches: searchesByDay[dateKey] || 0
        };
      });
      
      // Calculate success rate
      const successRate = totalSearches > 0 
        ? Math.round((searchesWithMatches / totalSearches) * 100) 
        : 0;
      
      const exactMatchRate = totalSearches > 0
        ? Math.round((searchesWithExactMatch / totalSearches) * 100)
        : 0;
      
      const avgMatchesPerSearch = searchesWithMatches > 0
        ? Math.round((totalMatchCount / searchesWithMatches) * 10) / 10
        : 0;
      
      res.json({
        summary: {
          totalSearches,
          searchesWithMatches,
          searchesWithExactMatch,
          demandGapsCount: demandGaps.length,
          successRate,
          exactMatchRate,
          avgMatchesPerSearch
        },
        categoryDistribution: categoryData,
        topMatchedProducts: topMatched,
        hourlyDistribution: hourlyData,
        dailyTrend: dailyData,
        demandGaps: demandGaps.slice(0, 20) // Limit to recent 20
      });
    } catch (error: any) {
      console.error('[Vista Insights] Error:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // Product search endpoint for Jewelry Showcase with text search and filters
  // Enhanced to search through AI-generated descriptions and attributes
  app.post("/api/products/search", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      const { query, categoryId, minPrice, maxPrice, page = 1, limit = 20 } = req.body;
      
      // Get all products first
      let allProducts = await storage.getAllProducts(businessAccountId);
      
      // Apply text search filter (search in name, description, AI description, and AI attributes)
      if (query && query.trim()) {
        const searchTerms = query.toLowerCase().trim().split(/\s+/);
        
        // Fetch AI-generated descriptions and attributes for all products
        const productIds = allProducts.map(p => p.id);
        
        // Guard against empty array (inArray fails with empty array)
        let aiDataRows: { productId: string; description: string | null; attributes: any; jewelryType: string | null }[] = [];
        if (productIds.length > 0) {
          aiDataRows = await db.select({
            productId: productJewelryEmbeddings.productId,
            description: productJewelryEmbeddings.description,
            attributes: productJewelryEmbeddings.attributes,
            jewelryType: productJewelryEmbeddings.jewelryType
          })
          .from(productJewelryEmbeddings)
          .where(inArray(productJewelryEmbeddings.productId, productIds));
        }
        
        // Create a map for quick lookup
        const aiDataMap = new Map<string, { description: string | null; attributes: any; jewelryType: string | null }>();
        for (const row of aiDataRows) {
          aiDataMap.set(row.productId, {
            description: row.description,
            attributes: row.attributes,
            jewelryType: row.jewelryType
          });
        }
        
        // Helper function to check if any search term matches a string
        const matchesAnyTerm = (text: string | null | undefined, terms: string[]): boolean => {
          if (!text) return false;
          const lowerText = text.toLowerCase();
          return terms.some(term => lowerText.includes(term));
        };
        
        // Helper function to extract searchable text from attributes
        const getAttributeSearchText = (attributes: any): string => {
          if (!attributes || typeof attributes !== 'object') return '';
          
          const searchableFields: string[] = [];
          
          // Add direct string fields
          if (attributes.metalType) searchableFields.push(attributes.metalType);
          if (attributes.finish) searchableFields.push(attributes.finish);
          if (attributes.designComplexity) searchableFields.push(attributes.designComplexity);
          if (attributes.style) searchableFields.push(attributes.style);
          if (attributes.centerpiece) searchableFields.push(attributes.centerpiece);
          if (attributes.stoneSetting) searchableFields.push(attributes.stoneSetting);
          if (attributes.edgeStyle) searchableFields.push(attributes.edgeStyle);
          if (attributes.necklineStyle) searchableFields.push(attributes.necklineStyle);
          if (attributes.dangleElements) searchableFields.push(attributes.dangleElements);
          if (attributes.layers) searchableFields.push(attributes.layers);
          
          // Add array fields
          if (Array.isArray(attributes.stoneTypes)) {
            searchableFields.push(...attributes.stoneTypes);
          }
          if (Array.isArray(attributes.stoneColors)) {
            searchableFields.push(...attributes.stoneColors);
          }
          if (Array.isArray(attributes.motifs)) {
            searchableFields.push(...attributes.motifs);
          }
          
          return searchableFields.join(' ').toLowerCase();
        };
        
        // Build combined searchable text for each product and filter using ALL terms must match
        allProducts = allProducts.filter(product => {
          // Combine all searchable text for this product
          const searchableTexts: string[] = [];
          
          // Add product name and manual description
          if (product.name) searchableTexts.push(product.name.toLowerCase());
          if (product.description) searchableTexts.push(product.description.toLowerCase());
          
          // Add AI-generated data
          const aiData = aiDataMap.get(product.id);
          if (aiData?.description) searchableTexts.push(aiData.description.toLowerCase());
          if (aiData?.jewelryType) searchableTexts.push(aiData.jewelryType.toLowerCase());
          
          // Add AI attributes
          if (aiData?.attributes) {
            const attrText = getAttributeSearchText(aiData.attributes);
            if (attrText) searchableTexts.push(attrText);
          }
          
          // Combine all text into one searchable string
          const combinedText = searchableTexts.join(' ');
          
          // ALL search terms must match somewhere in the combined text
          return searchTerms.every(term => combinedText.includes(term));
        });
        
        console.log(`[Product Search] Query "${query}" matched ${allProducts.length} products (ALL terms must match in name, description, AI data, or attributes)`);
      }
      
      // Apply category filter
      if (categoryId) {
        const categoryProducts = await db
          .select({ productId: productCategoriesTable.productId })
          .from(productCategoriesTable)
          .where(eq(productCategoriesTable.categoryId, categoryId));
        
        const productIdsWithCategory = new Set(categoryProducts.map(pc => pc.productId));
        allProducts = allProducts.filter(product => productIdsWithCategory.has(product.id));
      }
      
      // Apply price range filter
      if (minPrice !== undefined || maxPrice !== undefined) {
        allProducts = allProducts.filter(product => {
          if (!product.price) return false;
          const price = parseFloat(product.price);
          if (minPrice !== undefined && price < minPrice) return false;
          if (maxPrice !== undefined && price > maxPrice) return false;
          return true;
        });
      }
      
      // Calculate pagination
      const totalCount = allProducts.length;
      const totalPages = Math.ceil(totalCount / limit);
      const offset = (page - 1) * limit;
      const paginatedProducts = allProducts.slice(offset, offset + limit);
      
      // Enrich products with categories and tags
      const enrichedProducts = await Promise.all(
        paginatedProducts.map(async (product) => {
          const [categories, tags] = await Promise.all([
            storage.getProductCategories(product.id, businessAccountId),
            storage.getProductTags(product.id, businessAccountId)
          ]);
          return {
            ...product,
            categories: categories || [],
            tags: tags || []
          };
        })
      );
      
      // Get price range for all products (for slider)
      const allProductsForRange = await storage.getAllProducts(businessAccountId);
      const prices = allProductsForRange
        .filter(p => p.price)
        .map(p => parseFloat(p.price!));
      const priceRange = {
        min: prices.length > 0 ? Math.min(...prices) : 0,
        max: prices.length > 0 ? Math.max(...prices) : 100000
      };
      
      res.json({
        products: enrichedProducts,
        pagination: {
          page,
          limit,
          totalCount,
          totalPages
        },
        priceRange
      });
    } catch (error: any) {
      res.status(500).json({ error: error.message });
    }
  });

