  app.get("/api/smart-replies/:channel", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) return res.status(400).json({ error: "Business account not found" });
      const { channel } = req.params;
      if (!["whatsapp", "instagram", "website"].includes(channel)) {
        return res.status(400).json({ error: "Invalid channel. Must be whatsapp, instagram, or website" });
      }
      const results = await db
        .select()
        .from(smartReplies)
        .where(and(eq(smartReplies.businessAccountId, businessAccountId), eq(smartReplies.channel, channel)))
        .orderBy(smartReplies.priority);
      res.json({ smartReplies: results });
    } catch (error: any) {
      res.status(500).json({ error: error.message });
    }
  });

  app.post("/api/smart-replies/:channel", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) return res.status(400).json({ error: "Business account not found" });
      const { channel } = req.params;
      if (!["whatsapp", "instagram", "website"].includes(channel)) {
        return res.status(400).json({ error: "Invalid channel" });
      }
      const { keywords, responseText, responseUrl, priority, isActive } = req.body;
      if (!keywords || !responseText) {
        return res.status(400).json({ error: "keywords and responseText are required" });
      }
      const [created] = await db.insert(smartReplies).values({
        businessAccountId,
        channel,
        keywords,
        responseText,
        responseUrl: responseUrl || null,
        priority: priority ?? 0,
        isActive: isActive ?? true,
      }).returning();
      res.status(201).json(created);
    } catch (error: any) {
      res.status(500).json({ error: error.message });
    }
  });

  app.patch("/api/smart-replies/:id", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) return res.status(400).json({ error: "Business account not found" });
      const { id } = req.params;
      const { keywords, responseText, responseUrl, priority, isActive } = req.body;
      const updates: Record<string, any> = { updatedAt: new Date() };
      if (keywords !== undefined) updates.keywords = keywords;
      if (responseText !== undefined) updates.responseText = responseText;
      if (responseUrl !== undefined) updates.responseUrl = responseUrl;
      if (priority !== undefined) updates.priority = priority;
      if (isActive !== undefined) updates.isActive = isActive;
      const [updated] = await db
        .update(smartReplies)
        .set(updates)
        .where(and(eq(smartReplies.id, id), eq(smartReplies.businessAccountId, businessAccountId)))
        .returning();
      if (!updated) return res.status(404).json({ error: "Smart reply not found" });
      res.json(updated);
    } catch (error: any) {
      res.status(500).json({ error: error.message });
    }
  });

