      const { id } = req.params;
      const [deleted] = await db
        .delete(smartReplies)
        .where(and(eq(smartReplies.id, id), eq(smartReplies.businessAccountId, businessAccountId)))
        .returning();
      if (!deleted) return res.status(404).json({ error: "Smart reply not found" });
      res.json({ success: true });
