  // FAQ Quality Analyzer - Analyzes FAQ quality and suggests improvements
  app.post("/api/faqs/analyze-quality", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }
      
      const { question, answer } = req.body;
      
      if (!question && !answer) {
        return res.status(400).json({ error: "Question or answer is required" });
      }
      
      // Get business account for context (business name, industry) and OpenAI key
      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      const businessName = businessAccount?.name || "the business";
      
      // Get OpenAI API key
      const openaiApiKey = await storage.getBusinessAccountOpenAIKey(businessAccountId);
      if (!openaiApiKey) {
        return res.status(400).json({ error: "OpenAI API key not configured. Please add your API key in Settings." });
      }
      const openai = new OpenAI({ apiKey: openaiApiKey });
      
      // Get existing FAQs to check for duplicates
      const existingFaqs = await storage.getAllFaqs(businessAccountId);
      const existingQuestions = existingFaqs.map(f => f.question).slice(0, 20);
      
      const analysisPrompt = `You are an FAQ quality analyzer for a business chatbot. Analyze this FAQ and provide improvement suggestions.

Business Context: ${businessName}

FAQ being analyzed:
Question: "${question}"
Answer: "${answer}"

Existing FAQs for duplicate detection:
${existingQuestions.map((q, i) => `${i + 1}. ${q}`).join('\n')}

Analyze the FAQ and respond with a JSON object:
{
  "score": <number 1-100, overall quality score>,
  "specificity": <number 1-100, how specific vs generic the question is>,
  "completeness": <number 1-100, how complete the answer is>,
  "searchability": <number 1-100, how easily AI can match user queries to this>,
  "issues": [<array of specific problems found>],
  "suggestions": [<array of actionable improvement suggestions>],
  "improvedQuestion": "<suggested improved version of the question with context>",
  "improvedAnswer": "<optional: improved answer if needed, or null>",
  "similarFaqs": [<array of indices of existing FAQs that are too similar, empty if none>],
  "duplicateWarning": "<warning message if very similar FAQ exists, or null>"
}

Quality Guidelines:
1. Questions should include business/product context (e.g., "What is the fee structure for Symbiosis Online MBA?" not just "What is the fee structure?")
2. Generic questions like "What are the benefits?" should mention WHAT has benefits
3. Answers should be comprehensive but concise
4. Questions should match how real users would ask
5. Avoid ambiguous terms that could apply to any business

Be constructive and helpful. Return ONLY valid JSON.`;

      const response = await openai.chat.completions.create({
        model: "gpt-4o-mini",
        messages: [{ role: "user", content: analysisPrompt }],
        temperature: 0.3,
        max_tokens: 1000,
        response_format: { type: "json_object" }
      });
      
      const analysisText = response.choices[0]?.message?.content || "{}";
      let analysis;
      
      try {
        analysis = JSON.parse(analysisText);
      } catch (e) {
        analysis = {
          score: 50,
          specificity: 50,
          completeness: 50,
          searchability: 50,
          issues: ["Could not analyze FAQ"],
          suggestions: ["Please ensure question and answer are clear and specific"],
          improvedQuestion: null,
          improvedAnswer: null,
          similarFaqs: [],
          duplicateWarning: null
        };
      }
      
      // Track AI cost
      aiUsageLogger.logUsage({
        businessAccountId,
        category: "faq_quality_analysis",
        model: "gpt-4o-mini",
        tokensInput: response.usage?.prompt_tokens || 0,
        tokensOutput: response.usage?.completion_tokens || 0,
        metadata: { questionLength: question?.length || 0 }
      }).catch(err => console.error("Error logging AI usage:", err));
      
      res.json(analysis);
    } catch (error: any) {
      console.error("Error analyzing FAQ quality:", error);
      res.status(500).json({ error: error.message || "Failed to analyze FAQ" });
    }
  });

  // Bulk add FAQs
  app.post("/api/faqs/bulk", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const { faqs } = req.body;
      const businessAccountId = req.user?.businessAccountId;
      
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      if (!faqs || !Array.isArray(faqs) || faqs.length === 0) {
        return res.status(400).json({ error: "FAQs array is required" });
      }

      // Add businessAccountId to each FAQ and insert
      const createdFaqs = [];
      for (const faq of faqs) {
        const faqData = {
          ...faq,
          businessAccountId
        };
        
        const result = insertFaqSchema.safeParse(faqData);
        if (!result.success) {
          continue; // Skip invalid FAQs
        }
        
        const created = await storage.createFaq(result.data);
        createdFaqs.push(created);
      }

      res.json({ 
        success: true,
        count: createdFaqs.length,
        faqs: createdFaqs
      });
    } catch (error: any) {
      console.error("Error bulk adding FAQs:", error);
      res.status(500).json({ error: error.message || "Failed to add FAQs" });
    }
  });

