  // AI Instruction Analysis
  app.post("/api/training/analyze", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      const { instructions } = req.body;
      
      if (!Array.isArray(instructions)) {
        return res.status(400).json({ error: "Instructions array is required" });
      }

      // Get business account for OpenAI API key
      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      
      if (!businessAccount) {
        return res.status(404).json({ error: "Business account not found" });
      }

      if (!businessAccount.openaiApiKey) {
        return res.status(400).json({ error: "OpenAI API key not configured for this account" });
      }

      // Import instruction analyzer
      const { InstructionAnalyzer } = await import('./services/instructionAnalyzer');
      
      // Create analyzer instance with API key
      const analyzer = new InstructionAnalyzer(businessAccount.openaiApiKey);
      
      // Analyze instructions
      const analysis = await analyzer.analyzeInstructions(instructions);
      
      // Get best practice library and merge missing practices into results
      const bestPracticeLibrary = analyzer.getBestPracticeLibrary();
      
      // Merge library practices that aren't already in the analysis
      const existingPracticeIds = new Set(analysis.bestPractices.map(bp => bp.id));
      const missingPractices = bestPracticeLibrary.filter(bp => !existingPracticeIds.has(bp.id));
      
      if (missingPractices.length > 0) {
        analysis.bestPractices = [...analysis.bestPractices, ...missingPractices];
      }
      
      res.json(analysis);
    } catch (error: any) {
      console.error("Error analyzing instructions:", error);
      res.status(500).json({ error: error.message || "Failed to analyze instructions" });
    }
  });

  // Lead routes
  app.post("/api/leads", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }
      
      const validatedData = insertLeadSchema.parse({
        ...req.body,
        businessAccountId
      });
      const lead = await storage.createLead(validatedData);
      
      // Auto-sync to LeadSquared if enabled (background task, don't block response)
      (async () => {
        try {
          const settings = await storage.getWidgetSettings(businessAccountId);
          
          if (settings && 
              settings.leadsquaredEnabled === 'true' && 
              settings.leadsquaredAccessKey && 
              settings.leadsquaredSecretKey && 
              settings.leadsquaredRegion) {
            
            console.log('[LeadSquared] Auto-syncing new lead:', lead.id);
            
            // Get business account info for sync
            const businessAccount = await storage.getBusinessAccount(businessAccountId);
            
            // Decrypt the secret key
            const { decrypt } = await import('./services/encryptionService');
            const decryptedSecretKey = decrypt(settings.leadsquaredSecretKey);
            
            const { createLeadSquaredService, extractUtmCampaign, extractUtmSource, extractUtmMedium } = await import('./services/leadsquaredService');
            const leadsquaredService = await createLeadSquaredService({
              accessKey: settings.leadsquaredAccessKey,
              secretKey: decryptedSecretKey,
              region: settings.leadsquaredRegion as 'india' | 'us' | 'other',
              customHost: settings.leadsquaredCustomHost || undefined,
            });
            
            // Get field mappings from database (dynamic, configurable)
            const fieldMappings = await storage.getLeadsquaredFieldMappings(businessAccountId);
            
            // Build context for dynamic field mapping
            const leadContext = {
              lead: {
                name: lead.name || null,
                email: lead.email || null,
                phone: lead.phone || null,
                whatsapp: null,
                createdAt: lead.createdAt || null,
                sourceUrl: lead.sourceUrl || null,
              },
              session: {
                city: lead.city || null,
                utmCampaign: extractUtmCampaign(lead.sourceUrl) || null,
                utmSource: extractUtmSource(lead.sourceUrl) || null,
                utmMedium: extractUtmMedium(lead.sourceUrl) || null,
                pageUrl: lead.sourceUrl || null,
              },
              business: {
                name: businessAccount?.name || null,
                website: businessAccount?.website || null,
              }
            };
            
            console.log('[LeadSquared] Auto-sync using dynamic field mappings, count:', fieldMappings.length);
            
            // Sync to LeadSquared with dynamic field mappings
            const result = await leadsquaredService.createLeadWithMappings(fieldMappings, leadContext);
            
            if (result.success) {
              await storage.updateLead(lead.id, businessAccountId, {
                leadsquaredSyncStatus: 'synced',
                leadsquaredSyncedAt: new Date(),
                leadsquaredLeadId: result.leadId,
                leadsquaredSyncError: null,
                leadsquaredSyncPayload: result.syncPayload || null,
              });
              console.log('[LeadSquared] Auto-sync successful:', lead.id, '→', result.leadId);
            } else {
              await storage.updateLead(lead.id, businessAccountId, {
                leadsquaredSyncStatus: 'failed',
                leadsquaredSyncError: result.message,
              });
              console.error('[LeadSquared] Auto-sync failed:', lead.id, result.message);
            }
          }
        } catch (error: any) {
          console.error('[LeadSquared] Auto-sync error:', error);
          // Try to update lead with error status
          try {
            await storage.updateLead(lead.id, businessAccountId, {
              leadsquaredSyncStatus: 'failed',
              leadsquaredSyncError: error.message,
            });
          } catch (updateError) {
            console.error('[LeadSquared] Failed to update lead status:', updateError);
          }
        }
      })();
      
      res.json(lead);
    } catch (error: any) {
      res.status(400).json({ error: error.message });
    }
  });

