  app.get("/api/leads/:leadId/journey-responses", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      const { leadId } = req.params;
      const { eq, and, desc: descOrder } = await import('drizzle-orm');

      const [lead] = await db.select().from(leads).where(and(
        eq(leads.id, leadId),
        eq(leads.businessAccountId, businessAccountId)
      ));

      if (!lead) {
        return res.status(404).json({ error: "Lead not found" });
      }

      let session: { sessionId: string; journeyName: string | null; completed: string } | null = null;

      if (lead.conversationId) {
        const sessions = await db
          .select({
            sessionId: journeySessions.id,
            journeyName: conversationJourneys.name,
            completed: journeySessions.completed,
          })
          .from(journeySessions)
          .leftJoin(conversationJourneys, eq(journeySessions.journeyId, conversationJourneys.id))
          .where(and(
            eq(journeySessions.conversationId, lead.conversationId),
            eq(journeySessions.businessAccountId, businessAccountId)
          ))
          .orderBy(descOrder(journeySessions.createdAt))
          .limit(1);

        if (sessions.length > 0) {
          session = sessions[0];
        }
      }

      if (!session && lead.phone) {
        const phoneMatches = await db
          .select({
            sessionId: journeySessions.id,
            journeyName: conversationJourneys.name,
            completed: journeySessions.completed,
          })
          .from(journeyResponses)
          .innerJoin(journeySessions, eq(journeyResponses.sessionId, journeySessions.id))
          .leftJoin(conversationJourneys, eq(journeySessions.journeyId, conversationJourneys.id))
          .where(and(
            eq(journeyResponses.response, lead.phone),
            eq(journeySessions.businessAccountId, businessAccountId)
          ))
          .orderBy(descOrder(journeySessions.createdAt))
          .limit(1);

        if (phoneMatches.length > 0) {
          session = phoneMatches[0];
        }
      }

      if (!session) {
        return res.json({ journeyName: null, completed: false, responses: [] });
      }
      const responses = await db
        .select({
          response: journeyResponses.response,
          questionText: journeySteps.questionText,
          stepOrder: journeySteps.stepOrder,
        })
        .from(journeyResponses)
        .leftJoin(journeySteps, eq(journeyResponses.stepId, journeySteps.id))
        .where(eq(journeyResponses.sessionId, session.sessionId))
        .orderBy(journeySteps.stepOrder);

      res.json({
        journeyName: session.journeyName || 'Unknown Journey',
        completed: session.completed === 'true',
        responses: responses.map(r => ({
          question: r.questionText || 'Unknown',
          answer: r.response,
          stepOrder: r.stepOrder || 0,
        })),
      });
    } catch (error: any) {
      console.error('[Admin] Error fetching journey responses by lead:', error);
      res.status(500).json({ error: error.message });
    }
  });

