  // Automation Analytics
  app.get("/api/analytics/automation", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      const allTickets = await storage.getAllSupportTickets(businessAccountId);
      
      const totalTickets = allTickets.length;
      const aiResolvedTickets = allTickets.filter((t: any) => t.autoResolved === 'true').length;
      const humanResolvedTickets = totalTickets - aiResolvedTickets;
      
      const aiResolutionRate = totalTickets > 0 ? (aiResolvedTickets / totalTickets) * 100 : 0;
      const humanInterventionRate = totalTickets > 0 ? (humanResolvedTickets / totalTickets) * 100 : 0;
      const hoursSaved = aiResolvedTickets * 1.75;
      
      const resolvedTickets = allTickets.filter((t: any) => t.resolvedAt);
      let totalAIResolveTime = 0, totalHumanResolveTime = 0, aiCount = 0, humanCount = 0;
      
      resolvedTickets.forEach((t: any) => {
        const resolveTime = (new Date(t.resolvedAt).getTime() - new Date(t.createdAt).getTime()) / (1000 * 60 * 60);
        if (t.autoResolved === 'true') {
          totalAIResolveTime += resolveTime;
          aiCount++;
        } else {
          totalHumanResolveTime += resolveTime;
          humanCount++;
        }
      });
      
      const feedbackBreakdown = {
        positive: allTickets.filter((t: any) => t.customerFeedback === 'positive').length,
        negative: allTickets.filter((t: any) => t.customerFeedback === 'negative').length,
        neutral: allTickets.filter((t: any) => !t.customerFeedback || t.customerFeedback === 'neutral').length
      };
      
      const customerSatisfactionRate = feedbackBreakdown.positive > 0 
        ? (feedbackBreakdown.positive / (feedbackBreakdown.positive + feedbackBreakdown.negative)) * 100 
        : 0;
      
      const escalationReasons: Record<string, number> = {};
      allTickets.forEach((t: any) => {
        if (t.escalationReason) {
          const reason = t.escalationReason.split(':')[0] || 'Other';
          escalationReasons[reason] = (escalationReasons[reason] || 0) + 1;
        }
      });
      
      const categoryBreakdown: Record<string, { total: number; aiResolved: number }> = {};
      allTickets.forEach((t: any) => {
        const category = t.category || 'general';
        if (!categoryBreakdown[category]) categoryBreakdown[category] = { total: 0, aiResolved: 0 };
        categoryBreakdown[category].total++;
        if (t.autoResolved === 'true') categoryBreakdown[category].aiResolved++;
      });
      
      const trendData = [];
      for (let i = 6; i >= 0; i--) {
        const date = new Date();
        date.setDate(date.getDate() - i);
        const dateStr = date.toISOString().split('T')[0];
        const dayTickets = allTickets.filter((t: any) => new Date(t.createdAt).toISOString().split('T')[0] === dateStr);
        trendData.push({
          date: dateStr,
          aiResolved: dayTickets.filter((t: any) => t.autoResolved === 'true').length,
          humanResolved: dayTickets.filter((t: any) => t.autoResolved !== 'true' && t.status === 'resolved').length,
          totalTickets: dayTickets.length
        });
      }
      
      res.json({
        aiResolutionRate,
        humanInterventionRate,
        averageAutoResolveTime: aiCount > 0 ? totalAIResolveTime / aiCount : 0,
        averageHumanResolveTime: humanCount > 0 ? totalHumanResolveTime / humanCount : 0,
        customerSatisfactionRate,
        totalTickets,
        aiResolvedTickets,
        humanResolvedTickets,
        hoursSaved,
        escalationReasons,
        feedbackBreakdown,
        categoryBreakdown,
        trendData
      });
    } catch (error: any) {
      console.error('[API] Error getting automation analytics:', error);
      res.status(500).json({ error: error.message });
    }
  });

