  // Agent Response - Sends response to customer via chat
  app.post("/api/tickets/:id/respond", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(403).json({ error: "No business account associated with user" });
      }

      const ticketId = req.params.id;
      const { message } = req.body;

      if (!message || !message.trim()) {
        return res.status(400).json({ error: "Message is required" });
      }

      // Get ticket to find linked conversation
      const ticket = await storage.getSupportTicket(ticketId, businessAccountId);
      if (!ticket) {
        return res.status(404).json({ error: "Ticket not found" });
      }

      // Store message in ticket
      const agentName = req.user?.username || 'Agent';
      await storage.createTicketMessage({
        ticketId,
        senderName: agentName,
        senderType: 'agent',
        senderId: req.user?.id,
        message,
        messageType: 'text',
        isInternal: 'false',
        aiDrafted: 'false'
      });

      // If ticket has a linked conversation, send response to chat
      if (ticket.conversationId) {
        await storage.createMessage({
          conversationId: ticket.conversationId,
          role: 'assistant',
          content: message
        });
      }

      // Update ticket status to in_progress if it was open
      if (ticket.status === 'open') {
        await storage.updateSupportTicket(ticketId, businessAccountId, { status: 'in_progress' });
      }

      // AI Learning: If agent sent different response than AI suggested, learn from it
      if (ticket.aiDraftedResponse && ticket.aiDraftedResponse !== message) {
        const { aiLearningService } = await import('./services/aiLearningService');
        await aiLearningService.learnFromHumanCorrection(
          businessAccountId,
          ticketId,
          ticket.description,
          ticket.aiDraftedResponse,
          message,
          ticket.category || 'general'
        );
      }

      res.json({ success: true, message: "Response sent to customer" });
    } catch (error: any) {
      console.error('Error sending agent response:', error);
      res.status(500).json({ error: error.message });
    }
  });

