  // Journey Leads routes
  app.get("/api/journey-leads", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      const { fromDate, toDate, search, page = '1', limit = '20' } = req.query;
      
      // Validate and clamp pagination parameters
      const pageNum = Math.max(1, parseInt(page as string) || 1);
      const limitNum = Math.max(1, Math.min(100, parseInt(limit as string) || 20));
      const offset = (pageNum - 1) * limitNum;

      // Build query to fetch journey responses grouped by conversation
      const { sql: dsql, eq, and, gte, lte, desc, or, ilike, inArray } = await import('drizzle-orm');
      const { conversationJourneys, journeySessions, journeyResponses, journeySteps, conversations } = await import('../shared/schema');

      let conditions = [eq(journeySessions.businessAccountId, businessAccountId)];

      // Date filters
      if (fromDate) {
        conditions.push(gte(journeySessions.createdAt, new Date(fromDate as string)));
      }
      if (toDate) {
        conditions.push(lte(journeySessions.createdAt, new Date(toDate as string)));
      }

      // Search filter (search in conversation title or journey name)
      if (search) {
        const searchTerm = `%${search}%`;
        conditions.push(
          or(
            ilike(conversations.title, searchTerm),
            ilike(conversationJourneys.name, searchTerm)
          )!
        );
      }

      // Get total count
      const countResult = await db
        .select({ count: dsql<number>`count(distinct ${journeySessions.id})` })
        .from(journeySessions)
        .leftJoin(conversations, eq(journeySessions.conversationId, conversations.id))
        .leftJoin(conversationJourneys, eq(journeySessions.journeyId, conversationJourneys.id))
        .where(and(...conditions));

      const total = Number(countResult[0]?.count || 0);

      // Get journey sessions with journey and conversation details
      const sessions = await db
        .select({
          sessionId: journeySessions.id,
          journeyId: journeySessions.journeyId,
          journeyName: conversationJourneys.name,
          conversationId: journeySessions.conversationId,
          conversationTitle: conversations.title,
          completed: journeySessions.completed,
          createdAt: journeySessions.createdAt,
        })
        .from(journeySessions)
        .leftJoin(conversations, eq(journeySessions.conversationId, conversations.id))
        .leftJoin(conversationJourneys, eq(journeySessions.journeyId, conversationJourneys.id))
        .where(and(...conditions))
        .orderBy(desc(journeySessions.createdAt))
        .limit(limitNum)
        .offset(offset);

      // Get all responses for these journey sessions using direct sessionId join
      const sessionIds = sessions.map(s => s.sessionId);
      
      const responses = sessionIds.length > 0 ? await db
        .select({
          sessionId: journeyResponses.sessionId,
          response: journeyResponses.response,
          questionText: journeySteps.questionText,
          stepOrder: journeySteps.stepOrder,
        })
        .from(journeyResponses)
        .leftJoin(journeySteps, eq(journeyResponses.stepId, journeySteps.id))
        .where(inArray(journeyResponses.sessionId, sessionIds))
        .orderBy(journeySteps.stepOrder) : [];

      // Group responses by journey session
      const journeyLeads = sessions.map(session => {
        const sessionResponses = responses
          .filter(r => r.sessionId === session.sessionId)
          .map(r => ({
            question: r.questionText || 'Unknown',
            answer: r.response,
            stepOrder: r.stepOrder || 0,
          }));

        return {
          id: session.sessionId,
          journeyName: session.journeyName || 'Unknown Journey',
          conversationId: session.conversationId,
          conversationTitle: session.conversationTitle || 'Untitled Conversation',
          completed: session.completed === 'true',
          responses: sessionResponses,
          createdAt: session.createdAt,
        };
      });

      res.json({
        journeyLeads,
        total,
      });
    } catch (error: any) {
      console.error('[Journey Leads API] Error:', error);
      res.status(500).json({ error: error.message });
    }
  });

