  app.post("/api/widget-settings/avatar/upload", requireAuth, requireBusinessAccount, avatarUpload.single('avatar'), async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      if (!req.file) {
        return res.status(400).json({ error: "No file uploaded" });
      }

      let avatarUrl: string;

      // Ensure R2 is initialized (checks database config if not already loaded)
      await r2Storage.ensureInitialized();

      // Try R2 storage first, fall back to local storage
      if (r2Storage.isEnabled()) {
        const result = await r2Storage.uploadFile(
          req.file.buffer,
          req.file.originalname,
          "avatars",
          req.file.mimetype,
          businessAccountId
        );

        if (result.success && result.url) {
          avatarUrl = result.url;
          console.log('[Avatar Upload] Uploaded to R2:', avatarUrl);
        } else {
          console.error('[Avatar Upload] R2 upload failed:', result.error);
          return res.status(500).json({ error: "Failed to upload avatar" });
        }
      } else {
        // Fallback to local storage
        const uniqueName = `avatar_${Date.now()}_${randomUUID()}${path.extname(req.file.originalname)}`;
        const filepath = path.join(avatarDir, uniqueName);
        fs.writeFileSync(filepath, req.file.buffer);
        avatarUrl = `/avatars/custom/${uniqueName}`;
        console.log('[Avatar Upload] Saved locally:', avatarUrl);
      }

      // Add to customAvatars array in widget settings
      const settings = await storage.getWidgetSettings(businessAccountId);
      const existingAvatars = (settings?.customAvatars as Array<{url: string, uploadedAt: string}>) || [];
      const updatedAvatars = [...existingAvatars, { url: avatarUrl, uploadedAt: new Date().toISOString() }];
      
      await storage.upsertWidgetSettings(businessAccountId, {
        customAvatars: updatedAvatars,
        avatarType: 'custom',
        avatarUrl: avatarUrl
      });
      
      businessContextCache.invalidate(BusinessContextCache.KEYS.WIDGET_SETTINGS(businessAccountId));

      res.json({ avatarUrl, customAvatars: updatedAvatars });
    } catch (error: any) {
      console.error("Error uploading avatar:", error);
      res.status(500).json({ error: error.message || "Failed to upload avatar" });
    }
  });

  // Delete custom avatar endpoint
  app.delete("/api/widget-settings/avatar", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      const { avatarUrl } = req.body;
      if (!avatarUrl) {
        return res.status(400).json({ error: "Avatar URL is required" });
      }

      // Get current settings
      const settings = await storage.getWidgetSettings(businessAccountId);
      const existingAvatars = (settings?.customAvatars as Array<{url: string, uploadedAt: string}>) || [];
      
      // Remove from customAvatars array
      const updatedAvatars = existingAvatars.filter(a => a.url !== avatarUrl);
      
      // Delete from R2 or local storage
      // Ensure R2 is initialized to check if it's enabled and get proper URL matching
      await r2Storage.ensureInitialized();
      
      if (avatarUrl.startsWith('http')) {
        // R2 storage - try to extract key and delete
        const r2Key = r2Storage.extractKeyFromUrl(avatarUrl);
        console.log('[Avatar Delete] Attempting R2 deletion for URL:', avatarUrl, 'Extracted key:', r2Key);
        if (r2Key) {
          const deleteResult = await r2Storage.deleteFile(r2Key);
          if (deleteResult.success) {
            console.log('[Avatar Delete] Deleted from R2:', r2Key);
          } else {
            console.log('[Avatar Delete] Could not delete from R2:', deleteResult.error);
          }
        } else {
          console.log('[Avatar Delete] Could not extract R2 key from URL:', avatarUrl);
        }
      } else if (avatarUrl.startsWith('/avatars/custom/')) {
        // Local storage
        const filename = avatarUrl.replace('/avatars/custom/', '');
        const filepath = path.join(avatarDir, filename);
        try {
          fs.unlinkSync(filepath);
          console.log('[Avatar Delete] Deleted from local:', filepath);
        } catch (fileError) {
          console.error('[Avatar Delete] Could not delete local file:', fileError);
        }
      }

      // Update settings - if deleted avatar was selected, reset to first available or none
      const updateData: any = { customAvatars: updatedAvatars };
      
      if (settings?.avatarUrl === avatarUrl) {
        // Current avatar was deleted, select another or reset
        if (updatedAvatars.length > 0) {
          updateData.avatarUrl = updatedAvatars[0].url;
          updateData.avatarType = 'custom';
        } else {
          updateData.avatarUrl = null;
          updateData.avatarType = 'none';
        }
      }

      await storage.upsertWidgetSettings(businessAccountId, updateData);
      
      businessContextCache.invalidate(BusinessContextCache.KEYS.WIDGET_SETTINGS(businessAccountId));

      res.json({ success: true, customAvatars: updatedAvatars });
    } catch (error: any) {
      console.error("Error deleting avatar:", error);
      res.status(500).json({ error: error.message || "Failed to delete avatar" });
    }
  });

  // Avatar selection endpoint
  app.put("/api/widget-settings/avatar", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      const { avatarType, avatarUrl } = req.body;

      // Validate avatarType
      const validAvatarTypes = ['none', 'preset-female-1', 'preset-female-2', 'preset-female-3', 'preset-male-1', 'preset-male-2', 'preset-male-3', 'custom'];
      if (!avatarType || !validAvatarTypes.includes(avatarType)) {
        return res.status(400).json({ error: "Invalid avatar type" });
      }

      // For custom avatars, avatarUrl is required
      if (avatarType === 'custom' && !avatarUrl) {
        return res.status(400).json({ error: "Avatar URL is required for custom avatars" });
      }

      // Update widget settings with avatar selection
      const updateData: Partial<{ avatarType: string; avatarUrl: string | null }> = {
        avatarType
      };

      if (avatarType === 'custom') {
        updateData.avatarUrl = avatarUrl;
      } else {
        // Clear avatarUrl for non-custom avatars
        updateData.avatarUrl = null;
      }

      const settings = await storage.upsertWidgetSettings(businessAccountId, updateData);
      
      businessContextCache.invalidate(BusinessContextCache.KEYS.WIDGET_SETTINGS(businessAccountId));
      
      res.json(settings);
    } catch (error: any) {
      console.error("Error updating avatar:", error);
      res.status(500).json({ error: error.message || "Failed to update avatar" });
    }
  });

