  // Widget Settings routes
  // Public endpoint for widget settings (used by embed iframe)
  app.get("/api/widget-settings/public", async (req, res) => {
    try {
      const businessAccountId = req.query.businessAccountId as string;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account ID required" });
      }

      let settings = await storage.getWidgetSettings(businessAccountId);
      
      // If no settings exist, create default ones
      if (!settings) {
        settings = await storage.upsertWidgetSettings(businessAccountId, {});
      }

      // Get business account to check if voice mode and visual search are enabled
      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      const voiceModeEnabled = businessAccount?.voiceModeEnabled === "true";
      const visualSearchEnabled = businessAccount?.visualSearchEnabled === "true";

      // Force chat-only mode when voice mode is disabled
      const chatMode = !voiceModeEnabled ? "chat-only" : (settings.chatMode || "both");

      const jobPortalEnabled = businessAccount?.jobPortalEnabled === 'true';
      res.json({ ...settings, voiceModeEnabled, visualSearchEnabled, chatMode, jobPortalEnabled });
    } catch (error: any) {
      res.status(500).json({ error: error.message });
    }
  });

