  // Voice preview endpoint - generate TTS sample
  app.get("/api/voice-preview", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      const voice = req.query.voice as string;
      if (!voice || !['alloy', 'ash', 'ballad', 'coral', 'echo', 'fable', 'onyx', 'nova', 'sage', 'shimmer', 'verse'].includes(voice)) {
        return res.status(400).json({ error: "Invalid voice selection" });
      }

      // Get the business account's OpenAI API key
      const apiKey = await storage.getBusinessAccountOpenAIKey(businessAccountId);
      if (!apiKey) {
        return res.status(400).json({ error: "OpenAI API key not configured" });
      }

      const openai = new OpenAI({ apiKey });

      // Generate voice sample
      const sampleText = "Hello! I'm Chroney, your AI assistant. How can I help you today?";
      const mp3Response = await openai.audio.speech.create({
        model: "tts-1",
        voice: voice as any,
        input: sampleText,
        speed: 1.0
      });

      // Convert response to buffer
      const buffer = Buffer.from(await mp3Response.arrayBuffer());

      // Set headers for audio streaming
      res.setHeader('Content-Type', 'audio/mpeg');
      res.setHeader('Content-Length', buffer.length);
      res.setHeader('Cache-Control', 'public, max-age=3600');
      res.send(buffer);
    } catch (error: any) {
      console.error("Error generating voice preview:", error);
      res.status(500).json({ error: error.message || "Failed to generate voice preview" });
    }
  });

