  // Generate AI conversation starters based on business context
  app.post("/api/widget-settings/generate-starters", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      // Get OpenAI API key
      const apiKey = await storage.getBusinessAccountOpenAIKey(businessAccountId);
      if (!apiKey) {
        return res.status(400).json({ error: "OpenAI API key not configured" });
      }

      const openai = new OpenAI({ apiKey });

      // Gather business context
      const [products, faqs, widgetSettings, businessAccount] = await Promise.all([
        storage.getAllProducts(businessAccountId),
        storage.getAllFaqs(businessAccountId),
        storage.getWidgetSettings(businessAccountId),
        storage.getBusinessAccount(businessAccountId)
      ]);

      // Build context for AI
      const contextParts: string[] = [];
      
      if (businessAccount?.name) {
        contextParts.push(`Business: ${businessAccount.name}`);
      }

      if (widgetSettings?.customInstructions) {
        contextParts.push(`Custom Instructions: ${widgetSettings.customInstructions}`);
      }

      if (products && products.length > 0) {
        const productList = products.slice(0, 10).map((p: any) => `- ${p.name}${p.price ? ` ($${p.price})` : ''}`).join('\n');
        contextParts.push(`Products:\n${productList}`);
      }

      if (faqs && faqs.length > 0) {
        const faqList = faqs.slice(0, 5).map((f: any) => `- ${f.question}`).join('\n');
        contextParts.push(`Common Questions:\n${faqList}`);
      }

      const context = contextParts.join('\n\n');

      // Generate conversation starters using GPT-4o-mini
      const completion = await openai.chat.completions.create({
        model: "gpt-4o-mini",
        messages: [
          {
            role: "system",
            content: `You are a helpful AI assistant that generates engaging conversation starters for a chatbot. Generate 3 short, natural questions (6-12 words each) that customers might ask based on the business context. Make them conversational, specific to the business, and diverse in topics. Focus on products, services, common questions, or general help.`
          },
          {
            role: "user",
            content: `Generate 3 conversation starter questions for this business:\n\n${context || 'General business chatbot'}\n\nFormat: Return only a JSON array of 3 strings, nothing else. Example: ["Question 1?", "Question 2?", "Question 3?"]`
          }
        ],
        temperature: 0.8,
        max_tokens: 200
      });

      const generatedText = completion.choices[0].message.content?.trim() || '[]';
      
      // Parse the JSON response
      let starters: string[];
      try {
        starters = JSON.parse(generatedText);
        if (!Array.isArray(starters) || starters.length === 0) {
          throw new Error("Invalid response format");
        }
        // Ensure we have exactly 3 starters
        starters = starters.slice(0, 3);
      } catch (parseError) {
        // Fallback to generic starters
        starters = [
          "What products do you offer?",
          "How can you help me today?",
          "Tell me about your services"
        ];
      }

      // Save conversation starters to widget settings
      await storage.upsertWidgetSettings(businessAccountId, {
        conversationStarters: JSON.stringify(starters)
      });

      res.json({ starters });
    } catch (error: any) {
      console.error("Error generating conversation starters:", error);
      res.status(500).json({ error: error.message || "Failed to generate conversation starters" });
    }
  });

