  // Visitor Session Tracking API endpoints (for embedded widget)
  
  // Track unique page visitor - called immediately when widget script loads (before chat opens)
  const visitorDedup = {
    date: '',
    visits: new Map<string, Set<string>>(),
    chatOpens: new Map<string, Set<string>>(),
    getToday() {
      const today = new Date().toISOString().slice(0, 10);
      if (this.date !== today) {
        this.date = today;
        this.visits.clear();
        this.chatOpens.clear();
      }
      return today;
    },
    hasVisited(businessId: string, visitorToken: string): boolean {
      this.getToday();
      const key = `${businessId}`;
      const set = this.visits.get(key);
      return set ? set.has(visitorToken) : false;
    },
    markVisited(businessId: string, visitorToken: string): void {
      this.getToday();
      const key = `${businessId}`;
      if (!this.visits.has(key)) this.visits.set(key, new Set());
      this.visits.get(key)!.add(visitorToken);
    },
    hasChatOpened(businessId: string, visitorToken: string): boolean {
      this.getToday();
      const key = `${businessId}`;
      const set = this.chatOpens.get(key);
      return set ? set.has(visitorToken) : false;
    },
    markChatOpened(businessId: string, visitorToken: string): void {
      this.getToday();
      const key = `${businessId}`;
      if (!this.chatOpens.has(key)) this.chatOpens.set(key, new Set());
      this.chatOpens.get(key)!.add(visitorToken);
    },
  };

  app.post("/api/widget/page-visit", async (req, res) => {
    try {
      const { 
        businessAccountId, 
        visitorToken,
        deviceType,
        country: clientCountry,
        city: clientCity
      } = req.body;

      if (!businessAccountId) {
        return res.status(400).json({ error: "businessAccountId is required" });
      }

      if (visitorToken && visitorDedup.hasVisited(businessAccountId, visitorToken)) {
        return res.json({ success: true, deduplicated: true });
      }

      let country = clientCountry || 
        (req.headers['cf-ipcountry'] as string) || 
        (req.headers['x-vercel-ip-country'] as string) ||
        (req.headers['x-country'] as string) ||
        null;
      
      let city = clientCity ||
        (req.headers['cf-ipcity'] as string) || 
        (req.headers['x-vercel-ip-city'] as string) ||
        (req.headers['x-city'] as string) ||
        null;
      
      if (!country || !city) {
        try {
          const clientIp = (req.headers['x-forwarded-for'] as string)?.split(',')[0].trim() || 
                          req.socket.remoteAddress || 
                          'unknown';
          
          if (clientIp && clientIp !== 'unknown' && !clientIp.startsWith('127.') && !clientIp.startsWith('192.168.') && !clientIp.startsWith('10.')) {
            const geoResponse = await fetch(`http://ip-api.com/json/${clientIp}?fields=status,country,city`);
            if (geoResponse.ok) {
              const geoData = await geoResponse.json();
              if (geoData.status === 'success') {
                country = country || geoData.country;
                city = city || geoData.city;
              }
            }
          }
        } catch (error) {
        }
      }

      if (visitorToken) visitorDedup.markVisited(businessAccountId, visitorToken);
      await storage.incrementDailyStats(businessAccountId, { deviceType, country, city });

      res.json({ success: true });
    } catch (error: any) {
      console.error('[Page Visit] Error tracking page visit:', error);
      res.status(500).json({ error: "Failed to track page visit" });
    }
  });
  
