  // Get visitor stats for dashboard (using daily aggregated stats)
  app.get("/api/page-visitors/stats", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      const { fromDate, toDate } = req.query;
      const stats = await storage.getDailyStats(businessAccountId, {
        fromDate: fromDate as string,
        toDate: toDate as string,
      });

      const convoConditions = [
        eq(conversations.businessAccountId, businessAccountId),
        eq(conversations.isInternalTest, "false"),
      ];
      if (fromDate) convoConditions.push(gte(conversations.createdAt, new Date(fromDate as string)));
      if (toDate) convoConditions.push(lte(conversations.createdAt, new Date(toDate as string)));

      const leadConditions = [eq(leads.businessAccountId, businessAccountId)];
      if (fromDate) leadConditions.push(gte(leads.createdAt, new Date(fromDate as string)));
      if (toDate) leadConditions.push(lte(leads.createdAt, new Date(toDate as string)));

      // Get unique conversation count (phone dedup for form convs, visitorToken for others)
      const [dashAllConvRows, dashFormLeadRows, [leadResult]] = await Promise.all([
        db.select({ id: conversations.id, visitorToken: conversations.visitorToken })
          .from(conversations).where(and(...convoConditions)),
        db.select({ conversationId: leads.conversationId, phone: leads.phone })
          .from(leads)
          .where(and(eq(leads.businessAccountId, businessAccountId), sql`${leads.topicsOfInterest}::text LIKE '%Via Form%'`, sql`${leads.phone} IS NOT NULL AND ${leads.phone} != ''`)),
        db.select({ total: count() }).from(leads).where(and(...leadConditions)),
      ]);
      const dashFormPhoneMap = new Map<string, string>();
      for (const l of dashFormLeadRows) {
        if (l.conversationId && l.phone) {
          const normalized = l.phone.replace(/\D/g, '').slice(-10);
          if (normalized.length >= 7 && !dashFormPhoneMap.has(l.conversationId)) {
            dashFormPhoneMap.set(l.conversationId, 'form_' + normalized);
          }
        }
      }

      const totalPageVisitors = stats.deviceBreakdown.desktop + stats.deviceBreakdown.mobile + stats.deviceBreakdown.tablet;
      const engagedVisitors = new Set(dashAllConvRows.map(c => dashFormPhoneMap.get(c.id) || c.visitorToken || c.id)).size;
      const leadsGenerated = leadResult?.total || 0;

      res.json({
        uniqueVisitors: stats.openedChatCount,
        totalPageVisitors,
        engagedVisitors,
        leadsGenerated,
        engagementRate: totalPageVisitors > 0 ? Math.round((engagedVisitors / totalPageVisitors) * 100) : 0,
        deviceBreakdown: stats.deviceBreakdown,
        topCountries: stats.topCountries,
        topCities: stats.topCities,
      });
    } catch (error: any) {
      console.error("[Page Visitors] Error getting stats:", error);
      res.status(500).json({ error: error.message });
    }
  });

