  // SuperAdmin: MIS (Management Information System) — aggregated metrics across all accounts
  app.get("/api/super-admin/mis", requireAuth, requireRole("super_admin"), async (req, res) => {
    try {
      const now = new Date();
      const istOffset = 5.5 * 60 * 60 * 1000;
      const istNow = new Date(now.getTime() + istOffset);
      const todayIST = istNow.toISOString().split("T")[0];
      const mtdStartIST = `${istNow.getFullYear()}-${String(istNow.getMonth() + 1).padStart(2, "0")}-01`;

      const allAccounts = await db.select({ id: businessAccounts.id, name: businessAccounts.name }).from(businessAccounts);
      const allMembers = await db.select({
        groupId: accountGroupMembers.groupId,
        businessAccountId: accountGroupMembers.businessAccountId,
      }).from(accountGroupMembers);
      const allGroups = await db.select({ id: accountGroups.id, name: accountGroups.name }).from(accountGroups);

      const accountToGroup = new Map<string, string>();
      for (const m of allMembers) {
        accountToGroup.set(m.businessAccountId, m.groupId);
      }
      const groupNameMap = new Map<string, string>();
      for (const g of allGroups) {
        groupNameMap.set(g.id, g.name);
      }

      interface MISRow {
        name: string;
        accountIds: string[];
        type: "group" | "individual";
        accountCount: number;
      }
      const rows: MISRow[] = [];
      const groupedAccountIds = new Map<string, string[]>();
      const ungrouped: { id: string; name: string | null }[] = [];

      for (const acc of allAccounts) {
        const gId = accountToGroup.get(acc.id);
        if (gId) {
          if (!groupedAccountIds.has(gId)) groupedAccountIds.set(gId, []);
          groupedAccountIds.get(gId)!.push(acc.id);
        } else {
          ungrouped.push(acc);
        }
      }
      for (const [gId, ids] of groupedAccountIds) {
        rows.push({ name: groupNameMap.get(gId) || "Unknown Group", accountIds: ids, type: "group", accountCount: ids.length });
      }
      for (const acc of ungrouped) {
        rows.push({ name: acc.name || "Unnamed", accountIds: [acc.id], type: "individual", accountCount: 1 });
      }

      if (allAccounts.length === 0) {
        return res.json([]);
      }

      const [visitorRows, leadRows, convoRows] = await Promise.all([
        db.execute(sql`
          SELECT business_account_id,
            SUM(CASE WHEN date >= ${mtdStartIST} THEN opened_chat_count ELSE 0 END)::int AS mtd,
            SUM(CASE WHEN date = ${todayIST} THEN opened_chat_count ELSE 0 END)::int AS today
          FROM visitor_daily_stats
          WHERE date >= ${mtdStartIST}
          GROUP BY business_account_id
        `),
        db.execute(sql`
          SELECT business_account_id,
            COUNT(CASE WHEN created_at >= ${mtdStartIST}::date THEN 1 END)::int AS mtd,
            COUNT(CASE WHEN created_at >= ${todayIST}::date AND created_at < (${todayIST}::date + interval '1 day') THEN 1 END)::int AS today
          FROM leads
          WHERE created_at >= ${mtdStartIST}::date
          GROUP BY business_account_id
        `),
        db.execute(sql`
          SELECT business_account_id,
            COUNT(CASE WHEN created_at >= ${mtdStartIST}::date THEN 1 END)::int AS mtd,
            COUNT(CASE WHEN created_at >= ${todayIST}::date AND created_at < (${todayIST}::date + interval '1 day') THEN 1 END)::int AS today
          FROM conversations
          WHERE created_at >= ${mtdStartIST}::date
          GROUP BY business_account_id
        `),
      ]);

      const visitorMap = new Map<string, { mtd: number; today: number }>();
      for (const r of visitorRows.rows as any[]) {
        visitorMap.set(r.business_account_id, { mtd: Number(r.mtd) || 0, today: Number(r.today) || 0 });
      }
      const leadMap = new Map<string, { mtd: number; today: number }>();
      for (const r of leadRows.rows as any[]) {
        leadMap.set(r.business_account_id, { mtd: Number(r.mtd) || 0, today: Number(r.today) || 0 });
      }
      const convoMap = new Map<string, { mtd: number; today: number }>();
      for (const r of convoRows.rows as any[]) {
        convoMap.set(r.business_account_id, { mtd: Number(r.mtd) || 0, today: Number(r.today) || 0 });
      }

      const result = rows.map(row => {
        let vMtd = 0, vToday = 0, lMtd = 0, lToday = 0, cMtd = 0, cToday = 0;
        for (const id of row.accountIds) {
          const v = visitorMap.get(id);
          if (v) { vMtd += v.mtd; vToday += v.today; }
          const l = leadMap.get(id);
          if (l) { lMtd += l.mtd; lToday += l.today; }
          const c = convoMap.get(id);
          if (c) { cMtd += c.mtd; cToday += c.today; }
        }
        return {
          name: row.name,
          type: row.type,
          accountCount: row.accountCount,
          visitors: { mtd: vMtd, today: vToday },
          leads: { mtd: lMtd, today: lToday },
          conversations: { mtd: cMtd, today: cToday },
          conversionRate: {
            mtd: vMtd > 0 ? Number(((lMtd / vMtd) * 100).toFixed(2)) : 0,
            today: vToday > 0 ? Number(((lToday / vToday) * 100).toFixed(2)) : 0,
          },
        };
      });

      const filtered = result.filter(r => r.visitors.mtd > 0 || r.leads.mtd > 0 || r.conversations.mtd > 0);
      filtered.sort((a, b) => b.visitors.mtd - a.visitors.mtd);
      res.json(filtered);
    } catch (error: any) {
      console.error("[SuperAdmin MIS] Error:", error);
      res.status(500).json({ error: "Failed to fetch MIS data" });
    }
  });

