  // R2 Cloud Backup - Restore from backup
  app.post("/api/super-admin/backups/restore", requireAuth, requireRole("super_admin"), async (req, res) => {
    try {
      const { backupKey, confirmationCode } = req.body;
      
      if (!backupKey) {
        return res.status(400).json({ error: "Backup key is required" });
      }

      // Server-side validation: Ensure backup key has valid prefix
      const validPrefixes = ['database-backups/daily/', 'database-backups/weekly/', 'database-backups/monthly/'];
      const hasValidPrefix = validPrefixes.some(prefix => backupKey.startsWith(prefix));
      
      if (!hasValidPrefix) {
        console.warn('[R2 Backup] Invalid backup key attempted:', backupKey);
        return res.status(400).json({ error: "Invalid backup key format" });
      }

      // Verify backup exists in the actual backup list
      const existingBackups = await databaseBackupService.listBackups();
      const backupExists = existingBackups.some(b => b.key === backupKey);
      
      if (!backupExists) {
        console.warn('[R2 Backup] Backup not found in list:', backupKey);
        return res.status(404).json({ error: "Backup not found" });
      }

      console.log('[R2 Backup] Restore triggered by SuperAdmin', { 
        backupKey, 
        userId: req.user?.id,
        timestamp: new Date().toISOString()
      });

      // Extract backup info from key
      const backupInfo = existingBackups.find(b => b.key === backupKey);
      const backupType = backupInfo?.type || 'daily';
      const backupDateMatch = backupKey.match(/backup_(\d{4}-\d{2}-\d{2})/);
      const backupDate = backupDateMatch ? backupDateMatch[1] : new Date().toISOString().split('T')[0];
      
      const triggeredBy = req.user?.username || 'manual';
      const result = await databaseBackupService.restoreBackup(backupKey, triggeredBy);
      
      // Record restore history
      try {
        await storage.createRestoreHistory({
          backupKey,
          backupType,
          backupDate,
          restoredBy: req.user?.id,
          restoredByEmail: req.user?.username || undefined,
          durationMs: result.duration?.toString(),
          status: result.success ? 'success' : 'failed',
          errorMessage: result.error,
        });
      } catch (historyError) {
        console.error('[R2 Backup] Failed to record restore history:', historyError);
      }
      
      if (!result.success) {
        return res.status(500).json({ error: result.error });
      }

      res.json({
        success: true,
        message: "Database restored successfully",
        duration: result.duration,
      });
    } catch (error: any) {
      console.error('[R2 Backup] Error during restore:', error);
      res.status(500).json({ error: "Failed to restore database" });
    }
  });

