  // AI Conversation Analysis endpoint
  app.get("/api/insights/conversation-analysis", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.activeBusinessAccountId || req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      const forceRefresh = req.query.refresh === 'true';

      const sevenDaysAgo = new Date();
      sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
      const now = new Date();

      const convCount = await db
        .select({ count: sql<number>`count(*)::int` })
        .from(conversations)
        .where(and(
          eq(conversations.businessAccountId, businessAccountId),
          gte(conversations.createdAt, sevenDaysAgo),
          lte(conversations.createdAt, now)
        ));
      const currentCount = convCount[0]?.count || 0;

      if (currentCount === 0) {
        return res.json({
          topicsOfInterest: [],
          sentiment: { positive: 0, neutral: 100, negative: 0, overall: "neutral" },
          commonPatterns: [],
          engagementInsights: { avgMessagesPerConversation: 0, totalConversations: 0, mostActiveTopics: [] },
          recommendations: [],
          cachedAt: null,
          conversationCount: 0,
        });
      }

      if (!forceRefresh) {
        const [cached] = await db
          .select()
          .from(conversationAnalysisCache)
          .where(eq(conversationAnalysisCache.businessAccountId, businessAccountId))
          .limit(1);

        if (cached) {
          const cacheAge = Date.now() - new Date(cached.updatedAt).getTime();
          const cacheValid = cacheAge < 24 * 60 * 60 * 1000;
          if (cacheValid) {
            const cachedResult = JSON.parse(cached.analysisResult);
            return res.json({ ...cachedResult, cachedAt: cached.updatedAt, conversationCount: currentCount });
          }
        }
      }

      const openaiApiKey = await storage.getBusinessAccountOpenAIKey(businessAccountId);
      const { storage: storageModule } = await import('./storage');
      const master = await storageModule.getMasterAiSettings().catch(() => null);
      const useMaster = !!(master?.masterEnabled && master.primaryApiKey);
      const effectiveKey = useMaster ? master!.primaryApiKey! : openaiApiKey;

      if (!effectiveKey) {
        return res.status(400).json({ 
          error: "OpenAI API key not configured. Please contact SuperAdmin to set it up." 
        });
      }

      const provider = useMaster ? (master!.primaryProvider || 'openai') : 'openai';
      const model = useMaster ? (master!.primaryModel || 'gpt-4o-mini') : 'gpt-4o-mini';

      const recentConversations = await storage.getConversationsByBusinessAccount(
        businessAccountId,
        sevenDaysAgo.toISOString(),
        now.toISOString()
      );

      const conversationIds = recentConversations.map(c => c.id);
      const allMessages = await storage.getMessagesByConversationIds(conversationIds);

      const conversationSummaries = recentConversations.slice(0, 50).map(conv => {
        const convMessages = allMessages.filter(m => m.conversationId === conv.id);
        return {
          title: conv.title,
          messageCount: convMessages.length,
          messages: convMessages.slice(0, 20).map(m => ({
            role: m.role,
            content: m.content.substring(0, 500)
          }))
        };
      });
      const GEMINI_BASE_URL = 'https://generativelanguage.googleapis.com/v1beta/openai/';
      const OpenAIClient = (await import('openai')).default;
      const openai = provider === 'gemini'
        ? new OpenAIClient({ apiKey: effectiveKey, baseURL: GEMINI_BASE_URL })
        : new OpenAIClient({ apiKey: effectiveKey });

      const prompt = `Analyze these customer conversations from the last 7 days and provide a weekly insights report:

${JSON.stringify(conversationSummaries, null, 2)}

Provide a comprehensive analysis with:
1. Top 5 topics users are most interested in
2. Overall sentiment breakdown (positive, neutral, negative percentages that add up to 100)
3. Common patterns or frequently asked questions (3-5 patterns)
4. Engagement insights (what users care about most)
5. 3-5 actionable recommendations for the business to improve customer engagement

Format your response as JSON with this structure:
{
  "topicsOfInterest": ["topic 1", "topic 2", "topic 3", "topic 4", "topic 5"],
  "sentiment": {
    "positive": <percentage>,
    "neutral": <percentage>,
    "negative": <percentage>,
    "overall": "positive|neutral|negative"
  },
  "commonPatterns": ["pattern 1", "pattern 2", "pattern 3"],
  "engagementInsights": {
    "avgMessagesPerConversation": <number>,
    "totalConversations": ${recentConversations.length},
    "mostActiveTopics": ["topic 1", "topic 2", "topic 3"]
  },
  "summary": "Brief 2-3 sentence summary of overall conversation insights",
  "recommendations": ["actionable recommendation 1", "actionable recommendation 2", "actionable recommendation 3"]
}`;

      const completion = await openai.chat.completions.create({
        model,
        messages: [
          {
            role: "system",
            content: "You are an expert data analyst specializing in customer conversation analysis. Provide insights in valid JSON format only."
          },
          { role: "user", content: prompt }
        ],
        temperature: 0.3,
        max_tokens: 1500,
        response_format: { type: "json_object" }
      });

      const analysisText = completion.choices[0].message.content || '{}';
      const analysis = JSON.parse(analysisText);

      await db
        .insert(conversationAnalysisCache)
        .values({
          businessAccountId,
          conversationCount: currentCount,
          analysisResult: JSON.stringify(analysis),
        })
        .onConflictDoUpdate({
          target: conversationAnalysisCache.businessAccountId,
          set: {
            conversationCount: currentCount,
            analysisResult: JSON.stringify(analysis),
            updatedAt: new Date(),
          },
        });

      res.json({ ...analysis, cachedAt: new Date().toISOString(), conversationCount: currentCount });
    } catch (error: any) {
      console.error("Conversation analysis error:", error);
      res.status(500).json({ error: error.message || "Failed to analyze conversations" });
    }
  });

