  app.put("/api/settings/conversation-categories", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.activeBusinessAccountId || req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      const { categories, allowOtherCategory } = req.body;

      if (!Array.isArray(categories)) {
        return res.status(400).json({ error: "categories must be an array" });
      }

      const seen = new Set<string>();
      for (const cat of categories) {
        if (!cat.name || typeof cat.name !== 'string' || !cat.name.trim()) {
          return res.status(400).json({ error: "Each category must have a non-empty name" });
        }
        const key = cat.name.trim().toLowerCase();
        if (seen.has(key)) {
          return res.status(400).json({ error: `Duplicate category name: "${cat.name.trim()}"` });
        }
        seen.add(key);
        if (!Array.isArray(cat.subcategories)) {
          cat.subcategories = [];
        }
        cat.name = cat.name.trim();
        cat.subcategories = cat.subcategories
          .map((s: string) => (typeof s === 'string' ? s.trim() : ''))
          .filter((s: string) => s.length > 0);

        const subSeen = new Set<string>();
        for (const sub of cat.subcategories) {
          const subKey = sub.toLowerCase();
          if (subSeen.has(subKey)) {
            return res.status(400).json({ error: `Duplicate subcategory "${sub}" in category "${cat.name}"` });
          }
          subSeen.add(subKey);
        }
      }

      const [existing] = await db
        .select({ id: conversationCategorySettings.id })
        .from(conversationCategorySettings)
        .where(eq(conversationCategorySettings.businessAccountId, businessAccountId));

      if (existing) {
        await db
          .update(conversationCategorySettings)
          .set({
            categories,
            allowOtherCategory: allowOtherCategory !== false,
            updatedAt: new Date(),
          })
          .where(eq(conversationCategorySettings.id, existing.id));
      } else {
        await db.insert(conversationCategorySettings).values({
          businessAccountId,
          categories,
          allowOtherCategory: allowOtherCategory !== false,
        });
      }

      const { clearCustomCategoriesCache } = await import('./services/conversationCategorizationService');
      clearCustomCategoriesCache(businessAccountId);

      res.json({ success: true });
    } catch (error: any) {
      console.error("[Category Settings PUT] Error:", error);
      res.status(500).json({ error: error.message || "Failed to save category settings" });
    }
  });

  app.post("/api/settings/conversation-categories/auto-generate", requireAuth, requireBusinessAccount, async (req, res) => {
    try {
      const businessAccountId = req.user?.activeBusinessAccountId || req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account not found" });
      }

      const [business] = await db
        .select({
          name: businessAccounts.name,
          description: businessAccounts.description,
          website: businessAccounts.website,
        })
        .from(businessAccounts)
        .where(eq(businessAccounts.id, businessAccountId));

      if (!business) {
        return res.status(400).json({ error: "Business account not found" });
      }

      const [widget] = await db
        .select({ customInstructions: widgetSettings.customInstructions })
        .from(widgetSettings)
        .where(eq(widgetSettings.businessAccountId, businessAccountId));

      const contextParts: string[] = [];
      if (business.name) contextParts.push(`Business Name: ${business.name}`);
      if (business.description) contextParts.push(`Description: ${business.description}`);
      if (business.website) contextParts.push(`Website: ${business.website}`);
      if (widget?.customInstructions) contextParts.push(`AI Instructions: ${widget.customInstructions}`);
      const businessContext = contextParts.join("\n") || "No business context available";

      const { default: OpenAI } = await import("openai");
      const { storage } = await import('./storage');
      const businessApiKey = await storage.getBusinessAccountOpenAIKey(businessAccountId).catch(() => null);
      const envKey = process.env.AI_INTEGRATIONS_OPENAI_API_KEY;
      const baseKey = businessApiKey || envKey;
      const master = await storage.getMasterAiSettings().catch(() => null);
      const useMaster = !!(master?.masterEnabled && master.primaryApiKey);
      const effectiveKey = useMaster ? master!.primaryApiKey! : baseKey;
      if (!effectiveKey) {
        return res.status(500).json({ error: "AI API key not configured" });
      }
      const provider = useMaster ? (master!.primaryProvider || 'openai') : 'openai';
      const model = useMaster ? (master!.primaryModel || 'gpt-4o-mini') : 'gpt-4o-mini';
      const GEMINI_BASE_URL = 'https://generativelanguage.googleapis.com/v1beta/openai/';
      const openai = provider === 'gemini'
        ? new OpenAI({ apiKey: effectiveKey, baseURL: GEMINI_BASE_URL })
        : new OpenAI({ apiKey: effectiveKey });

      const completion = await openai.chat.completions.create({
        model,
        temperature: 0.7,
        messages: [
          {
            role: "system",
            content: `You are a business analyst. Given business information, generate a set of conversation categories and subcategories that would be useful for classifying customer conversations with this business's AI chatbot.

Rules:
- Generate 5-10 main categories that are specific and relevant to this type of business
- Each category should have 2-5 subcategories
- Categories should cover the typical topics customers would discuss
- Use clear, concise names (2-4 words max per category/subcategory)
- Include a "General" or "Other Inquiry" category for miscellaneous topics

Return ONLY a valid JSON object in this format:
{
  "categories": [
    { "name": "Category Name", "subcategories": ["Sub 1", "Sub 2", "Sub 3"] }
  ]
}`
          },
          {
            role: "user",
            content: `Generate conversation categories for this business:\n\n${businessContext}`
          }
        ],
      });

      const responseText = completion.choices[0]?.message?.content || "{}";
      let parsed: any;
      try {
        parsed = JSON.parse(responseText);
      } catch {
        const match = responseText.match(/\{[\s\S]*\}/);
        if (match) {
          try { parsed = JSON.parse(match[0]); } catch { parsed = {}; }
        } else {
          parsed = {};
        }
      }

      const categories = Array.isArray(parsed?.categories) ? parsed.categories
        .filter((c: any) => c?.name && typeof c.name === 'string')
        .map((c: any) => ({
          name: c.name.trim(),
          subcategories: Array.isArray(c.subcategories) ? c.subcategories.filter((s: any) => typeof s === 'string' && s.trim()).map((s: string) => s.trim()) : [],
        })) : [];

      res.json({ categories });
    } catch (error: any) {
      console.error("[Category Auto-Generate] Error:", error);
      res.status(500).json({ error: error.message || "Failed to auto-generate categories" });
    }
  });

