  async function retagLeadAttachments(leadId: string, collectedDocuments: Record<string, any>, delayMs: number = 3000) {
    try {
      const originalCollectedDocuments = collectedDocuments;
      const validDocuments = Object.fromEntries(
        Object.entries(collectedDocuments).filter(([, d]: any) => d?.isValid !== false)
      );
      collectedDocuments = validDocuments;

      if (delayMs > 0) {
        await new Promise(resolve => setTimeout(resolve, delayMs));
      }

      const allAttachments = await db
        .select({ id: whatsappLeadAttachments.id, mediaUrl: whatsappLeadAttachments.mediaUrl, filePath: whatsappLeadAttachments.filePath, documentCategory: whatsappLeadAttachments.documentCategory })
        .from(whatsappLeadAttachments)
        .where(eq(whatsappLeadAttachments.leadId, leadId));

      if (allAttachments.length === 0) return;

      for (const docType of Object.keys(collectedDocuments)) {
        const doc = collectedDocuments[docType];
        if (!doc) continue;
        const docLabel = doc.label || docType.replace(/_/g, ' ');
        const docCapitalized = docLabel.charAt(0).toUpperCase() + docLabel.slice(1);

        const allDocUrls: string[] = [];
        if (doc.sourceMediaUrl) allDocUrls.push(doc.sourceMediaUrl);
        if (doc.fileUrl) allDocUrls.push(doc.fileUrl);
        const additionalPhotos = doc.additionalPhotos || [];
        for (const photo of additionalPhotos) {
          if (photo.sourceMediaUrl) allDocUrls.push(photo.sourceMediaUrl);
          if (photo.fileUrl) allDocUrls.push(photo.fileUrl);
        }

        const matchingIds: string[] = [];
        for (const att of allAttachments) {
          const attMediaUrl = att.mediaUrl || '';
          const attFilePath = att.filePath || '';
          if (allDocUrls.some(u => u === attMediaUrl || u === attFilePath)) {
            matchingIds.push(att.id);
          }
        }

        if (matchingIds.length > 0) {
          const existingForCategory = allAttachments.find(a =>
            a.documentCategory === docType && allDocUrls.some(u => u === a.filePath || u === a.mediaUrl)
          );

          if (existingForCategory) {
            console.log(`[MSG91 Webhook] Retag: attachment already tagged as ${docType} for lead ${leadId}, skipping`);
          } else {
            const untaggedMatch = matchingIds.find(id => {
              const att = allAttachments.find(a => a.id === id);
              return att && !att.documentCategory;
            });

            if (untaggedMatch) {
              await db
                .update(whatsappLeadAttachments)
                .set({ caption: docCapitalized, documentCategory: docType })
                .where(eq(whatsappLeadAttachments.id, untaggedMatch));
              const att = allAttachments.find(a => a.id === untaggedMatch);
              if (att) att.documentCategory = docType;
              console.log(`[MSG91 Webhook] Retag: tagged attachment as ${docType} for lead ${leadId}`);
            } else {
              const sourceAttId = matchingIds[0];
              const fullAtt = await db
                .select()
                .from(whatsappLeadAttachments)
                .where(eq(whatsappLeadAttachments.id, sourceAttId))
                .then(rows => rows[0]);

              if (fullAtt) {
                const newId = crypto.randomUUID();
                await db.insert(whatsappLeadAttachments).values({
                  id: newId,
                  leadId: fullAtt.leadId,
                  businessAccountId: fullAtt.businessAccountId,
                  fileName: fullAtt.fileName,
                  fileType: fullAtt.fileType,
                  mimeType: fullAtt.mimeType,
                  fileSize: fullAtt.fileSize,
                  filePath: fullAtt.filePath,
                  mediaId: fullAtt.mediaId,
                  mediaUrl: fullAtt.mediaUrl,
                  caption: docCapitalized,
                  documentCategory: docType,
                });
                allAttachments.push({
                  id: newId,
                  mediaUrl: fullAtt.mediaUrl,
                  filePath: fullAtt.filePath,
                  documentCategory: docType,
                });
                console.log(`[MSG91 Webhook] Retag: created duplicate attachment as ${docType} for lead ${leadId} (same file, new category)`);
              }
            }
          }

          const staleAttachments = allAttachments.filter(att =>
            att.documentCategory === docType &&
            !allDocUrls.some(u => u === att.filePath || u === att.mediaUrl)
          );
          if (staleAttachments.length > 0) {
            const staleIds = staleAttachments.map(a => a.id);
            await db
              .delete(whatsappLeadAttachments)
              .where(sql`${whatsappLeadAttachments.id} IN (${sql.join(staleIds.map(id => sql`${id}`), sql`, `)})`);
            console.log(`[MSG91 Webhook] Retag cleanup: removed ${staleIds.length} superseded ${docType} attachment(s) for lead ${leadId}`);
          }
        }
      }

      const invalidDocTypes = Object.entries(originalCollectedDocuments)
        .filter(([, d]: any) => d?.isValid === false)
        .map(([type]) => type);

      for (const invalidType of invalidDocTypes) {
        const invalidAtts = allAttachments.filter(att => att.documentCategory === invalidType);
        for (const att of invalidAtts) {
          if (att.filePath) {
            const r2Key = r2Storage.extractKeyFromUrl(att.filePath);
            if (r2Key && r2Storage.isEnabled()) {
              await r2Storage.deleteFile(r2Key);
            }
          }
        }
        if (invalidAtts.length > 0) {
          const invalidIds = invalidAtts.map(a => a.id);
          await db
            .delete(whatsappLeadAttachments)
            .where(sql`${whatsappLeadAttachments.id} IN (${sql.join(invalidIds.map(id => sql`${id}`), sql`, `)})`);
          console.log(`[MSG91 Webhook] Retag: deleted ${invalidAtts.length} invalid ${invalidType} attachment(s) and R2 files for lead ${leadId}`);
        }
      }
    } catch (err) {
      console.error("[MSG91 Webhook] Error in retagLeadAttachments:", err);
    }
  }

  // MSG91 Webhook - Receive WhatsApp messages
  const processedWebhookIds = new Set<string>();

  app.post("/api/webhook/msg91/:businessId", async (req, res) => {
    // Log ALL incoming webhook requests immediately
    console.log("[MSG91 Webhook] ============================================");
    console.log("[MSG91 Webhook] INCOMING REQUEST at", new Date().toISOString());
    console.log("[MSG91 Webhook] Business ID:", req.params.businessId);
    console.log("[MSG91 Webhook] Query params:", JSON.stringify(req.query));
    console.log("[MSG91 Webhook] Headers:", JSON.stringify({
      'content-type': req.headers['content-type'],
      'user-agent': req.headers['user-agent'],
      'x-webhook-secret': req.headers['x-webhook-secret'],
    }));
    console.log("[MSG91 Webhook] Body:", JSON.stringify(req.body, null, 2));
    console.log("[MSG91 Webhook] ============================================");
    
    try {
      const { businessId } = req.params;
      const webhookSecret = req.query.secret as string || req.headers['x-webhook-secret'] as string;
      const { whatsappService } = await import("./services/whatsappService");

      // Verify business exists and has WhatsApp enabled
      const businessAccount = await storage.getBusinessAccount(businessId);
      if (!businessAccount) {
        console.log("[MSG91 Webhook] Business not found:", businessId);
        return res.status(404).json({ error: "Business account not found" });
      }

      if (businessAccount.whatsappEnabled !== "true") {
        console.log("[MSG91 Webhook] WhatsApp not enabled for:", businessId);
        return res.status(403).json({ error: "WhatsApp not enabled for this business" });
      }

      // Verify webhook secret for authentication (always required)
      const settings = await whatsappService.getSettings(businessId);
      
      // Check user-level WhatsApp toggle (in settings)
      if (settings?.whatsappEnabled === "false") {
        console.log("[MSG91 Webhook] WhatsApp disabled by user for:", businessId);
        return res.status(403).json({ error: "WhatsApp AI Agent is disabled" });
      }
      
      if (!settings?.webhookSecret) {
        console.log("[MSG91 Webhook] No webhook secret configured for:", businessId);
        return res.status(401).json({ error: "Webhook not configured. Please configure WhatsApp settings first." });
      }
      if (webhookSecret !== settings.webhookSecret) {
        console.log("[MSG91 Webhook] Invalid webhook secret for:", businessId);
        return res.status(401).json({ error: "Invalid webhook secret" });
      }

      const payload = req.body;

      const incomingIntegratedNumber = (payload.integratedNumber || "").replace(/\D/g, '');
      const configuredWhatsappNumber = (settings.whatsappNumber || "").replace(/\D/g, '');
      if (incomingIntegratedNumber && configuredWhatsappNumber && incomingIntegratedNumber !== configuredWhatsappNumber) {
        console.log(`[MSG91 Webhook] SKIPPING - integratedNumber ${incomingIntegratedNumber} does not match configured number ${configuredWhatsappNumber} for business ${businessId}`);
        return res.json({ status: "received", note: "message not for this business number" });
      }

      console.log("[MSG91 Webhook] Received:", JSON.stringify(payload, null, 2));

      // MSG91 "Webhook (New)" format detection
      // New format has flat fields: customerNumber, text, contentType, direction, uuid, url, filename, caption
      // Old format has: type="message", payload object with source, type, text.body, etc.
      
      const isNewFormat = payload.customerNumber !== undefined || payload.direction !== undefined;
      
      if (isNewFormat) {
        // MSG91 "Webhook (New)" format
        console.log("[MSG91 Webhook] Detected NEW format payload");
        
        const { 
          customerNumber,   // sender phone
          text,             // message text
          contentType,      // text, image, document, interactive, etc.
          direction,        // "0" = inbound, "1" = outbound
          uuid,             // unique message ID from Meta
          url,              // media URL (for images/documents)
          filename,         // file name (for documents)
          caption,          // caption (for media)
          customerName,     // sender name if available
          integratedNumber, // your WhatsApp business number
          requestId,        // MSG91 request ID
        } = payload;

        // Only process inbound messages (direction = "0" or 0)
        if (direction === "1" || direction === 1) {
          console.log("[MSG91 Webhook] Skipping outbound message (direction=1)");
          return res.json({ status: "received", note: "outbound message skipped" });
        }

        const messageId = uuid || requestId || `msg_${Date.now()}_${Math.random()}`;
        const senderPhone = customerNumber?.replace(/\D/g, '') || null;

        if (!senderPhone) {
          console.log("[MSG91 Webhook] No sender phone in payload");
          return res.json({ status: "received", note: "no sender phone" });
        }

        const bizScopedMessageId = `${businessId}:${messageId}`;
        if (processedWebhookIds.has(bizScopedMessageId)) {
          console.log(`[MSG91 Webhook] Duplicate webhook for message ${messageId} on business ${businessId}, skipping entirely`);
          return res.json({ status: "received", note: "duplicate webhook skipped" });
        }

        const hasReliableId = !!(uuid || requestId);
        if (!hasReliableId) {
          const senderDedupKey = `${businessId}:${senderPhone}:${(text || '').substring(0, 100)}:${contentType}`;
          if (processedWebhookIds.has(senderDedupKey)) {
            console.log(`[MSG91 Webhook] Duplicate sender+content for ${senderPhone} on business ${businessId}, skipping (no reliable messageId)`);
            return res.json({ status: "received", note: "duplicate sender+content skipped" });
          }
          processedWebhookIds.add(senderDedupKey);
          setTimeout(() => processedWebhookIds.delete(senderDedupKey), 2 * 1000);
          console.log(`[MSG91 Webhook] WARNING: No uuid/requestId in payload, using sender+content dedup`);
        }

        processedWebhookIds.add(bizScopedMessageId);
        setTimeout(() => processedWebhookIds.delete(bizScopedMessageId), 5 * 60 * 1000);

        if (settings?.whitelistEnabled === "true") {
          const { whatsappWhitelist } = await import("../shared/schema");
          const allWhitelisted = await db.select({ phoneNumber: whatsappWhitelist.phoneNumber })
            .from(whatsappWhitelist)
            .where(eq(whatsappWhitelist.businessAccountId, businessId));
          const isWhitelisted = allWhitelisted.some(entry => {
            const wn = entry.phoneNumber;
            return wn === senderPhone || senderPhone.endsWith(wn) || wn.endsWith(senderPhone);
          });
          if (!isWhitelisted) {
            console.log(`[MSG91 Webhook] Number ${senderPhone} not whitelisted for business ${businessId}, skipping`);
            return res.json({ status: "received", note: "not whitelisted" });
          }
        }

        const { updateSession } = await import("./services/whatsappSessionService");
        updateSession(businessId, senderPhone).catch(err =>
          console.error("[MSG91 Webhook] Session update error (non-fatal):", err)
        );

        // Process based on content type
        if (contentType === "text" && text) {
          const webhookStartTime = Date.now();
          const { whatsappFlowService } = await import("./services/whatsappFlowService");
          const { whatsappAutoReplyService } = await import("./services/whatsappAutoReplyService");
          
          const pendingSession = await whatsappFlowService.getActiveSession(businessId, senderPhone);
          const pendingCollected = (pendingSession?.collectedData as Record<string, any>) || {};
          let flowResult;
          if (pendingCollected._pendingPdfUrl) {
            const activeFlow = await whatsappFlowService.getActiveFlow(businessId);
            const triggerKw = activeFlow?.triggerKeyword?.trim()?.toLowerCase();
            const normalizedText = text.trim().toLowerCase();
            if (triggerKw && normalizedText === triggerKw) {
              console.log("[MSG91 Webhook] Trigger keyword during PDF password flow, restarting journey");
              flowResult = await whatsappFlowService.processMessage(businessId, senderPhone, text, pendingSession);
            } else {
              console.log("[MSG91 Webhook] Session has pending PDF, treating text as password");
              flowResult = await whatsappFlowService.processPdfPassword(businessId, senderPhone, text);
            }
          } else {
            flowResult = await whatsappFlowService.processMessage(businessId, senderPhone, text, pendingSession);
          }
          
          console.log(`[MSG91 Webhook] [Timing] Flow processing: ${Date.now() - webhookStartTime}ms`);
          
          if (flowResult.handled) {
            // Flow handled this message — respond to MSG91 immediately, do storage in background
            console.log(`[MSG91 Webhook] [Timing] Total webhook (flow-handled): ${Date.now() - webhookStartTime}ms`);
            res.json({ status: "received" });
            
            // Background: store incoming message FIRST, then send outgoing response
            // This preserves correct chronological ordering in conversation history
            (async () => {
              try {
                const lead = await whatsappService.storeFlowMessage(
                  businessId,
                  messageId,
                  senderPhone,
                  text,
                  customerName,
                  flowResult.sessionId
                );
                if (lead) {
                  console.log(`[MSG91 Webhook] Flow message stored, lead: ${lead.id}`);
                }
                console.log(`[MSG91 Webhook] [Timing] Background message stored: ${Date.now() - webhookStartTime}ms`);
                
                // Send WhatsApp response AFTER incoming is stored
                if (settings && (flowResult.preMessages?.length || flowResult.response)) {
                  for (const preMsg of (flowResult.preMessages || [])) {
                    await whatsappAutoReplyService.sendFlowResponse(settings, senderPhone, preMsg, flowResult.sessionId);
                  }
                  if (flowResult.response) {
                    const result = await whatsappAutoReplyService.sendFlowResponse(
                      settings,
                      senderPhone,
                      flowResult.response,
                      flowResult.sessionId
                    );
                    if (result.success) {
                      console.log("[MSG91 Webhook] Flow response sent successfully");
                    } else {
                      console.log("[MSG91 Webhook] Flow response failed:", result.error);
                    }
                  }
                }
                
                // Update lead with flow-collected data AFTER message is stored (so lead exists)
                if (flowResult.collectedData && Object.keys(flowResult.collectedData).length > 0) {
                  try {
                    const updatedLead = await whatsappService.updateLeadWithFlowData(
                      businessId,
                      senderPhone,
                      flowResult.collectedData,
                      flowResult.sessionId,
                      !!flowResult.flowCompleted
                    );
                    if (updatedLead) {
                      console.log(`[MSG91 Webhook] Lead updated with flow data (completed=${!!flowResult.flowCompleted}):`, updatedLead.id);

                      if (flowResult.flowCompleted) {
                        (async () => {
                          try {
                            const [crmSettings] = await db
                              .select()
                              .from(customCrmSettings)
                              .where(eq(customCrmSettings.businessAccountId, businessId))
                              .limit(1);

                            if (crmSettings?.enabled && crmSettings.autoSyncEnabled && crmSettings.apiBaseUrl && crmSettings.apiEndpoint) {
                              console.log('[Custom CRM] Auto-syncing WhatsApp lead:', updatedLead.id);
                              const crmMappings = await db
                                .select()
                                .from(customCrmFieldMappings)
                                .where(eq(customCrmFieldMappings.businessAccountId, businessId))
                                .orderBy(customCrmFieldMappings.sortOrder);

                              const extractedData = (updatedLead.extractedData as Record<string, any>) || {};
                              const documents = await buildDocumentContext(updatedLead.id);
                              const leadContext = {
                                lead: {
                                  customerName: updatedLead.customerName || null,
                                  customerEmail: updatedLead.customerEmail || null,
                                  customerPhone: updatedLead.customerPhone || null,
                                  loanAmount: updatedLead.loanAmount || null,
                                  address: updatedLead.address || null,
                                  loanType: updatedLead.loanType || null,
                                  senderPhone: updatedLead.senderPhone || null,
                                },
                                extracted: extractedData,
                                documents,
                              };

                              let autoStoreCredential: CrmStoreCredential | undefined = undefined;
                              const asStoreName = extractedData.store_name || extractedData.storeName;
                              const asDealerName = extractedData.dealer_name || extractedData.dealerName || extractedData.dealer;
                              const asCityName = extractedData.city || extractedData.city_name || extractedData.dealer_city || extractedData.dealerCity;
                              if (asStoreName || asDealerName) {
                                const asStoreCreds = await db.select().from(crmStoreCredentials).where(and(eq(crmStoreCredentials.businessAccountId, businessId), eq(crmStoreCredentials.isActive, true)));
                                const asNorm = (s?: string | null) => s ? s.trim().toLowerCase() : '';
                                const asNS = asNorm(asStoreName), asND = asNorm(asDealerName), asNC = asNorm(asCityName);
                                if (asNS && asND && asNC) autoStoreCredential = asStoreCreds.find(sc => asNorm(sc.storeName) === asNS && asNorm(sc.dealerName) === asND && asNorm(sc.city) === asNC);
                                if (!autoStoreCredential && asNS && asND) autoStoreCredential = asStoreCreds.find(sc => asNorm(sc.storeName) === asNS && asNorm(sc.dealerName) === asND);
                                if (!autoStoreCredential && asNS) autoStoreCredential = asStoreCreds.find(sc => asNorm(sc.storeName) === asNS);
                                if (!autoStoreCredential && asStoreCreds.length > 0 && (asNS || asND)) {
                                  try {
                                    const OpenAI = (await import('openai')).default;
                                    const [bizAcct] = await db.select().from(businessAccounts).where(eq(businessAccounts.id, businessId)).limit(1);
                                    const asApiKey = bizAcct?.openaiApiKey ? (await import('./services/encryptionService')).decrypt(bizAcct.openaiApiKey) : process.env.OPENAI_API_KEY;
                                    if (asApiKey) {
                                      const asOAI = new OpenAI({ apiKey: asApiKey, timeout: 15000 });
                                      const asList = asStoreCreds.map(sc => ({ id: sc.id, dealerName: sc.dealerName, storeName: sc.storeName, city: sc.city || '', storeId: sc.storeId }));
                                      const asPrompt = `Match the lead's store info to the closest store credential.\n\nLead info:\n- Dealer: ${asDealerName || 'unknown'}\n- City: ${asCityName || 'unknown'}\n- Store: ${asStoreName || 'unknown'}\n\nAvailable stores (JSON):\n${JSON.stringify(asList)}\n\nReturn ONLY a JSON object: {"matchedId": "<store id or null>", "confidence": <0.0-1.0>}\nIf no good match exists, return {"matchedId": null, "confidence": 0}`;
                                      const asCompletion = await asOAI.chat.completions.create({ model: 'gpt-4o-mini', messages: [{ role: 'user', content: asPrompt }], temperature: 0, max_tokens: 100, response_format: { type: 'json_object' } });
                                      const asContent = asCompletion.choices[0]?.message?.content;
                                      if (asContent) { const asAI = JSON.parse(asContent) as { matchedId: string | null; confidence: number }; if (asAI.matchedId && asAI.confidence >= 0.75) { autoStoreCredential = asStoreCreds.find(sc => sc.id === asAI.matchedId); console.log(`[CRM AutoSync] AI fuzzy match: store=${autoStoreCredential?.storeName}, confidence=${asAI.confidence}`); } }
                                    }
                                  } catch (asErr) { console.warn('[CRM AutoSync] AI fuzzy store matching failed:', asErr); }
                                }
                                if (autoStoreCredential) console.log(`[CRM AutoSync] Resolved store: ${autoStoreCredential.storeName} (SID: ${autoStoreCredential.sid})`);
                              }

                              const { syncLeadWithDocuments } = await import('./services/customCrmService');
                              const crmResult = await syncLeadWithDocuments(crmSettings, crmMappings, leadContext, autoStoreCredential);

                              if (crmResult.success) {
                                await db.update(whatsappLeads)
                                  .set({
                                    customCrmSyncStatus: 'synced',
                                    customCrmSyncedAt: new Date(),
                                    customCrmLeadId: crmResult.leadId || crmResult.applicationId || null,
                                    customCrmSyncError: null,
                                    customCrmSyncPayload: crmResult.payload as any,
                                    updatedAt: new Date(),
                                  })
                                  .where(eq(whatsappLeads.id, updatedLead.id));
                                console.log('[Custom CRM] Auto-sync success:', updatedLead.id);
                              } else {
                                await db.update(whatsappLeads)
                                  .set({
                                    customCrmSyncStatus: 'failed',
                                    customCrmSyncError: crmResult.message,
                                    customCrmSyncPayload: crmResult.payload as any,
                                    updatedAt: new Date(),
                                  })
                                  .where(eq(whatsappLeads.id, updatedLead.id));
                                console.error('[Custom CRM] Auto-sync failed:', updatedLead.id, crmResult.message);
                              }
                            }
                          } catch (crmErr) {
                            console.error('[Custom CRM] Auto-sync error:', crmErr);
                          }
                        })();
                      }
                    }
                  } catch (flowDataErr) {
                    console.error("[MSG91 Webhook] Failed to update lead with flow data:", flowDataErr);
                  }
                }
              } catch (err) {
                console.error("[MSG91 Webhook] Background flow processing error:", err);
              }
            })();
          } else if (flowResult.skipLeadCreation) {
            // User already completed flow — store message for conversation history only, no new lead
            await whatsappService.storeMessageOnly(
              businessId,
              messageId,
              senderPhone,
              text,
              customerName
            );
            console.log(`[MSG91 Webhook] Message stored (post-flow conversation, no lead created)`);
            console.log(`[MSG91 Webhook] [Timing] Total webhook (post-flow): ${Date.now() - webhookStartTime}ms`);
            res.json({ status: "received" });
          } else {
            // Non-flow message — use full AI extraction path (synchronous)
            const aiStartTime = Date.now();
            const lead = await whatsappService.processTextMessage(
              businessId,
              messageId,
              senderPhone,
              text,
              customerName,
              flowResult.sessionId
            );
            console.log(`[MSG91 Webhook] [Timing] AI extraction + message stored: ${Date.now() - aiStartTime}ms`);
            if (lead) {
              console.log("[MSG91 Webhook] Created lead from text:", lead.id);
            } else {
              console.log("[MSG91 Webhook] Text message processed, no lead created (didn't meet criteria)");
            }

            // Non-flow messages don't have auto-reply from flow, handled elsewhere
            console.log(`[MSG91 Webhook] [Timing] Total webhook (non-flow): ${Date.now() - webhookStartTime}ms`);
            res.json({ status: "received" });
          }
          
          // Non-critical background tasks (fire-and-forget)
          if (flowResult.handled && flowResult.collectedData?._bankStatementPassword && flowResult.collectedData?._collectedDocuments) {
            whatsappService.findLeadByFlowSession(businessId, flowResult.sessionId || pendingSession?.id || '').then(async (existingLead) => {
              if (existingLead) {
                const [freshLead] = await db
                  .select({ extractedData: whatsappLeads.extractedData })
                  .from(whatsappLeads)
                  .where(eq(whatsappLeads.id, existingLead.id))
                  .limit(1);
                const currentData = (freshLead?.extractedData as Record<string, any>) || {};
                currentData._documents = {
                  ...((currentData._documents as Record<string, any>) || {}),
                  ...flowResult.collectedData._collectedDocuments
                };
                currentData.bank_statement_password = flowResult.collectedData._bankStatementPassword;
                await db
                  .update(whatsappLeads)
                  .set({ extractedData: currentData })
                  .where(eq(whatsappLeads.id, existingLead.id));
                console.log("[MSG91 Webhook] Stored bank statement password and documents for lead:", existingLead.id);

                const docs = flowResult.collectedData._collectedDocuments;
                for (const docType of Object.keys(docs)) {
                  const doc = docs[docType];
                  const docLabel = doc.label || docType.replace(/_/g, ' ');
                  const docCapitalized = docLabel.charAt(0).toUpperCase() + docLabel.slice(1);
                  const allUrls: string[] = [];
                  const primaryUrl = doc.sourceMediaUrl || doc.fileUrl;
                  if (primaryUrl) allUrls.push(primaryUrl);
                  const additionalPhotos = doc.additionalPhotos || [];
                  for (const photo of additionalPhotos) {
                    const photoUrl = photo.sourceMediaUrl || photo.fileUrl;
                    if (photoUrl) allUrls.push(photoUrl);
                  }
                  const newlyTaggedIds: string[] = [];
                  for (const sourceUrl of allUrls) {
                    const tagged = await db
                      .update(whatsappLeadAttachments)
                      .set({ caption: docCapitalized, documentCategory: docType })
                      .where(and(
                        eq(whatsappLeadAttachments.leadId, existingLead.id),
                        sql`(${whatsappLeadAttachments.caption} IS NULL OR ${whatsappLeadAttachments.caption} = '')`,
                        sql`(${whatsappLeadAttachments.mediaUrl} = ${sourceUrl} OR ${whatsappLeadAttachments.filePath} = ${sourceUrl})`
                      ))
                      .returning({ id: whatsappLeadAttachments.id });
                    if (tagged.length > 0) {
                      newlyTaggedIds.push(...tagged.map(t => t.id));
                      console.log(`[MSG91 Webhook] Tagged attachment as: ${docCapitalized} (category: ${docType}, matched by URL)`);
                    }
                  }
                  if (newlyTaggedIds.length > 0) {
                    const deleted = await db
                      .delete(whatsappLeadAttachments)
                      .where(and(
                        eq(whatsappLeadAttachments.leadId, existingLead.id),
                        eq(whatsappLeadAttachments.documentCategory, docType),
                        sql`${whatsappLeadAttachments.id} NOT IN (${sql.join(newlyTaggedIds.map(id => sql`${id}`), sql`, `)})`
                      ))
                      .returning({ id: whatsappLeadAttachments.id });
                    if (deleted.length > 0) {
                      console.log(`[MSG91 Webhook] Removed ${deleted.length} duplicate ${docType} attachment(s) for lead ${existingLead.id}`);
                    }
                  }
                  if (allUrls.length === 0) {
                    const isPdf = docType.includes('bank') || docType.includes('statement');
                    if (isPdf) {
                      const tagged = await db
                        .update(whatsappLeadAttachments)
                        .set({ caption: docCapitalized, documentCategory: docType })
                        .where(and(
                          eq(whatsappLeadAttachments.leadId, existingLead.id),
                          sql`(${whatsappLeadAttachments.caption} IS NULL OR ${whatsappLeadAttachments.caption} = '')`,
                          sql`${whatsappLeadAttachments.fileName} ILIKE '%.pdf'`
                        ))
                        .returning({ id: whatsappLeadAttachments.id });
                      if (tagged.length > 0) {
                        console.log(`[MSG91 Webhook] Tagged ${tagged.length} PDF attachment(s) as: ${docCapitalized} (category: ${docType})`);
                      }
                    }
                  }
                }
              }
            }).catch(err => {
              console.error("[MSG91 Webhook] Failed to store documents:", err);
            });
          }

          if (flowResult.handled && flowResult.collectedData?._collectedDocuments && !flowResult.collectedData?._bankStatementPassword) {
            const updateLeadId = flowResult.collectedData?._updateExistingLeadId;
            const findLeadPromise = updateLeadId
              ? db.select().from(whatsappLeads).where(eq(whatsappLeads.id, updateLeadId)).limit(1).then(rows => rows[0] || null)
              : whatsappService.findLeadByFlowSession(businessId, flowResult.sessionId || pendingSession?.id || '');

            findLeadPromise.then(async (existingLead: any) => {
              if (existingLead) {
                await whatsappService.syncLeadDocuments(existingLead.id, flowResult.collectedData._collectedDocuments);
                await retagLeadAttachments(existingLead.id, flowResult.collectedData._collectedDocuments);
                if (updateLeadId) {
                  console.log(`[MSG91 Webhook] Updated existing lead ${existingLead.id} with new documents (update flow)`);
                }
              }
            }).catch((err: any) => {
              console.error("[MSG91 Webhook] Failed to sync collected documents to lead:", err);
            });
          }

          
          if (flowResult.shouldFallbackToAI && settings?.autoReplyEnabled === "true" && text) {
            whatsappAutoReplyService.generateAndSendReply(
              businessId,
              senderPhone,
              text,
              uuid
            ).then(result => {
              if (result.success) {
                console.log("[MSG91 Webhook] Auto-reply sent successfully");
              } else {
                console.log("[MSG91 Webhook] Auto-reply failed:", result.error);
              }
            }).catch(err => {
              console.error("[MSG91 Webhook] Auto-reply error:", err);
            });
          } else if (!flowResult.handled && settings?.autoReplyEnabled === "true" && text) {
            whatsappAutoReplyService.generateAndSendReply(
              businessId,
              senderPhone,
              text,
              uuid
            ).then(result => {
              if (result.success) {
                console.log("[MSG91 Webhook] Auto-reply sent successfully");
              } else {
                console.log("[MSG91 Webhook] Auto-reply failed:", result.error);
              }
            }).catch(err => {
              console.error("[MSG91 Webhook] Auto-reply error:", err);
            });
          }
          
          return;
        } else if ((contentType === "image" || contentType === "document" || contentType === "file") && url) {
          // Get the active flow session ID for this sender (for lead deduplication)
          const { whatsappFlowService } = await import("./services/whatsappFlowService");
          const activeSession = await whatsappFlowService.getActiveSession(businessId, senderPhone);
          const attachmentFlowSessionId = activeSession?.id;
          
          // Check if this is a file/image upload for document identification in an upload step
          // Also allow processing when no active session exists (returning user detection in processImageUpload)
          if ((contentType === "image" || contentType === "file" || contentType === "document")) {
            // Validate URL is from MSG91 domain for security (prevent SSRF)
            const urlObj = new URL(url);
            const allowedDomains = ["msg91.com", "cdn.msg91.com", "api.msg91.com", "msg91.io", "storage.googleapis.com", "phone91.com"];
            const isAllowedDomain = allowedDomains.some(domain => 
              urlObj.hostname === domain || urlObj.hostname.endsWith(`.${domain}`)
            );
            
            if (isAllowedDomain) {
              console.log("[MSG91 Webhook] Downloading image immediately to prevent URL expiry");
              let preDownloadedBuffer: Buffer | null = null;
              try {
                const controller = new AbortController();
                const timeoutId = setTimeout(() => controller.abort(), 15000);
                const imgResponse = await fetch(url, { signal: controller.signal });
                clearTimeout(timeoutId);
                if (imgResponse.ok) {
                  const arrayBuffer = await imgResponse.arrayBuffer();
                  preDownloadedBuffer = Buffer.from(arrayBuffer);
                  console.log(`[MSG91 Webhook] Image pre-downloaded: ${preDownloadedBuffer.length} bytes`);
                } else {
                  console.log(`[MSG91 Webhook] Image pre-download failed: HTTP ${imgResponse.status}`);
                }
              } catch (dlErr: any) {
                console.error("[MSG91 Webhook] Image pre-download error:", dlErr.message);
              }

              console.log("[MSG91 Webhook] Checking if current step is upload step for document ID");
              const flowResult = await whatsappFlowService.processImageUpload(businessId, senderPhone, url, filename, preDownloadedBuffer || undefined);
              
              if (flowResult.handled) {
                console.log("[MSG91 Webhook] Document upload processed by flow service");

                const effectiveSessionId = flowResult.sessionId || activeSession?.id;
                const updateLeadId = flowResult.collectedData?._updateExistingLeadId;
                let lead: any = null;
                if (updateLeadId) {
                  const [existingLead] = await db.select().from(whatsappLeads).where(eq(whatsappLeads.id, updateLeadId)).limit(1);
                  lead = existingLead || null;
                }
                if (!lead && effectiveSessionId) {
                  lead = await whatsappService.findLeadByFlowSession(businessId, effectiveSessionId);
                }
                if (!lead && !updateLeadId) {
                  lead = await whatsappService.processTextMessage(
                    businessId,
                    messageId,
                    senderPhone,
                    caption || "[Document upload]",
                    customerName,
                    effectiveSessionId || undefined
                  );
                }
                
                if (url) {
                  const uploadMessage = await whatsappService.createMinimalLead(
                    businessId,
                    senderPhone,
                    caption || `📎 ${filename || "Document"}`,
                    effectiveSessionId,
                    'incoming'
                  );
                  console.log("[MSG91 Webhook] Stored incoming file upload as message:", uploadMessage.id);

                  if (flowResult.rejectedDuplicate) {
                    console.log("[MSG91 Webhook] Document was rejected as duplicate — skipping R2 upload and attachment creation");
                  } else {
                  let mediaType: "image" | "document" = "document";
                  if (contentType === "image" || (contentType === "file" && filename?.match(/\.(jpg|jpeg|png|gif|webp)$/i))) {
                    mediaType = "image";
                  }
                  const attachToLeadId = lead?.id || uploadMessage.id;
                  const r2Url = await whatsappService.downloadAndSaveMediaFromUrl(
                    attachToLeadId,
                    businessId,
                    url,
                    mediaType,
                    filename,
                    caption
                  );
                  
                  if (r2Url && attachToLeadId !== uploadMessage.id) {
                    const { whatsappLeadAttachments: wlaSchema } = await import("../shared/schema");
                    await db.insert(wlaSchema).values({
                      leadId: uploadMessage.id,
                      businessAccountId: businessId,
                      fileName: filename || `${mediaType}_${Date.now()}`,
                      fileType: mediaType === "image" ? "image" : "document",
                      mimeType: mediaType === "image" ? "image/jpeg" : "application/pdf",
                      filePath: r2Url,
                      mediaUrl: url,
                      caption: caption || null,
                    });
                    console.log("[MSG91 Webhook] Also linked attachment to conversation message:", uploadMessage.id);
                  }
                  
                  if (r2Url) {
                    try {
                      const freshSession = await whatsappFlowService.getActiveSession(businessId, senderPhone);
                      if (freshSession) {
                        const sessionData = (freshSession.collectedData as Record<string, any>) || {};
                        const docs = sessionData._collectedDocuments || {};
                        let updated = false;
                        let matchedDocLabel: string | null = null;
                        let matchedDocType: string | null = null;
                        for (const docType of Object.keys(docs)) {
                          const docObj = docs[docType];
                          if (!docObj) continue;
                          if (docObj.sourceMediaUrl === url) {
                            docObj.fileUrl = r2Url;
                            delete docObj.sourceMediaUrl;
                            matchedDocLabel = docObj.label || docType.replace(/_/g, ' ');
                            matchedDocType = docType;
                            updated = true;
                            break;
                          }
                          const additionalPhotos = docObj.additionalPhotos || [];
                          const matchedPhoto = additionalPhotos.find((p: any) => p.sourceMediaUrl === url);
                          if (matchedPhoto) {
                            matchedPhoto.fileUrl = r2Url;
                            delete matchedPhoto.sourceMediaUrl;
                            matchedDocLabel = docObj.label || docType.replace(/_/g, ' ');
                            matchedDocType = docType;
                            updated = true;
                            break;
                          }
                        }
                        if (!matchedDocLabel) {
                          for (const docType of Object.keys(docs)) {
                            const docObj = docs[docType];
                            if (!docObj) continue;
                            if (docObj.fileUrl === r2Url) {
                              matchedDocLabel = docObj.label || docType.replace(/_/g, ' ');
                              matchedDocType = docType;
                              break;
                            }
                            const additionalPhotos = docObj.additionalPhotos || [];
                            if (additionalPhotos.some((p: any) => p.fileUrl === r2Url)) {
                              matchedDocLabel = docObj.label || docType.replace(/_/g, ' ');
                              matchedDocType = docType;
                              break;
                            }
                          }
                        }
                        if (updated) {
                          sessionData._collectedDocuments = docs;
                          await whatsappFlowService.updateSessionData(freshSession.id, sessionData);
                        }
                        if (matchedDocLabel && matchedDocType) {
                          const { whatsappLeadAttachments } = await import("../shared/schema");
                          const { eq, and } = await import("drizzle-orm");
                          const docEntry = docs[matchedDocType];
                          if (docEntry?.isValid === false) {
                            const [invalidAtt] = await db
                              .select({ id: whatsappLeadAttachments.id, filePath: whatsappLeadAttachments.filePath })
                              .from(whatsappLeadAttachments)
                              .where(and(
                                eq(whatsappLeadAttachments.leadId, attachToLeadId),
                                eq(whatsappLeadAttachments.mediaUrl, url)
                              ));
                            if (invalidAtt?.filePath) {
                              const r2Key = r2Storage.extractKeyFromUrl(invalidAtt.filePath);
                              if (r2Key && r2Storage.isEnabled()) {
                                await r2Storage.deleteFile(r2Key);
                              }
                            }
                            await db.delete(whatsappLeadAttachments)
                              .where(and(
                                eq(whatsappLeadAttachments.leadId, attachToLeadId),
                                eq(whatsappLeadAttachments.mediaUrl, url)
                              ));
                            console.log(`[MSG91 Webhook] Deleted invalid ${matchedDocType} attachment and R2 file for lead ${attachToLeadId}`);
                          } else {
                            const taggedRows = await db.update(whatsappLeadAttachments)
                              .set({ caption: matchedDocLabel, documentCategory: matchedDocType })
                              .where(and(
                                eq(whatsappLeadAttachments.leadId, attachToLeadId),
                                eq(whatsappLeadAttachments.mediaUrl, url)
                              ))
                              .returning({ id: whatsappLeadAttachments.id });
                            console.log(`[MSG91 Webhook] Tagged attachment as: ${matchedDocLabel} (category: ${matchedDocType})`);
                            if (taggedRows.length > 0) {
                              const taggedIds = taggedRows.map(t => t.id);
                              const deletedDups = await db
                                .delete(whatsappLeadAttachments)
                                .where(and(
                                  eq(whatsappLeadAttachments.leadId, attachToLeadId),
                                  eq(whatsappLeadAttachments.documentCategory, matchedDocType),
                                  sql`${whatsappLeadAttachments.id} NOT IN (${sql.join(taggedIds.map(id => sql`${id}`), sql`, `)})`
                                ))
                                .returning({ id: whatsappLeadAttachments.id });
                              if (deletedDups.length > 0) {
                                console.log(`[MSG91 Webhook] Removed ${deletedDups.length} duplicate ${matchedDocType} attachment(s) for lead ${attachToLeadId}`);
                              }
                            }
                          }
                        }
                      }
                    } catch (err) {
                      console.error("[MSG91 Webhook] Error updating doc fileUrl:", err);
                    }
                  }
                  }
                }
                
                if (lead) {
                  let docsToSync: any = null;
                  try {
                    const freshSession = await whatsappFlowService.getActiveSession(businessId, senderPhone);
                    if (freshSession) {
                      const sessionData = (freshSession.collectedData as Record<string, any>) || {};
                      docsToSync = sessionData._collectedDocuments;
                    }
                  } catch (err) {
                    console.error("[MSG91 Webhook] Error fetching session for doc sync:", err);
                  }
                  if (!docsToSync) {
                    docsToSync = flowResult.collectedData?._collectedDocuments;
                  }
                  if (docsToSync && Object.keys(docsToSync).length > 0) {
                    await whatsappService.syncLeadDocuments(lead.id, docsToSync);
                    await retagLeadAttachments(lead.id, docsToSync);
                  }
                  if (flowResult.collectedData && Object.keys(flowResult.collectedData).length > 0) {
                    try {
                      const updatedLead = await whatsappService.updateLeadWithFlowData(
                        businessId,
                        senderPhone,
                        flowResult.collectedData,
                        flowResult.sessionId,
                        !!flowResult.flowCompleted
                      );
                      if (updatedLead) {
                        console.log(`[MSG91 Webhook] Lead updated with doc flow data:`, updatedLead.id);
                      }
                    } catch (err) {
                      console.error("[MSG91 Webhook] Error updating lead with doc flow data:", err);
                    }
                  }
                }
                
                if (flowResult.response || flowResult.preMessages?.length) {
                  const whatsappSettings = await whatsappService.getSettings(businessId);
                  if (whatsappSettings) {
                    const { whatsappAutoReplyService } = await import("./services/whatsappAutoReplyService");
                    (async () => {
                      for (const preMsg of (flowResult.preMessages || [])) {
                        await whatsappAutoReplyService.sendFlowResponse(whatsappSettings, senderPhone, preMsg, activeSession.id);
                      }
                      if (flowResult.response) {
                        const result = await whatsappAutoReplyService.sendFlowResponse(
                          whatsappSettings,
                          senderPhone,
                          flowResult.response,
                          activeSession.id
                        );
                        if (result.success) {
                          console.log("[MSG91 Webhook] Document upload flow response sent successfully");
                        } else {
                          console.error("[MSG91 Webhook] Failed to send document upload flow response:", result.error);
                        }
                      }
                    })();
                  }
                } else {
                  console.log("[MSG91 Webhook] Batch upload: suppressing intermediate response, more uploads expected");
                }
                
                return res.status(200).json({ success: true, handled: true });
              }
            } else {
              console.log("[MSG91 Webhook] Skipping document ID - URL domain not allowed:", urlObj.hostname);
            }
          }
          
          // Check if caption contains a 10-digit mobile number for linking to existing lead
          let targetLead = null;
          let linkedToExisting = false;
          
          // First, if we have an active flow session, check for existing lead in that session
          if (attachmentFlowSessionId) {
            targetLead = await whatsappService.findLeadByFlowSession(businessId, attachmentFlowSessionId);
            if (targetLead) {
              linkedToExisting = true;
              console.log("[MSG91 Webhook] Found existing lead by flow session:", targetLead.id);
            }
          }
          
          // If no lead from flow session, extract 10-digit mobile number from caption
          if (!targetLead) {
            const phoneMatch = caption?.match(/\b(\d{10})\b/);
            
            if (phoneMatch) {
              const captionPhone = phoneMatch[1];
              console.log("[MSG91 Webhook] Found phone in caption:", captionPhone);
              
              // Try to find existing lead by customer phone
              targetLead = await whatsappService.findLeadByCustomerPhone(businessId, captionPhone);
              if (targetLead) {
                linkedToExisting = true;
                console.log("[MSG91 Webhook] Found existing lead by customer phone:", targetLead.id);
              }
            } else {
              // No phone in caption - attach to most recent lead from this sender
              console.log("[MSG91 Webhook] No phone in caption, looking for recent lead from sender");
              targetLead = await whatsappService.findMostRecentLeadBySender(businessId, senderPhone);
              if (targetLead) {
                linkedToExisting = true;
                console.log("[MSG91 Webhook] Attaching to most recent lead from sender:", targetLead.id);
              }
            }
          }
          
          // If no existing lead found, create new lead (with flow session ID for deduplication)
          if (!targetLead) {
            targetLead = await whatsappService.processTextMessage(
              businessId,
              messageId,
              senderPhone,
              caption || `[${contentType} attachment]`,
              customerName,
              attachmentFlowSessionId // Pass flow session ID for deduplication
            );
            
            // If processTextMessage returns null (lead qualification failed), 
            // create a minimal lead to ensure attachment is saved
            if (!targetLead) {
              console.log("[MSG91 Webhook] Creating minimal lead for attachment storage");
              targetLead = await whatsappService.createMinimalLead(
                businessId,
                senderPhone,
                caption || `[${contentType} attachment]`,
                attachmentFlowSessionId // Pass flow session ID for deduplication
              );
            }
          }

          if (targetLead) {
            // Download and save media if auth key available
            const whatsappSettings = await whatsappService.getSettings(businessId);
            if (whatsappSettings?.msg91AuthKey && url) {
              // Determine media type - treat "file" as appropriate type based on filename
              let mediaType: "image" | "document" = "document";
              if (contentType === "image" || (contentType === "file" && filename?.match(/\.(jpg|jpeg|png|gif|webp)$/i))) {
                mediaType = "image";
              }
              await whatsappService.downloadAndSaveMediaFromUrl(
                targetLead.id,
                businessId,
                url,
                mediaType,
                filename,
                caption
              );
            }
            if (linkedToExisting) {
              console.log("[MSG91 Webhook] Attached media to existing lead:", targetLead.id);
            } else {
              console.log("[MSG91 Webhook] Created lead for media:", targetLead.id);
            }
          }
        } else if (contentType === "interactive" || contentType === "button") {
          const webhookStartTime = Date.now();
          const interactiveText = text || caption || "";
          
          const { whatsappFlowService } = await import("./services/whatsappFlowService");
          const { whatsappAutoReplyService } = await import("./services/whatsappAutoReplyService");
          
          let flowSessionId: string | undefined;
          let flowResult: any = { handled: false };
          
          if (interactiveText) {
            const pendingSession = await whatsappFlowService.getActiveSession(businessId, senderPhone);
            const pendingCollected = (pendingSession?.collectedData as Record<string, any>) || {};
            if (pendingCollected._pendingPdfUrl) {
              console.log("[MSG91 Webhook] Interactive response during PDF password flow, routing to processPdfPassword:", interactiveText);
              flowResult = await whatsappFlowService.processPdfPassword(businessId, senderPhone, interactiveText);
            } else {
              console.log("[MSG91 Webhook] Processing interactive response through flow:", interactiveText);
              flowResult = await whatsappFlowService.processMessage(businessId, senderPhone, interactiveText, pendingSession, true);
            }
            flowSessionId = flowResult.sessionId;
          }
          
          console.log(`[MSG91 Webhook] [Timing] Interactive flow processing: ${Date.now() - webhookStartTime}ms`);
          
          // Store incoming message FIRST so it gets an earlier timestamp than the outgoing response
          const lead = await whatsappService.processTextMessage(
            businessId,
            messageId,
            senderPhone,
            interactiveText || "[Interactive message]",
            customerName,
            flowSessionId
          );
          if (lead) {
            console.log("[MSG91 Webhook] Created lead from interactive:", lead.id);
          } else {
            console.log("[MSG91 Webhook] Interactive message processed, no lead created");
          }
          
          if (flowSessionId) {
            console.log(`[MSG91 Webhook] Interactive message stored with flow session: ${flowSessionId}`);
          }

          console.log(`[MSG91 Webhook] [Timing] Interactive message stored: ${Date.now() - webhookStartTime}ms`);
          
          // Send outgoing response AFTER incoming is stored to preserve correct conversation order
          if (flowResult.handled && (flowResult.preMessages?.length || flowResult.response) && settings) {
            console.log("[MSG91 Webhook] Flow handled interactive response, sending next step");
            (async () => {
              try {
                for (const preMsg of (flowResult.preMessages || [])) {
                  await whatsappAutoReplyService.sendFlowResponse(settings, senderPhone, preMsg, flowResult.sessionId);
                }
                if (flowResult.response) {
                  const result = await whatsappAutoReplyService.sendFlowResponse(
                    settings,
                    senderPhone,
                    flowResult.response,
                    flowResult.sessionId
                  );
                  if (result.success) {
                    console.log("[MSG91 Webhook] Flow response sent successfully");
                  } else {
                    console.log("[MSG91 Webhook] Flow response failed:", result.error);
                  }
                }
              } catch (err) {
                console.error("[MSG91 Webhook] Flow response error:", err);
              }
            })();
          }

          // Respond to MSG91 immediately - remaining work is non-critical
          console.log(`[MSG91 Webhook] [Timing] Interactive total: ${Date.now() - webhookStartTime}ms`);
          res.json({ status: "received" });
          
          // Non-critical background tasks (fire-and-forget)
          if (flowResult.handled && flowResult.collectedData && Object.keys(flowResult.collectedData).length > 0) {
            const { whatsappService } = await import("./services/whatsappService");
            whatsappService.updateLeadWithFlowData(
              businessId,
              senderPhone,
              flowResult.collectedData,
              flowResult.sessionId,
              !!flowResult.flowCompleted
            ).then(async (updatedLead) => {
              if (updatedLead) {
                console.log(`[MSG91 Webhook] Interactive lead updated with flow data (completed=${!!flowResult.flowCompleted}):`, updatedLead.id);

                if (flowResult.flowCompleted) {
                  try {
                    const [crmSettings] = await db
                      .select()
                      .from(customCrmSettings)
                      .where(eq(customCrmSettings.businessAccountId, businessId))
                      .limit(1);

                    if (crmSettings?.enabled && crmSettings.autoSyncEnabled && crmSettings.apiBaseUrl && crmSettings.apiEndpoint) {
                      console.log('[Custom CRM] Auto-syncing interactive WhatsApp lead:', updatedLead.id);
                      const crmMappings = await db
                        .select()
                        .from(customCrmFieldMappings)
                        .where(eq(customCrmFieldMappings.businessAccountId, businessId))
                        .orderBy(customCrmFieldMappings.sortOrder);

                      const extractedData = (updatedLead.extractedData as Record<string, any>) || {};
                      const documents = await buildDocumentContext(updatedLead.id);
                      const leadContext = {
                        lead: {
                          customerName: updatedLead.customerName || null,
                          customerEmail: updatedLead.customerEmail || null,
                          customerPhone: updatedLead.customerPhone || null,
                          loanAmount: updatedLead.loanAmount || null,
                          address: updatedLead.address || null,
                          loanType: updatedLead.loanType || null,
                          senderPhone: updatedLead.senderPhone || null,
                        },
                        extracted: extractedData,
                        documents,
                      };

                      let iAutoStoreCredential: CrmStoreCredential | undefined = undefined;
                      const iAsStoreName = extractedData.store_name || extractedData.storeName;
                      const iAsDealerName = extractedData.dealer_name || extractedData.dealerName || extractedData.dealer;
                      const iAsCityName = extractedData.city || extractedData.city_name || extractedData.dealer_city || extractedData.dealerCity;
                      if (iAsStoreName || iAsDealerName) {
                        const iAsStoreCreds = await db.select().from(crmStoreCredentials).where(and(eq(crmStoreCredentials.businessAccountId, businessId), eq(crmStoreCredentials.isActive, true)));
                        const iAsNorm = (s?: string | null) => s ? s.trim().toLowerCase() : '';
                        const iAsNS = iAsNorm(iAsStoreName), iAsND = iAsNorm(iAsDealerName), iAsNC = iAsNorm(iAsCityName);
                        if (iAsNS && iAsND && iAsNC) iAutoStoreCredential = iAsStoreCreds.find(sc => iAsNorm(sc.storeName) === iAsNS && iAsNorm(sc.dealerName) === iAsND && iAsNorm(sc.city) === iAsNC);
                        if (!iAutoStoreCredential && iAsNS && iAsND) iAutoStoreCredential = iAsStoreCreds.find(sc => iAsNorm(sc.storeName) === iAsNS && iAsNorm(sc.dealerName) === iAsND);
                        if (!iAutoStoreCredential && iAsNS) iAutoStoreCredential = iAsStoreCreds.find(sc => iAsNorm(sc.storeName) === iAsNS);
                        if (!iAutoStoreCredential && iAsStoreCreds.length > 0 && (iAsNS || iAsND)) {
                          try {
                            const OpenAI = (await import('openai')).default;
                            const [bizAcct] = await db.select().from(businessAccounts).where(eq(businessAccounts.id, businessId)).limit(1);
                            const iAsApiKey = bizAcct?.openaiApiKey ? (await import('./services/encryptionService')).decrypt(bizAcct.openaiApiKey) : process.env.OPENAI_API_KEY;
                            if (iAsApiKey) {
                              const iAsOAI = new OpenAI({ apiKey: iAsApiKey, timeout: 15000 });
                              const iAsList = iAsStoreCreds.map(sc => ({ id: sc.id, dealerName: sc.dealerName, storeName: sc.storeName, city: sc.city || '', storeId: sc.storeId }));
                              const iAsPrompt = `Match the lead's store info to the closest store credential.\n\nLead info:\n- Dealer: ${iAsDealerName || 'unknown'}\n- City: ${iAsCityName || 'unknown'}\n- Store: ${iAsStoreName || 'unknown'}\n\nAvailable stores (JSON):\n${JSON.stringify(iAsList)}\n\nReturn ONLY a JSON object: {"matchedId": "<store id or null>", "confidence": <0.0-1.0>}\nIf no good match exists, return {"matchedId": null, "confidence": 0}`;
                              const iAsCompletion = await iAsOAI.chat.completions.create({ model: 'gpt-4o-mini', messages: [{ role: 'user', content: iAsPrompt }], temperature: 0, max_tokens: 100, response_format: { type: 'json_object' } });
                              const iAsContent = iAsCompletion.choices[0]?.message?.content;
                              if (iAsContent) { const iAsAI = JSON.parse(iAsContent) as { matchedId: string | null; confidence: number }; if (iAsAI.matchedId && iAsAI.confidence >= 0.75) { iAutoStoreCredential = iAsStoreCreds.find(sc => sc.id === iAsAI.matchedId); console.log(`[CRM AutoSync] AI fuzzy match (interactive): store=${iAutoStoreCredential?.storeName}, confidence=${iAsAI.confidence}`); } }
                            }
                          } catch (iAsErr) { console.warn('[CRM AutoSync] AI fuzzy store matching failed (interactive):', iAsErr); }
                        }
                        if (iAutoStoreCredential) console.log(`[CRM AutoSync] Resolved store (interactive): ${iAutoStoreCredential.storeName} (SID: ${iAutoStoreCredential.sid})`);
                      }

                      const { syncLeadWithDocuments } = await import('./services/customCrmService');
                      const crmResult = await syncLeadWithDocuments(crmSettings, crmMappings, leadContext, iAutoStoreCredential);

                      if (crmResult.success) {
                        await db.update(whatsappLeads)
                          .set({
                            customCrmSyncStatus: 'synced',
                            customCrmSyncedAt: new Date(),
                            customCrmLeadId: crmResult.leadId || crmResult.applicationId || null,
                            customCrmSyncError: null,
                            customCrmSyncPayload: crmResult.payload as any,
                            updatedAt: new Date(),
                          })
                          .where(eq(whatsappLeads.id, updatedLead.id));
                        console.log('[Custom CRM] Auto-sync success (interactive):', updatedLead.id);
                      } else {
                        await db.update(whatsappLeads)
                          .set({
                            customCrmSyncStatus: 'failed',
                            customCrmSyncError: crmResult.message,
                            customCrmSyncPayload: crmResult.payload as any,
                            updatedAt: new Date(),
                          })
                          .where(eq(whatsappLeads.id, updatedLead.id));
                        console.error('[Custom CRM] Auto-sync failed (interactive):', updatedLead.id, crmResult.message);
                      }
                    }
                  } catch (crmErr) {
                    console.error('[Custom CRM] Auto-sync error (interactive):', crmErr);
                  }
                }
              }
            }).catch(err => {
              console.error("[MSG91 Webhook] Failed to update lead with flow data:", err);
            });
          }
          
          if (flowResult.shouldFallbackToAI && settings?.autoReplyEnabled === "true") {
            whatsappAutoReplyService.generateAndSendReply(
              businessId,
              senderPhone,
              interactiveText,
              uuid
            ).then(result => {
              if (result.success) {
                console.log("[MSG91 Webhook] Auto-reply sent successfully");
              } else {
                console.log("[MSG91 Webhook] Auto-reply failed:", result.error);
              }
            }).catch(err => {
              console.error("[MSG91 Webhook] Auto-reply error:", err);
            });
          }
          
          return;
        } else {
          // Unknown content type, still save it
          // Try to get flow session for this user if in an active flow
          const { whatsappFlowService } = await import("./services/whatsappFlowService");
          const flowResult = await whatsappFlowService.processMessage(businessId, senderPhone, text || caption || "");
          
          const lead = await whatsappService.processTextMessage(
            businessId,
            messageId,
            senderPhone,
            text || caption || `[${contentType || 'unknown'} message]`,
            customerName,
            flowResult.sessionId // Pass the flow session ID
          );
          if (lead) {
            console.log("[MSG91 Webhook] Created lead from unknown type:", lead.id, "contentType:", contentType);
          } else {
            console.log("[MSG91 Webhook] Unknown message processed, no lead created");
          }
        }

        return res.json({ status: "received" });
      }

      // OLD MSG91 format (legacy support)
      console.log("[MSG91 Webhook] Detected OLD format payload");
      
      if (payload.type === "message" && payload.payload) {
        const { id: messageId, source: senderPhone, type: messageType, text, image, document, timestamp } = payload.payload;

        if (senderPhone) {
          const { updateSession } = await import("./services/whatsappSessionService");
          updateSession(businessId, senderPhone).catch(err =>
            console.error("[MSG91 Webhook] Session update error (non-fatal):", err)
          );
        }

        if (messageType === "text" && text?.body) {
          const lead = await whatsappService.processTextMessage(
            businessId,
            messageId,
            senderPhone,
            text.body
          );
          if (lead) {
            console.log("[MSG91 Webhook] Created lead:", lead.id);
          } else {
            console.log("[MSG91 Webhook] Legacy text message processed, no lead created");
          }
        } else if (messageType === "image" && image) {
          const lead = await whatsappService.processTextMessage(
            businessId,
            messageId,
            senderPhone,
            image.caption || "[Image attachment]"
          );

          if (lead) {
            const whatsappSettings = await whatsappService.getSettings(businessId);
            if (whatsappSettings?.msg91AuthKey) {
              await whatsappService.downloadAndSaveMedia(
                lead.id,
                businessId,
                image.id,
                "image",
                image.mime_type,
                image.caption,
                undefined,
                whatsappSettings.msg91AuthKey
              );
            }
          }
        } else if (messageType === "document" && document) {
          const lead = await whatsappService.processTextMessage(
            businessId,
            messageId,
            senderPhone,
            document.caption || "[Document attachment]"
          );

          if (lead) {
            const whatsappSettings = await whatsappService.getSettings(businessId);
            if (whatsappSettings?.msg91AuthKey) {
              await whatsappService.downloadAndSaveMedia(
                lead.id,
                businessId,
                document.id,
                "document",
                document.mime_type,
                document.caption,
              document.filename,
              whatsappSettings.msg91AuthKey
            );
            }
          }
        }
      }

      // MSG91 requires a quick response
      res.status(200).json({ status: "received" });
    } catch (error: any) {
      console.error("[MSG91 Webhook] Error:", error);
      // Still return 200 to prevent retries
      res.status(200).json({ status: "error", message: error.message });
    }
  });

  // Get WhatsApp settings for a business
  app.get("/api/whatsapp/settings", requireAuth, async (req: AuthenticatedRequest, res) => {
    try {
      const businessAccountId = req.user?.activeBusinessAccountId || req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "No active business account" });
      }

      // Feature gating: check if WhatsApp is enabled for this business
      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      if (!businessAccount || businessAccount.whatsappEnabled !== "true") {
        return res.status(403).json({ error: "WhatsApp is not enabled for this business account" });
      }

      const { whatsappService } = await import("./services/whatsappService");
      let settings = await whatsappService.getSettings(businessAccountId);

      // Auto-generate webhook secret if not exists
      if (!settings) {
        const webhookSecret = whatsappService.generateWebhookSecret();
        settings = await whatsappService.saveSettings(businessAccountId, {
          msg91AuthKey: null,
          whatsappNumber: null,
          extractionFields: null,
          customPrompt: null,
          autoSyncToLeadsquared: "false",
          webhookSecret,
          leadCaptureEnabled: "true",
          requireName: "false",
          requirePhone: "false",
          requireEmail: "false",
          minFieldsRequired: 1,
        });
      } else if (!settings.webhookSecret) {
        const webhookSecret = whatsappService.generateWebhookSecret();
        settings = await whatsappService.saveSettings(businessAccountId, {
          msg91AuthKey: settings.msg91AuthKey,
          whatsappNumber: settings.whatsappNumber,
          extractionFields: settings.extractionFields,
          customPrompt: settings.customPrompt,
          autoSyncToLeadsquared: settings.autoSyncToLeadsquared,
          webhookSecret,
          leadCaptureEnabled: settings.leadCaptureEnabled || "true",
          requireName: settings.requireName || "false",
          requirePhone: settings.requirePhone || "false",
          requireEmail: settings.requireEmail || "false",
          minFieldsRequired: settings.minFieldsRequired ?? 1,
        });
      }

      // Generate webhook URL - derived from the incoming request so it always reflects the actual public domain
      const protocol = req.get('x-forwarded-proto') || req.protocol || 'https';
      const baseUrl = `${protocol}://${req.get('host')}`;
      const webhookUrl = `${baseUrl}/api/webhook/msg91/${businessAccountId}`;

      // Convert string booleans to actual booleans for frontend
      const formattedSettings = {
        ...settings,
        autoSyncToLeadsquared: settings.autoSyncToLeadsquared === "true",
        leadCaptureEnabled: settings.leadCaptureEnabled !== "false",
        requireName: settings.requireName === "true",
        requirePhone: settings.requirePhone === "true",
        requireEmail: settings.requireEmail === "true",
        minFieldsRequired: settings.minFieldsRequired ?? 1,
        autoReplyEnabled: settings.autoReplyEnabled === "true",
        msg91IntegratedNumberId: settings.msg91IntegratedNumberId || "",
        newApplicationCooldownDays: settings.newApplicationCooldownDays ?? 7,
        phoneNumberLength: settings.phoneNumberLength ?? 10,
        updateLeadEnabled: settings.updateLeadEnabled !== "false",
        whitelistEnabled: settings.whitelistEnabled === "true",
      };

      res.json({
        settings: formattedSettings,
        webhookUrl,
      });
    } catch (error: any) {
      console.error("Error fetching WhatsApp settings:", error);
      res.status(500).json({ error: error.message });
    }
  });

  // Update WhatsApp settings
  app.put("/api/whatsapp/settings", requireAuth, async (req: AuthenticatedRequest, res) => {
    try {
      const businessAccountId = req.user?.activeBusinessAccountId || req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "No active business account" });
      }

      // Feature gating: check if WhatsApp is enabled for this business
      const businessAccount = await storage.getBusinessAccount(businessAccountId);
      if (!businessAccount || businessAccount.whatsappEnabled !== "true") {
        return res.status(403).json({ error: "WhatsApp is not enabled for this business account" });
      }

      const { whatsappService } = await import("./services/whatsappService");
      
      let existingSettings = await whatsappService.getSettings(businessAccountId);
      const webhookSecret = existingSettings?.webhookSecret || whatsappService.generateWebhookSecret();

      const body = req.body;
      const updateData: Record<string, any> = { webhookSecret };

      if (body.msg91AuthKey !== undefined) updateData.msg91AuthKey = body.msg91AuthKey;
      if (body.whatsappNumber !== undefined) updateData.whatsappNumber = body.whatsappNumber;
      if (body.extractionFields !== undefined) updateData.extractionFields = body.extractionFields;
      if (body.customPrompt !== undefined) updateData.customPrompt = body.customPrompt;
      if (body.autoSyncToLeadsquared !== undefined) updateData.autoSyncToLeadsquared = body.autoSyncToLeadsquared ? "true" : "false";
      if (body.leadCaptureEnabled !== undefined) updateData.leadCaptureEnabled = body.leadCaptureEnabled === false ? "false" : "true";
      if (body.leadGenerationMode !== undefined) updateData.leadGenerationMode = body.leadGenerationMode === 'flow_only' ? 'flow_only' : 'first_message';
      if (body.requireName !== undefined) updateData.requireName = body.requireName ? "true" : "false";
      if (body.requirePhone !== undefined) updateData.requirePhone = body.requirePhone ? "true" : "false";
      if (body.requireEmail !== undefined) updateData.requireEmail = body.requireEmail ? "true" : "false";
      if (body.minFieldsRequired !== undefined) updateData.minFieldsRequired = Math.max(0, Math.min(6, parseInt(body.minFieldsRequired) || 1));
      if (body.autoReplyEnabled !== undefined) updateData.autoReplyEnabled = body.autoReplyEnabled ? "true" : "false";
      if (body.msg91IntegratedNumberId !== undefined) updateData.msg91IntegratedNumberId = body.msg91IntegratedNumberId || null;
      if (body.newApplicationCooldownDays !== undefined) updateData.newApplicationCooldownDays = Math.max(0, parseInt(body.newApplicationCooldownDays) || 7);
      if (body.phoneNumberLength !== undefined) updateData.phoneNumberLength = Math.max(1, Math.min(20, parseInt(body.phoneNumberLength) || 10));
      if (body.updateLeadEnabled !== undefined) updateData.updateLeadEnabled = body.updateLeadEnabled === false ? "false" : "true";
      if (body.useMasterTraining !== undefined) updateData.useMasterTraining = body.useMasterTraining === false ? "false" : "true";
      if (body.useLeadTraining !== undefined) updateData.useLeadTraining = body.useLeadTraining === false ? "false" : "true";
      if (body.whitelistEnabled !== undefined) updateData.whitelistEnabled = body.whitelistEnabled ? "true" : "false";
      if (body.whatsappEnabled !== undefined) updateData.whatsappEnabled = body.whatsappEnabled;
      if (body.sessionTemplateName !== undefined) updateData.sessionTemplateName = body.sessionTemplateName || null;
      if (body.sessionTemplateNamespace !== undefined) updateData.sessionTemplateNamespace = body.sessionTemplateNamespace || null;
      if (body.docConfirmationEnabled !== undefined) updateData.docConfirmationEnabled = body.docConfirmationEnabled ? "true" : "false";
      if (body.docConfirmationMode !== undefined) updateData.docConfirmationMode = ["per_document", "after_all_documents"].includes(body.docConfirmationMode) ? body.docConfirmationMode : "per_document";
      if (body.docConfirmationHeader !== undefined) updateData.docConfirmationHeader = body.docConfirmationHeader || null;
      if (body.docConfirmationFooter !== undefined) updateData.docConfirmationFooter = body.docConfirmationFooter || null;

      const settings = await whatsappService.saveSettings(businessAccountId, updateData);

      res.json(settings);
    } catch (error: any) {
      console.error("Error updating WhatsApp settings:", error);
      res.status(500).json({ error: error.message });
    }
  });

