  app.post("/api/whatsapp/document-types", requireAuth, async (req: AuthenticatedRequest, res) => {
    try {
      const businessAccountId = req.user?.activeBusinessAccountId || req.user?.businessAccountId;
      if (!businessAccountId) return res.status(400).json({ error: "No active business account" });
      const { key, name, promptTemplate, extractionFields, validationRules, leadFieldMappings, confirmationRequired } = req.body;
      if (!key || !name) return res.status(400).json({ error: "Key and name are required" });
      if (!extractionFields || !Array.isArray(extractionFields) || extractionFields.length === 0) {
        return res.status(400).json({ error: "At least one extraction field is required" });
      }
      const validConfirmValues = [null, undefined, "always", "never"];
      const sanitizedConfirmation = validConfirmValues.includes(confirmationRequired) ? (confirmationRequired ?? null) : null;
      const { documentTypeService } = await import("./services/documentTypeService");
      const created = await documentTypeService.createDocumentType(businessAccountId, {
        key: key.toLowerCase().replace(/[^a-z0-9_]/g, "_"),
        name,
        promptTemplate,
        extractionFields,
        validationRules,
        leadFieldMappings,
        confirmationRequired: sanitizedConfirmation,
      });
      res.json({ documentType: created });
    } catch (error: any) {
      if (error.message?.includes("duplicate key") || error.code === "23505") {
        return res.status(409).json({ error: "A document type with this key already exists" });
      }
      res.status(500).json({ error: error.message });
    }
  });

