      const validConfirmValues = [null, undefined, "always", "never"];
      const sanitizedConfirmation = confirmationRequired !== undefined
        ? (validConfirmValues.includes(confirmationRequired) ? (confirmationRequired ?? null) : null)
        : undefined;
      const { documentTypeService } = await import("./services/documentTypeService");
