  // WhatsApp Whitelist - Add a number
  app.post("/api/whatsapp/whitelist", requireAuth, async (req: AuthenticatedRequest, res) => {
    try {
      const businessAccountId = req.user?.activeBusinessAccountId || req.user?.businessAccountId;
      if (!businessAccountId) return res.status(400).json({ error: "No active business account" });

      const { phoneNumber, label } = req.body;
      if (!phoneNumber) return res.status(400).json({ error: "Phone number is required" });

      const normalized = phoneNumber.replace(/\D/g, '');
      if (normalized.length < 7) return res.status(400).json({ error: "Invalid phone number" });

      const { whatsappWhitelist } = await import("../shared/schema");

      const existing = await db.select().from(whatsappWhitelist)
        .where(and(
          eq(whatsappWhitelist.businessAccountId, businessAccountId),
          eq(whatsappWhitelist.phoneNumber, normalized)
        ))
        .limit(1);

      if (existing.length > 0) return res.status(409).json({ error: "Number already whitelisted" });

      const [entry] = await db.insert(whatsappWhitelist).values({
        businessAccountId,
        phoneNumber: normalized,
        label: label || null,
      }).returning();

      res.json({ entry });
    } catch (error: any) {
      console.error("Error adding to whitelist:", error);
      res.status(500).json({ error: error.message });
    }
  });

  // WhatsApp Whitelist - Bulk add numbers
  app.post("/api/whatsapp/whitelist/bulk", requireAuth, async (req: AuthenticatedRequest, res) => {
    try {
      const businessAccountId = req.user?.activeBusinessAccountId || req.user?.businessAccountId;
      if (!businessAccountId) return res.status(400).json({ error: "No active business account" });

      const { numbers } = req.body;
      if (!Array.isArray(numbers) || numbers.length === 0) return res.status(400).json({ error: "Numbers array is required" });

      const { whatsappWhitelist } = await import("../shared/schema");

      const existing = await db.select({ phoneNumber: whatsappWhitelist.phoneNumber })
        .from(whatsappWhitelist)
        .where(eq(whatsappWhitelist.businessAccountId, businessAccountId));
      const existingSet = new Set(existing.map(e => e.phoneNumber));

      const toInsert: { businessAccountId: string; phoneNumber: string; label: string | null }[] = [];
      let skipped = 0;

      for (const item of numbers) {
        const phone = typeof item === 'string' ? item : item.phoneNumber;
        const label = typeof item === 'string' ? null : (item.label || null);
        const normalized = phone?.replace(/\D/g, '');
        if (!normalized || normalized.length < 7) { skipped++; continue; }
        if (existingSet.has(normalized)) { skipped++; continue; }
        existingSet.add(normalized);
        toInsert.push({ businessAccountId, phoneNumber: normalized, label });
      }

      let added = 0;
      if (toInsert.length > 0) {
        await db.insert(whatsappWhitelist).values(toInsert);
        added = toInsert.length;
      }

      res.json({ added, skipped });
    } catch (error: any) {
      console.error("Error bulk adding to whitelist:", error);
      res.status(500).json({ error: error.message });
    }
  });

