  app.post("/api/whatsapp/lead-fields", requireAuth, async (req: AuthenticatedRequest, res) => {
    try {
      const businessAccountId = req.user?.activeBusinessAccountId || req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "No active business account" });
      }

      const { fieldKey, fieldLabel, fieldType, isRequired, isEnabled, defaultCrmFieldKey } = req.body;
      if (!fieldKey || !fieldLabel) {
        return res.status(400).json({ error: "Field key and label are required" });
      }

      const { whatsappService } = await import("./services/whatsappService");
      const field = await whatsappService.createLeadField(businessAccountId, {
        fieldKey,
        fieldLabel,
        fieldType: fieldType || "text",
        isRequired: isRequired || false,
        isEnabled: isEnabled !== false,
        defaultCrmFieldKey: defaultCrmFieldKey || undefined,
      });

      // Auto-create CRM mapping if defaultCrmFieldKey is provided and no mapping exists yet for derived sourceField
      if (defaultCrmFieldKey && isEnabled !== false) {
        const normalizedKey = field.fieldKey;
        const defaultKeys = ['customer_name', 'customer_phone', 'customer_email'];
        const isDefaultField = defaultKeys.includes(normalizedKey);
        const sourceField = isDefaultField
          ? (normalizedKey === 'customer_name' ? 'lead.customerName' : normalizedKey === 'customer_phone' ? 'lead.customerPhone' : 'lead.customerEmail')
          : `extracted.${normalizedKey}`;
        const existing = await db.select({ id: customCrmFieldMappings.id }).from(customCrmFieldMappings)
          .where(and(eq(customCrmFieldMappings.businessAccountId, businessAccountId), eq(customCrmFieldMappings.sourceField, sourceField)))
          .limit(1);
        if (existing.length === 0) {
          const maxSort = await db.select({ maxOrder: sql`COALESCE(MAX(sort_order), 0)` }).from(customCrmFieldMappings).where(eq(customCrmFieldMappings.businessAccountId, businessAccountId));
          await db.insert(customCrmFieldMappings).values({ businessAccountId, crmField: defaultCrmFieldKey, sourceType: 'dynamic', sourceField, displayName: fieldLabel || field.fieldLabel, isEnabled: 'true', sortOrder: (maxSort[0]?.maxOrder as number || 0) + 1, isAutoManaged: true });
        }
      }

      res.json({ field });
    } catch (error: any) {
      console.error("Error creating WhatsApp lead field:", error);
      res.status(500).json({ error: error.message });
    }
  });

