  // Instagram Webhook - GET for Meta verification challenge
  app.get("/api/instagram/webhook", async (req, res) => {
    try {
      const mode = req.query["hub.mode"];
      const token = req.query["hub.verify_token"];
      const challenge = req.query["hub.challenge"];

      if (mode === "subscribe" && token && challenge) {
        const { instagramService } = await import("./services/instagramService");
        const settings = await instagramService.findSettingsByVerifyToken(token as string);
        
        if (settings) {
          console.log("[Instagram Webhook] Verification successful");
          return res.status(200).send(challenge);
        }
        
        console.warn("[Instagram Webhook] Verify token mismatch");
        return res.sendStatus(403);
      }

      return res.sendStatus(400);
    } catch (error: any) {
      console.error("[Instagram Webhook] Verification error:", error);
      return res.sendStatus(500);
    }
  });

  // Instagram Webhook - POST for incoming DMs and Comments
  app.post("/api/instagram/webhook", async (req, res) => {
    res.status(200).send("EVENT_RECEIVED");

    try {
      const body = req.body;
      if (body.object !== "instagram") return;

      const { instagramService } = await import("./services/instagramService");
      const { instagramAutoReplyService } = await import("./services/instagramAutoReplyService");
      const { instagramCommentReplyService } = await import("./services/instagramCommentReplyService");
      const crypto = await import("crypto");

      for (const entry of body.entry || []) {
        // Handle comment webhook events (changes field)
        if (entry.changes && Array.isArray(entry.changes)) {
          for (const change of entry.changes) {
            if (change.field !== "comments" || !change.value) continue;

            const commentValue = change.value;
            const commentId = commentValue.id;
            const commentText = commentValue.text || "";
            const commenterId = commentValue.from?.id;
            const commenterUsername = commentValue.from?.username;
            const postId = commentValue.media?.id;

            if (!commentId || !commentText || !commenterId) {
              console.warn("[Instagram Webhook] Incomplete comment data - skipping");
              continue;
            }

            console.log(`[Instagram Webhook] Incoming comment from @${commenterUsername || commenterId}: "${commentText.substring(0, 50)}..."`);

            const entryId = entry.id;
            const businessData = entryId
              ? await instagramService.findBusinessByIgAccountId(entryId)
              : null;

            if (!businessData) {
              console.warn(`[Instagram Webhook] No business found for IG account (comment): ${entryId}`);
              continue;
            }

            const { businessAccountId, settings } = businessData;

            instagramCommentReplyService.processComment(
              settings,
              businessAccountId,
              {
                commentId,
                commentText,
                commenterId,
                commenterUsername,
                postId,
              }
            ).catch(err => console.error("[Instagram Webhook] Comment reply error:", err));
          }
        }

        // Handle DM webhook events (messaging field)
        for (const event of entry.messaging || []) {
          if (!event.message || !event.sender?.id) continue;
          if (event.message.is_echo) continue;

          const senderId = event.sender.id;
          const recipientId = event.recipient?.id;
          const messageText = event.message?.text || "";
          const igMessageId = event.message?.mid;

          console.log(`[Instagram Webhook] Incoming DM from ${senderId}: ${messageText.substring(0, 50)}...`);

          const businessData = recipientId 
            ? await instagramService.findBusinessByIgAccountId(recipientId)
            : null;

          if (!businessData) {
            console.warn(`[Instagram Webhook] No business found for IG account: ${recipientId}`);
            continue;
          }

          const { businessAccountId, settings } = businessData;

          if (settings.appSecret) {
            const signature = req.headers["x-hub-signature-256"] as string;
            if (!signature) {
              console.warn("[Instagram Webhook] Missing signature header - skipping");
              continue;
            }
            const rawBody = (req as any).rawBody;
            if (rawBody) {
              const decryptedAppSecret = instagramService.getDecryptedAppSecret(settings);
              if (decryptedAppSecret) {
                const expectedHash = crypto
                  .createHmac("sha256", decryptedAppSecret)
                  .update(rawBody)
                  .digest("hex");
                if (signature !== `sha256=${expectedHash}`) {
                  console.warn("[Instagram Webhook] Signature mismatch - skipping");
                  continue;
                }
              }
            }
          }

          if (igMessageId) {
            const existing = await instagramService.findMessageByIgId(igMessageId);
            if (existing) {
              console.log(`[Instagram Webhook] Duplicate message ${igMessageId} - skipping`);
              continue;
            }
          }

          let senderUsername: string | undefined;
          try {
            const decryptedToken = instagramService.getDecryptedAccessToken(settings);
            if (decryptedToken) {
              const profile = await instagramService.getUserProfile(decryptedToken, senderId);
              senderUsername = profile?.username;
            }
          } catch {}

          await instagramService.storeMessage(
            businessAccountId,
            senderId,
            messageText,
            "incoming",
            {
              senderUsername: senderUsername || undefined,
              igMessageId: igMessageId || undefined,
              messageType: event.message?.attachments ? "image" : "text",
              mediaUrl: event.message?.attachments?.[0]?.payload?.url || undefined,
            }
          );

          if (messageText) {
            const businessAccount = await db.query.businessAccounts.findFirst({
              where: eq(businessAccounts.id, businessAccountId)
            });
            
            if (businessAccount && businessAccount.instagramEnabled === "true") {
              const { instagramFlowService } = await import("./services/instagramFlowService");
              
              try {
                const flowResult = await instagramFlowService.processMessage(businessAccountId, senderId, messageText);
                
                if (flowResult.handled && flowResult.response) {
                  if (flowResult.response.type === "buttons" && flowResult.response.buttons && flowResult.response.buttons.length > 0) {
                    const quickReplies = flowResult.response.buttons.map(b => ({
                      content_type: "text" as const,
                      title: b.title,
                      payload: b.id,
                    }));
                    const sendResult = await instagramService.sendQuickReply(settings, senderId, flowResult.response.text, quickReplies);
                    if (sendResult.success) {
                      await instagramService.storeMessage(businessAccountId, senderId, flowResult.response.text, "outgoing", { messageType: "text" });
                    }
                  } else {
                    const sendResult = await instagramService.sendMessage(settings, senderId, flowResult.response.text);
                    if (sendResult.success) {
                      await instagramService.storeMessage(businessAccountId, senderId, flowResult.response.text, "outgoing", { messageType: "text" });
                    }
                  }

                  if (flowResult.flowCompleted && flowResult.collectedData && Object.keys(flowResult.collectedData).length > 0) {
                    try {
                      if (settings.leadCaptureEnabled === "true") {
                        await instagramService.createInstagramLead(businessAccountId, {
                          senderId,
                          senderUsername: senderUsername || undefined,
                          flowSessionId: flowResult.sessionId || undefined,
                          extractedData: flowResult.collectedData,
                        });
                        console.log(`[Instagram Webhook] Lead created from flow completion for sender ${senderId}`);
                      }
                    } catch (leadError) {
                      console.error("[Instagram Webhook] Error creating lead from flow:", leadError);
                    }
                  }
                } else if (flowResult.shouldFallbackToAI && settings.autoReplyEnabled === "true") {
                  instagramAutoReplyService.generateAndSendReply(
                    businessAccountId,
                    senderId,
                    messageText
                  ).catch(err => console.error("[Instagram Webhook] Auto-reply error:", err));
                } else if (!flowResult.handled && settings.autoReplyEnabled === "true") {
                  instagramAutoReplyService.generateAndSendReply(
                    businessAccountId,
                    senderId,
                    messageText
                  ).catch(err => console.error("[Instagram Webhook] Auto-reply error:", err));
                }
              } catch (flowError) {
                console.error("[Instagram Webhook] Flow processing error:", flowError);
                if (settings.autoReplyEnabled === "true") {
                  instagramAutoReplyService.generateAndSendReply(
                    businessAccountId,
                    senderId,
                    messageText
                  ).catch(err => console.error("[Instagram Webhook] Auto-reply error:", err));
                }
              }
            }
          }
        }
      }
    } catch (error: any) {
      console.error("[Instagram Webhook] Processing error:", error);
    }
  });

