  app.patch("/api/instagram/flows/:flowId/steps/:stepId/toggle-pause", requireAuth, async (req: AuthenticatedRequest, res) => {
    try {
      const { flowId, stepId } = req.params;
      const [step] = await db
        .select({ paused: instagramFlowSteps.paused })
        .from(instagramFlowSteps)
        .where(and(eq(instagramFlowSteps.id, stepId), eq(instagramFlowSteps.flowId, flowId)))
        .limit(1);

      if (!step) return res.status(404).json({ error: "Step not found" });

      const [updated] = await db
        .update(instagramFlowSteps)
        .set({ paused: !step.paused })
        .where(and(eq(instagramFlowSteps.id, stepId), eq(instagramFlowSteps.flowId, flowId)))
        .returning();

      res.json({ step: updated });
    } catch (error: any) {
      console.error("Error toggling Instagram step pause:", error);
      res.status(500).json({ error: error.message });
    }
  });

