  app.post("/api/facebook/test-connection", requireAuth, async (req, res) => {
    try {
      const businessAccountId = req.user!.businessAccountId;
      if (!businessAccountId) return res.status(400).json({ error: "No business account" });

      const { facebookService } = await import("./services/facebookService");
      const settings = await facebookService.getSettings(businessAccountId);

      if (!settings?.pageAccessToken) {
        return res.status(400).json({ error: "Facebook Page Access Token not configured" });
      }

      const decryptedToken = facebookService.getDecryptedAccessToken(settings);
      if (!decryptedToken) {
        return res.status(400).json({ error: "Failed to decrypt access token. Try re-saving your token." });
      }

      const response = await fetch(`https://graph.facebook.com/v21.0/me?fields=name,id&access_token=${encodeURIComponent(decryptedToken)}`);
      const data = await response.json();

      if (response.ok && data.id) {
        res.json({ success: true, profile: { name: data.name, id: data.id } });
      } else {
        res.status(400).json({ error: data.error?.message || "Failed to connect. Check your access token." });
      }
    } catch (error: any) {
      res.status(500).json({ error: error.message });
    }
  });

