  app.get("/api/facebook/insights", requireAuth, async (req: AuthenticatedRequest, res) => {
    try {
      const businessAccountId = req.user?.activeBusinessAccountId || req.user?.businessAccountId;
      if (!businessAccountId) {
        return res.status(400).json({ error: "No active business account" });
      }

      const { period } = req.query;
      const now = new Date();
      let startDate: Date | null = null;
      let endDate: Date | null = null;

      if (period === 'today') {
        startDate = new Date(now.getFullYear(), now.getMonth(), now.getDate());
      } else if (period === 'yesterday') {
        startDate = new Date(now.getFullYear(), now.getMonth(), now.getDate() - 1);
        endDate = new Date(now.getFullYear(), now.getMonth(), now.getDate());
      } else if (period === '7d') {
        startDate = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
      } else if (period === '30d') {
        startDate = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
      } else if (period === '90d') {
        startDate = new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000);
      }

      const dateFilter = startDate
        ? (endDate
          ? sql`AND created_at >= ${startDate} AND created_at < ${endDate}`
          : sql`AND created_at >= ${startDate}`)
        : sql``;

      const dateFilterReceived = startDate
        ? (endDate
          ? sql`AND received_at >= ${startDate} AND received_at < ${endDate}`
          : sql`AND received_at >= ${startDate}`)
        : sql``;

      const sessionsRows = await db.execute(sql`
        SELECT 
          COUNT(*) as total,
          COUNT(*) FILTER (WHERE status = 'completed') as completed,
          COUNT(*) FILTER (WHERE status = 'active') as active,
          COUNT(*) FILTER (WHERE status = 'expired' OR status = 'abandoned') as dropped
        FROM facebook_flow_sessions
        WHERE business_account_id = ${businessAccountId} ${dateFilter}
      `);
      const sessionsResult: any = sessionsRows.rows?.[0] || sessionsRows[0] || {};

      const leadsRows = await db.execute(sql`
        SELECT 
          COUNT(*) as total_leads,
          COUNT(DISTINCT sender_id) as unique_senders
        FROM facebook_leads
        WHERE business_account_id = ${businessAccountId} ${dateFilterReceived}
      `);
      const leadsResult: any = leadsRows.rows?.[0] || leadsRows[0] || {};

      const messagesRows = await db.execute(sql`
        SELECT 
          COUNT(*) FILTER (WHERE direction = 'incoming') as total_incoming,
          COUNT(*) FILTER (WHERE direction = 'outgoing') as total_outgoing
        FROM facebook_messages
        WHERE business_account_id = ${businessAccountId} ${dateFilter}
      `);
      const messagesResult: any = messagesRows.rows?.[0] || messagesRows[0] || {};

      const chartStartFilter = period === 'all'
        ? sql``
        : (() => {
            const chartDays = period === 'today' ? 1 : period === 'yesterday' ? 1 : period === '7d' ? 7 : period === '90d' ? 90 : 30;
            const chartStart = (period === 'today' || period === 'yesterday') ? startDate! : new Date(now.getTime() - chartDays * 24 * 60 * 60 * 1000);
            return sql`AND created_at >= ${chartStart}`;
          })();
      const chartStartFilterReceived = period === 'all'
        ? sql``
        : (() => {
            const chartDays = period === 'today' ? 1 : period === 'yesterday' ? 1 : period === '7d' ? 7 : period === '90d' ? 90 : 30;
            const chartStart = (period === 'today' || period === 'yesterday') ? startDate! : new Date(now.getTime() - chartDays * 24 * 60 * 60 * 1000);
            return sql`AND received_at >= ${chartStart}`;
          })();

      const dailySessionsRows = await db.execute(sql`
        SELECT 
          DATE(created_at) as date,
          COUNT(*) as sessions,
          COUNT(*) FILTER (WHERE status = 'completed') as completed
        FROM facebook_flow_sessions
        WHERE business_account_id = ${businessAccountId}
          ${chartStartFilter}
          ${endDate ? sql`AND created_at < ${endDate}` : sql``}
        GROUP BY DATE(created_at)
        ORDER BY date
      `);
      const dailySessions: any[] = dailySessionsRows.rows || dailySessionsRows;

      const dailyLeadsRows = await db.execute(sql`
        SELECT 
          DATE(received_at) as date,
          COUNT(*) as leads
        FROM facebook_leads
        WHERE business_account_id = ${businessAccountId}
          ${chartStartFilterReceived}
          ${endDate ? sql`AND received_at < ${endDate}` : sql``}
        GROUP BY DATE(received_at)
        ORDER BY date
      `);
      const dailyLeads: any[] = dailyLeadsRows.rows || dailyLeadsRows;

      const totalSessions = Number(sessionsResult?.total || 0);
      const completedSessions = Number(sessionsResult?.completed || 0);
      const completionRate = totalSessions > 0 ? Math.round((completedSessions / totalSessions) * 100) : 0;

      res.json({
        sessions: {
          total: totalSessions,
          completed: completedSessions,
          active: Number(sessionsResult?.active || 0),
          dropped: Number(sessionsResult?.dropped || 0),
          completionRate,
        },
        leads: {
          total: Number(leadsResult?.total_leads || 0),
          uniqueSenders: Number(leadsResult?.unique_senders || 0),
        },
        messages: {
          totalIncoming: Number(messagesResult?.total_incoming || 0),
          totalOutgoing: Number(messagesResult?.total_outgoing || 0),
        },
        daily: {
          sessions: dailySessions.map((d: any) => ({
            date: d.date,
            sessions: Number(d.sessions),
            completed: Number(d.completed),
          })),
          leads: dailyLeads.map((d: any) => ({
            date: d.date,
            leads: Number(d.leads),
          })),
        },
      });
    } catch (error: any) {
      console.error("Error fetching Facebook insights:", error);
      res.status(500).json({ error: error.message });
    }
  });

